-- Poems batch 95
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('07f141a2-ba63-4d62-aa9c-8a1e975450fd','有感  其三','葛立方','宋','宋诗','song-poetry','','[]','但知鬼目爲芝草，誰信羚羊破佛牙。',32,'全唐诗/poet.song.113000.json','["但知鬼目爲芝草，誰信羚羊破佛牙。", "娘子阿姨何處辨，時人識賣假金家。"]'),
('ad582d62-c774-45c3-ad9a-5675cce541b4','操葉舟凌巨浪訪道祖  其一','葛立方','宋','宋诗','song-poetry','','[]','一牛鳴處是君家，乘興煙蓬蹴浪花。',32,'全唐诗/poet.song.113000.json','["一牛鳴處是君家，乘興煙蓬蹴浪花。", "銀浦流雲新得路，人驚仙客在浮槎。"]'),
('29a98562-8bd4-4150-b4b6-28c061a3418d','操葉舟凌巨浪訪道祖  其二','葛立方','宋','宋诗','song-poetry','','[]','一頃煙波渺太空，獨操蓮葉破青銅。',32,'全唐诗/poet.song.113000.json','["一頃煙波渺太空，獨操蓮葉破青銅。", "炊煙不動無桐甑，底處求僧與二童。"]'),
('a77fcb35-795d-4734-9fe1-5dca7d358a35','春日野飲','葛立方','宋','宋诗','song-poetry','','[]','十載干戈僅脫身，殘年重作太平民。',64,'全唐诗/poet.song.113000.json','["十載干戈僅脫身，殘年重作太平民。", "杯鐺有趣於中好，花柳無情分外春。", "不遠上元新甲子，肯將短筆怨庚寅。", "從教蕙帳驚猿鶴，却欲重彈冠上塵。"]'),
('eb787b57-068a-4542-a5c4-62e0a70c5a86','余赴官宮庠與道祖通判久聚乍散每有懷想作詩五十韵道二十餘年出處寄呈','葛立方','宋','宋诗','song-poetry','','[]','初拜清揚日，菰城荻始芽。',288,'全唐诗/poet.song.113000.json','["初拜清揚日，菰城荻始芽。", "家聲璜出渭，駿氣馬生洼。", "博識該三篋，宏才記五車。", "高明挈日月，文彩炫雲霞。", "結友方傾蓋，連姻復附葭。", "鳳軿銀燭映，鸞扇綵雲遮。", "去作南陽別，俄成澤國賒。", "浚都先玉轡，濉水會仙槎。", "我止邗溝第，君歸霅水涯。", "枌關方弛檐，毳幕忽鳴笳。", "茂苑依城堞，菁山隠谽谺。", "林巒迷霧豹，鼓吹只池蛙。", "宇宙焦先室，庖厨蔡樽茄。", "旋聞翦蛇豕，却共注魚蝦。", "經笥精藍肄，辭鋒試席誇。", "棘闈排勝陣，楓殿趁朝赮。", "聯籍攀丹桂，連名擬墨緺。", "枕溪同擇勝，築室共崇窊。", "許邁通懸霤，何君住若耶。", "奇礓爭磊砢，嘉卉鬭紛葩。", "風入黄蘆浦，煙橫白鷺沙。", "鷁舟行櫂短，蟻酒酌尊污。", "覓句文詞競，枰棋笑語譁。", "山深陪杖屨，林僻預瓜茶。"]'),
('2a7d8669-5686-4f73-83f3-7245c9b26c29','宮庠旅泊','葛立方','宋','宋诗','song-poetry','','[]','客裏絕經營，清心摧五兵。',48,'全唐诗/poet.song.113000.json','["客裏絕經營，清心摧五兵。", "功名兩蝸角，田舍一牛鳴。", "行止成阿唯，榮枯略弟兄。", "欲攄今日意，聊仗五言城。"]'),
('c67caa93-3dda-4d42-9dcd-744e1fdbdfee','奉祠太一','葛立方','宋','宋诗','song-poetry','','[]','鼕鼕鼛鼓不勤民，幻出琳宮遠世塵。',64,'全唐诗/poet.song.113000.json','["鼕鼕鼛鼓不勤民，幻出琳宮遠世塵。", "風咽唄聲金殿邃，日移幡影石壇新。", "雲軿摇曳來三境，霧帳淒迷妥十神。", "堪笑茂陵成左計，虛將棗脯候秋春。"]'),
('26b08760-f831-4f68-8f6e-757e481519ec','次韵陳廷藻戶部西湖快目堂之集','葛立方','宋','宋诗','song-poetry','','["\u897f\u6e56"]','冰壺影裏集朋從，三雅同傾共一中。',64,'全唐诗/poet.song.113000.json','["冰壺影裏集朋從，三雅同傾共一中。", "相與文楸看飛雹，不須舞袖覓驚鴻。", "雲邊鳥道古來寺，煙際漁舟何處翁。", "竟日追歡難卜夜，只緣身在省牆東。"]'),
('c4b943e3-bc2b-4c16-9cde-e4ce99bb9519','周元舉待制挽歌詞  其一','葛立方','宋','宋诗','song-poetry','','[]','平生器業負經綸，誰謂公才不秉鈞。',64,'全唐诗/poet.song.113000.json','["平生器業負經綸，誰謂公才不秉鈞。", "讜論十年持紫橐，仁聲三郡駕朱輪。", "龜文豈是背無甲，駒隙俄驚歲在辰。", "宅夾清漳親義重，佳城引脰涕霑巾。"]'),
('6c623843-2e93-41a8-88b4-03ce4529064f','周元舉待制挽歌詞  其二','葛立方','宋','宋诗','song-poetry','','[]','手開榛棘啟雲扃，淳古胸懷到大庭。',64,'全唐诗/poet.song.113000.json','["手開榛棘啟雲扃，淳古胸懷到大庭。", "坐脫老龐那問日，自銘小杜不占星。", "牛頭吉兆空形夢，馬鬣新封遽妥靈。", "謦欬從今成永訣，欲瞻遺像只丹青。"]'),
('a4a5f9de-a62a-4c62-b995-536980f58b10','次韵周少隠梅花三絕  其一','葛立方','宋','宋诗','song-poetry','','[]','蠅館先生心若灰，猶憐梅蘤傍牆栽。',32,'全唐诗/poet.song.113000.json','["蠅館先生心若灰，猶憐梅蘤傍牆栽。", "瀛洲快覩春風面，却笑江南苦未開。"]'),
('8a396ee2-6830-4935-9241-9f3840e2e5d2','次韵周少隠梅花三絕  其二','葛立方','宋','宋诗','song-poetry','','["\u897f\u6e56"]','聞說青腰夜雨霜，水沉山麝洩寒香。',32,'全唐诗/poet.song.113000.json','["聞說青腰夜雨霜，水沉山麝洩寒香。", "西湖處士多標榜，端的包羞是海棠。"]'),
('662c2692-0974-4f66-9363-2ba44fe975d6','次韵周少隠梅花三絕  其三','葛立方','宋','宋诗','song-poetry','','[]','化工巧綴一枝斜，點玉凝酥碎疊紗。',32,'全唐诗/poet.song.113000.json','["化工巧綴一枝斜，點玉凝酥碎疊紗。", "待得春來開滿樹，何如忍凍雨三花。"]'),
('381cd316-b0dd-4cc4-a962-014ea68cd7e1','試院和陳蕃仲酴醿兩絕  其一','葛立方','宋','宋诗','song-poetry','','[]','芳心玉面出蠶叢，骨醉先生酒盞中。',32,'全唐诗/poet.song.113000.json','["芳心玉面出蠶叢，骨醉先生酒盞中。", "白髮病翁新止酒，枕囊猶覬夢魂通。"]'),
('34e9946b-9238-4c75-8ebe-ccb3a3eb09dd','試院和陳蕃仲酴醿兩絕  其二','葛立方','宋','宋诗','song-poetry','','[]','幽姿不分小山叢，合在江梅季孟中。',32,'全唐诗/poet.song.113000.json','["幽姿不分小山叢，合在江梅季孟中。", "香破鶴林真囈語，肯教七七擅神通。"]'),
('54f4cb4b-342a-4748-b8d5-70c73138bd4b','送胡汝明待制赴鎮桂林','葛立方','宋','宋诗','song-poetry','','[]','今代人中傑，攄忠久贊襄。',288,'全唐诗/poet.song.113000.json','["今代人中傑，攄忠久贊襄。", "摛文揮鏤管，積學儷青箱。", "體道經爲笥，臨機智作囊。", "威名知草木，義勇震戎羌。", "玄女傳符舊，黄公授略長。", "投壺祭征虜，納策蔡中郎。", "暫解淮西印，來浮霅水航。", "求田多好畤，卜宅類清漳。", "寄興紅塵外，追歡錦瑟旁。", "醉酣容偃鼠，吟詠許寒螿。", "邂逅升徐榻，夤緣上孔堂。", "周旋略名分，眄睞沐謙光。", "細札俄頒命，真儒起幹方。", "地寬連五嶺，權重讋三梁。", "油戟明朝日，銛戈耿夜霜。", "桂林飄黝粒，荔蒲劈瓊房。", "來暮歌廉袴，遄歸覲舜裳。", "謀謨多妙簡，夢想獨難忘。", "烏府思忠藎，丹墀渴對揚。", "一言蘇品類，三接屈皇王。", "沙水猶含凍，江梅漸放香。", "行行携部曲，去去背雲鄉。", "劈箭飛征櫂，牽繩黯別腸。", "平居膺刻畫，祖送倍淒涼。"]'),
('ef5eded9-8637-4ded-91c1-c4a3a1637fc4','冬至後雪','葛立方','宋','宋诗','song-poetry','','[]','客寐失通宵，寒聲動泬寥。',216,'全唐诗/poet.song.113000.json','["客寐失通宵，寒聲動泬寥。", "雲容頹玉宇，雪陣攪層霄。", "點點楷灰落，亭亭柳絮飄。", "文窗斜擊紙，老樹巧裝條。", "墮嶺篩寒髻，凌波洒碧綃。", "風狂初索索，雨細漸瀌瀌。", "入酒應愁凍，當爐覺易消。", "蕭森聲勢密，飄瞥路岐遥。", "蓑冷翁仍釣，山迷客罷樵。", "裁紈鋪縞素，脩月屑琨瑶。", "市小瓊樓合，時和玉燭調。", "三章歌睿製，五板賀寒朝。", "吠犬驚南嶺，騎馿憶灞橋。", "終南憂壓腦，少室衒齊腰。", "嗟我星霜老，經時鬢髮凋。", "摘蔬和凍煮，收葉带蘇燒。", "路滑難求馬，衣單悔貰貂。", "暖寒誰掃徑，莫負紫金蕉。"]'),
('e84c627f-d9ce-44e3-8104-eb2bba6e89b1','次韵陳元述見寄謝茶  其一','葛立方','宋','宋诗','song-poetry','','[]','年來直欲配茶神，石鼎山泉日日親。',64,'全唐诗/poet.song.113000.json','["年來直欲配茶神，石鼎山泉日日親。", "竹裏烹煎嗤左計，舌端緜味認前塵。", "書林坐攪枯腸讀，酒所渾消玉頰春。", "曾飲日邊甘露碗，沙溪難遣亂吾真。"]'),
('d3584195-c76f-4858-9e87-d514f5cc5edf','次韵陳元述見寄謝茶  其二','葛立方','宋','宋诗','song-poetry','','[]','露窠那畏主林神，小摘筠籃手自親。',64,'全唐诗/poet.song.113000.json','["露窠那畏主林神，小摘筠籃手自親。", "旋轉注湯雲作脚，繽紛出磨麴爲塵。", "睡魔已戰三竿日，詩社聊嘗一信春。", "不把膏油塗首面，要須色裏認天真。"]'),
('308c03e4-95f2-40b1-8950-776b7d346bed','次韵陳元述見寄謝茶  其三','葛立方','宋','宋诗','song-poetry','','[]','青縷宜嬰石穴神，薑鹽藙橘豈容親。',64,'全唐诗/poet.song.113000.json','["青縷宜嬰石穴神，薑鹽藙橘豈容親。", "湯鳴鼎甗颼颼響，末下刀圭瑟瑟塵。", "火裏槍旗俱發妙，胸中梨棗不妨春。", "柳州佳句誠堪誦，滌慮還源更發真。"]'),
('38256743-951b-45c5-a55a-4cee1f2bfd3f','次韵程天游敘舊','葛立方','宋','宋诗','song-poetry','','[]','太學虀鹽愴語離，半周甲子定何之。',64,'全唐诗/poet.song.113000.json','["太學虀鹽愴語離，半周甲子定何之。", "霜空過雁我宴坐，雲路看鴻君賦詩。", "鄙吝政憂陳仲舉，談諧喜值庾元規。", "東鄰更有程居士，鼎足論文妙一時。"]'),
('e4914c6c-394f-455e-a73e-aa252ff64039','天游以前韵賦雪詩走筆和','葛立方','宋','宋诗','song-poetry','','[]','剪水飛花下玉墀，駝裘忍凍一窺之。',64,'全唐诗/poet.song.113000.json','["剪水飛花下玉墀，駝裘忍凍一窺之。", "寒侵鑿落豪呼酒，冰合陶泓懶賦詩。", "嵩嶺齊腰緣個事，剡谿鼓棹欲何規。", "唯欣嗣歲千倉積，玉燭調和運四時。"]'),
('b0aef7a7-d346-4f34-9b9a-58a7c362173a','章氏園小集荷池上  其一','葛立方','宋','宋诗','song-poetry','','[]','一金營雅集，荷濕露香濃。',48,'全唐诗/poet.song.113000.json','["一金營雅集，荷濕露香濃。", "鳥起驚歌扇，雲移落酒鍾。", "碧筩彎象鼻，翠釜出駝峯。", "百歲風狂似，無因繫六龍。"]'),
('2a21f550-ae48-46fe-8ddb-b6406b74c271','章氏園小集荷池上  其二','葛立方','宋','宋诗','song-poetry','','[]','鉗釱困殘暑，杯鐺方興濃。',48,'全唐诗/poet.song.113000.json','["鉗釱困殘暑，杯鐺方興濃。", "歌舞趁晨版，歡呼從暮鍾。", "風聲回立鵲，雲影墮奇峯。", "行酒有佳麗，未須煩八龍。"]'),
('b31229b6-ac3e-4717-aa11-2cbe3ceb58e3','次韵伯父工部見慶塵忝之什','葛立方','宋','宋诗','song-poetry','','[]','江夏無雙舊姓黄，末科容我出寒鄉。',64,'全唐诗/poet.song.113000.json','["江夏無雙舊姓黄，末科容我出寒鄉。", "人間學子垂垂老，天上丹枝恰恰芳。", "避地本安元結洞，擁書猶記贊公房。", "豈知今世持衡者，不聽更籌聽織芒。"]'),
('89004d27-caaf-41e6-a287-321fccf7f3bf','接伴賀天申節北使至闕','葛立方','宋','宋诗','song-poetry','','[]','流虹壽節慶升平，嵩嶽遥呼萬歲聲。',64,'全唐诗/poet.song.113000.json','["流虹壽節慶升平，嵩嶽遥呼萬歲聲。", "毳幕奉琛充日闕，綵船卷旆息雲程。", "九天鎬宴歡魚藻，重譯賓筵詠鹿苹。", "聞有芝泥還餞客，淮山佳處擬班荆。"]'),
('c384b8e6-4e64-4733-a2b0-298c4240899a','送伴回至平江舟中與元覽試茶','葛立方','宋','宋诗','song-poetry','','[]','壑源春色起雲阿，拂拂輕塵動柘羅。',64,'全唐诗/poet.song.113000.json','["壑源春色起雲阿，拂拂輕塵動柘羅。", "騎火已驚官焙早，注湯還鬭乳花多。", "清風兩腋添詩興，紅日三竿戰睡魔。", "燕頷未能飛食肉，腹中藜莧且摩娑。"]'),
('5240c433-1547-46e2-aa92-ae8c7e1d7e62','正月十日小園瑞香盛開','葛立方','宋','宋诗','song-poetry','','[]','天上新春破，奇花照野塘。',96,'全唐诗/poet.song.113000.json','["天上新春破，奇花照野塘。", "靈苞洩蘭麝，仙骨傲風霜。", "未放攢丹粒，初開散粉囊。", "亭亭欹寶檻，戢戢動香房。", "廬阜移僧鉢，平泉出相堂。", "欒枝識嘉種，桐葉認真香。", "左紫空西洛，辛夷謾楚湘。", "邀賓須醉賞，莫訴引杯長。"]'),
('ebf14d82-5968-4adb-9684-0e63d4b76773','子直近日畫筆稍進而棋似倒長作詩戲之','葛立方','宋','宋诗','song-poetry','','[]','沈郎終日掩柴扉，遊藝雖多道日肥。',64,'全唐诗/poet.song.113000.json','["沈郎終日掩柴扉，遊藝雖多道日肥。", "東絹丹青真得髓，文楸黑白要知機。", "筆添龍眼防頹壁，陣合魚麗孰解圍。", "暇日杖藜須過子，一枰贏取畫圖歸。"]'),
('aa15d400-a531-403b-b275-472edb903184','比賦棋畫詩蒙子直次韵復和','葛立方','宋','宋诗','song-poetry','','[]','東床高韵畫兼棋，不比尋常似瓠肥。',64,'全唐诗/poet.song.113000.json','["東床高韵畫兼棋，不比尋常似瓠肥。", "莫向謝安爭別墅，自同劉子得天機。", "翻成小窟乖三捷，規出神光詫一圍。", "二事相從真可樂，籃輿訪子殆忘歸。"]'),
('e2d004d6-6c7e-4f1a-8d3f-3d8f660d05a3','園中新疊假山','葛立方','宋','宋诗','song-poetry','','[]','萬花爭放辟彊園，九仞功成對竹軒。',96,'全唐诗/poet.song.113000.json','["萬花爭放辟彊園，九仞功成對竹軒。", "鼇負崇基凌象緯，虎蹲深徑列兒孫。", "欄雕結綠籠芳砌，樹剪琉璃破綠痕。", "水遞畦丁飛瀑墮，煙吹童子亂雲屯。", "日晞絕頂金莖露，雨漲虛坳玉女盆。", "只欠五城樓十二，便應人指是崑崙。"]'),
('254e84b3-c8df-4b01-8ae0-e97b5e5d0ef5','禮部尚書洪公挽歌詞  其一','葛立方','宋','宋诗','song-poetry','','[]','沙場握節仗時髦，說舌縱橫小六弢。',64,'全唐诗/poet.song.113000.json','["沙場握節仗時髦，說舌縱橫小六弢。", "委質肯輕從晉鼓，摛文空見泣秦牢。", "冷山韵語名如斗，蓮濼危言命若毛。", "豈料歸朝纔十稔，白楊聲裏壽原高。"]'),
('82ef24d5-8e26-4ec6-890b-88789c96c643','禮部尚書洪公挽歌詞  其二','葛立方','宋','宋诗','song-poetry','','[]','守節冰天十五霜，歸來飛語又炎方。',64,'全唐诗/poet.song.113000.json','["守節冰天十五霜，歸來飛語又炎方。", "正欣射雁還幽窖，旋復飛鳶墮瘴鄉。", "位不當材僅喉舌，壽難酬德遽膏肓。", "八龍共侈荀門慶，雖厄龍蛇殆不亡。"]'),
('07f0e12c-ccff-4821-96a7-5c9c3dd1c354','禮部尚書洪公挽歌詞  其三','葛立方','宋','宋诗','song-poetry','','[]','高材博識服簪紳，玉樹瑶林絕點塵。',64,'全唐诗/poet.song.113000.json','["高材博識服簪紳，玉樹瑶林絕點塵。", "氏族源流推肉譜，春秋褒貶藉調人。", "膝間韵磬傳山水，枰上枯棋戰楚秦。", "妙處不傳今已矣，遥瞻遺像淚霑巾。"]'),
('74b762ff-beeb-47c8-88b1-73aa5a9b354d','江陰新阡松柏爲大浸所壞累夕見於夢寐','葛立方','宋','宋诗','song-poetry','','[]','新阡松檟已交柯，狂潦侵凌一尺過。',64,'全唐诗/poet.song.113000.json','["新阡松檟已交柯，狂潦侵凌一尺過。", "擬欲移根易嘉本，正須捄土捍層波。", "傷心半夜飛蝴蝶，觸眼何人是橐駝。", "火迫歸歟親在視，定教枯枿再婆娑。"]'),
('90524880-db24-4ce2-85bf-316614648d1d','所居二室號書癡禪悅各成一詩 書癡','葛立方','宋','宋诗','song-poetry','','[]','枕溪曲室巧涵虛，黄卷旁羅恣卷舒。',64,'全唐诗/poet.song.113000.json','["枕溪曲室巧涵虛，黄卷旁羅恣卷舒。", "單族未應慚四姓，寸陰端合競三餘。", "麟毛不具羞文虎，狸骨空傳尚墨豬。", "坐穴藜床逢掖事，那知新有鶴頭書。"]'),
('0da6d00f-0969-4b15-84ce-3ec563e0bd0a','所居二室號書癡禪悅各成一詩 禪悅','葛立方','宋','宋诗','song-poetry','','[]','多生業果種情田，鷲嶺宗風好著鞭。',64,'全唐诗/poet.song.113000.json','["多生業果種情田，鷲嶺宗風好著鞭。", "要使野狐驚鐵杖，莫令黄葉認金錢。", "傳衣雖落慧能後，成佛應居靈運前。", "趺坐蒲團成冷淡，比從人役竟誰賢。"]'),
('d5bd7c82-f509-41dd-bcad-f2692ec36242','聞琵琶方響成二絕  其一','葛立方','宋','宋诗','song-poetry','','[]','赤烏寶女眩新粧，九酘霞漿肯見觴。',32,'全唐诗/poet.song.113000.json','["赤烏寶女眩新粧，九酘霞漿肯見觴。", "但聽琵琶喧啄木，誰知捍撥是龍香。"]'),
('d5a072da-fad2-4cb4-9f5d-4164a1bd3fdd','聞琵琶方響成二絕  其二','葛立方','宋','宋诗','song-poetry','','[]','十六寒金犀作槌，舊人謾說馬仙期。',32,'全唐诗/poet.song.113000.json','["十六寒金犀作槌，舊人謾說馬仙期。", "荷間縱有蕤賓鐵，喚取廉郊始得知。"]'),
('52f15a47-1af8-451c-b8de-cb9f5535cf8c','己卯歲四月二十七日自湖州赴宜春郡餘杭出陸至富陽','葛立方','宋','宋诗','song-poetry','','[]','發軔出江津，晴熏綠野勻。',48,'全唐诗/poet.song.113000.json','["發軔出江津，晴熏綠野勻。", "泉聲漱莎石，嵐翠濕衣巾。", "天近雲衝馬，林深鳥喚人。", "將身入圖畫，誰復羨麒麟。"]'),
('4a3e506d-9def-4f64-8623-4879927d0307','觀插秧','葛立方','宋','宋诗','song-poetry','','[]','秧把束西畦，東畦翠罽齊。',48,'全唐诗/poet.song.113000.json','["秧把束西畦，東畦翠罽齊。", "甘心鶴俛啄，不用馬行泥。", "井井塍千曲，泱泱水半犂。", "黄雲它日事，歡喜舞齠齯。"]'),
('494bade1-aee0-49ee-a529-908f7a571dd6','和新城旅店壁間韵','葛立方','宋','宋诗','song-poetry','','[]','我本臞山澤，冠裳絆此身。',48,'全唐诗/poet.song.113000.json','["我本臞山澤，冠裳絆此身。", "平生只黄卷，晚歲誤朱輪。", "妓舞山禽怪，騶呼疊穎嗔。", "會當還此笏，不愧葛天民。"]'),
('410c0420-9984-4cf2-a2c9-28e2cb335105','新城道中','葛立方','宋','宋诗','song-poetry','','[]','已去日邊遠，宜春程尚賒。',48,'全唐诗/poet.song.113000.json','["已去日邊遠，宜春程尚賒。", "呼童秣征馬，带月趁啼鴉。", "橋斷復揭水，路窮還渡沙。", "誰能飾厨傳，裹飯野人家。"]'),
('4740d2fa-d382-4639-8f48-7f2d4ee51f03','桐廬牛嶺','葛立方','宋','宋诗','song-poetry','','[]','輿曳入崔嵬，連天霧不開。',48,'全唐诗/poet.song.113000.json','["輿曳入崔嵬，連天霧不開。", "驚波掀過雨，細路滑蒼苔。", "瞰下憂魚葬，凌高被鳥猜。", "垂堂千古戒，底急爲名來。"]'),
('efe7047f-c546-425f-86aa-341ecd3cece2','入壽昌縣界','葛立方','宋','宋诗','song-poetry','','[]','一躡壽昌境，山深溪水蒼。',48,'全唐诗/poet.song.113000.json','["一躡壽昌境，山深溪水蒼。", "編柴作籬落，囊石當橋梁。", "野店炊煙接，官塗松吹長。", "石田能幾稜，底用穀人忙。"]'),
('2047ead3-1401-470d-9975-2730c52d7429','壽昌道中壁間有烏石寺詩和其韵','葛立方','宋','宋诗','song-poetry','','[]','鍾情翠巘倚崚嶒，付與芒鞋與瘦藤。',64,'全唐诗/poet.song.113000.json','["鍾情翠巘倚崚嶒，付與芒鞋與瘦藤。", "君賜一麾方作吏，天融萬壑却輸僧。", "擬將矩矱追廉杜，未許機鋒嗣秀能。", "投幘它年應未晚，與君曲室話三乘。"]'),
('e0baf259-2070-41d7-a8fb-1bf74d4d565f','早行二絕  其一','葛立方','宋','宋诗','song-poetry','','[]','屈指雲程路尚賒，脂車秣馬閙栖鴉。',32,'全唐诗/poet.song.113000.json','["屈指雲程路尚賒，脂車秣馬閙栖鴉。", "夢魂正入無何有，誰著長鈎惱睡蛇。"]'),
('23c214ed-cf18-4edb-aa04-74e4a35678b5','早行二絕  其二','葛立方','宋','宋诗','song-poetry','','[]','二十五聲更漏短，那將殘漏費征塗。',32,'全唐诗/poet.song.113000.json','["二十五聲更漏短，那將殘漏費征塗。", "鈴齋擬欲尋胡蝶，朱墨還應許我無。"]'),
('c9ece91f-0028-4a8e-845e-e95e13ba4402','晚泊二絕  其一','葛立方','宋','宋诗','song-poetry','','[]','晚泊牛羊已下來，清泉爲我洗塵埃。',32,'全唐诗/poet.song.113000.json','["晚泊牛羊已下來，清泉爲我洗塵埃。", "解顔客裏無巵酒，壁上尋詩笑幾回。"]'),
('949bebaa-1dac-4984-8431-4b78de4caf56','晚泊二絕  其二','葛立方','宋','宋诗','song-poetry','','[]','曲突無煙驛吏忙，匆匆弛擔旋舂糧。',32,'全唐诗/poet.song.113000.json','["曲突無煙驛吏忙，匆匆弛擔旋舂糧。", "紞如五鼓還應起，早趁南窗一枕凉。"]'),
('d9c071df-2116-49f1-bc4d-4802f6562d0e','將至玉山','葛立方','宋','宋诗','song-poetry','','[]','蓐食轉前峯，梅黄細雨中。',48,'全唐诗/poet.song.113000.json','["蓐食轉前峯，梅黄細雨中。", "濤翻疑鷺翿，泉激認松風。", "山合秧畦窄，林深屐路通。", "怪來人語別，一置便江東。"]'),
('2394404d-1249-4389-9ed1-b43b7d07d375','過九坡','葛立方','宋','宋诗','song-poetry','','[]','行盡千山與萬山，鍾情偏在此煙嵐。',64,'全唐诗/poet.song.113000.json','["行盡千山與萬山，鍾情偏在此煙嵐。", "海波神闕今饒六，仙女巫峯尚欠三。", "雨潤蒙條生翠滴，雲封疊穎瑩脂涵。", "却思九坂修梁第，空使斯民命不堪。"]'),
('5f3fa2c6-cc5e-43e7-9c8b-b27c14cda734','寄睦之','葛立方','宋','宋诗','song-poetry','','[]','室如懸磬衆推賢，蓍草占來命尚邅。',64,'全唐诗/poet.song.113000.json','["室如懸磬衆推賢，蓍草占來命尚邅。", "不耐扊扅愁婦室，且歌欵乃上漁船。", "殺青聊卒檀溪業，破白難耕好畤田。", "外日同歸韉尚暖，依然清夢繞苕川。"]'),
('735b9193-8046-41ef-ba5a-b98addd2e7de','贈褚明遠','葛立方','宋','宋诗','song-poetry','','[]','今歲難衣食，知聞莫若君。',48,'全唐诗/poet.song.113000.json','["今歲難衣食，知聞莫若君。", "衣裳顛紫鳳，隴畝槁黄雲。", "主饋婦求去，承家子出分。", "清才豈長窶，奇相有龜文。"]'),
('d38d9047-20bb-4700-b272-c69cee5f6bc1','四絕贈馬浩然法師 木公','葛立方','宋','宋诗','song-poetry','','[]','餐霞吸瀣炯方瞳，時著青裙拜木公。',32,'全唐诗/poet.song.113000.json','["餐霞吸瀣炯方瞳，時著青裙拜木公。", "玉女投壺天爲笑，却來綉嶺伴仙翁。"]'),
('07720083-0769-4f41-95af-01385a41d40e','四絕贈馬浩然法師 魏伯陽','葛立方','宋','宋诗','song-poetry','','[]','丹成誰羨伯陽仙，白犬騰空恐浪傳。',32,'全唐诗/poet.song.113000.json','["丹成誰羨伯陽仙，白犬騰空恐浪傳。", "未似尊師得丹訣，火毬吞吐葛山前。"]'),
('764d2a1e-c615-4f51-985e-021337a5eacc','四絕贈馬浩然法師 張道陵','葛立方','宋','宋诗','song-poetry','','[]','靈桃入手亦艱勤，正一門中僅策勳。',32,'全唐诗/poet.song.113000.json','["靈桃入手亦艱勤，正一門中僅策勳。", "未說趙昇王長在，鵠鳴衣鉢已輸君。"]'),
('04cda4b9-d306-4f94-914c-feaf193091f6','四絕贈馬浩然法師 李筌吳真君','葛立方','宋','宋诗','song-poetry','','[]','舊得陰符虎口巖，素書漆軸玉函緘。',32,'全唐诗/poet.song.113000.json','["舊得陰符虎口巖，素書漆軸玉函緘。", "君方濡筆書靈篆，已有飛來青鳥銜。"]'),
('db96ec84-67eb-429d-8166-30130903cbac','子直畫屏求題詩 裴休乞食歌姬院','葛立方','宋','宋诗','song-poetry','','[]','一從黄蘗逗真機，瞥地回光更不疑。',32,'全唐诗/poet.song.113000.json','["一從黄蘗逗真機，瞥地回光更不疑。", "著脚洞房猶乞食，那知羅剎是歌姬。"]'),
('1bfe6db2-bb6f-4be6-98bc-04c73cbc7ad9','子直畫屏求題詩 杜牧之水嬉','葛立方','宋','宋诗','song-poetry','','[]','翬飛華屋浸漣漪，曼衍魚龍看水嬉。',32,'全唐诗/poet.song.113000.json','["翬飛華屋浸漣漪，曼衍魚龍看水嬉。", "自是翻階戀紅藥，哦詩莫恨十年遲。"]'),
('3abc95f8-c14e-4f6f-8439-8842e8ff5ec6','子直畫屏求題詩 謝安東山','葛立方','宋','宋诗','song-poetry','','[]','人間鍾鼎與山林，出處由來異此心。',32,'全唐诗/poet.song.113000.json','["人間鍾鼎與山林，出處由來異此心。", "既是東山成雅趣，底須捉鼻更微吟。"]'),
('d6c6eb0f-bdcd-48cd-853b-0787967b4150','子直畫屏求題詩 張禹受經','葛立方','宋','宋诗','song-poetry','','[]','談經難並綺羅邊，先聖微言可浪傳。',32,'全唐诗/poet.song.113000.json','["談經難並綺羅邊，先聖微言可浪傳。", "四海儒生知敗績，後堂何怯一彭宣。"]'),
('88dc622f-18b3-481c-8a0b-552fd6df2770','罷職還家漢卿叔賜詩和韵','葛立方','宋','宋诗','song-poetry','','[]','爝火疇能補大明，謾陪朝請趁晨興。',64,'全唐诗/poet.song.113000.json','["爝火疇能補大明，謾陪朝請趁晨興。", "雖叨荷橐簪纓舊，頗愧銓衡水鏡澄。", "夜帳歸來驚怨鶴，曉窗穴處縱癡蠅。", "自知浮食辜君賜，却擬扶犁換斗升。"]'),
('8c30363e-f7ba-47f9-b45d-8462e998bacb','致政宣義王公挽歌辭','葛立方','宋','宋诗','song-poetry','','[]','平生志趣漫無求，蠖屈鄉關七十秋。',64,'全唐诗/poet.song.113000.json','["平生志趣漫無求，蠖屈鄉關七十秋。", "不把楞伽堆案上，每將周易置床頭。", "天庭綸告榮初命，子舍安車互兩州。", "雲水俄驚遺寶劍，幽扉欲啟涕橫流。"]'),
('9dc357ba-95f4-46e9-b7df-dc0f1dc17837','贈施堯年老人  其一','葛立方','宋','宋诗','song-poetry','','[]','何須石室秘仙書，家有雲英尚藥爐。',32,'全唐诗/poet.song.113000.json','["何須石室秘仙書，家有雲英尚藥爐。", "奕世大年緣底事，知君華胄出肩吾。"]'),
('1047506e-a6a0-4e66-87d1-6cbafa4a342e','贈施堯年老人  其二','葛立方','宋','宋诗','song-poetry','','[]','從今九夏即期頤，小楷猶搜賀雨詩。',32,'全唐诗/poet.song.113000.json','["從今九夏即期頤，小楷猶搜賀雨詩。", "未得雨時曾過我，見君憂色上龐眉。"]'),
('84e17dbf-9998-434d-b672-f4ded9df3b23','贈施堯年老人  其三','葛立方','宋','宋诗','song-poetry','','[]','謁叟搘筇步後吳，茅簷枳落水平鋪。',32,'全唐诗/poet.song.113000.json','["謁叟搘筇步後吳，茅簷枳落水平鋪。", "大兒侍側霜飄領，猶著荆衣學弄烏。"]'),
('5b0cf29c-ee56-4d7c-a711-d912698fcc2a','題曲屏牡丹桃花  其一','葛立方','宋','宋诗','song-poetry','','[]','不與春風別有因，香苞長好四時新。',32,'全唐诗/poet.song.113000.json','["不與春風別有因，香苞長好四時新。", "曲屏忽見西明種，疑有藍關豎箔人。"]'),
('d8baa82c-db54-4a91-9503-1cd4e016fa16','題曲屏牡丹桃花  其二','葛立方','宋','宋诗','song-poetry','','[]','一枝濃艷欲燒空，誰畏門前人姓封。',32,'全唐诗/poet.song.113000.json','["一枝濃艷欲燒空，誰畏門前人姓封。", "豈有落英飄曲檻，與兒洗面作華容。"]'),
('9f721291-92ec-4965-a442-8651ef2a41f7','蒙恩除吏部侍郎子姪以詩相慶','葛立方','宋','宋诗','song-poetry','','[]','雞窗不夢筆頭花，分合扶犂霅水涯。',64,'全唐诗/poet.song.113000.json','["雞窗不夢筆頭花，分合扶犂霅水涯。", "禁掖俄膺九芝檢，仙逵許從五香車。", "厚陵戎部尊荷橐，徽廟司成踵棣華。", "無似鵜梁譏不稱，且欣紱冕粗承家。"]'),
('cb49449d-003d-4350-b940-8190eb6bd90b','蒙才孺伯惠詩頗及參問','葛立方','宋','宋诗','song-poetry','','[]','鶴氅蒲團養粹和，冥心十地六波羅。',64,'全唐诗/poet.song.113000.json','["鶴氅蒲團養粹和，冥心十地六波羅。", "宦情微似庵摩勒，佛行高於窣堵波。", "海裏泥牛端解笑，庵前石鏡不須磨。", "擬詢一句合頭語，只恐新羅鷂子過。"]'),
('bff143c8-760e-486d-af3b-37dcb28f6a09','丐祠將離雲間崔申之以詩爲別次韵','葛立方','宋','宋诗','song-poetry','','[]','荆蘭戲綵關情切，朱墨爲官與願違。',64,'全唐诗/poet.song.113000.json','["荆蘭戲綵關情切，朱墨爲官與願違。", "夜鶴帳空周子去，秋鱸風動季鷹歸。", "忍看妙句金聲振，行阻清談木屑飛。", "引領吳興何許是，碧雲深處暮山微。"]'),
('1e57fead-dcc5-4b29-b7f6-3a2673d2c2a0','崔申之以詩爲別蘇明父郭逢叔各有和章謹復用韵二首  其一','葛立方','宋','宋诗','song-poetry','','[]','露章瀝血上彤墀，螻蟻雖微願弗違。',64,'全唐诗/poet.song.113000.json','["露章瀝血上彤墀，螻蟻雖微願弗違。", "韞跡正慚高士傳，離羣却恐小人歸。", "身同玄豹霧中隠，目送孤鴻天際飛。", "丹竈素書今好在，臨風憶子話精微。"]'),
('274eb903-5f36-435d-9cd5-c1846664d251','崔申之以詩爲別蘇明父郭逢叔各有和章謹復用韵二首  其二','葛立方','宋','宋诗','song-poetry','','[]','見遠亭邊送落暉，菁山挽我作睽違。',64,'全唐诗/poet.song.113000.json','["見遠亭邊送落暉，菁山挽我作睽違。", "連年走俗爲貧仕，一日投閑恐富歸。", "谷水爲官輕似紙，苕溪轉櫂疾於飛。", "羽觴捧劍無人問，悵望如今束廣微。"]'),
('e73872f8-9505-4fc9-b1c6-8901d232021b','次韵施予善謝茶','葛立方','宋','宋诗','song-poetry','','[]','緗奩香葉裹新英，分與騷人取次烹。',64,'全唐诗/poet.song.113000.json','["緗奩香葉裹新英，分與騷人取次烹。", "碗裏定疑甘露薦，腋邊應覺午風生。", "色方蒙嶺雖微勝，品带沙溪未苦精。", "客好窗晴聊小試，跳珠急雨看泉清。"]'),
('242c5dec-4f7e-4c7f-a56a-528a0c63252c','具上人以詩相別復和之','葛立方','宋','宋诗','song-poetry','','[]','鉢囊已解何山夏，千頃堂前又飽參。',64,'全唐诗/poet.song.113000.json','["鉢囊已解何山夏，千頃堂前又飽參。", "仙裏未須求七七，禪中聊共說三三。", "遠師今日宜同社，彌勒它年可共龕。", "不見生公講經處，至今花雨落毿毿。"]'),
('5d6ee4e5-2d40-4236-8e6d-787b277f3372','朱丞相赴宣州四十韵','葛立方','宋','宋诗','song-poetry','','[]','天佑於皇宋，時生柱石賢。',288,'全唐诗/poet.song.113000.json','["天佑於皇宋，時生柱石賢。", "餘光承祖禰，秀氣稟山川。", "應物心如水，臨機直似弦。", "孔書窮竹簡，羲易玩韋編。", "記問諸儒竦，聲華六合傳。", "虎闈書考異，蟾窟姓名先。", "文卷驚嚴助，經師拜鄭虔。", "刊讎飽黄卷，遷擢冠青錢。", "稠疊膺神恉，澄清出使旜。", "陪都佐留鑰，東道握兵權。", "慘淡胡塵暗，低回漢節堅。", "肅陳鵝鸛列，坐困犬羊羶。", "潛拔淮陰幟，爭加祖逖鞭。", "力遮江國路，坐沮朔陲煙。", "氣槩青雲上，忠誠紫蓋邊。", "龍飛逢履位，蛇輔喜差肩。", "遭際風雲會，寅緣雨露偏。", "紫荷躋法從，碧落耀卿聯。", "揆事符中扆，論文動細氈。", "北扉鄰浴殿，夜直履花磚。", "將略驚頗牧，綸言粲許燕。", "覆袍分蜀錦，歸燭爛金蓮。", "左轄精搜選，中原付斡旋。", "鳳池邦本正，虎帳國威全。"]'),
('797cbd9c-1845-4190-9233-6c0c6c9484b8','不寐','葛立方','宋','宋诗','song-poetry','','[]','年來百念如灰冷，何物關心攪睡眠。',64,'全唐诗/poet.song.113000.json','["年來百念如灰冷，何物關心攪睡眠。", "奠枕不容安丙夜，乘軺端復類丁年。", "曲中誰辨齁齁趣，夢裏難成栩栩然。", "只恐睡蛇鈎已盡，髦蠻難到曲屏邊。"]'),
('11ae88a3-78d7-46e5-9764-8e5cd1d2e5b4','聞我師大捷虜騎宵遁上時宰五十韵','葛立方','宋','宋诗','song-poetry','','[]','憬彼金微虜，游魂擅一隅。',288,'全唐诗/poet.song.113000.json','["憬彼金微虜，游魂擅一隅。", "筋駑殂老革，乳臭立遺雛。", "毒螫鍾蛇豕，虔劉肆猰貙。", "請和包譎詐，歸地反膏腴。", "尚爾載書濕，俄然信誓渝。", "不庭時寇境，匪茹自干誅。", "作噩新年換，青陽窒月踰。", "違天輒非覬，掃國敢長驅。", "崛强提凶器，飛揚起逆徒。", "酋渠連渤海，部曲雜單于。", "區脫宵成寨，兜牟曉援桴。", "刺船窺采石，擐甲逼濡須。", "烽火來何急，囊書報不虞。", "山河依睿主，社稷倚真儒。", "自昔經綸手，惟公器業殊。", "保江卑謝傅，圖霸小夷吾。", "端揆開黄閤，中權正紫樞。", "邦基資翊戴，賢路闢崎嶇。", "傅說推良弼，周公孫碩膚。", "時危材愈見，位重德相符。", "勇决扳裴度，遲迴鄙蔡謨。", "艱難初議在，慷慨赤心輸。", "餉道通流馬，疲兵斥濫竽。", "機能乘眇忽，謀不失錙銖。"]'),
('d501885b-8c3b-441a-ad00-c0f9c53f5598','張千里以詩送邰姪銓試用其韵','葛立方','宋','宋诗','song-poetry','','[]','明堂一柱已扶顛，下詔猶求梠與椽。',64,'全唐诗/poet.song.113000.json','["明堂一柱已扶顛，下詔猶求梠與椽。", "言並玉巵宜閣筆，鑒同金鏡正持銓。", "驪珠魚目難齊價，嫫母西施孰是妍。", "勉矣一鳴驚衆彥，莫將梔蠟誤長鞭。"]'),
('9dc937b2-955d-4f16-9515-406283564edc','旅次二首  其一','葛立方','宋','宋诗','song-poetry','','[]','山行确犖趁雲程，食寢無多但有名。',64,'全唐诗/poet.song.113000.json','["山行确犖趁雲程，食寢無多但有名。", "作夢方成雞喚起，加餐未竟馬催行。", "鼓風飛壒渾無際，敲日吹炎似有聲。", "埃息火流知不晚，依然六幕自澄清。"]'),
('3705440b-d6e5-4820-b412-786e728c644f','旅次二首  其二','葛立方','宋','宋诗','song-poetry','','[]','視印宜春一月過，寧知平地起風波。',64,'全唐诗/poet.song.113000.json','["視印宜春一月過，寧知平地起風波。", "未成黔突真如傳，俄復脂車去似梭。", "雖快徵君還北牖，却思太守類南柯。", "流行坎止何須問，似覺閑中所得多。"]'),
('399f0e83-5ae4-4cd9-83ef-97bd6dfc1059','爲章道祖作頗及葛藤 綴景亭','葛立方','宋','宋诗','song-poetry','','[]','煙溪雲巘映朱扉，聲色叢中入定時。',64,'全唐诗/poet.song.113000.json','["煙溪雲巘映朱扉，聲色叢中入定時。", "十萬丈夫森鐵甲，三千宮女醉瑶池。", "纍纍珠帳露滋顆，點點金衣霜著枝。", "心境消融無一物，景從何得綴爲誰。"]'),
('c1f0d0ae-494e-4579-9a53-d2dd086b335f','爲章道祖作頗及葛藤 踊山閤','葛立方','宋','宋诗','song-poetry','','[]','橫空複閤面嵯峩，影墮前溪瑟瑟波。',64,'全唐诗/poet.song.113000.json','["橫空複閤面嵯峩，影墮前溪瑟瑟波。", "九坂端疑築梁第，二山應恐負夸娥。", "凌雲北固俗塵遠，採菊東籬真意多。", "會取祖師端的意，此間萬象正森羅。"]'),
('8969a059-bbe9-4bc3-89eb-0f5919484569','爲章道祖作頗及葛藤 滄浪亭','葛立方','宋','宋诗','song-poetry','','[]','滄浪亭下水連溪，影倒虛簷鳳翅齊。',64,'全唐诗/poet.song.113000.json','["滄浪亭下水連溪，影倒虛簷鳳翅齊。", "白小牽風動晨鏡，碧圓著雨響秋鼙。", "魚舟點點依蘋渚，雁齒依依跨柳堤。", "舊日滄浪元不變，何妨居士爲全提。"]'),
('726f8ee5-2190-4466-a56b-3df02e0726b7','爲章道祖作頗及葛藤 華藏庵','葛立方','宋','宋诗','song-poetry','','[]','鮮健龐翁今罷參，柱杖掛壁雲迷庵。',64,'全唐诗/poet.song.113000.json','["鮮健龐翁今罷參，柱杖掛壁雲迷庵。", "開花聊幻仙七七，逗機更說禪三三。", "未辦浮丘招挹袖，且邀彌勒與同龕。", "庵中認得華嚴界，何用宗風談北南。"]'),
('0b60450f-3383-458f-9678-941504309e33','爲章道祖作頗及葛藤 錦薰閤','葛立方','宋','宋诗','song-poetry','','[]','窈窕軒窗小閤深，種花卜得半晴陰。',64,'全唐诗/poet.song.113000.json','["窈窕軒窗小閤深，種花卜得半晴陰。", "眼根忽墮錦綉谷，鼻觀如遊薝蔔林。", "莫問花枝有開落，須知法性勿來今。", "色香塵裏回光照，只這凡心是佛心。"]'),
('4a4ddc68-2462-4c50-b1f9-46331acdbae1','洪慶善郎中挽詩四首  其一','葛立方','宋','宋诗','song-poetry','','[]','登名蟾窟值休辰，中外掀騰寵數頻。',64,'全唐诗/poet.song.113000.json','["登名蟾窟值休辰，中外掀騰寵數頻。", "錦帳握蘭榮帝所，綉衣持斧耀江濱。", "兩州民社施張在，四水門牆卜築新。", "豈料生還杳無日，塚邊唯卧石麒麟。"]'),
('0ff1f969-f269-44f0-96c5-1a295b551c3e','洪慶善郎中挽詩四首  其二','葛立方','宋','宋诗','song-poetry','','[]','筆下翻翻注九河，腹中空洞五車多。',64,'全唐诗/poet.song.113000.json','["筆下翻翻注九河，腹中空洞五車多。", "麟經旨妙傳洙泗，騷學詞明慰汨羅。", "六度有爲超梵業，一心無累證禪那。", "龍蛇歲惡賢人逝，心折風前薤露歌。"]'),
('5f238a89-2c2d-43bd-b983-5d1c07bbe452','洪慶善郎中挽詩四首  其三','葛立方','宋','宋诗','song-poetry','','[]','平生氣槩凜冰霜，聖讀潛心德愈光。',64,'全唐诗/poet.song.113000.json','["平生氣槩凜冰霜，聖讀潛心德愈光。", "賞善每能頻擊節，避人寧復解移床。", "第知中壘序論語，誰測詩仙流夜郎。", "有道固應黄髮壽，何期竟不驗長桑。"]'),
('e75a92b3-967f-4dbd-8198-b92f0a3702d9','洪慶善郎中挽詩四首  其四','葛立方','宋','宋诗','song-poetry','','[]','閹茂之年拜伏犀，雞豚同社記金溪。',64,'全唐诗/poet.song.113000.json','["閹茂之年拜伏犀，雞豚同社記金溪。", "情深縞紵論交契，義切蓬麻荷品題。", "花底醉春同挈榼，雲中歷妙共扶藜。", "豈知生死今殊路，抆淚佳城意慘悽。"]'),
('2247bc49-4ea1-40f6-8778-b3d07474cdca','響應山','葛立方','宋','宋诗','song-poetry','','[]','一派寒灘度白雲，幾重危磴遠紅塵。',64,'全唐诗/poet.song.113000.json','["一派寒灘度白雲，幾重危磴遠紅塵。", "奇礓煙合松筠古，紺殿香浮棟宇新。", "玉響碧潭鳴地籟，瀑垂蒼嶺挂天紳。", "潛虬未用升雲去，乞取晴天畀散人。"]'),
('98297cf6-8c07-4373-94e6-0f1f02b636ed','朝隠病瘧作譴瘧鬼文而差示佳句次韵','葛立方','宋','宋诗','song-poetry','','[]','浹旬移病卧荒村，冰炭交攻水帝魂。',64,'全唐诗/poet.song.113000.json','["浹旬移病卧荒村，冰炭交攻水帝魂。", "句詠髑髏詩老在，舌飛霹靂詛師存。", "徙居何事四方館，譴鬼宜歸白石門。", "壯士高人今藥喜，鮮粧隙地不須論。"]'),
('193eabb9-7085-4708-9d63-e0e9c0197d56','金燈花','葛立方','宋','宋诗','song-poetry','','[]','小圃金燈滿意芳，苞舒絳彩照煌煌。',64,'全唐诗/poet.song.113000.json','["小圃金燈滿意芳，苞舒絳彩照煌煌。", "珠璣小滴今朝雨，縞紵難禁昨夜霜。", "拂秉麟鬚蛾欲避，枝銜螭口蠟猶香。", "列錢都是銀缸影，莫遣狂風出土囊。"]'),
('7e020911-7709-446a-9c77-caa31ac4f64a','建國劉夫人挽歌詞  其一','葛立方','宋','宋诗','song-poetry','','[]','孌彼閨房秀，魚軒侈大家。',48,'全唐诗/poet.song.113000.json','["孌彼閨房秀，魚軒侈大家。", "鳩巢奠蘋藻，翟茀絢笄珈。", "覺海聊依筏，言筌謝算沙。", "平生功用在，無疾問毗耶。"]'),
('3d07bf5b-417b-402e-8405-066770b26a0e','建國劉夫人挽歌詞  其二','葛立方','宋','宋诗','song-poetry','','[]','四德推賢範，流芳在管彤。',48,'全唐诗/poet.song.113000.json','["四德推賢範，流芳在管彤。", "植蘭門戶秀，嚼蠟世緣空。", "荷橐夫官重，萱堂母道崇。", "相孫仍相婦，寂漠閟幽宮。"]'),
('5bdf9a19-608d-47bd-a786-39dcda8f5ee4','築室以乏金小輟','葛立方','宋','宋诗','song-poetry','','[]','萍蹤留異縣，小隠卜清苕。',48,'全唐诗/poet.song.113000.json','["萍蹤留異縣，小隠卜清苕。", "囊罄欲質史，官卑難貰貂。", "揮斤停匠手，伐木斷江潮。", "未有王司馬，携錢過野橋。"]'),
('eacf1fc2-8f96-4f16-8d59-081269fe991e','春日移舟章園  其一','葛立方','宋','宋诗','song-poetry','','[]','冰壺徹骨無纖塵，新來結屋苕溪濱。',64,'全唐诗/poet.song.113000.json','["冰壺徹骨無纖塵，新來結屋苕溪濱。", "傾銀注瓦叟泥飲，披錦裂繡天行春。", "沙平印篆鳥浴羽，浪暖破綃魚躍鱗。", "一丘一壑志願畢，肯待人招祁孔賓。"]'),
('0c723bee-e7b3-49e9-b24c-001ed258f55d','春日移舟章園  其二','葛立方','宋','宋诗','song-poetry','','[]','腰懸六印不用求，勝處引人著滄洲。',64,'全唐诗/poet.song.113000.json','["腰懸六印不用求，勝處引人著滄洲。", "波平草軟鷗鳥下，花明柳暗池亭幽。", "兩園牛鳴一舟了，三春駟隙千觴酬。", "肯將僕射易此樂，瀚海飛狐雲正愁。"]'),
('67bb0a9f-98ce-49cf-ad23-6d4f22195721','大雄寺陳朝檜','葛立方','宋','宋诗','song-poetry','','[]','老檜盤拏古殿春，空庭坐閲幾朝曛。',64,'全唐诗/poet.song.113000.json','["老檜盤拏古殿春，空庭坐閲幾朝曛。", "根株橫裂可尋蟻，枝葉倒垂猶拂雲。", "求福端同木居士，出靈那效柳將軍。", "黄奴已斃韓擒虎，獨有茲材貸斧斤。"]'),
('102bf71d-a754-40f7-80ea-d9753fe71fd9','喜閑','葛立方','宋','宋诗','song-poetry','','[]','白蘋花發兮水晶宮，捨此地兮余將曷從。',293,'全唐诗/poet.song.113000.json','["白蘋花發兮水晶宮，捨此地兮余將曷從。", "斧斤丁丁兮爲余之棲，葯作房兮梁則辛夷。", "朝迎山雲兮，莫送雲歸。", "伏臘粗給兮，朝市奚爲。", "薑畦兮芋疇，瓜㼌蔓長兮女桑始柔。", "高田兮壤沃，麥芒如篲兮黍如粟。", "下田兮若按，䆉䅉衡從兮碧泉。", "乳水不淫兮旱火不光，神之德兮疇敢忘。", "拜金鋪兮奠椒漿，賽鼓坎坎兮錦傘悠颺。", "傾銀兮注瓦，玄鯽霜芹兮父老同社。", "鳥勸飲兮風爲啟關，宇宙之間兮誰如我閑。", "熱官雖好兮寧守菟裘，彼有危機兮余差無憂。", "鷹綵緤兮金作鐶，搏狐兔兮供吾之餐。", "馬玉勒兮錦作障，檀溪深兮躍必五丈。", "爲人吠兮乃可以佩人之鋂，爲人鳴兮乃可以食人之粟。", "所貴兮寂寂而矯矯，所鄙兮赫赫而碌碌。", "吾寧爲鴻兮取食於江湖，吾寧爲龜兮曳尾於泥塗。"]'),
('2bd1140f-6e05-4059-9c4c-97f56180f5eb','雲仙','葛立方','宋','宋诗','song-poetry','','[]','木葉蕭蕭兮雨冥冥，山鬼呼風兮猨夜鳴。',167,'全唐诗/poet.song.113000.json','["木葉蕭蕭兮雨冥冥，山鬼呼風兮猨夜鳴。", "巫假神兮驚愚，髡假巫兮乞靈。", "雲仙來兮瑶席啟，坎坎擊鼓兮拜寒水。", "雲仙去兮閃倏不聞，錦傘摇兮望莫雲。", "紛姣服兮走朝與暮，焄蒿淫昏兮使君怒。", "青螭白虯兮不須款帝居，請發鏃兮何必天弧。", "沉主兮焚屋，正人伸氣兮淫神夜哭。", "妖止兮俗醇，請傾百川兮壽使君。", "鼻亭兮不記營道，蘇侯兮已屏堯廟。", "憤王去兮響莫出，狄梁公兮方草檄。"]'),
('ce8c4482-41e8-4cbe-b1e4-dbac12febb17','九效 天運','葛立方','宋','宋诗','song-poetry','','[]','陰陽寒暑兮運無積，天之成歲兮顧豈一日。',112,'全唐诗/poet.song.113000.json','["陰陽寒暑兮運無積，天之成歲兮顧豈一日。", "羲和敲日兮聲作玻璃，桂魄迎宵兮忽掛之。", "流沙兮揚土，簷涔涔兮又夜雨。", "嚴霜苦寒兮萬木不花，葉底兮俄茁其芽。", "星鳥星火兮四時有令，慘舒閶闔兮斟酌斗柄。", "三百六旬兮歲功始成，細人蠢蠢兮又豈知夫天運。"]'),
('b1a12ba7-6882-4f5c-bcb5-0e8daff2a88b','九效 慈寧','葛立方','宋','宋诗','song-poetry','','[]','天龍兮負圖，地龜兮負書。',140,'全唐诗/poet.song.113000.json','["天龍兮負圖，地龜兮負書。", "后皇兮純孝格天，台衮兮祕畫無前。", "薜荔兮出之水中，芙蓉兮搴之木末。", "碧玉上兮煙霄遠，彤霞爛兮秋水闊。", "重翟兮順動，長御兮啟引。", "交鼓兮緪瑟，簫鍾兮瑤簨。", "御玉衣兮珠步摇，赭黄奉觴兮臣妾入朝。", "建中天子兮百僞紛錯，我宋中興兮天返長樂。", "四海爲養兮子職供，千秋萬歲兮慈寧宮。"]'),
('4f01f311-573d-40c2-8d7b-0e4a1728391c','九效 永固','葛立方','宋','宋诗','song-poetry','','[]','珠丘峨峨兮蒼梧遠，弓劍杳隔兮九土魂斷。',118,'全唐诗/poet.song.113000.json','["珠丘峨峨兮蒼梧遠，弓劍杳隔兮九土魂斷。", "邊聲起兮春草深，木鐸無聲兮歲月換。", "上天悔禍兮誘天驕，黄腸素紼兮歸路迢迢。", "撫櫬循題兮愁霧重，江河傾淚兮雷霆聲慟。", "行妥靈兮金粟堆，白楊蕭蕭兮風送哀。", "匰主兮肖貌，穆將愉兮清廟。", "對越兮在天，永蒸嘗兮千萬年。"]'),
('53d70abd-8be9-4764-b3ce-499378112eed','九效 强弱','葛立方','宋','宋诗','song-poetry','','[]','堅木兮不可爲圈，鍊鐵兮不可爲鈎。',91,'全唐诗/poet.song.113000.json','["堅木兮不可爲圈，鍊鐵兮不可爲鈎。", "圈不成兮何箕之得，鈎不成兮何魚之求。", "委吳以筦籥兮復越，事狄以皮幣兮興周。", "故曰拯亂兮不如圖治，銳進兮不如觀勢。", "以弱爲强兮以予爲取，邊廷無犬吠兮息旗與鼓。"]'),
('e308ced6-b5a7-422a-a5c7-58dd103bfe07','九效 醫國','葛立方','宋','宋诗','song-poetry','','[]','破紐絕絡兮民不支，不了蘭藏兮舉世無醫。',92,'全唐诗/poet.song.113000.json','["破紐絕絡兮民不支，不了蘭藏兮舉世無醫。", "病在腠兮廢湯熨，未至血脈兮乃施鍼石。", "布指於位兮息至不知，陰陽倒置兮寒凉逆施。", "內實兮餌之桂附，中乾兮反投消以蠹。", "天生盧扁兮授術上池，躋民壽兮至期頤。"]'),
('17a4bf5f-f16d-4e95-bc15-ee354996be2a','九效 君臣','葛立方','宋','宋诗','song-poetry','','[]','虎嘯兮風生，龍舉兮雲從。',85,'全唐诗/poet.song.113000.json','["虎嘯兮風生，龍舉兮雲從。", "彈角兮應角，鼓宮兮應宮。", "有熊兮重華，風后兮皋繇。", "世卓兮眇眇，矩矱兮可尋。", "申椒兮杜蘅，揭車兮留夷。", "捋芽兮擷條，芳菲菲兮滿堂。", "梓人兮善工，赤籙兮重昌。"]'),
('0bb26662-bae7-4fdc-9f39-d53f29c86c13','九效 姦萌','葛立方','宋','宋诗','song-poetry','','[]','苗芃芃兮防莠，桂鬰鬰兮防蠹。',88,'全唐诗/poet.song.113000.json','["苗芃芃兮防莠，桂鬰鬰兮防蠹。", "欲苗實兮桂榮，必莠除兮蠹去。", "吾有少陵之鑱兮莠必耨，吾有尉佗之器兮蠹將奚逃。", "發嘉穎兮崑崙，繚樛枝兮招摇。", "粒米狼戾兮樂復樂，長塗炎日兮又庇之以垂天之幄。"]'),
('819d98aa-40e5-4db2-a4d5-186f0925c1c7','九效 自脩','葛立方','宋','宋诗','song-poetry','','[]','歲曶曶其欲頹兮，久棲身於幽仄。',113,'全唐诗/poet.song.113000.json','["歲曶曶其欲頹兮，久棲身於幽仄。", "慮脩名之不立兮，聊廣遂於前畫。", "搴玉英以自脩兮，結榮茝以佩之。", "服芰製而荷衣兮，又飾之以江蘺。", "望閬風之板桐兮，弱水瀰以見隔。", "造旬始而覲清都兮，求仙梯而未得。", "沐咸池兮，晞髮陽阿。", "鑿井耕田兮，姑擊壤以歌。"]'),
('0a9cc247-9e43-428a-86ff-953c7679719f','九效 鳴窮','葛立方','宋','宋诗','song-poetry','','[]','吾有車兮山之阿，吾有舟兮江之沚。',125,'全唐诗/poet.song.113000.json','["吾有車兮山之阿，吾有舟兮江之沚。", "任重兮致遠，欲行兮誰止。", "車欲行兮山路槎牙，舟欲行兮底著平沙。", "吾不能移王屋之山兮，通褒斜之阪。", "此舟車兮，孰推孰挽。", "將狶膏棘軸而强挽兮，畏顙泚兮力疲。", "將編蒲結草而强挽兮，憚褰裳而汩其泥。", "欲行石兮乘流，吾當求之梓人之與陽侯。"]'),
('b5245041-8dbd-488b-bbc4-5a9a1b6e36e6','橫山堂三章  其一','葛立方','宋','宋诗','song-poetry','','[]','陽羨之山兮領地靈，鴻洞欻吸兮九疊爲屏。',139,'全唐诗/poet.song.113000.json','["陽羨之山兮領地靈，鴻洞欻吸兮九疊爲屏。", "青蘿層層兮深巖絕壁，一鳥不鳴兮山更寂。", "橫山老人兮蟬蛻埃塵，倚石梁兮手攬白雲。", "眼中萬仞兮，胸中萬頃。", "泰華山林兮，秋毫鍾鼎。", "東山妓女兮，北山猿鶴。", "西山拄笏兮，亦復奚樂。", "節彼南山兮山巖巖，突鯨額兮霄堮間。", "民具瞻兮傾百川以爲壽，鴻毋遵陸兮公歸錦繡。"]'),
('35beb544-79e8-49a1-a090-4a253bd67d69','橫山堂三章  其二','葛立方','宋','宋诗','song-poetry','','[]','陽羨之水兮湍流喧豗，砅崖轉石兮萬壑殷雷。',163,'全唐诗/poet.song.113000.json','["陽羨之水兮湍流喧豗，砅崖轉石兮萬壑殷雷。", "瀨淺淺兮忽如瀉，畦碧綉兮溪罨畫。", "橫山老人兮樂天無憂，聊臨睨兮夷猶。", "擥芳茝兮大薄，搴杜若兮汀洲。", "摹寫兮寶唾傳，悲壯兮又雙瑣。", "沐髮兮何必咸池，濯吾纓兮水之湄。", "乘月兮何必牛渚，繫吾舟兮水之浦。", "吾之舟兮萬斛有餘，凌陽侯兮狎靈胥。", "百尺揭兮帆席舉，撇旋捎濆兮無險阻。", "傅說騎箕兮不可攀，留此舟兮橫山。"]'),
('4f0347f6-5e0a-4ba2-b90b-f1b0ed2678a9','橫山堂三章  其三','葛立方','宋','宋诗','song-poetry','','[]','陽羨之居兮宅淼茫，辛夷閨兮薜荔牆。',120,'全唐诗/poet.song.113000.json','["陽羨之居兮宅淼茫，辛夷閨兮薜荔牆。", "建芳馨兮廡門，爛昭昭兮未央。", "橫山老人兮獨處廓，十七地兮三一屋。", "龍馳兮沖天，花鳥水竹兮聊爾平泉。", "公有豫章楩楠兮聳萬仞，公有瑊玏玄厲兮磨而不磷。", "棟梁兮媞媞，柱之石兮不傾以支。", "此棟此石兮非斤非斧，盍以帡幪兮寰宇。"]'),
('2a2e576c-7813-4cd5-9267-361a9d29eac0','贈友人莫之用','葛立方','宋','宋诗','song-poetry','','[]','抱犬高眠已云足，更得牛衣有餘燠。',128,'全唐诗/poet.song.113000.json','["抱犬高眠已云足，更得牛衣有餘燠。", "起來敗絮擁懸鶉，誰羨龍髯織冰縠。", "踏翻菜園底用羊，從他春雷吼枯腸。", "擊鐘烹鼎莫渠愛，小芼自許猴葵香。", "半世饑寒孔移带，鼠米占來身漸泰。", "吉雲神馬日匝三，樗蒱肯作豬奴態。", "虎頭食肉何足誇，陰德由來報宜奢。", "丹竈功成無躍兔，玉函方祕緣青蛇。"]'),
('43f33c78-b8d8-4e0c-930e-fe4296222fcb','詠春申君二首  其一','葛立方','宋','宋诗','song-poetry','','[]','朱英在楚强黄歇，黄歇如何弱李園。',32,'全唐诗/poet.song.113000.json','["朱英在楚强黄歇，黄歇如何弱李園。", "一旦棘門奇禍作，自詒伊戚向誰論。"]'),
('47e95bdc-0cda-470d-bad7-df3f36e0b497','詠春申君二首  其二','葛立方','宋','宋诗','song-poetry','','[]','先秦豈謂嬴爲呂，東晉那知馬作牛。',32,'全唐诗/poet.song.113000.json','["先秦豈謂嬴爲呂，東晉那知馬作牛。", "不悟春申亦如許，敢憑宮掖妻邪謀。"]'),
('f1feadc1-d3fc-4490-8bd7-f9afb6f6a86d','二老堂','葛立方','宋','宋诗','song-poetry','','[]','去家纔隔水一股，二老堂成三百弓。',64,'全唐诗/poet.song.113000.json','["去家纔隔水一股，二老堂成三百弓。", "鴒原暮下沙水暖，雁行夜落霜天空。", "竹根酌酒不妨醉，花萼斵詩如許工。", "坐久與關笻竹杖，出門人指兩仙翁。"]'),
('c77c2361-ef6f-4020-b0dc-225e32cad632','余居吳興汎金溪上暇日率同志拏小舟載魚鼈蝦蟹命五比丘誦寶勝佛名若十二因緣法作梵唄捨之溪中坐間有請作詩以紀一時事者余輒爲書云','葛立方','宋','宋诗','song-poetry','','[]','漁師竟日漁，水族作斤賣。',204,'全唐诗/poet.song.113000.json','["漁師竟日漁，水族作斤賣。", "小捐使鬼兄，大載獲鱗介。", "鯤鯨未易羅，所得亦殊態。", "青蛙盡公私，朱鮪兼小大。", "霜鱸尚貫針，土負或黏塊。", "輪囷積文螺，郭索走蒼蟹。", "溼沫相煦濡，自分煮薑芥。", "豈知惻隠人，規作江湖貸。", "因呼小青翰，放留舞澎湃。", "趺坐延黑衣，號佛指清瀨。", "經翻流水篇，梵起魚山唄。", "傾盆带寒藻，圉圉看于邁。", "驚疑或依蒲，喜躍或生喝。", "快若鷹辭韝，歡如囚破械。", "定非校人池，恐是餘不派。", "願汝藉佛力，永脫鉤網債。", "口腹聊爾耳，香餌莫渠愛。"]'),
('531ebbee-9a40-441a-ae04-9e4b8df98224','喜子邲登第','葛立方','宋','宋诗','song-poetry','','[]','吾家五世十三人，競擷丹枝撼月輪。',64,'全唐诗/poet.song.113000.json','["吾家五世十三人，競擷丹枝撼月輪。", "慶曆賢科開後裔，隆興儒業繼前塵。", "泥金帖報家庭喜，燒尾筵張帝里春。", "從此傳芳應未艾，桂香應已襲天倫。"]'),
('ffe77fb5-88ee-4a50-9b4f-b7bb42ba5dc4','喜姪郯登第','葛立方','宋','宋诗','song-poetry','','[]','飛鈴走幟到金溪，喜子文闈預品題。',64,'全唐诗/poet.song.113000.json','["飛鈴走幟到金溪，喜子文闈預品題。", "名字巍峩光蕊榜，詞章斐亹動文奎。", "階梯已合嬰兒夢，星斗先分天老題。", "後日臚傳當第一，天倫科甲尚爲低。"]'),
('c61942f8-48e4-420d-97c9-c63bba50c5f2','瓢飲亭','葛立方','宋','宋诗','song-poetry','','[]','我不學許由隠煙霧，得瓢不飲惟挂樹。',82,'全唐诗/poet.song.113000.json','["我不學許由隠煙霧，得瓢不飲惟挂樹。", "又不學德義居虎丘，带瓢入市多騎牛。", "分無玉甌囊古錦，病渴文園只瓢飲。", "下瞰金溪新結亭，未須引吸如長鯨。", "但願金溪化爲酒，歲歲持瓢醉花柳。"]'),
('7bc2420c-971d-43b7-a04e-1a83a0325d5d','送舒殿丞','葛立方','宋','宋诗','song-poetry','','[]','紫蓋亭亭秀荆渚，股分綵水穿林莽。',32,'全唐诗/poet.song.113000.json','["紫蓋亭亭秀荆渚，股分綵水穿林莽。", "尚想當年老阿瞞，燕騎蛇矛走先主。"]'),
('751e68b5-6329-46b2-869f-149c03e934e4','衛卿叔自青暘寄詩一卷以飲酒果核殽味烹茶齋戒清修傷時等爲題皆紀一時之事凡十七首爲報  其一','葛立方','宋','宋诗','song-poetry','','[]','自歎杖頭無孔方，頭上貂蟬乏金黄。',80,'全唐诗/poet.song.113000.json','["自歎杖頭無孔方，頭上貂蟬乏金黄。", "醉鄉遥遥道路長，傲窗新釀汲新凉。", "指點銀瓶難索嘗，空教金縷唱秋娘。", "遥想玳席行觴忙，綉段裝簾篩妙香。", "夢熟有時歸故鄉，賜我屈巵澆客腸。"]'),
('497d0b30-0c51-4cc5-8d17-03529d3f8bb4','衛卿叔自青暘寄詩一卷以飲酒果核殽味烹茶齋戒清修傷時等爲題皆紀一時之事凡十七首爲報  其二','葛立方','宋','宋诗','song-poetry','','[]','不堪羈寓天一方，無心佩紫兼懷黄。',80,'全唐诗/poet.song.113000.json','["不堪羈寓天一方，無心佩紫兼懷黄。", "侍酒無由道路長，如意至今質西凉。", "箬溪竹葉儻許嘗，藝色何須留窈娘。", "緬懷星郎拋令忙，席上微聞雞舌香。", "支頤騰騰之醉鄉，惟有麴生可娛腸。"]'),
('4e2996ae-108b-42bf-b014-a7c1ae3601bb','衛卿叔自青暘寄詩一卷以飲酒果核殽味烹茶齋戒清修傷時等爲題皆紀一時之事凡十七首爲報  其三','葛立方','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','席中珍核來異方，烏椑正綠金棖黄。',80,'全唐诗/poet.song.113000.json','["席中珍核來異方，烏椑正綠金棖黄。", "大谷消梨紫蒂長，蒲萄馬乳堆西凉。", "深秋楊梅有何嘗，羅浮定逢何二娘。", "洞庭霜橘苞苴忙，吳姬手擘三日香。", "可憐猶子留他鄉，終日忍饑如龜腸。"]'),
('d15d892e-a8c8-4b47-bfa1-2c3e4dd90cdc','衛卿叔自青暘寄詩一卷以飲酒果核殽味烹茶齋戒清修傷時等爲題皆紀一時之事凡十七首爲報  其四','葛立方','宋','宋诗','song-poetry','','[]','闊展食前一丈方，羔兒釀酒鵝兒黄。',80,'全唐诗/poet.song.113000.json','["闊展食前一丈方，羔兒釀酒鵝兒黄。", "千里蒓羹紫絲長，乳肫豐貯琉璃凉。", "䓑虀豆粥得並嘗，尊前何用綠珠娘。", "貊炙羌煮庖厨忙，碗面濃封龍腦香。", "魯衛勾吳莫誇鄉，南北兩烹慰中腸。"]'),
('b8d6478f-300e-4c1f-b626-a591ae984450','衛卿叔自青暘寄詩一卷以飲酒果核殽味烹茶齋戒清修傷時等爲題皆紀一時之事凡十七首爲報  其五','葛立方','宋','宋诗','song-poetry','','[]','客居貧病醫無方，忍饑面作瞿曇黄。',80,'全唐诗/poet.song.113000.json','["客居貧病醫無方，忍饑面作瞿曇黄。", "楓葉蕭蕭風陣長，東廂曝背資滄凉。", "鄰家有酒難偷嘗，草書正藉公孫娘。", "家家刈熟畦丁忙，有口不識雲子香。", "令我馳神青暘鄉，杯粟有時來實腸。"]'),
('cd17a5ec-2214-4a37-b57b-2d80c42ca118','衛卿叔自青暘寄詩一卷以飲酒果核殽味烹茶齋戒清修傷時等爲題皆紀一時之事凡十七首爲報  其六','葛立方','宋','宋诗','song-poetry','','[]','金杯製宅初奠方，夏木陰陰囀鸝黄。',80,'全唐诗/poet.song.113000.json','["金杯製宅初奠方，夏木陰陰囀鸝黄。", "紫絲步障百里長，魚軒象服池閣凉。", "笙歌嘈雜聞未嘗，何止一曲杜韋娘。", "珠屨玳簪迎送忙，羅幃綉幕圍風香。", "須臾料理龍陽鄉，木奴千頭可充腸。"]'),
('b8f6fdc1-f40b-4558-9c06-08e9a8abd1a9','衛卿叔自青暘寄詩一卷以飲酒果核殽味烹茶齋戒清修傷時等爲題皆紀一時之事凡十七首爲報  其七','葛立方','宋','宋诗','song-poetry','','[]','靈芽胯底棋局方，茗碗班班金粟黄。',80,'全唐诗/poet.song.113000.json','["靈芽胯底棋局方，茗碗班班金粟黄。", "食罷煮香消日長，莫遣薑鹽資胃凉。", "廩君所嫉裴不嘗，誰是纖纖捧碗娘。", "識取真腴那得忙，不是沙溪不入香。", "可須臾醉無何鄉，甘膬肥濃能腐腸。"]'),
('b9d22559-9832-4745-a04c-a46580bf59b2','衛卿叔自青暘寄詩一卷以飲酒果核殽味烹茶齋戒清修傷時等爲題皆紀一時之事凡十七首爲報  其八','葛立方','宋','宋诗','song-poetry','','[]','紙窗蒲團竹几方，清曉聊翻經卷黄。',80,'全唐诗/poet.song.113000.json','["紙窗蒲團竹几方，清曉聊翻經卷黄。", "禪心無累鬚眉長，坐回熱惱生清凉。", "月六腥羶口不嘗，眼靜不覷登伽娘。", "名利從渠朝市忙，象口輕飄柏子香。", "菰蒓大嚼蜻蛙鄉，不教黎莧徒集腸。"]'),
('d3fa920f-8fb7-4d10-bbef-93974a03e388','衛卿叔自青暘寄詩一卷以飲酒果核殽味烹茶齋戒清修傷時等爲題皆紀一時之事凡十七首爲報  其九','葛立方','宋','宋诗','song-poetry','','[]','淮南空說枕中方，鬼物豈解爲金黄。',80,'全唐诗/poet.song.113000.json','["淮南空說枕中方，鬼物豈解爲金黄。", "虎龍自衛策最長，身閲寒暑無炎凉。", "王母蟠桃端可嘗，何必更值王巵娘。", "日月跳丸那覺忙，口中自有芝朮香。", "雲裝羽帔入仙鄉，爲公洗髓兼浣腸。"]'),
('998c4d08-437a-4aa5-997a-66c93e912144','衛卿叔自青暘寄詩一卷以飲酒果核殽味烹茶齋戒清修傷時等爲題皆紀一時之事凡十七首爲報  其一○','葛立方','宋','宋诗','song-poetry','','[]','玉軑華芝今省方，西風索索吹繖黄。',80,'全唐诗/poet.song.113000.json','["玉軑華芝今省方，西風索索吹繖黄。", "汴京宮闕秋草長，望風屑涕心淒涼。", "襲粲用命嗟何嘗，義軍誰是竹園娘。", "黠羌何事追奔忙，大似濃薰返魂香。", "清蹕何時還都鄉，中興慰我九回腸。"]'),
('a88b7595-0345-45b3-9924-e4826045cfb3','八月二十日與館中同舍遊西湖作  其一','葛立方','宋','宋诗','song-poetry','','["\u897f\u6e56"]','匏繫坐蝸舍，秋光只簷楹。',60,'全唐诗/poet.song.113000.json','["匏繫坐蝸舍，秋光只簷楹。", "懸知西湖佳，頗困官事嬰。", "今日復何日，綵舟天外橫。", "木落山骨露，千螺倒澄瀛。", "神仙勿浪求，玉京仍五城。"]'),
('302233f9-42c6-4908-8670-0f805b09b0dc','八月二十日與館中同舍遊西湖作  其二','葛立方','宋','宋诗','song-poetry','','["\u897f\u6e56"]','繫舟孤山脚，曳杖聊意行。',60,'全唐诗/poet.song.113000.json','["繫舟孤山脚，曳杖聊意行。", "三賢已仙去，丹青儼南榮。", "由來作詩苦，鼎峙太瘦生。", "碑板摘奇豔，銀鈎出金聲。", "湖山久寂寥，誰能作斯人。"]'),
('49859c30-d84e-4868-b00a-3f933601522c','八月二十日與館中同舍遊西湖作  其三','葛立方','宋','宋诗','song-poetry','','["\u897f\u6e56"]','跨馬綠楊堤，左右臨無地。',60,'全唐诗/poet.song.113000.json','["跨馬綠楊堤，左右臨無地。", "鞭影墮清泚，烏帽入蒼翠。", "老龍拏半空，九里作青吹。", "聞聲類擊竹，心與景相值。", "許由厭瓢鳴，渠未領真意。"]'),
('5ba063a4-7350-4ba7-b420-cc6b16c3d30b','八月二十日與館中同舍遊西湖作  其四','葛立方','宋','宋诗','song-poetry','','["\u897f\u6e56"]','下馬冷泉亭，懿此丹壑幽。',60,'全唐诗/poet.song.113000.json','["下馬冷泉亭，懿此丹壑幽。", "泓澄粲玉礫，半畝如潑油。", "巖岰起三板，轟雷濺濤頭。", "向來澄止面，怒沫喧山丘。", "莫作動靜觀，止性元不流。"]'),
('2d792ee2-bad7-4942-9296-eae8d8ae75b8','八月二十日與館中同舍遊西湖作  其五','葛立方','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天竺古浮屠，孤雲一鳥徑。',60,'全唐诗/poet.song.113000.json','["天竺古浮屠，孤雲一鳥徑。", "去天真尺五，峻步欲乘興。", "石壁半空立，略彴引危嶝。", "山底禽銜花，石罅僧入定。", "請從三昧起，林外有疏磬。"]'),
('86543c6c-e911-4a5f-8180-ee67a079c4ad','八月二十日與館中同舍遊西湖作  其六','葛立方','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不障庾公塵，那有劉輿膩。',72,'全唐诗/poet.song.113000.json','["不障庾公塵，那有劉輿膩。", "堂堂七丈夫，草木一臭味。", "躋攀亦云足，賞適興猶未。", "却呼三翼舟，擊汰舞綃翠。", "葦蒲紛已掃，奩鑑瑩新劑。", "持此壽諸公，空缸一沉醉。"]'),
('4f3accb6-d2d9-4e10-8b7b-7a6a32632f4a','王季恭蓬齋','葛立方','宋','宋诗','song-poetry','','[]','湖汊園林隠環堵，繫舟幾並春風浦。',96,'全唐诗/poet.song.113000.json','["湖汊園林隠環堵，繫舟幾並春風浦。", "桑櫓無聲百丈收，卧聽蕭蕭蓬皆雨。", "只今尺五明光宮，清夢時猶記短蓬。", "斧木爲齋劣容膝，舟居非水如張融。", "膏火自煎身有累，幾人不踏風波地。", "陽侯不動箕伯閑，蓬齋贔屭安如山。"]'),
('eabfc607-1d69-4158-8422-3aef16caf188','題鹽倉壁','葛立方','宋','宋诗','song-poetry','','[]','破賊須緡錢，箕斂困郡縣。',168,'全唐诗/poet.song.113000.json','["破賊須緡錢，箕斂困郡縣。", "孰若嚴矩矱，溟海恣煎煉。", "僚寀課惰勤，息入計虧羨。", "連艘走羣商，金帛委神甸。", "小人堪底用，吏鞅縻卑賤。", "怪來符似火，法制適中變。", "省覽幾牛腰，十日了未遍。", "鳬行摘紙尾，揮掃同掣電。", "盈車筆摧穎，溢匣印銷篆。", "壯士縛朱墨，食廢枕弗奠。", "忍饑危腸吼，失睡兩眼眩。", "我本丘壑姿，素乏封侯面。", "胡爲浪自苦，剛作五斗戀。", "會當還此笏，歸雲送蒼弁。"]'),
('ca560882-25d8-4d16-80f6-591f966cf6dd','月巖','葛立方','宋','宋诗','song-poetry','','[]','頭轉狻猊身卧虎，斕斑苔蘚蒼顔古。',128,'全唐诗/poet.song.113000.json','["頭轉狻猊身卧虎，斕斑苔蘚蒼顔古。", "鑿空融結寶月形，只露半規餘未吐。", "正觀傍睨苦有恨，擬借天工脩月斧。", "桂樹窅窊墮子香，未見姮娥來倚樹。", "姮娥只今居廣寒，虹橋幻成愁阿瞞。", "何如巖竇守孤潔，却視玉兔飛雲端。", "雲端之月有圓缺，常在爭如石中月。", "寒光萬丈照幽巖，石上雲端兩奇絕。"]'),
('2e62aa51-aed2-4a0e-aeea-00de65235a89','聞行在今歲元夕放燈頗盛','葛立方','宋','宋诗','song-poetry','','[]','寂寞元宵十六霜，月中披蓑带干將。',160,'全唐诗/poet.song.113000.json','["寂寞元宵十六霜，月中披蓑带干將。", "兜鍪第見烽火舉，觚棱不辨華燈張。", "新來冰天被聲教，鐵騎無復馳沙場。", "繒山再見舊燈影，金枝密焰看流芳。", "鳴珂篝燭競遊衍，金吾不禁春宵長。", "傳聞慈寧更煒燁，萬歲聲動東朝觴。", "琉璃雲母萬枝寶，桂膏蘭灺飄餘香。", "我今暫留三家野，豈有鵠采開蓮房。", "聊向豬欄迎紫女，更設膏粥祈蠶桑。", "葉師無恙可霄漢，會把如意遊西凉。"]'),
('59d65be5-35cf-49fb-9885-a72163bf2946','省習堂偶題','葛立方','宋','宋诗','song-poetry','','[]','格外官曹自在身，闔門掃軌養天真。',32,'全唐诗/poet.song.113000.json','["格外官曹自在身，闔門掃軌養天真。", "何須更待年三十，始約孤高不詣人。"]'),
('68c027bc-a8e9-4867-9039-7dd288730c4c','次韵劉無言壽山中五絕句敢請諸僚和之  其一','葛立方','宋','宋诗','song-poetry','','[]','載酒陶春久不歸，將花判斷定忘疲。',32,'全唐诗/poet.song.113000.json','["載酒陶春久不歸，將花判斷定忘疲。", "尋芳便作而今計，莫待他年子滿枝。"]'),
('1c4e4a7c-de2c-430b-8e2c-0c9c5ec0a21e','次韵劉無言壽山中五絕句敢請諸僚和之  其二','葛立方','宋','宋诗','song-poetry','','[]','命友登山共寄情，亦逢佳處便班荆。',32,'全唐诗/poet.song.113000.json','["命友登山共寄情，亦逢佳處便班荆。", "有時便取琴雙鎖，寫出蒼髯夜半聲。"]'),
('52049ac7-e66c-4b63-b722-78271ba155c1','次韵劉無言壽山中五絕句敢請諸僚和之  其三','葛立方','宋','宋诗','song-poetry','','[]','蕭閒谷飲更巖栖，應笑癡人簿領迷。',32,'全唐诗/poet.song.113000.json','["蕭閒谷飲更巖栖，應笑癡人簿領迷。", "萬頃青油行省舫，嫩黄輕拂柳條低。"]'),
('f203489e-d327-4b4c-b0cf-c17a0ae8b1d5','次韵劉無言壽山中五絕句敢請諸僚和之  其四','葛立方','宋','宋诗','song-poetry','','[]','川原紅綠遠交加，春物關心夢到家。',32,'全唐诗/poet.song.113000.json','["川原紅綠遠交加，春物關心夢到家。", "體骨素輕唯燕子，面皮最好是桃花。"]'),
('7da5cadf-89a8-4fa7-a96e-d3b9278f2617','次韵劉無言壽山中五絕句敢請諸僚和之  其五','葛立方','宋','宋诗','song-poetry','','[]','榮槁如環浪自循，一筇雙屐伴行春。',32,'全唐诗/poet.song.113000.json','["榮槁如環浪自循，一筇雙屐伴行春。", "溪翁野老來爭席，不識蓬山第一人。"]'),
('fe3c7d6d-fb53-4ada-b51a-9c2f01e37b9e','韓幹畫馬','葛立方','宋','宋诗','song-poetry','','[]','刖足俄然增足，蹶蹄那害全蹄。',28,'全唐诗/poet.song.113000.json','["刖足俄然增足，蹶蹄那害全蹄。", "還解追風奔雷，不妨一躍檀溪。"]'),
('0ff0eabd-2013-4afa-b93f-ed8bfac9fafc','和陶停雲  其一','吳芾','宋','宋诗','song-poetry','','[]','淵明抱節，不渝風雨。',40,'全唐诗/poet.song.113000.json','["淵明抱節，不渝風雨。", "爲米折腰，頗厭艱阻。", "歸卧柴桑，孤松獨撫。", "希蹤前賢，寤寐傾佇。"]'),
('650e6a93-c405-428b-84d0-2402fcf7c30b','和陶停雲  其二','吳芾','宋','宋诗','song-poetry','','[]','眷茲衡宇，草樹溟濛。',40,'全唐诗/poet.song.113000.json','["眷茲衡宇，草樹溟濛。", "坐對五柳，遥望九江。", "亦足寄傲，東軒南窗。", "獨恨無人，載酒相從。"]'),
('4bb15d2f-ab92-4dd6-aca7-702f7501e1dc','和陶停雲  其三','吳芾','宋','宋诗','song-poetry','','[]','我頃雖達，不足爲榮。',40,'全唐诗/poet.song.113000.json','["我頃雖達，不足爲榮。", "擬攀逸軌，少適真情。", "遐賞風味，魂夢宵征。", "葛巾藜杖，彷彿如生。"]'),
('c3ff0ac5-2da9-4487-8916-9bfa79724fd9','和陶停雲  其四','吳芾','宋','宋诗','song-poetry','','[]','吁嗟人世，如彼南柯。',40,'全唐诗/poet.song.113000.json','["吁嗟人世，如彼南柯。", "正宜閑處，養此太和。", "縱使得意，位高金多。", "老不知止，寧逃譴呵。"]'),
('6a34a1b4-4d85-49de-902c-353135563363','和陶勸農韵勉吾鄉之學者  其一','吳芾','宋','宋诗','song-poetry','','[]','士農工商，古有四民。',40,'全唐诗/poet.song.113000.json','["士農工商，古有四民。", "惟儒最貴，但患非真。", "誠能力學，進必有因。", "儻或中輟，豈能爲人。"]'),
('f80099e0-f825-4bb8-8401-f2a60ebd66ac','和陶勸農韵勉吾鄉之學者  其二','吳芾','宋','宋诗','song-poetry','','[]','譬如田家，所仰黍稷。',40,'全唐诗/poet.song.113000.json','["譬如田家，所仰黍稷。", "要當早夜，勤於種植。", "惰而自安，不稼不穡。", "歲云暮矣，何由足食。"]'),
('2d10b2da-0fab-404b-bfda-1afda8cd999d','和陶勸農韵勉吾鄉之學者  其三','吳芾','宋','宋诗','song-poetry','','[]','吾鄉人物，散處川陸。',40,'全唐诗/poet.song.113000.json','["吾鄉人物，散處川陸。", "豈無秀民，生而清穆。", "亦既從師，步趨隨逐。", "亦既窮經，訪尋歸宿。"]'),
('da3dbe39-517e-4cb9-9389-7b36c45b2b09','和陶勸農韵勉吾鄉之學者  其四','吳芾','宋','宋诗','song-poetry','','[]','奈何人性，易流難久。',40,'全唐诗/poet.song.113000.json','["奈何人性，易流難久。", "纔及長成，即求配耦。", "稍得其資，復營南畝。", "自暴自棄，有同游手。"]'),
('bab754c9-7e1b-4249-b22a-651056c18ac1','和陶勸農韵勉吾鄉之學者  其五','吳芾','宋','宋诗','song-poetry','','[]','大抵名儒，豈患窮匱。',40,'全唐诗/poet.song.113000.json','["大抵名儒，豈患窮匱。", "大抵外物，豈在僥冀。", "學成道尊，富貴自至。", "不學空虛，非惟自愧。"]'),
('e429d1b5-4ac1-48c1-8626-575a1ecc38dc','和陶勸農韵勉吾鄉之學者  其六','吳芾','宋','宋诗','song-poetry','','[]','縱得美官，人亦見鄙。',40,'全唐诗/poet.song.113000.json','["縱得美官，人亦見鄙。", "若博羣書，更堅素履。", "雖處常流，亦超塵軌。", "一旦進爲，必兼衆美。"]'),
('5d807948-268b-4cee-8f33-3051862a4164','和陶命子韵示津調官  其一','吳芾','宋','宋诗','song-poetry','','[]','我愛二龔，絕勝二唐。',40,'全唐诗/poet.song.113000.json','["我愛二龔，絕勝二唐。", "克著清節，終始有光。", "夫豈不知，伊傅在商。", "相湯洎高，俱致明昌。"]'),
('999501c3-ecc3-434c-936b-7b1dc47c7224','和陶命子韵示津調官  其二','吳芾','宋','宋诗','song-poetry','','[]','又豈不知，道否晚周。',40,'全唐诗/poet.song.113000.json','["又豈不知，道否晚周。", "天縱將聖，獨有孔丘。", "卒老於行，靡憚周流。", "胡爲潔己，耻事王侯。"]'),
('e5b486ae-ceda-422e-b528-9ad06f5e9f60','和陶命子韵示津調官  其三','吳芾','宋','宋诗','song-poetry','','[]','曰豈不欲，效彼羣龍。',40,'全唐诗/poet.song.113000.json','["曰豈不欲，效彼羣龍。", "潤澤萬物，助成歲功。", "潛而不用，夫豈自封。", "懼將有悔，不顯其蹤。"]'),
('dc20f8eb-ccb7-48ae-9684-4677ca7e30af','和陶命子韵示津調官  其四','吳芾','宋','宋诗','song-poetry','','[]','喬木千尋，竟困斧柯。',40,'全唐诗/poet.song.113000.json','["喬木千尋，竟困斧柯。", "屈原特立，終隕汨羅。", "水行地中，尚值坳窊。", "縱如賈誼，猶滯長沙。"]'),
('0923c7b2-2819-4691-90af-2b7c86c4b1df','和陶命子韵示津調官  其五','吳芾','宋','宋诗','song-poetry','','[]','勿謂吾身，有才有德。',40,'全唐诗/poet.song.113000.json','["勿謂吾身，有才有德。", "可以安世，可以益國。", "不善用之，鮮不爲忒。", "所以古人，戒之在得。"]'),
('0a0ad81e-39e6-432a-86a4-9a6d812fca81','和陶命子韵示津調官  其六','吳芾','宋','宋诗','song-poetry','','[]','我幸此生，不忘本始。',40,'全唐诗/poet.song.113000.json','["我幸此生，不忘本始。", "身雖朝廷，心實田里。", "所以暮年，知足知止。", "以進爲憂，以退爲喜。"]'),
('d99acc63-380f-45fe-b0f6-be3c427d52b9','和陶命子韵示津調官  其七','吳芾','宋','宋诗','song-poetry','','[]','汝能傳家，一第已及。',40,'全唐诗/poet.song.113000.json','["汝能傳家，一第已及。", "使進而爲，不患無立。", "奈何親老，奉親爲急。", "莫待異時，徒然涕泣。"]'),
('81ca023a-85bc-481b-bb5e-2b59bc7d405d','和陶命子韵示津調官  其八','吳芾','宋','宋诗','song-poetry','','[]','我不望汝，勳業濟時。',40,'全唐诗/poet.song.113000.json','["我不望汝，勳業濟時。", "縱得入侍，朝夕論思。", "欲供子職，何如在茲。", "人能盡孝，忠豈遠而。"]'),
('ed4da728-04a2-4f76-a409-800ff2c2a675','和陶命子韵示津調官  其九','吳芾','宋','宋诗','song-poetry','','[]','既有餘力，且親燈火。',40,'全唐诗/poet.song.113000.json','["既有餘力，且親燈火。", "讀破萬卷，百倍於我。", "我恨書少，意不自可。", "汝能雪耻，天亦見假。"]'),
('80d7529d-81ff-4013-b711-8f9f2f9ce1de','和陶命子韵示津調官  其一○','吳芾','宋','宋诗','song-poetry','','[]','我本白丁，恩及童孩。',40,'全唐诗/poet.song.113000.json','["我本白丁，恩及童孩。", "雖由先德，亦自書來。", "汝誠博古，爲世實才。", "時或未遇，又何慊哉。"]'),
('db88a6cb-93f3-4f03-9306-c6ccfa65c682','和陶歸鳥  其一','吳芾','宋','宋诗','song-poetry','','[]','翩翩歸鳥，投宿深林。',40,'全唐诗/poet.song.113000.json','["翩翩歸鳥，投宿深林。", "豈無所擇，相彼遥岑。", "厥有嘉樹，可以託心。", "雖逢赫日，終貯清陰。"]'),
('88643b75-4443-43d1-9dca-07c04198e768','和陶歸鳥  其二','吳芾','宋','宋诗','song-poetry','','[]','翩翩歸鳥，亦已倦飛。',40,'全唐诗/poet.song.113000.json','["翩翩歸鳥，亦已倦飛。", "平林在望，非此曷依。", "是用斂翮，一意來歸。", "世網雖密，容或我遺。"]'),
('cc1f5313-af8e-4b69-bad2-136da51cf28b','和陶歸鳥  其三','吳芾','宋','宋诗','song-poetry','','[]','翩翩歸鳥，慮患徘徊。',40,'全唐诗/poet.song.113000.json','["翩翩歸鳥，慮患徘徊。", "四顧萬里，獨有故棲。", "故棲來反，所願已諧。", "毋思寥廓，擾擾此懷。"]'),
('a3b2ab3e-b76c-4a26-9c35-1d979d638206','和陶歸鳥  其四','吳芾','宋','宋诗','song-poetry','','[]','翩翩歸鳥，顧影蕭條。',40,'全唐诗/poet.song.113000.json','["翩翩歸鳥，顧影蕭條。", "亦既休息，斂此風標。", "仍遇儔匹，其鳴交交。", "營巢雖苦，亦復亡勞。"]'),
('f16ceba2-4613-44ce-ba70-5c91dfc595c2','和陶形贈影','吳芾','宋','宋诗','song-poetry','','[]','吁嗟汝依我，自有此身時。',96,'全唐诗/poet.song.113000.json','["吁嗟汝依我，自有此身時。", "跬步不相捨，皆隨我所之。", "使汝動必正，端本皆在茲。", "念我已衰老，自知死有期。", "行且與汝別，此心寧不思。", "但我不畏死，亦恥涕漣洏。", "且把一樽酒，話別汝莫疑。", "淵明甫中壽，已作挽歌辭。"]'),
('7824e062-5944-4c98-98e2-2314de3ecbd3','和陶神釋','吳芾','宋','宋诗','song-poetry','','[]','人生稟一氣，自微而至著。',144,'全唐诗/poet.song.113000.json','["人生稟一氣，自微而至著。", "不問富與貧，不論新與故。", "自有形影初，我便相親附。", "二子既有言，我寧無一語。", "汝形未生時，影復在何處。", "偶與我有緣，同生復同住。", "幸我所依人，造理仍知數。", "身雖未溘然，已辦周身具。", "得酒即忘懷，寧復顧毀譽。", "醒即看雲眠，目送孤鴻去。", "我亦得安閑，不憂還不懼。", "說與二子知，莫爲身外慮。"]'),
('abdef1d6-7a17-4e3e-9c58-3ca7e0aad667','和陶示周續之祖企謝景夷韵寄朱元晦','吳芾','宋','宋诗','song-poetry','','[]','我愛朱夫子，處世無戚欣。',96,'全唐诗/poet.song.113000.json','["我愛朱夫子，處世無戚欣。", "淵明不可見，幸哉有斯人。", "奈何不苟合，進用苦無因。", "夫子於此道，妙處固已臻。", "尚欲傳後學，使聞所不聞。", "顧我景慕久，願見亦良勤。", "第恨隔千里，無由往卜隣。", "安得縮地杖，一到建溪濱。"]'),
('2f7901e2-8a24-4f8b-877a-0115bf6e116d','和陶與殷晉安別韵送陳順之赴官','吳芾','宋','宋诗','song-poetry','','[]','子往治畿邑，趣裝亦良勤。',120,'全唐诗/poet.song.113000.json','["子往治畿邑，趣裝亦良勤。", "惠然來過我，話別更情親。", "顧我老且病，已與死爲鄰。", "獨思陪勝侶，倍覺惜清晨。", "忍唱陽關徹，與子從此分。", "願子且少駐，醉我甕頭春。", "子雖未宦達，意氣已凌雲。", "今去天尺五，騰上豈無因。", "要無求速化，切莫慮長貧。", "抱才能自重，何患不如人。"]'),
('7ed49daf-c997-4ae1-a959-235a247c4e7d','乍晴與客登眺和陶和胡西曹韵','吳芾','宋','宋诗','song-poetry','','[]','方欣秋氣爽，庭戶生凉颸。',96,'全唐诗/poet.song.113000.json','["方欣秋氣爽，庭戶生凉颸。", "俄然毛骨冷，霜露侵人衣。", "乍霽還可喜，領客登翠微。", "猶有籬下菊，不見園中葵。", "徘徊視景物，似與人俱衰。", "幸有杯中物，何妨時一揮。", "人生得行樂，老去未爲遲。", "宋玉猶未老，何事苦多悲。"]'),
('d2e67bd1-221d-4d82-bcb8-9dde586f743b','和陶悲從弟仲德韵哭陳澤民','吳芾','宋','宋诗','song-poetry','','[]','年來朋舊少，大半已彫零。',132,'全唐诗/poet.song.113000.json','["年來朋舊少，大半已彫零。", "人物如吾子，共謂上青冥。", "行年纔五十，歎惜負平生。", "憶子初見我，我意已先傾。", "愛子器識遠，佇子功業成。", "縱不登要路，亦必享遐齡。", "貳邑曾未久，早已聞政聲。", "方將脫選調，榮養娛親庭。", "天公亦何事，於此獨無情。", "一旦棄我去，不復見儀形。", "痛傷風月夜，空對酒尊盈。"]'),
('5dba6fc3-1457-445d-ac6b-9045eb3b0e81','和陶始作鎮軍參軍經曲阿韵哭陳能之','吳芾','宋','宋诗','song-poetry','','[]','陳公行古道，出處盡堪書。',120,'全唐诗/poet.song.113000.json','["陳公行古道，出處盡堪書。", "俯仰端無負，初終總一如。", "粵從爲劇邑，平步上亨衢。", "正色主風憲，彈劾靡親疏。", "故雖頻補外，直性不可紆。", "召還方進用，謂當推緒餘。", "一朝忽攖疾，力請歸舊居。", "竟化遼東鶴，不作北溟魚。", "哀哉名世士，天胡賦分拘。", "有子傳衣鉢，無錢治室廬。"]'),
('65e66009-0627-4fbc-8dae-72d632d7e870','和陶阻風於規林韵寄陳時中二首  其一','吳芾','宋','宋诗','song-poetry','','[]','退處固云樂，未免歎索居。',96,'全唐诗/poet.song.113000.json','["退處固云樂，未免歎索居。", "頼有陳使君，情親如友于。", "自應長相見，豈謂各一隅。", "我雖事跧伏，閉門懶問塗。", "無日不看山，無時不面湖。", "君尤我所愛，良會安得疏。", "縱不思風度，亦欲聞緒餘。", "會須成二老，君意定何如。"]'),
('8bbb12da-b820-42b0-8b67-ad32b1c4af62','和陶阻風於規林韵寄陳時中二首  其二','吳芾','宋','宋诗','song-poetry','','[]','人皆有還往，我獨無所之。',72,'全唐诗/poet.song.113000.json','["人皆有還往，我獨無所之。", "若不見君子，誰與同襟期。", "嗟我已衰老，無復少壯時。", "縱使善衛養，豈能長在茲。", "願言時命駕，容我親色辭。", "我已不强酒，從今君莫疑。"]'),
('d61852af-f08b-4c37-9e03-7c6e2803e976','和陶赴假還江陵夜行途口韵寄江朝宗','吳芾','宋','宋诗','song-poetry','','[]','居閑歲月久，萬事心已冥。',120,'全唐诗/poet.song.113000.json','["居閑歲月久，萬事心已冥。", "獨於同調人，獨未能忘情。", "憶昔桂花發，君來訪柴荆。", "把酒坐花下，歡然話平生。", "今年秋更好，花還照眼明。", "無由共清賞，幽恨已難平。", "那聞遭橫議，意頗悔西征。", "既不樂朝市，却思巖石耕。", "古來未遇者，寧免寸祿榮。", "要當且隠忍，勉强就功名。"]'),
('13ee19d4-b7b0-40cc-a96a-3c0804473039','和陶己酉歲九月九日','吳芾','宋','宋诗','song-poetry','','[]','天地氣將肅，秋冬候欲交。',96,'全唐诗/poet.song.113000.json','["天地氣將肅，秋冬候欲交。", "眷茲萬木落，感我雙鬢彫。", "悠然清興動，與客共登高。", "有巖號景星，萬仞連雲霄。", "一覽快心目，寧辭杖履勞。", "但恨無酒量，一舉如沃焦。", "仍恨無坐客，可繼五柳陶。", "且拚風帽落，聊醉菊花朝。"]'),
('88e39430-e546-4a75-8024-92a19a75e63e','和陶庚戌歲九月中於西田穫早稻','吳芾','宋','宋诗','song-poetry','','[]','東風纔解凍，農事已開端。',120,'全唐诗/poet.song.113000.json','["東風纔解凍，農事已開端。", "田夫競力作，不獲須臾安。", "淵明於是時，亦豈容坐觀。", "日出負耒去，入夜乘牛還。", "寧不憚勞苦，要得逃饑寒。", "顧我獨何幸，雖知稼穡難。", "逢秋但一飽，此外了不干。", "回首視淵明，已是增汗顔。", "那堪萬事拙，只得長掩關。", "誦公穫稻句，倍爲公興歎。"]'),
('4ee67ba4-f16e-4ba2-b4e9-736e0c1fa33a','和陶丙辰歲八月中於下潠田舍穫','吳芾','宋','宋诗','song-poetry','','[]','淵明事南畝，躬自穫巖隈。',120,'全唐诗/poet.song.113000.json','["淵明事南畝，躬自穫巖隈。", "雖復竭吾力，却得舒我懷。", "所收既不薄，卒歲事可諧。", "隣家相慰勞，競持酒與雞。", "留連相酬酢，入夜未能迴。", "回思往歲歉，舉目俱堪哀。", "憂心今幸釋，笑口何妨開。", "須傾瓦盆盡，須放玉山頹。", "已是從吾好，寧憂與世乖。", "任他田父哂，未足爲高棲。"]'),
('b4fb8551-cba9-4eef-9a0b-71f782160f39','和陶詠貧士七首  其一','吳芾','宋','宋诗','song-poetry','','[]','士貧亦常事，但視其所依。',72,'全唐诗/poet.song.113000.json','["士貧亦常事，但視其所依。", "苟能依於道，暮景亦有輝。", "淵明生亂世，初不求奮飛。", "爲貧聊一出，違己即言歸。", "歸來坐衡宇，無粟可療饑。", "作詩詠貧士，泰然曾不悲。"]'),
('1ab51fc9-ed0f-4689-91eb-e24fb47ad502','和陶詠貧士七首  其二','吳芾','宋','宋诗','song-poetry','','[]','淵明抱歸興，未老辭華軒。',72,'全唐诗/poet.song.113000.json','["淵明抱歸興，未老辭華軒。", "應謂役於人，豈如歸田園。", "在家貧亦好，滿眼是風煙。", "親戚可晤語，書史可精研。", "妻子識此意，相對無間言。", "時取新酒漉，一笑中聖賢。"]'),
('99b7170c-f1c7-48ac-b023-e42baa5c3db0','和陶詠貧士七首  其三','吳芾','宋','宋诗','song-poetry','','[]','我家未爲貧，尚有綠綺琴。',72,'全唐诗/poet.song.113000.json','["我家未爲貧，尚有綠綺琴。", "手雖不能彈，頗喜聞遺音。", "時時命女奴，强於弦上尋。", "聽罷方寸適，取酒時一斟。", "顔回與原憲，平日我所欽。", "儻得從之游，雖貧亦甘心。"]'),
('4b36028d-3102-4c20-af99-90ab1e848d9f','和陶詠貧士七首  其四','吳芾','宋','宋诗','song-poetry','','[]','新春來未幾，已見日在婁。',72,'全唐诗/poet.song.113000.json','["新春來未幾，已見日在婁。", "游人怕春去，把酒急獻酬。", "折花各盈把，行歌滿道周。", "貧者壁四立，若不堪其憂。", "亦復典春衣，買酒呼朋儔。", "一醉人所嗜，此外非所求。"]'),
('4b9cf5ee-47b8-4b10-8028-5dd56e1abc6f','和陶詠貧士七首  其五','吳芾','宋','宋诗','song-poetry','','[]','我愛徐孺子，高名滿江干。',72,'全唐诗/poet.song.113000.json','["我愛徐孺子，高名滿江干。", "衆人皆欲仕，乃獨恥爲官。", "曾不憚辛苦，負耒營一餐。", "清節映千古，至今聞者寒。", "洪井有祠宇，我嘗瞻其顔。", "不覺愧汗下，竟歸長掩關。"]'),
('0b90f464-8635-4b4c-ad8b-70a3b100ae24','和陶詠貧士七首  其六','吳芾','宋','宋诗','song-poetry','','[]','光景如春花，身世似秋蓬。',72,'全唐诗/poet.song.113000.json','["光景如春花，身世似秋蓬。", "淵明洞此理，養拙不求工。", "上獨思四皓，下獨友兩龔。", "出處雖或異，心跡亦畧同。", "安貧抱全節，雖窮亦如通。", "九原儻可作，我欲以身從。"]'),
('0777ab05-3709-4b90-a804-437ced73b109','和陶詠貧士七首  其七','吳芾','宋','宋诗','song-poetry','','[]','入仕已四紀，把麾還六州。',72,'全唐诗/poet.song.113000.json','["入仕已四紀，把麾還六州。", "曾未見縣令，有若淵明儔。", "稍屈便引去，高致更風流。", "醉卧衡門下，曾無寒餓憂。", "獨抱千金璧，未許人輕酬。", "聲名傳不朽，千古仰前修。"]'),
('77755746-2b71-4a53-b992-7e749896cc0c','和陶詠二疏韵','吳芾','宋','宋诗','song-poetry','','[]','世人躭寵榮，往往麾不去。',108,'全唐诗/poet.song.113000.json','["世人躭寵榮，往往麾不去。", "日已迫桑榆，馳騖方成趣。", "誰肯急流中，便作冥鴻舉。", "屈指數哲人，在昔獨疏傅。", "萬口共稱賢，餞送塞歸路。", "天子亦嘉之，賜金示優顧。", "淵明作此詩，端欲迷者悟。", "我觀二疏高，豈無子孫慮。", "揮金以自娛，益表清節著。"]'),
('8310a7c2-53d1-4bce-8d37-67044f1519ad','和陶讀山海經十三首韵送機簡堂自景星巖再住隠靜  其一','吳芾','宋','宋诗','song-poetry','','[]','我自歸林下，亦復與世疏。',96,'全唐诗/poet.song.113000.json','["我自歸林下，亦復與世疏。", "頼有善知識，時能過吾廬。", "伴我說道話，我愛讀佛書。", "師爲巖上去，我亦爲膏車。", "便欲展我鉢，隨師同飯蔬。", "脫此塵俗累，長與巖石俱。", "此巖固高矣，卓出山海圖。", "但比吾師高，還恐巖不如。"]'),
('f60c4fb1-aec8-455c-bdcb-d8870bb0c50c','和陶讀山海經十三首韵送機簡堂自景星巖再住隠靜  其二','吳芾','宋','宋诗','song-poetry','','[]','我生山窟裏，終朝面孱顔。',48,'全唐诗/poet.song.113000.json','["我生山窟裏，終朝面孱顔。", "獨此巖未到，抱恨知幾年。", "茲遊信奇絕，一覽小衆山。", "更得師爲主，二妙爲易言。"]'),
('c33ffbd6-4e8c-4d57-a3bd-e67d5e155296','和陶讀山海經十三首韵送機簡堂自景星巖再住隠靜  其三','吳芾','宋','宋诗','song-poetry','','[]','幽棲非不勝，觸目是林丘。',48,'全唐诗/poet.song.113000.json','["幽棲非不勝，觸目是林丘。", "若比茲巖秀，培塿固難儔。", "雲山千里見，石泉四時流。", "登臨有如此，何必更他遊。"]'),
('1475160d-8cec-488a-ae90-7e4284864433','和陶讀山海經十三首韵送機簡堂自景星巖再住隠靜  其四','吳芾','宋','宋诗','song-poetry','','[]','我年七十五，木末掛殘陽。',48,'全唐诗/poet.song.113000.json','["我年七十五，木末掛殘陽。", "縱使身未逝，亦豈能久長。", "尚冀林間住，與師共末光。", "孤雲俄暫出，道俗紛蒼黄。"]'),
('27b9bdad-aa24-4434-8900-e900f03fece3','和陶讀山海經十三首韵送機簡堂自景星巖再住隠靜  其五','吳芾','宋','宋诗','song-poetry','','[]','愛山端有素，拘俗亦可憐。',48,'全唐诗/poet.song.113000.json','["愛山端有素，拘俗亦可憐。", "昨守當塗郡，不識隠靜山。", "羨師來又去，愧我復何言。", "尚期無久住，歸送我殘年。"]'),
('7f22ad62-3721-4a9f-b2a8-da639450fd70','和陶讀山海經十三首韵送機簡堂自景星巖再住隠靜  其六','吳芾','宋','宋诗','song-poetry','','[]','師心如死灰，形亦如槁木。',48,'全唐诗/poet.song.113000.json','["師心如死灰，形亦如槁木。", "胡爲衲子歸，以響答空谷。", "顧我塵垢身，擬向禪河浴。", "更願張佛燈，爲我代明燭。"]'),
('e3a584e9-2871-45f6-b4b8-7a0d19394a6c','和陶讀山海經十三首韵送機簡堂自景星巖再住隠靜  其七','吳芾','宋','宋诗','song-poetry','','[]','扶疏巖下樹，入夏總成陰。',48,'全唐诗/poet.song.113000.json','["扶疏巖下樹，入夏總成陰。", "幾年荆棘地，一旦爲叢林。", "我方與衲子，共聽海潮音。", "人生多聚散，離別忽驚心。"]'),
('0d9a114a-6188-44bf-867b-e03be4de97b4','和陶讀山海經十三首韵送機簡堂自景星巖再住隠靜  其八','吳芾','宋','宋诗','song-poetry','','[]','我與師來往，歲月雖未長。',48,'全唐诗/poet.song.113000.json','["我與師來往，歲月雖未長。", "相看成二老，風流亦異常。", "既宴坐巖上，我方爲聚糧。", "儻師能早歸，此樂猶未央。"]'),
('fbb75eb8-e5cf-4b51-bcbd-05ec1813cd12','和陶讀山海經十三首韵送機簡堂自景星巖再住隠靜  其九','吳芾','宋','宋诗','song-poetry','','[]','紛紛學禪者，腰包競奔走。',48,'全唐诗/poet.song.113000.json','["紛紛學禪者，腰包競奔走。", "才能脫葛藤，癡意便自負。", "求其道德尊，如師蓋希有。", "願傅上乘人，永光臨濟後。"]'),
('ff953ea3-698a-4f0e-9f10-23cfb506993a','和陶讀山海經十三首韵送機簡堂自景星巖再住隠靜  其一○','吳芾','宋','宋诗','song-poetry','','[]','吾邑多緇徒，浩浩若雲海。',48,'全唐诗/poet.song.113000.json','["吾邑多緇徒，浩浩若雲海。", "大機久已亡，頼有小機在。", "乃更與一岑，純全兩無悔。", "堂堂二老禪，海內共期待。"]'),
('cd86e4cd-e85f-458f-91fb-d937ddf275d2','和陶讀山海經十三首韵送機簡堂自景星巖再住隠靜  其一一','吳芾','宋','宋诗','song-poetry','','[]','古無住持事，但只傳法旨。',48,'全唐诗/poet.song.113000.json','["古無住持事，但只傳法旨。", "有能悟色空，便可超生死。", "庸僧昧本原，豈識西歸履。", "買帖坐禪床，佛法將何恃。"]'),
('835e3669-c2bc-458d-a62c-8a842a7b5583','和陶讀山海經十三首韵送機簡堂自景星巖再住隠靜  其一二','吳芾','宋','宋诗','song-poetry','','[]','僧中有高僧，士亦有高士。',48,'全唐诗/poet.song.113000.json','["僧中有高僧，士亦有高士。", "我雖不爲高，心粗能知止。", "師是箇中人，特患不爲爾。", "何幸我與師，俱是隣家子。"]'),
('67e1d223-6808-4465-b472-ad5345aa3d9c','和陶讀山海經十三首韵送機簡堂自景星巖再住隠靜  其一三','吳芾','宋','宋诗','song-poetry','','[]','師本窮和尚，我亦窮秀才。',48,'全唐诗/poet.song.113000.json','["師本窮和尚，我亦窮秀才。", "忍窮俱已徹，老肯不歸來。", "今師雖暫別，泉石莫相猜。", "應緣聊復耳，師豈有心哉。"]'),
('53f25960-f806-40dd-abfd-717c619eca63','和陶挽歌詞三首  其一','吳芾','宋','宋诗','song-poetry','','[]','吾年七十五，壽命不爲促。',84,'全唐诗/poet.song.113000.json','["吾年七十五，壽命不爲促。", "仕僅五十年，出處粗可錄。", "人生會有盡，自應身就木。", "寄語親舊輩，不必爲我哭。", "百年如一夢，吾夢今始覺。", "亦既了萬緣，無殆亦無辱。", "所欠惟一死，得死今已足。"]'),
('650bb56d-c43f-4270-a2c2-9432c1387aff','和陶挽歌詞三首  其二','吳芾','宋','宋诗','song-poetry','','[]','嗟我在生日，一飲數十觴。',72,'全唐诗/poet.song.113000.json','["嗟我在生日，一飲數十觴。", "有時無酒飲，亦復潑醅嘗。", "今日雖有酒，羅列在我傍。", "對之徒自歎，與世隔風光。", "所幸埋骨地，不離雲外鄉。", "魂魄時一遊，此樂猶未央。"]'),
('03a25fb6-1eb9-46cf-8e9b-b07003bb1b95','和陶挽歌詞三首  其三','吳芾','宋','宋诗','song-poetry','','[]','老眼日昏昏，華髮日蕭蕭。',108,'全唐诗/poet.song.113000.json','["老眼日昏昏，華髮日蕭蕭。", "不死竟何待，理合葬荒郊。", "荒郊何所有，四面俱岧嶢。", "榮木望秋落，亦已成枯條。", "青松爲我夕，白石爲我朝。", "仍幸二親墓，相去無幾何。", "今得從之遊，歡喜如還家。", "我心既歡喜，安用挽者歌。", "有人來奠我，但問山之阿。"]'),
('5cfb4c36-63be-4d23-9960-6a0b12b817b0','和陶桃花源','吳芾','宋','宋诗','song-poetry','','[]','我聞桃花源，其先是秦世。',192,'全唐诗/poet.song.113000.json','["我聞桃花源，其先是秦世。", "當時避地人，歲久俱已逝。", "其後長子孫，生理還不廢。", "種桃以自營，結茅以自憇。", "有兒但發蒙，初不工六藝。", "有田但收禾，了不輸二稅。", "有雞只晨號，有犬不夜吠。", "淵明愛其真，爲此成新製。", "我久聞其風，褰裳思一詣。", "所慮路難通，仍恐水難厲。", "夢寐不能忘，抱恨知幾歲。", "所恨天見私，於此施嘉惠。", "貽我萬株桃，漫山迷眼界。", "却勝武陵溪，草樹相蒙蔽。", "相去復不遠，只在吾廬外。", "人號小桃源，景物適相契。"]'),
('57930810-139b-4b28-8ed5-46a65f26638d','春雨不止魯漕有二詩因次韵  其一','吳芾','宋','宋诗','song-poetry','','[]','青春能幾何，况已過寒食。',72,'全唐诗/poet.song.113000.json','["青春能幾何，况已過寒食。", "此時對東風，一日亦可惜。", "正好倒清尊，呼婦戛鳴瑟。", "胡不少自寬，兀坐有憂色。", "一春雨已多，連日風更力。", "安得補天漏，坐待江月白。"]'),
('bf95f84e-3e95-4f83-a391-220d508ee0ed','春雨不止魯漕有二詩因次韵  其二','吳芾','宋','宋诗','song-poetry','','[]','春日固喜雨，雨多亦可已。',72,'全唐诗/poet.song.113000.json','["春日固喜雨，雨多亦可已。", "若爲尚霶𩃱，連月煙浪裏。", "江湖更瀰漫，不見蒲與葦。", "有時漏日光，烘雲薄如紙。", "欲晴又復陰，何以慰田里。", "鬰鬰不能舒，一坐四五起。"]'),
('fa4c4a21-7b33-4436-9173-3fc07f83b5ed','和陳平仲中秋懷舊遊','吳芾','宋','宋诗','song-poetry','','[]','天末逢秋半，臨流玩佳月。',192,'全唐诗/poet.song.113000.json','["天末逢秋半，臨流玩佳月。", "置酒延孤光，夜久凉風發。", "感時歌慨慷，醉來翻不悅。", "念人有聚散，念月有圓缺。", "萬事轉頭空，百年飛鳥瞥。", "粵從罹亂離，頭角嗟垂折。", "兀坐山谷間，何人定交結。", "素琴已塵埃，孤劍尚清刮。", "故人不可見，幽懷欲誰說。", "明月自團團，幽憂空烈烈。", "忽得陳子詩，辭旨兩奇絕。", "歷歷敘舊遊，筆端如有舌。", "何處復相從，酒壺行自揭。", "遥想鮑與劉，應亦歎胡越。", "要當按酒兵，無令冒斧鉞。", "吾儕豈長貧，廟堂方簡拔。"]'),
('16d0d448-3007-48d6-b985-766150e6704f','符倅同遊雁蕩賡其所和范相遊山韵','吳芾','宋','宋诗','song-poetry','','[]','晚學愧淹博，微官妨隠盤。',168,'全唐诗/poet.song.113000.json','["晚學愧淹博，微官妨隠盤。", "攀龍榮請事，歛板喜承顔。", "懦庸資盼睞，簿領洗塵煩。", "南豐茂人傑，才望藹江關。", "題輿裨德政，鎮俗念時艱。", "仙山尋勝外，妙句落人間。", "氣連天柱壯，清奪霜空寒。", "一讀三歎息，髮立誰敢謾。", "但嗟俊逸才，尚滯海之灣。", "中興急賢哲，日日聞賜環。", "况復有如公，驥足寧久閒。", "會須早命駕，即日當召還。", "發硎觀利器，斷鼇新海寰。", "宣室佇前席，顧問應夜闌。"]'),
('76c16313-a91f-4d5d-b0bc-f290b651059f','寄季元集','吳芾','宋','宋诗','song-poetry','','[]','劍池有逸人，過我談名理。',276,'全唐诗/poet.song.113000.json','["劍池有逸人，過我談名理。", "自謂出囂塵，知足更知止。", "高標拂煙雲，雅志在山水。", "既作陶淵明，且慕赤松子。", "我方聞緒餘，固已生歡喜。", "正欲叩淵源，獨恨未暇耳。", "忽云桐柏山，此去甚密邇。", "擬一往其間，尋真訪遺址。", "不久便可還，畢此玄妙旨。", "一去寂無音，逢人問行李。", "人言不復來，征車已西指。", "反把遊山屐，去踏長安市。", "似聞稍留連，尚稽歸故里。", "未免傍人門，乞憐應忍恥。", "縱使得美官，所喪亦多矣。", "嗟哉人學仙，如君能有幾。", "冥鴻合高翔，不謂事乃爾。", "徒有懶窩名，却入旋窩裏。", "始知聽空言，未若觀素履。", "意者天愛君，要君行處是。", "慮或成沈迷，敗道自此始。", "聊復小撓之，欲其全暮齒。", "庶發堅固心，永無塵念起。"]'),
('f9b5356e-5025-4c2b-b69b-c68f7e32ed8a','江行阻風','吳芾','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','我生走四方，足迹亦幾遍。',288,'全唐诗/poet.song.113000.json','["我生走四方，足迹亦幾遍。", "初未識江行，每起浮家羨。", "一從登此舟，舉室盡欣忭。", "既得捨車徒，且免入郵傳。", "高枕卧短篷，頓忘行役倦。", "始謂旬日間，便可朝行殿。", "縱未許歸田，行止亦可判。", "那知事好乖，一夜狂風轉。", "怒號動地來，波濤立江面。", "如屋復如山，拍天仍拍岸。", "三日不能休，雲容更千變。", "始疑江神驕，出與風伯戰。", "擁起千里潮，散作雪飛濺。", "跬步莫能前，有纜莫能牽。", "又疑慢爾神，至此獲深譴。", "亦自料平生，忠信粗表見。", "神既依人行，豈不略爲援。", "若謂神無私，應物當普現。", "胡爲泝流船，却乃去如箭。", "而我獨滯留，艤棹長江畔。", "終日困飄颻，使我頭目眩。", "試取蘋藻羞，更效潢汙薦。", "再拜祝天公，冀爲開方便。", "莫分往與來，莫問貴與賤。"]'),
('09c7a5d3-75e5-4183-ab63-ec6b7d1f9068','阻風又成數語呈江朝宗','吳芾','宋','宋诗','song-poetry','','[]','平生航浙河，不知幾往返。',144,'全唐诗/poet.song.113000.json','["平生航浙河，不知幾往返。", "豈不或滯留，有時容幸免。", "未若此番來，所向輒相反。", "順水即值風，便風還阻淺。", "夜來至奔牛，一雨成瓴建。", "妻孥笑相看，陡覺雙眉展。", "謂可便及城，假館少休偃。", "平明風橫生，吹我船頭轉。", "咫尺不可前，安能達京輦。", "客路固多艱，我行亦太蹇。", "何當歸去來，高卧青山遠。", "一任雨兼風，杜門都不管。"]'),
('a2338acc-4e83-43cf-a3e8-036fd249565a','和何倅遊雁蕩','吳芾','宋','宋诗','song-poetry','','[]','何侯富詞藻，能賦兼能詩。',288,'全唐诗/poet.song.113000.json','["何侯富詞藻，能賦兼能詩。", "百篇輩李白，十稔嗤左思。", "搜奇抉靈怪，造化不能私。", "每爲山水遊，錦囊隨所之。", "雁蕩閟神秀，鬼物潛司巘。", "開林發幽隠，肇自興國時。", "高巖聳崷崒，列岫森瑰奇。", "龍湫神光異，龍鼻靈液滋。", "天柱萬仞立，冰簾千丈垂。", "羨君沿檄來，暇日遂遍窺。", "興隨佳處發，景與高情宜。", "留步欣有得，過眼光如遺。", "乘寒躡危磴，躋險攀樛枝。", "雅有許詢興，心形不知疲。", "我漸動拘俗，薄宦方棲遲。", "恨君爲此行，不獲相追隨。", "平生愛山心，自視如調饑。", "尋幽儻有路，初不問險夷。", "幾欲老山間，便將雲衲披。", "頃幸官是邑，柴車日載馳。", "列賢不暫捨，游燕必於斯。", "每欲狀奇怪，苦乏幼婦詞。", "千巖與萬壑，胸中徒自知。", "別來歲月久，况復逢艱危。"]'),
('32b0ece2-f25e-42b7-9e56-a831db72f40e','丁亥守當塗中夏有獻瑞麥者今日池中復得雙頭蓮因成小詩以記之','吳芾','宋','宋诗','song-poetry','','[]','嗟我百無能，此身仍老矣。',48,'全唐诗/poet.song.113000.json','["嗟我百無能，此身仍老矣。", "濫此把一麾，何以慰千里。", "隴麥秀兩岐，池蓮綻雙蕊。", "斯事雖偶然，亦爲邦人喜。"]'),
('4641ecdd-27a6-4bcb-87db-bc2d6b8e6f71','和許守巖桂','吳芾','宋','宋诗','song-poetry','','[]','桂華燦秋杪，造物氣所鍾。',108,'全唐诗/poet.song.113000.json','["桂華燦秋杪，造物氣所鍾。", "清香遍十里，不與凡卉同。", "使君雅好客，携酒臨芳叢。", "被花惱不徹，一笑高堂烘。", "花本生月窟，何事來樊籠。", "疑是姮娥懶，睡起鬢蓬鬆。", "一枝欲斜插，誤落秋山中。", "要須排日賞，拚取百尊空。", "莫待花零落，惆悵隨西風。"]'),
('f58f3fdd-2aee-4cef-83ba-ee448ca8c30b','和任司理賞梅','吳芾','宋','宋诗','song-poetry','','[]','平生愛梅花，嘗有花前諾。',180,'全唐诗/poet.song.113000.json','["平生愛梅花，嘗有花前諾。", "花亦知我心，臭味頗相若。", "對花輒痛飲，席地天爲幕。", "常恐風雨摧，有負東君託。", "一從隨宦牒，但知究民瘼。", "動爲官拘守，進退非綽綽。", "倒指三十年，無復有此樂。", "每逢春信回，長憶花下酌。", "老來把一麾，亦欲强有作。", "牒訟日裝懷，朱墨苦紛錯。", "忽聞花已開，枝頭閙寒爵。", "喜即領賓僚，對花話離索。", "邂逅却成歡，清談間諧謔。", "勝賞雖未窮，亦足慰寥落。", "後夜霜月明，尚可理前約。"]'),
('e54da7a1-86bb-4102-94ca-2afad78f8487','和許守水晶蒲萄','吳芾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','珍果孰稱最，靜中試旁搜。',156,'全唐诗/poet.song.113000.json','["珍果孰稱最，靜中試旁搜。", "白柰非時至，赤梨經歲留。", "廬山杏萬株，武陵橘千頭。", "未若蒲萄美，甘滑仍脆柔。", "正當三伏暑，滿架走青虬。", "繁子何磊落，一一如綴旒。", "我家得異種，潔白映林丘。", "每笑棗與栗，濫比千戶侯。", "邇來事奔走，頗恨拋鉏耰。", "持此贈夫子，因復獻鄙謀。", "他年堆馬乳，豈但供薦羞。", "願以釀千斛，永言資燕遊。", "客來彌日醉，應不數青州。"]'),
('0023397a-dbbb-4c16-bcc1-072cd070ade9','門外池內荷生雙葉','吳芾','宋','宋诗','song-poetry','','[]','今朝池內荷，一柄生雙葉。',60,'全唐诗/poet.song.113000.json','["今朝池內荷，一柄生雙葉。", "傍人爲我言，喜事尚重疊。", "我老皆無用，榮望久已絕。", "偶有二婦妊，行將臨誕月。", "所願生二孫，綿綿傳世業。"]'),
('d22c0eea-96e9-4e7b-9407-1af575a19376','寄題楊宰清畏軒','吳芾','宋','宋诗','song-poetry','','[]','古人貴慎獨，舉世知者希。',96,'全唐诗/poet.song.113000.json','["古人貴慎獨，舉世知者希。", "末俗事誇耀，常患不我知。", "楊子有雅尚，傳家守清規。", "折腰三十載，不辭州縣卑。", "猶慮與衆異，憂讒還畏譏。", "開軒揭華榜，却恐非其宜。", "要當且用晦，處靜藏天機。", "昔賢忌獨清，此語非吾欺。"]'),
('9c0dcd1a-6fc1-4ef2-9b26-75282c965918','題碧雲亭','吳芾','宋','宋诗','song-poetry','','[]','累土創新亭，本擬還舊觀。',168,'全唐诗/poet.song.113000.json','["累土創新亭，本擬還舊觀。", "或言舊亭庳，視此纔及半。", "我方安樸拙，豈敢事輪奐。", "言念夢幻身，終日困几案。", "既未許自如，超然脫羈絆。", "亦欲對江山，時發一笑粲。", "自從得新亭，頓覺百憂散。", "亭前柳色新，亭下荷花亂。", "明月可坐邀，積雪堪俯玩。", "凭欄送飛鴻，千里歸一盼。", "詩成似有神，酒行欲無算。", "取次亦足樂，胡爲尚興歎。", "恨吾年已衰，志不在遊宦。", "何當歸去來，終老湖山畔。"]'),
('e2712e74-f249-476e-8235-d6a404b54888','次韵沈漕使寄和碧雲亭之作','吳芾','宋','宋诗','song-poetry','','[]','衰年厭塵勞，久念作浄觀。',168,'全唐诗/poet.song.113000.json','["衰年厭塵勞，久念作浄觀。", "奉祠還故山，閲歲更過半。", "草草結茅廬，雖無輪與奐。", "水作綠羅衣，山爲青玉案。", "自足了餘生，豈謂浮名絆。", "牽從江上來，去國同王粲。", "既與猿鶴疏，還驚鷗鷺散。", "公餘坐危亭，四顧雲影亂。", "新詩忽鼎來，累日飽吟玩。", "洗我胸中塵，宛如覩清盼。", "信知隠侯家，句法有成算。", "方今苦乏材，當饋屢興歎。", "如公人物英，寧久從遠宦。", "會見御追風，起自長淮畔。"]'),
('7c9fc8d3-5a72-49c4-88a0-ff8fb16c0562','寄題鮑昌朝足軒','吳芾','宋','宋诗','song-poetry','','[]','江南有散人，幾年卧草野。',144,'全唐诗/poet.song.113000.json','["江南有散人，幾年卧草野。", "破甑餘塵埃，衡門絕車馬。", "倘非義所安，一介不取捨。", "闢軒窮巷間，此意非滿假。", "雖云外不足，中有至足者。", "道義輩古人，文章播天下。", "一點浩然氣，萬象資陶冶。", "持此復何求，酣歌對醆斚。", "吁哉簞瓢樂，千古一回也。", "先生於此時，卓然秉大雅。", "顧我愧高風，亦忝詩酒社。", "何當登此軒，抵掌共披寫。"]'),
('8bb25b4b-dffa-459f-9a2a-fc18983fde28','題生春亭','吳芾','宋','宋诗','song-poetry','','[]','府治何偪仄，幾不容欠伸。',48,'全唐诗/poet.song.113000.json','["府治何偪仄，幾不容欠伸。", "我來撤敗屋，池館爲一新。", "便有鳥喚客，更多花惱人。", "誰知牢落地，一旦遽生春。"]'),
('86f32890-16a8-49aa-b1f4-073b24abb697','題涵碧亭','吳芾','宋','宋诗','song-poetry','','[]','幾年涵碧亭，吾亦屢來往。',48,'全唐诗/poet.song.113000.json','["幾年涵碧亭，吾亦屢來往。", "當暑既難逃，斯亭尤可賞。", "清照心膽寒，凉侵毛骨爽。", "我方困長塗，且此休塵鞅。"]'),
('7bac8624-fcfb-4398-8cdc-87e6984b294d','登遐觀亭','吳芾','宋','宋诗','song-poetry','','[]','城上闢新亭，似若規模小。',144,'全唐诗/poet.song.113000.json','["城上闢新亭，似若規模小。", "誰知此亭中，景勝冠江表。", "湖山既回旋，煙雲仍縹緲。", "萬象森目前，不數花與草。", "公餘乘興來，聊以散懷抱。", "四時風物新，一一發天巧。", "芳春柳色連，長夏荷花繞。", "月明固已佳，雪積還更好。", "凭欄認歸舟，策杖送飛鳥。", "適意豈在大，容膝自足了。", "第我思故山，上章方告老。", "指日是行人，頗恨來不早。"]'),
('126c38cb-00a4-4241-b71e-9d14ef7b9b23','寄隠者','吳芾','宋','宋诗','song-poetry','','[]','守道宋高士，築室齊東鄙。',120,'全唐诗/poet.song.113000.json','["守道宋高士，築室齊東鄙。", "植竹看歲寒，種田助形委。", "束書捐古今，抱易究生死。", "不以外移內，不以行責止。", "九十留童顔，湖山飽清視。", "或顧先生云，時平可以起。", "先生本無求，棄置如敝屣。", "俄聞與物化，精一未嘗毀。", "汗簡書逸民，義風洗貪士。", "東望呈肺肝，遥瀉一巵水。"]'),
('7b991d8c-e413-45d7-9292-6185c2c23513','和陳國佐亦愛堂韵','吳芾','宋','宋诗','song-poetry','','[]','紛紛當世士，盡道休官去。',240,'全唐诗/poet.song.113000.json','["紛紛當世士，盡道休官去。", "有墮塵網中，誰能復回顧。", "重爲軒冕惑，一念遂差互。", "要當發深省，悟此形皆寓。", "奔馳徒擾擾，靜中有奇趣。", "夫子廊廟材，華途昔榮遇。", "富貴方迫逐，脫身一何遽。", "蓋恐負初心，或爲名所誤。", "獨尋陶淵明，三徑歸來處。", "親朋續舊遊，寢食安故步。", "詩成月滿窗，坐久塵生屨。", "箇中有真樂，自足慰遲暮。", "我方困長途，因公識歸路。", "讀公寄傲篇，更覺忘世慮。", "有如逃空虛，傾耳聽韶頀。", "念此有限身，歲月空復度。", "他時願卜築，結茅相近住。", "如公邁往姿，平生已心慕。", "我雖負俗累，胸中無好句。", "儻獲從後塵，登高亦能賦。"]'),
('3e0272bc-e0c5-4829-9984-89d4db35f9bb','夏日同官會飲白鶴寺雙瀑亭李道濟作詩紀事因次其韵','吳芾','宋','宋诗','song-poetry','','[]','嗟予好泉石，所至窮幽勝。',228,'全唐诗/poet.song.113000.json','["嗟予好泉石，所至窮幽勝。", "年來墮塵埃，復苦炎熱盛。", "頼有古招提，相去不步仞。", "何時供燕遊，庶以息喧競。", "山僧結虛亭，瀟灑浄如鏡。", "雙瀑從天來，景物更幽迥。", "欄楯溢波光，清凉殊可凭。", "復幸僚友賢，雅與山川稱。", "得暇傾尊罍，相從盡豪俊。", "令尹如子文，去就亡喜慍。", "貳邑不負丞，所蓄金玉潤。", "耿侯固坦夷，趙子亦純正。", "盍簪已足樂，况復有名醖。", "酒酣人意適，坐久天宇靜。", "踏月各言歸，清風遠相趁。", "君詩繼踵來，敏捷過於瞬。", "中復含妙理，不獨寫幽興。", "讀罷愈驚人，癡坐不知暝。", "援筆强續貂，安能繼高詠。"]'),
('a816ea50-a974-4fbb-95ea-1232474f8ac5','和王夷仲詠施粥','吳芾','宋','宋诗','song-poetry','','[]','伊昔豈無旱，赫日流金石。',240,'全唐诗/poet.song.113000.json','["伊昔豈無旱，赫日流金石。", "伊昔豈無水，巨浸連天白。", "未若去歲風，飄忽幾終夕。", "時方屬新秋，稻子半黄赤。", "倏然卷地來，一掃不遺力。", "但覺田畝空，不見倉箱積。", "餘禍及吾民，來春有饑色。", "巡門粥妻子，不足充貴糴。", "往往成流離，有家歸不得。", "我方還里閭，正值此艱厄。", "有心懷拯救，不寐欲通昔。", "念無捐廩人，此意空憤激。", "民饑猶己饑，吾寧忍獨食。", "作糜倒瓶粟，恨不及九百。", "糾合族與隣，樂從有吾叔。", "豈但一時利，永作他年額。", "要令里中人，自此長飽德。", "雖或有凶年，不復更他適。", "鄭罕與宋樂，未足爲匹敵。", "施厚報必豐，會須看他日。"]'),
('2a682d0c-67ee-4f6e-b042-2873873ae183','再和','吳芾','宋','宋诗','song-poetry','','[]','嗟我性拙疏，平生好泉石。',240,'全唐诗/poet.song.113000.json','["嗟我性拙疏，平生好泉石。", "好景與良辰，風清並月白。", "必對佳友朋，一尊陶永夕。", "雅志在輕肥，每笑公西赤。", "歲晚效一官，粗竭區區力。", "所得僅牛毛，罪戾如山積。", "與其鎮營營，終朝有憂色。", "孰若歸去來，日作太倉糴。", "雖然食不充，野性還自得。", "况復二老人，年來多病厄。", "杜門奉旨甘，此意自平昔。", "端欲務寬閑，初非爲矯激。", "他日會稽歸，斯言終不食。", "人誰諒此心，交遊謾千百。", "獨幸王夫子，相知如鮑叔。", "憐我氣早衰，短髮僅覆額。", "信我非作僞，有意在作德。", "餘生能幾何，捨此將安適。", "世路多風波，談間起仇敵。", "且復倒壺觴，樂此承平日。"]'),
('159f0b02-d072-4e94-bb1b-0008dd3efff6','有感','吳芾','宋','宋诗','song-poetry','','[]','陰陽失調燮，歲事成大饑。',192,'全唐诗/poet.song.113000.json','["陰陽失調燮，歲事成大饑。", "我聞江湖間，細民競流離。", "療饑已無食，卒歲還無衣。", "民窮聚爲盜，自古誠有之。", "不謂嚴冬日，宛如暮春時。", "里閭疫癘起，災迍逮嬰兒。", "今已歲殘臘，不見雪片飛。", "中夜不能寐，念此方涕洟。", "上天復赫怒，雷聲震四維。", "驟雨相繼作，奔電仍交馳。", "連夕不能止，遠近俱憂疑。", "我心更驚愕，倍畏天之威。", "炷香拜庭下，再三爲民祈。", "願天正時令，順行無逆施。", "反雷變作雪，盈尺以爲期。", "庶幾宇宙內，物物各得宜。"]'),
('1052abc6-93f0-495b-b632-2db983feb637','和王澧州喜雨','吳芾','宋','宋诗','song-poetry','','[]','田父苦亢旱，傷心涕泗沱。',120,'全唐诗/poet.song.113000.json','["田父苦亢旱，傷心涕泗沱。", "使君憫斯民，雩禜亦何多。", "古廟舞羣巫，袂屬肩相摩。", "密雲自西郊，奈汝旱魃何。", "天官感精誠，霹靂加譴訶。", "遂協畢星好，一洗吾民痾。", "頓覺田畝間，歡然聲氣和。", "人生一飽足，寧復憂其他。", "要當及豐年，對酒仍高歌。", "祇愁偃鼠腹，未醉顔已酡。"]'),
('da8cd44a-cc93-48bb-be89-41298a8fbb76','和林大任上許守喜雨','吳芾','宋','宋诗','song-poetry','','[]','退之訟風伯，風伯罪固彰。',96,'全唐诗/poet.song.113000.json','["退之訟風伯，風伯罪固彰。", "未若旱魃甚，千里塵沙黄。", "我欲持斧鉞，尸諸古道傍。", "此志竟未就，展轉成悲凉。", "使君有妙術，在德非馨香。", "神龍不敢卧，感會趨靈場。", "霈然下甘雨，天地森開張。", "旱魃不待誅，一旦自摧藏。"]'),
('878711da-7359-4ed6-b0f1-c6a9187e1bd1','機簡堂余里人也在方外三十年未識其面乾道己丑余帥豫章乃自圓通來謁與之款語連日忘疲不謂末法中有此龍象且喜余里之有人因其歸作詩以送之','吳芾','宋','宋诗','song-poetry','','[]','我家石井旁，山水非不奇。',240,'全唐诗/poet.song.113000.json','["我家石井旁，山水非不奇。", "所恨過從少，無與同襟期。", "獨幸里巷間，高僧有二機。", "大機傳祖印，海內聲名馳。", "晚歸結草庵，杜門人莫窺。", "嗟哉已物化，不見三十朞。", "我爲銘其塔，世猶仰清規。", "小機真龍象，方爲人天師。", "宴坐一禪榻，天花零亂飛。", "聞名亦二紀，頗愧會面稀。", "忽自廬阜來，訪我江之湄。", "共說無生話，不覺日晷移。", "顧我麋鹿姿，久欲脫馽羈。", "來日寧有幾，擾擾將何爲。", "一點退閑心，不謂師已知。", "祇俟及新歲，上章力丐歸。", "師儻還故里，願言款柴扉。", "我雖無長物，亦有筇一枝。", "正欲穿林壑，相與窮幽微。", "庶幾進此道，盡洗平生非。"]'),
('0df8dcd4-3742-43c9-aec5-e5e6beffaca1','白石道者棲於洪巖以石爲糧先朝敬愛之賜予之物甚盛一日主僧持來郡齋因獲恭覽歎仰之餘偶成拙句二首  其一','吳芾','宋','宋诗','song-poetry','','[]','高僧隠青山，宴坐咀白石。',48,'全唐诗/poet.song.113000.json','["高僧隠青山，宴坐咀白石。", "不知幾何年，人猶訪遺迹。", "顧我頑鈍姿，但知能肉食。", "回首仰高風，捫心有慚色。"]'),
('3a44c6e5-79ad-48f7-93a5-91bd98d7880d','白石道者棲於洪巖以石爲糧先朝敬愛之賜予之物甚盛一日主僧持來郡齋因獲恭覽歎仰之餘偶成拙句二首  其二','吳芾','宋','宋诗','song-poetry','','[]','道人厭塵紛，萬乘挽不住。',48,'全唐诗/poet.song.113000.json','["道人厭塵紛，萬乘挽不住。", "愧我未得歸，見之愈增慕。", "奎畫儼若新，真容宛如故。", "舊隠雖寂寥，山靈尚可護。"]'),
('b6b19095-9bd7-46d9-bbe7-63dd27acb901','和黄作霖白髮','吳芾','宋','宋诗','song-poetry','','[]','白髮有公道，古來人盡然。',72,'全唐诗/poet.song.113000.json','["白髮有公道，古來人盡然。", "我初未四十，霜雪已滿顛。", "黄子我同歲，比我還更賢。", "時命未遇合，退藏非自捐。", "不須悲晚景，不須怨蒼天。", "如君豈長貧，時主方御乾。"]'),
('2d9613f2-59f3-43c0-a6c0-18689809f2ba','病中有感','吳芾','宋','宋诗','song-poetry','','[]','大暑苦河魚，久乃變成痢。',144,'全唐诗/poet.song.113000.json','["大暑苦河魚，久乃變成痢。", "輾轉枕席間，百藥幾盡試。", "神氣頓索然，不止形容悴。", "自謂與鬼隣，偶然有生意。", "方欲少開眉，赤目又爲祟。", "餘年能幾何，十日不知味。", "今雖强支持，下筯猶畏忌。", "去歲夏到官，今年又秋至。", "默數一年中，安好無一二。", "顧此衰病軀，豈堪長代匱。", "回首望故山，幸有寬閑地。", "不如歸去來，笑歌聊自慰。"]'),
('6621e362-9a8c-4af3-ab82-13e381af6e9b','和胡經仲中秋','吳芾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','平生惡晻昧，虛空光陸離。',168,'全唐诗/poet.song.113000.json','["平生惡晻昧，虛空光陸離。", "心與此月同，不容一毫疵。", "恨月有圓缺，不得常清奇。", "每欲語天公，仍斫此桂枝。", "青冥去無路，思慮空勞疲。", "明知此意苦，殷勤長我隨。", "去年西湖上，爛醉吟悲辭。", "今年巧相覓，似欲敘離思。", "西風爲披拂，浮雲無蔽虧。", "坐開百壺酒，與月論襟期。", "永結無情歡，謝此世上兒。", "吾友胡夫子，豪蕩笑墨釐。", "擬借月顔色，爲君鑒薄帷。", "告之且痛飲，行樂當及時。"]'),
('05183296-750b-4593-97f9-00fe7a29775b','和閭丘莘叟中秋玩月','吳芾','宋','宋诗','song-poetry','','[]','平生愛明月，夜坐長忘眠。',168,'全唐诗/poet.song.113000.json','["平生愛明月，夜坐長忘眠。", "每見冰輪上，兩足先跰躚。", "清賞意未足，常恐雲油然。", "老來有餘興，猶不減少年。", "今歲值秋半，一醉擬流連。", "無何山雨來，不見觚稜圓。", "尚意閏餘夕，百分棹觥船。", "居然遂此願，使我喜欲顛。", "引滿對清影，席地仍幕天。", "豈知賢伯仲，亦愛此嬋娟。", "與我嗜好同，清夜聳詩肩。", "此景已買斷，初不用一錢。", "况復有佳句，還與月爭妍。", "愧我無好語，濫繼聯珠篇。"]'),
('82fd76bb-49ba-4bbc-8408-85f10d2838b5','酒爲偷兒所竊','吳芾','宋','宋诗','song-poetry','','[]','我性苦拙疏，與世不相偶。',204,'全唐诗/poet.song.113000.json','["我性苦拙疏，與世不相偶。", "平生不如意，往往十八九。", "何以遣此懷，頼有樽中酒。", "去冬釀碧香，頗不計升斗。", "準擬與親朋，興來一聚首。", "庶幾牢落中，時時開笑口。", "偷兒何好事，一夕負之走。", "可惜數十壺，化爲一烏有。", "昔聞韋秀才，有酒盜不取。", "今我乃致寇，退省良可醜。", "無乃造物者，知我疏慵久。", "恐我醉時狂，未免自遺咎。", "用此警昏迷，意在鞭其後。", "顧我雖無知，自愛豈不厚。", "從今誓改圖，停此傳杯手。", "炷香捧茶甌，閉門清自守。", "坐對古聖賢，永作忘年友。"]'),
('07bd6975-1850-4142-af9b-82c4231f8d99','和董伯玉不向東山久韵  其一','吳芾','宋','宋诗','song-poetry','','[]','讀書想前人，往往得師友。',48,'全唐诗/poet.song.113000.json','["讀書想前人，往往得師友。", "每愛釣渭濱，頗喜耕谷口。", "夫豈與世違，甘心卧巖藪。", "升沉自有時，此意君知不。"]'),
('a02483b8-e274-47f6-8311-4f4f5be16c74','和董伯玉不向東山久韵  其二','吳芾','宋','宋诗','song-poetry','','[]','野外少過從，出門欲何向。',48,'全唐诗/poet.song.113000.json','["野外少過從，出門欲何向。", "所幸得夫君，相與樂閑曠。", "年來既倦遊，老去那病忘。", "且復對酒樽，尚須時一訪。"]'),
('66b109ed-b1e7-4095-9768-023b4f147af7','和董伯玉不向東山久韵  其三','吳芾','宋','宋诗','song-poetry','','[]','我暫出山去，常憂蕙帳空。',48,'全唐诗/poet.song.113000.json','["我暫出山去，常憂蕙帳空。", "聞君東山樂，愛君古人風。", "日暮君不來，碧雲蔽高穹。", "凌晨戒僮僕，駕言將徂東。"]'),
('ab584321-fa3d-4f13-8c8f-659ad89d69b9','和董伯玉不向東山久韵  其四','吳芾','宋','宋诗','song-poetry','','[]','塵緣嗟未斷，俗事頗相關。',48,'全唐诗/poet.song.113000.json','["塵緣嗟未斷，俗事頗相關。", "雖懷林下趣，坐失山中閑。", "時令清夜裏，夢繞雲水灣。", "寄語猿鶴伴，明朝歸故山。"]'),
('cbc1c762-ec7c-4f8e-98c3-4af510fe94c5','和董伯玉不向東山久韵  其五','吳芾','宋','宋诗','song-poetry','','[]','雲氣滿戶庭，嵐光入窗牖。',48,'全唐诗/poet.song.113000.json','["雲氣滿戶庭，嵐光入窗牖。", "是中有佳處，不出吾座右。", "邇來獨何事，未免踆踆走。", "三讀寄佳篇，臨風嗟歎久。"]'),
('8a831d23-500a-49c6-9840-0c96eeba6161','和王朝議韵','吳芾','宋','宋诗','song-poetry','','[]','晚日轉雲頭，長空收雨脚。',168,'全唐诗/poet.song.113000.json','["晚日轉雲頭，長空收雨脚。", "稍覺暑氣清，獨坐傾桑落。", "興來或醉吟，接䍦還倒著。", "胸中了無憂，事事俱脫畧。", "緬懷我友朋，蹤跡東西各。", "幾欲往從之，恨被微官縛。", "此來得夫子，臭味頗相若。", "傾蓋便論心，開懷不我却。", "新詩一何工，清思渺寥廓。", "才如李杜雄，句壓曹劉弱。", "顧我志意衰，筆力不如昨。", "明時百無用，正恐填溝壑。", "公餘幸少閑，對酒且深酌。", "拭目看諸公，衮衮登臺閣。"]'),
('5b2349c6-0886-4c22-a753-e246eb55aef1','和樓大防韵','吳芾','宋','宋诗','song-poetry','','[]','嗟余本何人，纍然居海嶠。',288,'全唐诗/poet.song.113000.json','["嗟余本何人，纍然居海嶠。", "家世業爲農，有田在巖窔。", "春到耦妻耕，寒來從母漂。", "屋角日誅茅，杖頭時荷蓧。", "迨冠知讀書，聊爲起家兆。", "有琴既無弦，有劔亦無鞘。", "僥倖厠末科，安敢綴天彯。", "但期竊斗升，活此老與少。", "豈謂暮年中，亦誤蒙收召。", "曾未著微勞，遽使登華要。", "自度老無能，共知愚不肖。", "縱未遭人非，難逃天日照。", "儻不速休官，寧免淵明笑。", "矯矯淵明賢，千載誰能紹。", "瓶粟雖無儲，風標松比峭。", "詩篇雖不多，筆力天與妙。", "顧余豈能詩，微吟蚯蚓竅。", "可笑不自量，輒欲賡高調。", "貳車真豪英，逸如千里驃。", "又如禮樂器，肅然在宗廟。", "有美頎而長，視容清且瞭。", "自應輔明時，與國增光耀。", "胡爲佐一州，從容陪坐嘯。", "乘興來湖山，欲看余把釣。"]'),
('0a9e6c0d-aa1c-4be6-b2ec-7bf329efea44','二月晦日惜春有感','吳芾','宋','宋诗','song-poetry','','[]','春半年已除，舊聞詩人語。',144,'全唐诗/poet.song.113000.json','["春半年已除，舊聞詩人語。", "老夫始信之，倍覺傷時序。", "方春未來時，屈指朝朝數。", "十分擬春來，欲與春爲主。", "那知事已乖，十日九風雨。", "縱得暫時晴，應酬紛萬緒。", "舉眼看枝頭，春事已如許。", "還憶故園花，連年成間阻。", "南園亦可人，雖美非吾土。", "願天早放歸，容我老農圃。", "月下與風前，對花歌且舞。", "日日是青春，何必唱金縷。"]'),
('8c4c395c-0153-4e67-b95f-b884dcafc935','送春有感','吳芾','宋','宋诗','song-poetry','','[]','物物俱有情，情尤鍾我輩。',264,'全唐诗/poet.song.113000.json','["物物俱有情，情尤鍾我輩。", "况復病且衰，白髮不相貸。", "今日送殘春，倍覺生感慨。", "正恐明年春，此身不復在。", "憶昔少年時，逢春便傾蓋。", "五十六年中，相親復相愛。", "春雖自天來，祇在花叢內。", "常憂地不寬，栽花容有礙。", "買山敢論錢，惟恐力不逮。", "花開即欲看，花好還須戴。", "詩必爲花吟，酒必與花對。", "醉則卧花間，豈事形骸外。", "醒復繞花行，視之過粉黛。", "從人笑我狂，我作童兒態。", "自云盡此身，與春長相會。", "人事苦相爭，花謝春亦退。", "我欲苦留春，春去不少待。", "爲春攪離腸，寢食俱忘廢。", "悲來不可禁，未免歌慷慨。", "我當保餘齡，相見猶可再。", "若或徑溘然，遂成永分背。", "願春畧躊躇，一樽容我酹。"]'),
('dcfb291a-d10a-4880-a8e2-e4f5b5495438','憂居杜門久廢筆硯茲因卜築輒有所感不免破戒作數語呈諸親友','吳芾','宋','宋诗','song-poetry','','[]','平生事幽討，性與山水便。',288,'全唐诗/poet.song.113000.json','["平生事幽討，性與山水便。", "晚歲闢三徑，頗喜得地偏。", "遠不去桑梓，近與松楸連。", "青山枕其後，流水繞其前。", "羣山更簇簇，左右相周旋。", "棟宇雖未立，氣象已足觀。", "旁人笑我拙，空囊無一錢。", "何苦欲架屋，作此煩惱緣。", "我豈不自知，老去將終焉。", "游居與寢卧，安可無數椽。", "人生七十稀，自古嘗有言。", "我今五十七，髭鬢已皤然。", "縱使此身健，前去能幾年。", "仕宦雖齟齬，亦復忝蕃宣。", "向來爲親養，猶或强著鞭。", "今既成永感，前事都棄捐。", "儻或未死滅，誓將老林泉。", "遂此卜築志，閉門日高眠。", "栽花滿我屋，種竹環我園。", "山上創一堂，湖中具一船。", "從容與親舊，取次中聖賢。", "雖無萬鍾祿，雖無二頃田。", "胸中富邱壑，眼界飽風煙。", "自足了一世，此外休問天。"]'),
('a4cf98c7-f532-4d3c-b327-d52fb868c8b5','再和','吳芾','宋','宋诗','song-poetry','','[]','嗟我椎鈍姿，處世百不便。',288,'全唐诗/poet.song.113000.json','["嗟我椎鈍姿，處世百不便。", "性獨愛山水，固非嗜好偏。", "本來山中人，家與青山連。", "仕宦三十載，塵事雖滿前。", "登臨興不減，佳處輒盤旋。", "搜奇更探勝，往往窮遊觀。", "所恨坐艱窘，苦乏買山錢。", "年來足憂患，杜門絕世緣。", "百念俱不起，此心已休焉。", "尚欲對山水，茅茨架短椽。", "非爲求安計，蓋守知足言。", "如我百無似，自視仍闕然。", "餘生亦何幸，獲覩中興年。", "賢能隨任使，熙運逢周宣。", "退量駑鈍姿，老去難加鞭。", "有如不才木，偶未溝中捐。", "寧復幾寒暑，白骨埋黄泉。", "且趁此身健，飽食仍醉眠。", "衣葛謝軒冕，杖藜守丘園。", "朝躡登山屐，暮上泛湖船。", "保真師古語，樂聖繼前賢。", "有妻能執爨，有兒能力田。", "萬事不介意，過眼如雲烟。", "無榮亦無辱，庶以全吾天。"]'),
('02b230f5-f26b-467a-9760-26385122f65a','久雨','吳芾','宋','宋诗','song-poetry','','[]','歲旦值庚午，已有旱暵憂。',144,'全唐诗/poet.song.113000.json','["歲旦值庚午，已有旱暵憂。", "甲申與甲子，仍更雨不收。", "豈惟主夏旱，還慮麥不收。", "農占吁可畏，使我生春愁。", "我今安靜退，身外百無求。", "止願年穀熟，高枕卧林丘。", "時時與親友，尊酒相獻酬。", "天意今乃爾，一飽未易謀。", "衆人憂餓死，我能獨樂不。", "念此不成寐，中夜涕泗流。", "無所用吾力，止望天賜休。", "天不絕民命，會見大有秋。"]'),
('2eecfb76-d37b-49d9-8f69-b9b8d9d45b38','送董伯玉造朝改秩','吳芾','宋','宋诗','song-poetry','','[]','之子久言別，今秋忽此來。',168,'全唐诗/poet.song.113000.json','["之子久言別，今秋忽此來。", "訪我湖山上，連月相追陪。", "和詩動盈軸，舉酒必盡罍。", "使我增眼明，頓覺忘衰頹。", "方將走山谷，乘興共尋梅。", "一笑坐花下，覆此黄金杯。", "俄然告我去，遮路挽不回。", "匆匆陳祖席，再豁懷抱開。", "自古論治道，常患無人才。", "如子雖寒素，萬口稱賢哉。", "時運偶未至，半在困塵埃。", "從今脫選調，寧復嗟淹回。", "會見日千里，騰躍如龍媒。", "願言更努力，聖主方築臺。"]'),
('dbb396fc-358e-45a6-a276-013623f6cb76','丙戌送春有作','吳芾','宋','宋诗','song-poetry','','[]','三月三十日，春去人盡惜。',264,'全唐诗/poet.song.113000.json','["三月三十日，春去人盡惜。", "我獨惜春多，欲留春不得。", "憶昨仕行都，亦屢逢春色。", "王事多鞅掌，常苦無暇隙。", "擔上看桃李，負春長歎息。", "每欲早歸田，恨不生羽翼。", "及至今得歸，亦復少歡適。", "平生無室廬，方且事工役。", "老妻病累年，年來覺轉劇。", "百事總關心，十日九不懌。", "把酒對東風，一春能幾夕。", "因念夢幻軀，處世不滿百。", "今日六十三，已是桑榆迫。", "縱使到七十，能得幾年客。", "幸春有舊好，一笑常莫逆。", "今既舍我歸，動是經年隔。", "聊復倒離樽，與春話胸臆。", "我方葺園亭，隨分足泉石。", "準擬共東君，著此幾兩屐。", "丁寧春早回，莫使常相憶。", "今宵已拚醉，坐待東方白。", "明旦各分飛，斷腸芳草碧。"]'),
('e5a8ee05-7556-4d29-bce0-85ef3f7d1136','和送春詩送陳澤民','吳芾','宋','宋诗','song-poetry','','[]','少年買青春，千金初不惜。',264,'全唐诗/poet.song.113000.json','["少年買青春，千金初不惜。", "常恐春不留，韶華難再得。", "種杏更栽桃，爲春添景色。", "對酒復當歌，與春亡間隙。", "春去或未來，日探春消息。", "及至春又歸，送春恨無翼。", "追隨九十日，無日不自適。", "胡爲把一麾，千里從吏役。", "當塗古道院，事簡非繁劇。", "宴坐對江山，亦足自怡懌。", "所歎乏游從，無與共良夕。", "陳侯有高標，鷙鳥空累百。", "落筆動成篇，端不在促迫。", "不意牢落中，乃得此佳客。", "人事苦參商，天意有順逆。", "笑言猶未竟，遽爾成乖隔。", "雖未唱陽關，別恨已填臆。", "此邦固寂寥，頗亦富水石。", "方擬出郊坰，共試登山屐。", "何事逐春歸，不念人相憶。", "春事雖已闌，殘花尚紅白。", "且復引離尊，倒此香醪碧。"]'),
('c66bed9c-5229-49e1-be8b-82eb33e2ec5f','答客難','吳芾','宋','宋诗','song-poetry','','[]','我治湖上園，占斷山水窟。',288,'全唐诗/poet.song.113000.json','["我治湖上園，占斷山水窟。", "幽事日相關，頗覺無暇逸。", "有客來相過，云欲救我失。", "謂我雖愛閒，未得居閒術。", "衆人役利名，公獨役景物。", "固與衆人殊，未免俱汩沒。", "孰若淡無營，燕坐一虛室。", "百念盡消除，百事付真率。", "物來則應之，豈可自攖拂。", "客言非不忠，我意客未悉。", "萬物仗境生，百果因花實。", "我聞洛陽城，名園渾比迹。", "至如司馬公，樸素世莫及。", "有園號獨樂，晚歲亦加葺。", "人心固不同，豈能盡如一。", "顧我病且衰，行年將七十。", "光景去不留，餘齡那可必。", "要當且逍遥，樂此桑榆日。", "寧如土木偶，終朝長兀兀。", "况有佳山水，茲焉久蟠鬰。", "地靈盡發露，一旦爲我出。", "若不一領畧，無乃太拘執。", "何妨几席間，時與相顧揖。", "擇勝把酒杯，搜奇入詩筆。"]'),
('af432832-d829-461e-90d4-4a8df6bd889f','聞同庚不幸有感','吳芾','宋','宋诗','song-poetry','','[]','我生甲申歲，同歲知幾人。',180,'全唐诗/poet.song.113000.json','["我生甲申歲，同歲知幾人。", "十中無一在，使我涕隕巾。", "嘗試屈指數，誰登要路津。", "不過五六輩，蹤跡半已陳。", "其一最先達，進爲國大臣。", "寵榮無與比，近亦以訃聞。", "顧我何爲者，本是隴畝民。", "持橐已過分，壽更近七旬。", "獨恨苦拘縛，歸志不得申。", "天復放我歸，遂此自由身。", "湖山堪寓目，風月足怡神。", "有花我共醉，有鳥助我吟。", "若不自娛樂，開口對芳辰。", "却恐泉下客，笑我浪苦辛。", "雖生亦何益，徒負百年春。"]'),
('fbbea7f2-515b-43a8-a5b8-c1ba5bb6aea4','和陳天予卜居二首  其一','吳芾','宋','宋诗','song-poetry','','[]','夫子有直氣，聲名重如山。',120,'全唐诗/poet.song.113000.json','["夫子有直氣，聲名重如山。", "上書遭放逐，去國知幾年。", "傷弓念投林，失水思潛淵。", "但期歸里社，問舍仍求田。", "迨茲是卜築，占勝郊野間。", "梅竹映左右，溪山繞後前。", "且欣輪奐美，碧瓦生青烟。", "莫歎經營苦，綠鬢成華顛。", "君雖欲退處，天豈容久閑。", "會起佐明主，四海俱晏然。"]'),
('34160435-5934-4668-90b4-64780a6bdcb7','和陳天予卜居二首  其二','吳芾','宋','宋诗','song-poetry','','[]','我亦初卜築，止有湖與山。',120,'全唐诗/poet.song.113000.json','["我亦初卜築，止有湖與山。", "一區未易就，首尾八九年。", "種竹已成林，積水已成淵。", "我始得棲息，守此桑麻田。", "羨君治第敏，不出數月間。", "落成寫胸臆，遥寄到我前。", "佳句粲珠玉，妙畫梯雲烟。", "我見爲君動，喜甚殆欲顛。", "第恨隔山嶽，無由相伴閑。", "何時一會面，尊酒共陶然。"]'),
('73f145a5-cf8b-4bbd-bbba-d3f0b185f757','湖山遣興','吳芾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我在小西湖，浩渺仍清曠。',288,'全唐诗/poet.song.113000.json','["我在小西湖，浩渺仍清曠。", "大旱未嘗枯，久雨亦不漲。", "灌溉數千頃，無欠亦無長。", "中有十里荷，花開密相傍。", "疑若水仙遊，波間張供帳。", "既列萬紅粧，復陳千彩仗。", "風細月明時，天香互飄蕩。", "縱有老畫師，丹青難髣像。", "我心如死灰，萬事俱廢忘。", "獨於此留情，曾不忘一餉。", "日日繞岸行，踏破屐幾緉。", "無以寄幽懷，誅茅聊小創。", "開窗面湖光，納此無盡藏。", "冀得日臨賦，少效陶元亮。", "用以償素心，庶不孤雅尚。", "每自謂生前，足可供酬唱。", "偶未脫世緣，一出成牽强。", "紅塵四十年，白髮三千丈。", "勞力復勞心，時時嬰拙恙。", "夢寢到湖邊，恨無縮地杖。", "迨今始歸休，掛冠老湖上。", "坐看水中天，依然涵萬象。", "近樹與遠山，倒引還彌望。", "驚湍瀉兩閘，飛瀑來千嶂。"]'),
('136ec21b-e3d9-433d-a61b-968f0dc07f56','紀夢','吳芾','宋','宋诗','song-poetry','','[]','平生好山水，至老心不移。',240,'全唐诗/poet.song.113000.json','["平生好山水，至老心不移。", "每聞有佳處，欲見唯恐遲。", "相去雖云遠，不憚脚力疲。", "縱不能得到，夜夢必見之。", "晚歲卜築地，一半在翠微。", "山水既俱勝，景物還相宜。", "旁人來覩此，已自心目怡。", "若乃夢中見，則又遠過斯。", "高山與流水，到處皆崛奇。", "其間有樓觀，金碧仍相輝。", "幽深極險怪，皆世所未窺。", "謂必神仙窟，非世所得知。", "不謂我凡骨，乃獲來遊嬉。", "恍然若驚覺，有如天上歸。", "是豈造物者，不與人相違。", "知我有雅好，特以此見貽。", "嗟我今老矣，萬事都棄遺。", "猶有山水債，未能忘夢思。", "他日或蟬蛻，百態不願爲。", "只願海山去，赴我赤松期。"]'),
('508625b4-98bf-4edf-b2f0-6a62a51243f3','機簡堂自隠靜歸爲萬年主人訪余林下相與道舊因以述懷','吳芾','宋','宋诗','song-poetry','','[]','吾鄉本仙窟，石井尤奇特。',264,'全唐诗/poet.song.113000.json','["吾鄉本仙窟，石井尤奇特。", "民物生其間，古來蓋千億。", "惟師與我家，所居共阡陌。", "少小初無殊，長乃分儒釋。", "術業雖不同，於道俱有得。", "師爲方外遊，聲價已籍籍。", "象教久衰微，頼師振業席。", "爐鞴與鉗鎚，信有彌天力。", "果續佛慧命，作大善知識。", "我雖登禁涂，無功亦無德。", "但有憂國心，徒勞竟何益。", "掛冠歸林下，面亦無慚色。", "知心獨有師，相視笑莫逆。", "每思共談玄，傾倒此胸臆。", "江浙遥相望，恨不生羽翼。", "昨朝忽惠然，得得訪泉石。", "一見雙眼明，歡喜幾折屐。", "第念我與師，彼此頭顱白。", "世路方艱難，老去合休息。", "師既歸故鄉，不應復他適。", "願言却世緣，來伴我幽寂。", "相看成二老，永爲閭里式。"]'),
('0a08cd8a-e619-4200-b4e3-bde295fc91ec','葉性之有詩紀十五夜之集因用來韵','吳芾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','人生重行樂，樂事古難全。',264,'全唐诗/poet.song.113000.json','["人生重行樂，樂事古難全。", "有如天邊月，多闕還少圓。", "又如牛女星，會合動經年。", "今夕羣賢集，定知非偶然。", "顧我老多病，要路懶著鞭。", "年年上章疏，只丐早歸田。", "頼天憐此意，得遂性所便。", "歸來小西湖，湖水清且漣。", "吾廬在其上，可濯仍可沿。", "一望興無盡，十里開紅蓮。", "風前波渺渺，雨後竹娟娟。", "到此百念滅，已是卜終焉。", "但恨乏勝侶，使我心懸懸。", "今得與公輩，共上泛湖船。", "載月娛清夜，同醉壺中天。", "雖無管弦奏，雖無羅綺筵。", "看此水與月，自足中聖賢。", "况復座上客，盡如珠玉聯。", "其間有老匠，自舊稱詩仙。", "飲散出佳句，爲我寫由拳。", "紀此一時勝，付與山水傳。", "合當風月夕，更結一笑緣。"]'),
('9a058f45-f8c2-48e6-80e1-623af42e2539','家人生朝','吳芾','宋','宋诗','song-poetry','','[]','相從四十年，於今成二老。',120,'全唐诗/poet.song.113000.json','["相從四十年，於今成二老。", "向來苦宦遊，頗恨歸不早。", "我家枕湖山，彷彿如蓬島。", "今始得歸來，方喜開懷抱。", "復值君誕辰，滿目春光好。", "幸有酒千鍾，足可共傾倒。", "要須且沈酣，莫被閑愁惱。", "我方務清虛，志不在金寶。", "亦復戒浮華，意豈在花草。", "但願享遐齡，白首長相保。"]'),
('2a0ceac8-e13a-4539-b81d-5cf36e5bfe00','生朝偶成','吳芾','宋','宋诗','song-poetry','','[]','今晨是生朝，今夕是除夜。',84,'全唐诗/poet.song.113000.json','["今晨是生朝，今夕是除夜。", "年年聚親朋，往往羅酒炙。", "而我忽抱痾，見酒輒避舍。", "一滴不沾唇，何以相慰藉。", "人生能幾許，今已迫衰謝。", "病軀復如斯，令人發悲咤。", "展轉竟無眠，作詩訴同社。"]'),
('46060bc8-9429-4c01-b94c-aff330e32b40','送津兒之官麗水','吳芾','宋','宋诗','song-poetry','','[]','憶我初仕時，不敢望高位。',288,'全唐诗/poet.song.113000.json','["憶我初仕時，不敢望高位。", "但得宰一同，便可行己志。", "實惠儻及民，死亦有生氣。", "况復著陰功，子孫將不墜。", "胡爲人憚之，百計欲求避。", "我聞事無難，辭難豈爲義。", "世路雖多艱，官途須歷試。", "是用俾吾兒，往當民社寄。", "眷言古括州，山水有佳致。", "我尚記昔年，嘗爲郡守貳。", "雖無德在人，人亦安平易。", "百里聞汝來，想見多忻慰。", "要當盡此心，有以塞其意。", "誠能使吏民，自此知懷畏。", "家家各安居，人人共稱治。", "縱或罹謗傷，固自有公議。", "有如汝所存，俯仰似無愧。", "功名餘事耳，何必成與遂。", "年來我掛冠，方得閑中味。", "無乃逼桑榆，七十仍有二。", "知復幾何時，得見汝娛侍。", "雖幸枕湖山，已闢幽棲地。", "有詩誰伴吟，有酒誰同醉。", "正欲汝相隨，俄然又相離。"]'),
('cef215de-aae6-405b-a89f-61806586e8e6','予與王瞻叔韓通一林梅卿余知默徐彥才六人皆同庚也一登政路五上禁塗其四久已物故所存者獨知默與予耳今日得報知默又已云亡念年齒至此予亦豈久於世者乎悵然有感於懷因成數語以自解','吳芾','宋','宋诗','song-poetry','','[]','同庚非不多，達者能有幾。',168,'全唐诗/poet.song.113000.json','["同庚非不多，達者能有幾。", "七十二年間，六人而已矣。", "其四迹已陳，止予二人爾。", "今朝聞訃音，其一又不起。", "嗟予獨何人，偶爾未見鬼。", "自度如許衰，寧久紅塵裏。", "念此夢幻身，誰能保終始。", "失者雖或非，得亦未爲是。", "死者固可悲，生亦不足喜。", "幸然已掛冠，萬事不到耳。", "何妨日憑欄，樂此佳山水。", "仍更日開尊，賞此新桃李。", "時時命歌童，唱箇陶真理。", "倘或未溘然，亦足娛暮齒。"]'),
('997b7485-1be8-49f5-a7dc-d39644daee8e','病中有作','吳芾','宋','宋诗','song-poetry','','[]','吾年七十五，一朝忽患瘧。',216,'全唐诗/poet.song.113000.json','["吾年七十五，一朝忽患瘧。", "仍害及老妻，對床更撼鐸。", "寒時寒如冰，熱後熱如灼。", "既去還復來，如與我有約。", "連日莫能休，盡室皆驚愕。", "飲啖一不忺，形骸頓如削。", "細思豈無因，良由賦分薄。", "本是農家子，只合事耕作。", "既已得美官，復有歸田樂。", "已是無福當，又不知慚怍。", "遂至瘧鬼憎，故意來相虐。", "作詩告天公，縱我有過惡。", "願天少垂憐，疾痛且濶畧。", "但速賜之死，莫令我知覺。", "一生纏世網，正欲解其縛。", "假使壽百年，寧免此一著。", "不如早歸藏，且免論强弱。", "我非畏死人，久已辦棺槨。"]'),
('f76937d5-214e-40db-a610-a5071ccbda13','述懷','吳芾','宋','宋诗','song-poetry','','[]','我愛白樂天，千載共稱賢。',216,'全唐诗/poet.song.113000.json','["我愛白樂天，千載共稱賢。", "行年七十五，奄忽遂溘先。", "我愛范忠宣，一代名德全。", "年齡甫至此，亦復成棄捐。", "二公雖已逝，四海至今傳。", "顧我百無事，幸及二公年。", "今夏疾疢作，已分歸黄泉。", "偶然得無事，固荷天見憐。", "但我有一語，恰欲與天言。", "有生則有死，如行者言旋。", "我是久行客，亦自應息肩。", "念人處一世，動爲世網纏。", "開口罕歡笑，觸緒多憂煎。", "縱使至百歲，終困塵俗緣。", "不如早瞑目，庶以全吾天。", "是非與寵辱，總不到我前。", "一心亦安靜，却得返自然。", "况我辦歸計，久已卜新阡。"]'),
('f51c9896-f491-4f83-bb59-497bb4538473','里有蔣生者頗志於學迫於貧困吾叔德先見而憐之贍其有無使從胡經仲學作詩勉之','吳芾','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','君不見昔日泰山孫先生，蹭蹬窮途道未行。',381,'全唐诗/poet.song.113000.json','["君不見昔日泰山孫先生，蹭蹬窮途道未行。", "讀書有志破萬卷，置錐無地可躬耕。", "高堂親老仰甘旨，未免道路長營營。", "睢陽客舍一再過，牢落誰人如姓名。", "文正范公真好士，一見賓階喜氣形。", "深知先生非乞客，金在泥沙玉在荆。", "底事窮年事奔走，厄貧廢學誠可矜。", "因留鄉校周所急，奉親爲學使有成。", "先生果不負公望，行益修兮經益明。", "十年聲名動廊廟，天下望之如日星。", "一代儒宗君試數，誰不首以先生稱。", "向使不遇文正公，亦將因循埋沒如腐螢。", "吁嗟此風寂寞久，豈是𤱶畝無如先生之才能。", "世人俗眼棄貧賤，胸中壯氣空崢嶸。", "吾家叔父特達士，汪汪偉量如滄溟。", "比隣有蔣生，所志在窮經。", "迫於饑寒故，無以贍親庭。", "不問師道己未足，聚訓青衿已十齡。", "銳志日已喪，塵事日已嬰。", "顧雖僅能供子職，而此術業何由精。", "吾叔念之爲慨然，一見自待如父兄。", "恐子坐窮竟廢棄，亟使就學趨準繩。", "况有括蒼胡夫子，傳道吾里作世程。", "執經座下子無忽，子之所須吾其應。"]'),
('eb579d5b-3430-4a52-8e85-5dc61b035e5a','續潘仲嚴秋夜歎','吳芾','宋','宋诗','song-poetry','','[]','秋夜凉，秋夜凉，碧天如水涵月光。',346,'全唐诗/poet.song.113000.json','["秋夜凉，秋夜凉，碧天如水涵月光。", "空堂耿耿不成寐，起坐拔劍歌慨慷。", "罷金樽，還獨酌，試一停杯問寥廓。", "此身此世竟如何，摇摇驚燕巢風幕。", "伊昔我生適太平，豈信中原有甲兵。", "揚鞭走馬長安市，美人如玉酒如澠。", "可惜太平留不住，一旦風塵沓回互。", "誰知年少樂遊場，翻作敵人爭戰處。", "烽火照天光奪日，殺氣騰空暗如霧。", "皇家骨肉幾千人，盡逐鑾輿沙漠去。", "回頭宮闕成一空，惟有山河在如故。", "咄咄姦諛何誤國，二十年來啟邊隙。", "邊隙已成猶自如，忍使吾民罹此極。", "哀哉吾民亦何辜，父子連年死鋒鏑。", "興言及此心膽寒，空對秋風淚橫臆。", "淚橫臆，宇宙回旋雲失色。", "我聞古亦有亂離，人道亂離今過昔。", "一人厭奔走，四海念休息。", "如何廊廟土木人，安坐恬然有肉食。", "我今願得上方斬馬劍，盡取兇徒肆誅殛。", "却總堂堂百萬師，浄掃邊塵空塞北。", "莫言草芥無奇策，願蒙天子一前席。"]'),
('48488a2d-6b82-41a5-ada2-aadf38633142','和林大任勸耕','吳芾','宋','宋诗','song-poetry','','[]','壯哉溢目還盈耳，千騎出城歌吹起。',320,'全唐诗/poet.song.113000.json','["壯哉溢目還盈耳，千騎出城歌吹起。", "野人一覩快爭先，奔走歡呼幾折趾。", "往年戎馬偶出郊，田間彌望皆荒茅。", "使君篤意勸農課，盡使惰游如所教。", "麥欲連雲桑蔽野，此心猶恐孤民社。", "要將治績邁龔黄，不但文辭超賈馬。", "編民擊壤自欣歡，盡道年來百慮寬。", "承流宣化得賢帥，湛恩霑溉何漫漫。", "不愧剖符仍受玉，善政已爲千里福。", "年豐穀賤復何憂，向也窮民今亦足。", "固知博施非屯膏，况能好善如干旄。", "賓僚倘有公輔器，寧辭解贈腰間刀。", "有客有客歌賢業，詞爛春葩光煒燁。", "一時酬唱已清新，四坐朋從更和叶。", "酒酣諧笑應云云，元白李杜疑前身。", "想當揮毫落紙時，筆端往往俱有神。", "我來觸緒未暇給，首覩明珠千百粒。", "豁然兩眼頓增明，更覺慢心無自入。", "已幸從今日往還，况復賦詩賓客間。", "只恐使君丹詔下，擢歸青瑣點朝班。"]'),
('b1fc79d6-4e2d-4f4f-8e41-f222f0d41650','又勸耕','吳芾','宋','宋诗','song-poetry','','[]','浙東十載歌豐登，去年水旱俄相乘。',176,'全唐诗/poet.song.113000.json','["浙東十載歌豐登，去年水旱俄相乘。", "吾州何幸得一熟，四野絕聞愁歎聲。", "田疇二月土膏動，樹頭布穀爭飛鳴。", "田家飽食苦無事，雨後一犁方對耕。", "敢意使君親勸率，千騎曉作田間行。", "老農感激前致語，使君不用憂西成。", "臘中昨已見三白，今日還逢甲子晴。", "年豐穀賤定可卜，倉箱會見如坻京。", "但願使君對春色，莫負花前雙玉瓶。", "人生適意未易得，况復時節遭昇平。", "要須拚與賓客醉，無使旁人笑獨醒。"]'),
('747e1666-bdcb-41c9-92e7-0968821bdf3a','喜晴','吳芾','宋','宋诗','song-poetry','','[]','我家世業本農夫，力作耕田供百需。',296,'全唐诗/poet.song.113000.json','["我家世業本農夫，力作耕田供百需。", "食無魚兮出無車，但守桑梓依枌榆。", "中更兵火田園蕪，骨肉奔迸幾爲奴。", "饑腸雷轉寒侵膚，中夜窮鬼常揶揄。", "自笑爲生亦良劬，此身何由出泥塗。", "始棄耒耜親詩書，一以經訓爲菑畬。", "弟兄相繼躡雲衢，吾鄉往往推諸吳。", "我雖有志徒區區，顧慚小技非大巫。", "向來聊出應時須，亦復接武丹陛趨。", "退視才慳思且枯，敢意濫吹東郭竽。", "自從得請歸田廬，萬事閉眼不問渠。", "豈謂割分姑孰符，一時乏使偶見除。", "此邦自昔稱膏腴，千里舊富稻與魚。", "十年九潦田無租，今歲䆉稏方滿圩。", "邦人舉首爭歡呼，謂此豐登亙古無。", "驟然一雨驚里閭，直疑平地浮江湖。", "靈祠致禱纔登輿，已見皎日升東隅。", "一方今既奠厥居，太守寧不欲自娛，便可投紱歌歸歟。"]'),
('de640b33-2d42-424c-9d88-1e27b78f69c0','癸巳歲邑中大歉三七姪捐金散穀以濟艱食因成三十韵以紀之','吳芾','宋','宋诗','song-poetry','','[]','吾家謂姪非常兒，自幼讀書嘗下帷。',384,'全唐诗/poet.song.113000.json','["吾家謂姪非常兒，自幼讀書嘗下帷。", "平居事母盡孝道，力供子職曾無違。", "辛勤農畝三十載，頓立門戶成家肥。", "耻同流俗事驕吝，好賢樂業常怡怡。", "聞人急難如在己，見義踴躍無不爲。", "造橋砌路未爲德，折券釋逋未足奇。", "究其存心用意處，尤在邑人艱食時。", "此邑山多土田少，民貧自昔難支持。", "其間歲收數百斛，已爲富室他可知。", "况復今年苦亢旱，州里遠近咸告饑。", "田疇彌望總如燎，細民未免俱流移。", "縱使人能保常産，亦復有甑無米炊。", "雖幸朝家行賑濟，正恐未能遍羣黎。", "往往傾村走山谷，荷鋤掘地尋蕨萁。", "取根爲粉雖可飽，食之既久人亦羸。", "春來必至生疫癘，死填溝壑夫何疑。", "吾姪見之軫憂惻，首議倡率輸家貲。", "既捐青蚨二百萬，猶恨糴貴難療饑。", "庾中僅存二千石，一旦傾倒盡散之。", "此心但欲濟隣里，身外浮名非所希。", "吁嗟薄俗務貪鄙，計較升斗爭刀錐。", "徒知富有可潤屋，豈慮人怨親戚離。", "有如吾姪爲此舉，吾鄉自古應亦稀。", "小惠所施固未博，風義自足洗澆漓。"]'),
('a66f9dcf-b445-4edd-9ea0-1c0f5589bbf8','和向巨源冷語  其一','吳芾','宋','宋诗','song-poetry','','[]','長空一夜飛瑞葉，正是人間苦寒月。',48,'全唐诗/poet.song.113000.json','["長空一夜飛瑞葉，正是人間苦寒月。", "靜坐遥聞修竹折，天慘雲愁風更冽。", "喜君試水烹春雪，却笑酒酣長耳熱。"]'),
('d50a0d4e-5555-4bf1-a183-a6fa54a11bbe','和向巨源冷語  其二','吳芾','宋','宋诗','song-poetry','','[]','風掃千林無一葉，獨有疏梅浸霜月。',48,'全唐诗/poet.song.113000.json','["風掃千林無一葉，獨有疏梅浸霜月。", "欲御瑶琴愁指折，試酌寒泉驚齒冽。", "最愛閉門人卧雪，不作羣兒附炎熱。"]'),
('21f68ff3-f38a-443c-bea2-b65c7d95cb14','釋奠于學和劉判官韵','吳芾','宋','宋诗','song-poetry','','[]','憶昔未冠隨親庭，采芹曾挹泮水清。',160,'全唐诗/poet.song.113000.json','["憶昔未冠隨親庭，采芹曾挹泮水清。", "仰高先聖空有志，逮壯纔能脫白丁。", "三釜及親雖可喜，抗塵不復論書史。", "舊遊恍若一夢中，十載何期兩來此。", "慚無善政及邦人，况負平生道德心。", "再瞻廟像直汗下，正恐不爲神所歆。", "朝來俎豆敬通靈，幸頼賢僚贊禮成。", "更勤佳句愧盛意，敢與前賢齊令名。", "詞場自顧非元帥，白髮星星徒滿戴。", "尚期君與振斯文，休嗟蓮幕淹三載。"]'),
('46e3a06c-fe0c-4604-acd5-18032cc94555','朱世同喜雪中得酒出佳篇相謝用韵奉酬','吳芾','宋','宋诗','song-poetry','','[]','吾子一布衣，抱道仍懷德。',288,'全唐诗/poet.song.113000.json','["吾子一布衣，抱道仍懷德。", "人雖仰其高，耐寒如松柏。", "亦復誚其介，忍窮如鐵石。", "欲耕且無田，欲住且無宅。", "借人茅舍居，破漏無遮冪。", "兀坐懶掃除，凝塵常滿席。", "文章老更成，初不事雕刻。", "間爲場屋遊，往往遭棄擲。", "進取既不諧，資身又無策。", "斆學三十年，嘗作離鄉客。", "亦豈無六親，爲親成間隔。", "亦欲求知音，無奈俗眼白。", "不知何所負，半生罹此厄。", "空讀萬卷書，不得稽古力。", "昨朝起開門，雪深平地尺。", "極目望四郊，萬里如一色。", "窮人盡皺眉，共畏寒威逼。", "亦大不能堪，君獨無戚戚。", "危然書窗下，哦詩度朝夕。", "我送一壺酒，酒面蛆浮碧。", "但可澆愁腸，豈足資歡適。", "君乃走長篇，再三敘感激。", "筆下有如君，足爲人楷式。", "勿謂道難行，自古有通塞。"]'),
('c8786085-9f72-4541-8a6a-8b2fe2359ef2','和劉判官喜雪','吳芾','宋','宋诗','song-poetry','','[]','濫把州麾奉北堂，自慚政術非龔黄。',128,'全唐诗/poet.song.113000.json','["濫把州麾奉北堂，自慚政術非龔黄。", "年豐物阜天所賜，容我養拙山水鄉。", "今朝瑞氣俄融結，散作飛花應時節。", "萬家疫癘一掃除，盡道年時無此雪。", "幕中佳士欣得公，筆端能與造化通。", "乃知冰柱有家法，寡和未饒歌郢中。", "一望瓊瑶迷四境，我復白頭臨絕頂。", "要須相與作春溫，共向尊前拚酩酊。"]'),
('dd3c7e13-0c7b-4ae6-b47c-c63562ec059e','詠海棠','吳芾','宋','宋诗','song-poetry','','[]','古人花譜名浮實，獨有海棠真第一。',192,'全唐诗/poet.song.113000.json','["古人花譜名浮實，獨有海棠真第一。", "我家千樹足奇花，晚得此花尤傑出。", "每逢春色鼎來時，爭逞新粧媚晴日。", "渾如酒暈入香腮，宛似臙脂施玉質。", "雨後妖嬈倍有情，天然富貴曾無匹。", "夜深燭下更端相，睡起還疑春思鬰。", "老來百事盡疏慵，頗喜與花時款密。", "豈知牢落向江城，驟爾乖離心若失。", "試從僻陋强搜尋，偶得一株天所乞。", "纖枝雖瘦不禁春，亦有花光相照拂。", "一時遊子覩爭先，共歎凡花難跂及。", "愈令倦客憶故園，不覺淚沾衫袖濕。"]'),
('335d8196-1487-48b7-9e35-4a089650e257','對海棠懷江朝宗','吳芾','宋','宋诗','song-poetry','','[]','我住湖山歲月賒，年年長醉海棠花。',240,'全唐诗/poet.song.113000.json','["我住湖山歲月賒，年年長醉海棠花。", "憶昨君來花未放，却言花放定相過。", "亦欲花間同一醉，肯教垂老負陽和。", "東風始動花始蕊，君已翩然到我家。", "意君爲花必少駐，那知事復成參差。", "眼底垂絲先弄影，一時浮艷亦堪誇。", "豈若神仙真態度，紅粧翠袖肩相摩。", "躊躇花下不忍別，回頭彼此奈愁何。", "匆匆直向剡溪去，急爲饑民救札瘥。", "萬人既欲全性命，賞心樂事自應那。", "待得明春來修好，因循又恐成蹉跎。", "世間萬事無不爾，不用逢春苦歎嗟。", "如君年年走塵俗，深疑天不付芳華。", "何似相隨林下住，共將爛醉爲生涯。", "不但有花供笑語，還應有句助吟哦。"]'),
('1d070769-b92b-45db-8b95-35698759fb63','王若夫謂水晶蒲萄本出其家求詩','吳芾','宋','宋诗','song-poetry','','[]','君家蒲萄天下奇，奴視百果何其卑。',320,'全唐诗/poet.song.113000.json','["君家蒲萄天下奇，奴視百果何其卑。", "種成滿架日蕃衍，清似水晶甘若飴。", "八月江南風日美，正是人家酒熟時。", "盤中珍果有如此，誰數閩中生荔枝。", "鄉人歆艷競分種，不過數年條已萎。", "胡爲君家植此樹，閲歲數十如新移。", "我聞尤物天所靳，盛衰頗與人相隨。", "君家令祖有賢行，一邑遠近人爭推。", "少雖失身事刀筆，吏之操術皆耻爲。", "處心積慮人莫及，奉法循理古亦稀。", "人與黄金目不視，身居暗室心不欺。", "退處郊坰忍窮困，只教子孫爲布衣。", "天公無以表純懿，特以此果先見貽。", "其孫努力效儒業，表表穎出非常兒。", "未壯果能立門戶，直上蟾宮攀桂枝。", "自餘雖未登上第，亦已飛鳴到禮闈。", "俱傳清白守家訓，端若此果光陸離。", "今君既取以餉我，又復琢句形聲詩。", "願君採折多醖釀，積千萬石爲酒池。", "客來自此酌不竭，永永百年供壽巵。"]'),
('1275c21e-2179-40f5-8a56-b3f8f0019341','和陳天予巖桂','吳芾','宋','宋诗','song-poetry','','[]','乞身未遂歸巖谷，滿面塵埃慵靧沐。',208,'全唐诗/poet.song.113000.json','["乞身未遂歸巖谷，滿面塵埃慵靧沐。", "鈴齋獨坐更悲秋，喜見吾人駐車轂。", "吾人別久正懷思，一旦渴心還慰沃。", "天公助我作清歡，特遣仙花薦芬馥。", "萬枝瑣碎屑黄金，幾樹陰森攢碧玉。", "天然風韵月中來，頗鄙人間桃李俗。", "秋高氣爽人意佳，衰病無悰惟我獨。", "胡爲却被此花惱，盡日簷前看不足。", "况是欣逢磊落人，遠追渭釣並巖築。", "須知天欲長吟哦，使向筠陽看修竹。", "見花落筆作長謠，燦若珠璣千百斛。", "我方觸緒不自聊，得此細看還熟讀。", "明朝人去花亦殘，只把新詩時反覆。"]'),
('d4a34658-ae9f-4468-b857-91fc0813e007','得家書報敝居紫丁香盛開悵然有感','吳芾','宋','宋诗','song-poetry','','[]','我家丁香大盈丈，天公靳惜非凡材。',224,'全唐诗/poet.song.113000.json','["我家丁香大盈丈，天公靳惜非凡材。", "去年花開香滿屋，我方局促纏悲哀。", "準擬今年必無事，儘可花下相追陪。", "何期頓與花隔絕，斗粟牽從江上來。", "前日我家寄書至，爲報堂前花正開。", "熏人已如蘭麝噴，照眼還若錦繡堆。", "狂蜂遊蝶自來往，舊成蹊處今生苔。", "主人有花不解賞，向來何以事栽培。", "置書不覺雙淚墮，人事好乖如此哉。", "嗟我行年近六十，鬢髮星星心已灰。", "縱使從今得自便，此生看花能幾回。", "况復奔馳未能已，斷蓬正滾風中埃。", "欲往一見尚不可，敢望近前持酒杯。", "須知軒冕儻來耳，不如歸去山之隈。"]'),
('056e5ef5-300f-415d-9b35-a93a68ab4368','病中秋香開因成拙句呈諸親友','吳芾','宋','宋诗','song-poetry','','[]','仙姿元自廣寒來，分得天香長馥郁。',224,'全唐诗/poet.song.113000.json','["仙姿元自廣寒來，分得天香長馥郁。", "千古風流獨占秋，一枝曾比崑山玉。", "伊余老去百念灰，已是形骸如土木。", "年年尚爲此花狂，有似淵明偏愛菊。", "坐中不可一日無，又似子猷真愛竹。", "一從秋到天宇清，頗費夢思眠不熟。", "凌晨便起探花枝，走遍荒園常僕僕。", "可怪司秋失故常，時節已深花尚伏。", "迨余抱病卧匡床，始報枝頭綴金粟。", "折來三嗅忽悽然，不覺淚珠懸兩目。", "天胡祇賦惜花心，不容享此看花福。", "今年疾疢已如斯，來歲衰頹還可卜。", "縱令牽强到花間，空使此心生不足。", "不如等是趁西風，把花一掃還空谷。"]'),
('36f4cdbf-f8b5-4bf8-9dc2-6787480b5f38','陳正卿示蛤蜊解嘲之作因次來韵','吳芾','宋','宋诗','song-poetry','','[]','夫君雅志知誰會，身在寰中心物外。',128,'全唐诗/poet.song.113000.json','["夫君雅志知誰會，身在寰中心物外。", "平生初不入州縣，一任傍人驚且怪。", "日來杖屨忽相過，爲我踏破松陰碎。", "亹亹清談頗逼人，祇將萬卷窺千載。", "得酒歡然竟不辭，右手持杯左手蟹。", "夫君真是人中豪，寧比尋常庸俗輩。", "不食蛤蜊何足羞，但能適口斯爲快。", "山肴野䔩亦自佳，豈必蒓羹與鱸膾。"]'),
('f08ce79d-9d64-458c-9a3e-78623bf1f535','復次韵','吳芾','宋','宋诗','song-poetry','','[]','老來絕意風雲會，久欲脫身塵垢外。',128,'全唐诗/poet.song.113000.json','["老來絕意風雲會，久欲脫身塵垢外。", "有時偶被世緣牽，咄咄書空常作怪。", "一麾何事到江城，却犯喧囂親瑣碎。", "簿書叢裏度光陰，倏忽已驚踰一載。", "所幸連年值有秋，頗足稻粱富魚蟹。", "正愁客少無與娛，忽得詩流真我輩。", "劇談終日坐生風，洗濯煩襟一何快。", "酒行到手君莫辭，有鼈可炰魚可膾。"]'),
('2ed4ad12-3ea2-4d3a-91fa-e0837140cee0','中秋會於照水堂竟不見月和劉判官','吳芾','宋','宋诗','song-poetry','','[]','又是人間八月秋，西風萬里殘暑收。',112,'全唐诗/poet.song.113000.json','["又是人間八月秋，西風萬里殘暑收。", "簿書汩沒日復日，忽逢佳節聊舉頭。", "開樽喜有賓僚共，準擬延月歸城樓。", "姮娥何事苦相惱，使我珠簾空上鈎。", "百年樂事能有幾，興來不憚秉燭遊。", "雖無月華助吟賞，須知節物不可留。", "樽前莫問漏聲促，且對溪山倒玉舟。"]'),
('6546e87f-7231-4da0-96dc-d4bef3f08985','九日感懷','吳芾','宋','宋诗','song-poetry','','[]','淡雲籠日秋容薄，淅淅西風度簾幕。',160,'全唐诗/poet.song.113000.json','["淡雲籠日秋容薄，淅淅西風度簾幕。", "籬邊黄菊自重陽，天外幽人正離索。", "登高那可望長安，記得當年醉豐樂。", "十千美酒一百分，脫帽狂歌恣歡謔。", "風流坐上盡英豪，醉倒不知紅日落。", "誰知陳迹轉頭空，漠漠烟塵暗京洛。", "又是秋高塞馬肥，萬國城頭悲戰角。", "對花强飲欲忘懷，萬感並生還作惡。", "河水之濁有日清，世亂當復見太平。", "只應人老鬢毛疏，愧他年少插茱萸。"]'),
('ef467f87-eeed-4725-94e6-5ec4aa064a70','臻公釋氏之秀者浮游徜徉跡接天下乃者歸卧雲山閉門不出遂命齋名曰戲鯨真得古惠師之遺趣也予喜其志因留二十韵以贈之','吳芾','宋','宋诗','song-poetry','','[]','吸盡百川還見底，頭角驚殺鱣與鮪。',320,'全唐诗/poet.song.113000.json','["吸盡百川還見底，頭角驚殺鱣與鮪。", "有時大瞋明月珠，照耀六合光不死。", "滄溟浩蕩極遊巡，鈎深匪憚窮涯涘。", "今者修鱗何側倚，豈是吞舟厭遷徙。", "祇應噴浪雲日翳，故此盤桓良有以。", "朝發夕至固無難，在在處處期一視。", "苟容肯向尋常溝，要養此身數千里。", "圉圉洋洋信自如，涵泳嚅嚌真得理。", "從容詎止濠梁游，枯槁寧同車轍裏。", "至樂元非惠子知，入舟肯作周王美。", "謫仙跨背應無由，昌黎鱠鮑誠虛擬。", "終日相望誰得似，井蛙安足爲跨跱。", "得所一任笑獱獺，旋體寧容咂螻蟻。", "清波孤虛有餘澤，何必龍津誇鋸齒。", "蕞爾鰥鮞徒唯唯，春來秋化無暫已。", "隨陽上下一何勞，風波蕩薄不自止。", "謷乎大哉天獨委，居然不與衆鱗比。", "高摩無爲還已矣，肯向人求升斗水。", "古來大魚不池活，會須終作風雷起。", "殷勤寄語任公子，收拾巨釣毋進跬。"]'),
('0d473e75-be02-49fb-9766-6133e14cb7ca','忠侍者自隠靜來既歸覓詩因述其意以贈之自可呈似簡堂老師也','吳芾','宋','宋诗','song-poetry','','[]','上人手持隠靜書，示我刊成送行句。',160,'全唐诗/poet.song.113000.json','["上人手持隠靜書，示我刊成送行句。", "飄忽如雲不可留，又歸隠靜山中去。", "自謂爲僧亦有緣，獲事老師非易遇。", "第念學道須遍參，要證此心歸宿處。", "退量天分不如人，亦復性資非穎悟。", "那能終日坐蒲團，只看水上浮杯渡。", "挑囊亦欲走諸方，趁此年齡猶未暮。", "他時參竟却歸來，伴我老師巖上住。", "上人此意似可嘉，止是出家兒調度。", "老師若也可其言，不應忘却來時路。"]'),
('6a639a01-ffc1-4a8b-82a2-c7ab1c502722','寄江朝宗','吳芾','宋','宋诗','song-poetry','','[]','藕花爽約約寒梅，開遍南枝尚未來。',64,'全唐诗/poet.song.113000.json','["藕花爽約約寒梅，開遍南枝尚未來。", "今日有人傳尺素，却云直待海棠開。", "若賞海棠猶未晚，回頭便見春風轉。", "只恐君無必信言，守到此時還更展。"]'),
('29bb3814-8f43-42b4-8ad3-3fb1bdde5f0f','呂丞相生日','吳芾','宋','宋诗','song-poetry','','[]','日躔析木當良月，辰象煌煌森羅列。',256,'全唐诗/poet.song.113000.json','["日躔析木當良月，辰象煌煌森羅列。", "忽驚昴宿下天來，果向明時作人傑。", "巍巍德望冠簪纓，魯國真儒獨擅名。", "五百年來世希有，端爲社稷萬人生。", "胸中素抱經綸術，致身便欲扶王室。", "不學磻溪坐釣磯，洗光直取虞淵日。", "艱難將相罕全才，天使我公居上台。", "公能以道佐人主，四海俱知天意回。", "蒼生政爾資霖雨，未許超然成獨處。", "佇看丹詔下嚴宸，會見敖叔三相楚。", "向來忠烈已無前，此去勳庸非偶然。", "便使呼韓朝魏闕，直須光復舊山川。", "富貴功名人所欲，世間萬事今合足。", "龍門客至亦何言，獨有長年爲公祝。", "但願我公如汾陽，二十四考中書堂。", "他年更伴赤松遊，永作漢家張子房。"]'),
('d125aafd-ae25-4377-b661-ad85885f8750','寄劉與權與幾','吳芾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','君在桃源山下居，我家相距百里餘。',312,'全唐诗/poet.song.113000.json','["君在桃源山下居，我家相距百里餘。", "神仙襟韵固異稟，草木臭味曾不殊。", "一日京華定交契，十年太學論詩書。", "斷金高義薄雲漢，濶視往往輕俗徒。", "一時儕輩稍推許，二劉之外稱三吳。", "風雲際會有早晚，一吳近已聯朝裾。", "四子徒懷經濟術，蹭蹬今猶卧海隅。", "蒼生顒顒未蘇息，天意其肯終捨諸。", "丈夫遇則行所學，未遇不應爲腐儒。", "共約天台最深處，考定古今相與俱。", "所冀激昂平日志，力取功名攄壯圖。", "誰知人事竟好乖，合并欲進還趦趄。", "空堂獨坐弔形影，仰天不覺興長吁。", "却憶長安日，相親如友于。", "一朝不會面，猶且嫌跡疏。", "何况久睽隔，動見歲月除。", "竟負雞黍約，中心當何如。", "窗間琴數弄，花下酒一壺。", "自歌還自酌，此意君知無。", "聞君南塘富山水，清虛曠絕如西湖。", "好藏頭角俟雷雨，他年同躍天之衢。"]'),
('73e8b07b-1eb9-439f-b6bd-71299805cfc0','三老圖既成久欲作詩未果因次任漕韵','吳芾','宋','宋诗','song-poetry','','[]','我久欲作三老詩，苦無佳句能解頤。',272,'全唐诗/poet.song.113000.json','["我久欲作三老詩，苦無佳句能解頤。", "抽軋鄙思成無期，有語欲吐還茹之。", "忽得新篇向此詩，恍如春草生謝池。", "明珠萬斛光陸離，璀璨不減珊瑚枝。", "壓倒元白頭欲垂，直與李杜肩相差，使我手把不停披。", "憶昨梅花吐瓊蕤，枝頭愛日仍舒遲。", "雖恨捧觴無翠眉，吾人臭味自相宜，花下清歡聊共追。", "嗟我老來意氣衰，歸心已决不復疑。", "雖來江右把一麾，但知痛飲真吾師。", "尊前况逢冰雪姿，豈容不醉負屈巵。", "二老攬轡方並馳，一氣相和如壎箎。", "百城感化熏蘭芝，不事威怒轟雷椎。", "後園探春容我隨，開懷笑語何熙熙。", "丹青寫此一段奇，未羨九老洛水湄。", "何日歸去山之崖，時命柴車載鴟夷。", "相逢徑醉莫問誰，飲盡不妨尋酒旗。"]'),
('349dae45-9480-476b-96de-634b08a0b032','耿曼老將命鄉邦見過匆遽言別復作詩送之','吳芾','宋','宋诗','song-poetry','','[]','我方退老湖山上，混跡漁樵甘放浪。',256,'全唐诗/poet.song.113000.json','["我方退老湖山上，混跡漁樵甘放浪。", "親舊凋零會面稀，與君亦復成疏曠。", "何期擁節到鄉邦，得得驅車肯迂訪。", "開門倒屣笑相迎，盡室歡忻無此况。", "湖光山色似爭輝，兩眼韶華更駘蕩。", "伸眉抵掌話中腸，正好花前倒春釀。", "胡爲欲去挽不留，忍把陽關容易唱。", "嗟乎來日苦無多，况是頻年嬰拙恙。", "興來亦欲强登臨，龍鍾未免扶藜杖。", "目前衰颯已如斯，寧保明年見花放。", "而今花下幸逢君，豈容不盡長鯨量。", "如君志尚迥不羣，治行既高心且壯。", "方當聖主急搜揚，爲斲豈應遺巧匠。", "會看唾手取功名，盡展才猷結旒纊。", "出處從今不復齊，尊酒何由更相向。", "臨期一醉尚何辭，後夜月明空悵望。"]'),
('4c6a03c1-fec5-4ec8-ac77-d7d21099c8b2','符倅同遊雁蕩賡其所和范相遊山韵','吳芾','宋','宋诗','song-poetry','','[]','高才獨立萬夫却，險語磨崖山鬼愕。',128,'全唐诗/poet.song.113000.json','["高才獨立萬夫却，險語磨崖山鬼愕。", "翕然萬口競流傳，一字誰能加筆削。", "自憐庸鈍百不聰，晚來喜見人中龍。", "更看揮翰光奪目，恍如海蜃浮青紅。", "一時聞望已難攀，相見平居養浩然。", "慷慨胸襟包海岳，軒昂高義薄雲天。", "散材不謂蒙知遇，孤迹何期遂保全。", "碌碌未能酬國士，正慚他日尉通泉。"]'),
('34331c75-f7a9-4a51-9f5f-8bd8e25f71f3','夜來同諸公泛舟湖中樂甚因更潭名作北湖乃作拙句呈諸友親聊以紀一時之勝云','吳芾','宋','宋诗','song-poetry','','[]','北山萬仞羅翠屏，下有湖水鏡面平。',320,'全唐诗/poet.song.113000.json','["北山萬仞羅翠屏，下有湖水鏡面平。", "山影靜倒千丈碧，波光冷浸一天星。", "自有此湖知幾歲，居人日日常經行。", "但知湖水鴨頭綠，誰人向此含幽情。", "我來正值秋容媚，野曠天空風物清。", "烟橫木末斜陽晚，雲散溪頭明月升。", "放舟直入波深處，水鳥窺人元不驚。", "天晴水暖魚亦樂，時見潑剌波間鳴。", "持竿舉網忽有得，滿座歡呼山嶽傾。", "水面黄花更堪愛，盈盈佇立如娉婷。", "栗玉簪頭紅一點，隨風翠带還相縈。", "興來不覺千鍾盡，衆賓皆醉無一醒。", "漁榔敲罷棹歌起，十里猶聞笑語聲。", "謫仙死後無此樂，我今此樂真難並。", "人生適意未易得，此湖從此宜知名。", "要配北山長不朽，酹酒更告山之靈。", "我欲結茅湖上住，盡使湖光入戶庭。", "枕流潄石過一世，不妨清處時濯纓。", "更釀此湖作春酒，招我四海良友朋。", "夜夜扁舟同載月，樽前吹笛到天明。"]'),
('e50dda46-8359-4a6b-8d3c-3b7302a67a4c','又和謝良輔惠箭筍','吳芾','宋','宋诗','song-poetry','','[]','卜得幽居山繞屋，四圍景物何紛鬰。',240,'全唐诗/poet.song.113000.json','["卜得幽居山繞屋，四圍景物何紛鬰。", "門前掩映百垂楊，牆裏回環萬修竹。", "風來花氣競薰人，日出鳥聲渾滿谷。", "簷前花樹盡堪攀，砌下清泉常可掬。", "暮年得此復何求，但閉柴荆理松菊。", "客至草草具杯盤，隨分烹炮薦魚肉。", "野人頗厭近腥羶，長苦春蔬餐不足。", "固知竹箭已抽萌，玉筯瓊簪破苔綠。", "非君好事遠寄將，安得今朝充我腹。", "禮勤意厚已難當，仍出長篇相付囑。", "嗟予樸拙豈知詩，祇覺珠璣照雙目。", "朝吟夕詠自忘疲，雖欲安眠眠不熟。", "起來爛煮飽枯腸，盡却韭葅并豆粥。", "人生嗜好固不同，此味定知人共欲。", "第慚作報乏瓊瑶，惡語雖多漫盈牘。"]'),
('985d47cb-26eb-4e89-991e-e713c9f71677','哭元帥宗公澤','吳芾','宋','宋诗','song-poetry','','[]','嗚呼哀哉元帥公，百世一人不易逢。',366,'全唐诗/poet.song.113000.json','["嗚呼哀哉元帥公，百世一人不易逢。", "堂堂天下想風采，心如鐵石氣如虹。", "正色立朝不顧死，半生常在謫籍中。", "真金百鍊愈不變，流水萬折歸必東。", "落落奇才世莫識，欲知勁草須疾風。", "維時中原丁禍亂，塵氛漲天天濛濛。", "衆人畏縮公獨奮，毅然來建中興功。", "雄圖一定百廢舉，復見南陽起卧龍。", "嗚呼哀哉元帥公，翩然遺世何匆匆。", "無乃天上亦乏才，故促我公還帝宮。", "公還帝宮應有用，何忍坐視四海窮。", "吁哉四海正困窮，興仆植僵頼有公。", "公雖居東都，天下日望公登庸。", "公今既云亡，天下不知何時康。", "正如濟巨川，中流失舟航。", "當今士夫豈無人，請問誰有公器業，誰如公忠良。", "公雖不爲相，德望震要荒。", "公雖非世將，威稜讋豺狼。", "偉哉奇節冠今古，我試一二聊鋪張。", "靖康元年冬，敵人正披猖。", "廟堂驚失色，愁覩赤白囊。", "公首慨然乞奉使，欲以口伐定擾攘。", "朝廷是時未知公，公之蚤志不獲償。", "憂國耿耿思自效，再乞守土河之旁。"]'),
('198e943e-5a75-4ae3-9113-0e3004240d80','釋奠禮畢偶得數語呈廣文兼簡諸生','吳芾','宋','宋诗','song-poetry','','[]','黌舍修方畢，還欣祭服成。',48,'全唐诗/poet.song.113000.json','["黌舍修方畢，還欣祭服成。", "豆籩羅庶品，環佩出新聲。", "已見威儀肅，更須經術明。", "願言俱努力，看即奮鵬程。"]'),
('979b42e5-b002-4152-97ed-6adf17f6e6de','學中諸士子惠和篇復次韵爲謝','吳芾','宋','宋诗','song-poetry','','[]','欲爲多士勸，聊綴五言成。',48,'全唐诗/poet.song.113000.json','["欲爲多士勸，聊綴五言成。", "乃得瓊瑶報，仍聞韶頀聲。", "塵襟因頓豁，老眼爲增明。", "有句能如此，何憂萬里程。"]'),
('f71470b3-96c1-41f3-916d-dfda294991cb','二月晦日勸耕石城三首  其一','吳芾','宋','宋诗','song-poetry','','[]','春曉喜新晴，聊爲野外行。',48,'全唐诗/poet.song.113000.json','["春曉喜新晴，聊爲野外行。", "殘花紅雨亂，垂柳綠絲輕。", "路入藏雲寺，山圍走馬城。", "空餘懷古意，往事與誰評。"]'),
('960c168c-77cf-43ed-bce6-809c3686bf51','二月晦日勸耕石城三首  其二','吳芾','宋','宋诗','song-poetry','','[]','經年縈吏役，今日作春遊。',48,'全唐诗/poet.song.113000.json','["經年縈吏役，今日作春遊。", "梅雪隨風去，桃花逐水流。", "已驚時節晚，還歎物華休。", "擾擾終何補，歸與老一丘。"]'),
('92e0b835-15f2-4efc-9afa-fcb437b0b7e3','二月晦日勸耕石城三首  其三','吳芾','宋','宋诗','song-poetry','','[]','兀坐無聊頼，所期懷抱開。',48,'全唐诗/poet.song.113000.json','["兀坐無聊頼，所期懷抱開。", "偶驅千騎出，還得十朋來。", "遣興非無句，消愁亦有杯。", "此心終不樂，祇是憶天台。"]'),
('33c0d6eb-385e-4d97-9c7e-e19c3223a47b','和左達功春日即事二首  其一','吳芾','宋','宋诗','song-poetry','','[]','世途雖反側，春草自萋迷。',48,'全唐诗/poet.song.113000.json','["世途雖反側，春草自萋迷。", "獨樹花仍發，何枝鵲可棲。", "犬羊終逐北，貔虎未征西。", "回首長安路，茫茫日欲低。"]'),
('23e2b09c-d8b3-4467-b146-ed7fc285db95','和左達功春日即事二首  其二','吳芾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春色還如舊，吾生愧此心。',48,'全唐诗/poet.song.113000.json','["春色還如舊，吾生愧此心。", "功名嗟晼晚，時序憶追尋。", "萬國豺狼滿，重城草木深。", "西湖真賞處，空想舊登臨。"]'),
('54b06dab-6b88-4f45-a6a0-efcbfccd2d4b','和李子儀韵四首  其一','吳芾','宋','宋诗','song-poetry','','[]','甚矣吾兒病，求安欲籲天。',48,'全唐诗/poet.song.113000.json','["甚矣吾兒病，求安欲籲天。", "憂心千里切，喜信一朝傳。", "遠勝開金穴，渾如得寶鞭。", "若非天相我，今日豈能然。"]'),
('aee62ac8-d01e-463a-b5bf-d000f3324943','和李子儀韵四首  其二','吳芾','宋','宋诗','song-poetry','','[]','我已成衰謝，傳家在此兒。',48,'全唐诗/poet.song.113000.json','["我已成衰謝，傳家在此兒。", "俄然聞感疾，至欲別呼醫。", "愁緒渾無奈，憂心祇自知。", "如今安樂也，有酒任盈巵。"]'),
('931f4e21-cf6c-48ac-91e2-19770ae0e653','和李子儀韵四首  其三','吳芾','宋','宋诗','song-poetry','','[]','我自吾兒病，匆匆去若逃。',48,'全唐诗/poet.song.113000.json','["我自吾兒病，匆匆去若逃。", "天寒霜似雪，山險石如刀。", "已得平安信，寧辭往復勞。", "故園歸去也，醉裏甚遊遨。"]'),
('72e95bdf-3873-4772-b5ee-3028d6666471','和李子儀韵四首  其四','吳芾','宋','宋诗','song-poetry','','[]','夜向茅茨宿，晨興矯首看。',48,'全唐诗/poet.song.113000.json','["夜向茅茨宿，晨興矯首看。", "遠山俱有雪，小店更多寒。", "客路雖云惡，兒曹幸已安。", "不妨頻小憩，時引一杯乾。"]'),
('62ae35b4-018b-4bda-8eed-a9a819453782','和張君美韵二首  其一','吳芾','宋','宋诗','song-poetry','','[]','志大空憂國，途窮欲問天。',48,'全唐诗/poet.song.113000.json','["志大空憂國，途窮欲問天。", "功名羞短褐，蹭蹬惜流年。", "死友留天末，生涯寄海邊。", "相逢是何日，回首重依然。"]'),
('388c8434-64ba-4278-b05c-790aac196ae2','和張君美韵二首  其二','吳芾','宋','宋诗','song-poetry','','[]','風塵環四海，烟水繞孤村。',48,'全唐诗/poet.song.113000.json','["風塵環四海，烟水繞孤村。", "涉世曾無味，思君更斷魂。", "區區何面目，苒苒且朝昏。", "此意憑誰語，悠然付酒樽。"]'),
('2556e1e4-4720-4b14-879d-636ace3acca3','和尹少稷席上韵','吳芾','宋','宋诗','song-poetry','','[]','每恨千山隔，俄欣一日同。',48,'全唐诗/poet.song.113000.json','["每恨千山隔，俄欣一日同。", "交遊非比衆，人物少如公。", "正欲扶公道，端期振此風。", "不須深退避，風雨要帡幪。"]'),
('bbaf61de-a17c-4a2c-9625-01259c896567','和王夷仲韵','吳芾','宋','宋诗','song-poetry','','[]','故人聲氣合，交契久彌深。',48,'全唐诗/poet.song.113000.json','["故人聲氣合，交契久彌深。", "不棄荒村陋，來分古木陰。", "意傾陳篤論，興發出高吟。", "豈料逃空谷，猶聞正始音。"]'),
('97941535-d9ca-47eb-96a9-bd9157315903','和鮑昌朝韵','吳芾','宋','宋诗','song-poetry','','[]','參軍長俊逸，醉裏度流年。',48,'全唐诗/poet.song.113000.json','["參軍長俊逸，醉裏度流年。", "客路三千里，狂吟幾百篇。", "貧寧貽俗笑，死不受人憐。", "別後知何處，相思夜不眠。"]'),
('bc870dd1-8c1f-4887-a8a3-875624a55578','洪景伯行縣以不得相見寄詩道意因和其韵','吳芾','宋','宋诗','song-poetry','','[]','準擬君行縣，相隨入醉鄉。',48,'全唐诗/poet.song.113000.json','["準擬君行縣，相隨入醉鄉。", "何知旋旆速，空負倚樓望。", "室邇嗟人遠，愁多覺夜長。", "後亭梅正發，誰共賞寒香。"]'),
('ecff8ec5-1fc1-4995-ab5b-9fc42f19b3e6','和范遷善見寄三首  其一','吳芾','宋','宋诗','song-poetry','','[]','蒼生未蘇息，誰與任安危。',48,'全唐诗/poet.song.113000.json','["蒼生未蘇息，誰與任安危。", "騰蹋思千里，棲遲尚一枝。", "謾勞男子志，空憶太平時。", "讀罷君詩句，愁端愈上眉。"]'),
('ec8e73c4-9fc7-41db-a95d-315553c04a5d','和范遷善見寄三首  其二','吳芾','宋','宋诗','song-poetry','','[]','平生誇志氣，妄意語功名。',48,'全唐诗/poet.song.113000.json','["平生誇志氣，妄意語功名。", "自顧心無歉，誰知道不行。", "霜蹄從暫蹶，嘉木會重榮。", "願守焚舟志，他年學孟明。"]'),
('06649e5f-4e2f-4f6f-b971-bab2bfb3fdbd','和范遷善見寄三首  其三','吳芾','宋','宋诗','song-poetry','','[]','新詩勞遠寄，深識子憐余。',48,'全唐诗/poet.song.113000.json','["新詩勞遠寄，深識子憐余。", "句法追元白，交情笑耳餘。", "飄零疏酒盞，離亂足兵車。", "何日相從去，白雲深處居。"]'),
('87fa6420-8a6a-4e78-b8d4-dfc3aea837f7','再和三首  其一','吳芾','宋','宋诗','song-poetry','','[]','不才當退縮，何况國阽危。',48,'全唐诗/poet.song.113000.json','["不才當退縮，何况國阽危。", "猶事毛錐子，欲攀丹桂枝。", "人憐無好命，自笑不知時。", "且盡一樽酒，高歌展兩眉。"]'),
('c09647cd-39dd-43f9-888e-15d9a86948ce','再和三首  其二','吳芾','宋','宋诗','song-poetry','','[]','范侯心貌古，懶與世爭名。',48,'全唐诗/poet.song.113000.json','["范侯心貌古，懶與世爭名。", "此去窮彌壯，逢時用則行。", "琴尊無限好，道義有餘榮。", "末俗方奔競，思君坐到明。"]'),
('4840b510-2d27-425f-aa69-677b3b095fc0','再和三首  其三','吳芾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','憶昔干戈裏，勞君遠訪余。',48,'全唐诗/poet.song.113000.json','["憶昔干戈裏，勞君遠訪余。", "再爲千里別，又是一年餘。", "天末空樽酒，人生念輔車。", "西湖從處好，畢竟若爲居。"]'),
('17bfb5f4-90eb-448f-bb66-4966aa6bb27d','和左達功春日見寄二首  其一','吳芾','宋','宋诗','song-poetry','','[]','良覿彌年阻，相思入夢迷。',48,'全唐诗/poet.song.113000.json','["良覿彌年阻，相思入夢迷。", "性疏仍寡合，世亂且幽棲。", "極目蒼山北，傷心白水西。", "書空愁坐處，還是暮雲低。"]'),
('ee0dbe9c-2212-43f4-b35b-80c10dc73a51','和左達功春日見寄二首  其二','吳芾','宋','宋诗','song-poetry','','[]','萬方多難日，千里故人心。',48,'全唐诗/poet.song.113000.json','["萬方多難日，千里故人心。", "酒社知誰在，詩盟阻重尋。", "鶑啼空日暮，花落又春深。", "我去慚無計，何年許見臨。"]'),
('01b8f2af-8c23-45bf-bc94-eb064792723a','和何倅與林大任韵二首  其一','吳芾','宋','宋诗','song-poetry','','[]','遲日郊原好，杖藜春色隨。',48,'全唐诗/poet.song.113000.json','["遲日郊原好，杖藜春色隨。", "此行端不惡，對酒醉何辭。", "竹外名花發，簷間野鳥窺。", "晚來登閣望，山水更幽奇。"]'),
('1923c565-07a0-4d46-8522-cdaab61a3f11','和何倅與林大任韵二首  其二','吳芾','宋','宋诗','song-poetry','','[]','久欲尋高隠，今朝信馬行。',48,'全唐诗/poet.song.113000.json','["久欲尋高隠，今朝信馬行。", "閑看花上蝶，靜聽柳間鶑。", "披豁塵襟盡，從容樂事並。", "醉來猶有恨，未許見傾城。"]'),
('1e253f4d-896f-4e52-ad79-76dbcd3a7ee3','和黄作霖董伯玉東山嶺上及崇相沙頭會飲二首  其一','吳芾','宋','宋诗','song-poetry','','[]','寒日傳佳節，聯鑣出近坰。',48,'全唐诗/poet.song.113000.json','["寒日傳佳節，聯鑣出近坰。", "預憂賓騎散，欲駐日車停。", "坐上人頹玉，燈前酒盡瓶。", "但知修故事，三日不能醒。"]'),
('ecad6a3c-b087-465b-8cc9-e6abc501220e','和黄作霖董伯玉東山嶺上及崇相沙頭會飲二首  其二','吳芾','宋','宋诗','song-poetry','','[]','杖藜尋古寺，把酒俯長流。',48,'全唐诗/poet.song.113000.json','["杖藜尋古寺，把酒俯長流。", "節物尚三月，風流似十洲。", "且看花滿眼，休說錦纏頭。", "但得陶陶醉，何妨守舊丘。"]'),
('01b9609f-509f-4058-bdc7-400f6b69090c','和良老寄別韵','吳芾','宋','宋诗','song-poetry','','[]','紫籜從師住，山幽水亦深。',48,'全唐诗/poet.song.113000.json','["紫籜從師住，山幽水亦深。", "方將償素約，一到洗塵心。", "別去遽如許，愁來且至今。", "何時能見過，容我聽潮音。"]'),
('45efae3c-7cad-42f6-a049-272275194d6d','贈恪上人','吳芾','宋','宋诗','song-poetry','','[]','上人來訪我，袖裏出佳篇。',48,'全唐诗/poet.song.113000.json','["上人來訪我，袖裏出佳篇。", "窮理通三命，知音妙七弦。", "不妨時對榻，聊與共談禪。", "一飯雖粗糲，閑中且結緣。"]'),
('c8a7950d-125d-4a82-96af-2e4a7969f615','題湯宰山居','吳芾','宋','宋诗','song-poetry','','[]','住在青山下，風流踵謝家。',48,'全唐诗/poet.song.113000.json','["住在青山下，風流踵謝家。", "屋頭千箇竹，園裏萬株花。", "亂石危通徑，清泉淺見沙。", "幽居誰得此，倦客倍興嗟。"]'),
('3fc21545-1940-4b15-a8f6-8448c0ac4254','和魯漕喜雨韵','吳芾','宋','宋诗','song-poetry','','[]','下車逢好雨，清興一何長。',48,'全唐诗/poet.song.113000.json','["下車逢好雨，清興一何長。", "暑退郊原爽，風生院落凉。", "登樓延夜月，繞樹探秋香。", "况得陪詩社，從容樂歲穰。"]'),
('bf7b9357-36be-4047-948b-9adc6b858b0c','和胡經仲即事二首  其一','吳芾','宋','宋诗','song-poetry','','[]','世事憑誰論，羈懷只自諳。',48,'全唐诗/poet.song.113000.json','["世事憑誰論，羈懷只自諳。", "風烟悲蜀魄，桑柘老吳蠶。", "晚步惜殘照，春衫怯曉嵐。", "日來鼙鼓近，牢落愈無堪。"]'),
('cbaafa17-620b-4036-a3fd-58c4ced7480b','和胡經仲即事二首  其二','吳芾','宋','宋诗','song-poetry','','[]','雨脚轉前灣，烟蓑带雨還。',48,'全唐诗/poet.song.113000.json','["雨脚轉前灣，烟蓑带雨還。", "清詩陶野色，薄酒散愁顔。", "簷鳥下苔徑，溪雲媚屋山。", "世途方擾擾，誰得似君閑。"]'),
('6239a933-794d-4235-94a7-a0323494743e','和陳宗師','吳芾','宋','宋诗','song-poetry','','[]','昨幸朋簪盍，還驚客袂分。',48,'全唐诗/poet.song.113000.json','["昨幸朋簪盍，還驚客袂分。", "相望千里月，獨占一溪雲。", "高論無由款，新詩忽得聞。", "羨君巖穴下，清坐絕埃氛。"]'),
('26157012-9d03-4266-aa1c-e38f51ff6bb3','和任漕韵','吳芾','宋','宋诗','song-poetry','','[]','耆英持漕節，一稔百無憂。',48,'全唐诗/poet.song.113000.json','["耆英持漕節，一稔百無憂。", "心計唯豐國，文移罕到州。", "澤流千嶂雨，效見萬家秋。", "早晚趨嚴召，雍容侍冕旒。"]'),
('483e7a0a-ace8-4e64-92f3-457dd407c247','病中再繼前韵書懷','吳芾','宋','宋诗','song-poetry','','[]','暌違行十日，日抱負薪憂。',48,'全唐诗/poet.song.113000.json','["暌違行十日，日抱負薪憂。", "已疾無良藥，呼醫到別州。", "不堪當劇暑，漸喜近新秋。", "痛定因追念，從生若綴旒。"]'),
('d80a052b-b208-48b0-9950-24a4d6d170a2','和任漕羅溪道中韵','吳芾','宋','宋诗','song-poetry','','[]','攬轡馳原隰，行行四牡驕。',48,'全唐诗/poet.song.113000.json','["攬轡馳原隰，行行四牡驕。", "風烟方入眼，雷雨忽連宵。", "官事終期了，征途豈憚遥。", "經旬懷笑語，嗟我亦何聊。"]'),
('121c9aeb-11ab-48f5-a947-eae43936487e','和許守小閣','吳芾','宋','宋诗','song-poetry','','[]','依山開戶牖，每到眼增明。',48,'全唐诗/poet.song.113000.json','["依山開戶牖，每到眼增明。", "爽塏偏宜性，清虛更醒酲。", "地高朝納日，江近夜聞聲。", "默坐觀身世，還應百念輕。"]'),
('ae747dd5-86c3-4515-9348-f360963d0de3','寄江朝宗','吳芾','宋','宋诗','song-poetry','','[]','自遣迎君騎，期君指日來。',48,'全唐诗/poet.song.113000.json','["自遣迎君騎，期君指日來。", "胡爲多坎坷，欲動却遲回。", "望眼凝還斷，愁懷鬰不開。", "相過須及早，莫待折寒梅。"]'),
('c73f69d3-d77e-4af7-ab47-027d5f1ea596','再和前韵贈江朝宗','吳芾','宋','宋诗','song-poetry','','[]','方欣佳客至，已寄好詩來。',48,'全唐诗/poet.song.113000.json','["方欣佳客至，已寄好詩來。", "玩味徒三歎，披尋欲百回。", "相思愁夢斷，一見笑顔開。", "便欲扶藜杖，江頭共探梅。"]'),
('3fc9d9ab-d625-4828-818e-a912d73b2df9','寄李彥平','吳芾','宋','宋诗','song-poetry','','[]','日佇高軒過，從容慰別離。',48,'全唐诗/poet.song.113000.json','["日佇高軒過，從容慰別離。", "已乖桂子約，還失菊花期。", "正爾思一面，忽然掀兩眉。", "聞君有召節，平步上丹墀。"]'),
('0714c6be-9005-4184-9148-0958df469a12','寄江朝宗','吳芾','宋','宋诗','song-poetry','','[]','相聚纔經歲，分携又許時。',48,'全唐诗/poet.song.113000.json','["相聚纔經歲，分携又許時。", "遣懷還有酒，排悶豈無詩。", "飲罷憑誰語，吟成祇自知。", "願君憐此意，命駕莫遲遲。"]'),
('4829319a-1c85-4716-b7c9-8c70dc02d413','任漕魯漕同謁史發運爲廬阜之遊恨不得偕行因成小詩二首  其一','吳芾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','不向廬山久，回頭五十秋。',48,'全唐诗/poet.song.113000.json','["不向廬山久，回頭五十秋。", "羨君聯騎去，顧我幾時遊。", "五老想如故，二林應更幽。", "無因陪後乘，神往但形留。"]'),
('e3374dca-a69e-469b-ad02-0efba63e02d6','任漕魯漕同謁史發運爲廬阜之遊恨不得偕行因成小詩二首  其二','吳芾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','歲事行將半，今年又有秋。',48,'全唐诗/poet.song.113000.json','["歲事行將半，今年又有秋。", "喜君將漕計，容我厠英遊。", "湓浦古來勝，廬山天下幽。", "此行殊不惡，莫惜少遲留。"]'),
('bc2e2633-5f7d-47fd-8652-f2738265465e','遊金山二首  其一','吳芾','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','造物分南北，長江欲盡頭。',48,'全唐诗/poet.song.113000.json','["造物分南北，長江欲盡頭。", "有山浮碧玉，亙古屹中流。", "萬頃涵空月，千帆破浪舟。", "羨他雲水客，長此占清幽。"]'),
('7c3f394d-9f8f-41aa-b9d9-41b39e251dda','遊金山二首  其二','吳芾','宋','宋诗','song-poetry','','[]','欲向南昌去，先爲北固行。',48,'全唐诗/poet.song.113000.json','["欲向南昌去，先爲北固行。", "泛舟遊寺古，倚檻看江清。", "久作市朝客，喜聞鐘磬聲。", "登臨曾未竟，已足快平生。"]'),
('808335b7-2311-422c-9a8b-294826d846e0','遊荆山寺','吳芾','宋','宋诗','song-poetry','','[]','道左逢幽寺，巍然氣象新。',48,'全唐诗/poet.song.113000.json','["道左逢幽寺，巍然氣象新。", "泉聲長繞舍，山色欲侵人。", "疏牖時穿竹，虛堂不染塵。", "老僧仍好事，不厭客來頻。"]'),
('6cada08a-9b33-4339-9f1e-92370250935d','用王龜齡韵題五柳堂','吳芾','宋','宋诗','song-poetry','','[]','久矣斯堂廢，重興頼有公。',48,'全唐诗/poet.song.113000.json','["久矣斯堂廢，重興頼有公。", "雙溪修故事，五柳振遺風。", "頓覺烟光好，端由氣味同。", "莫言官獨冷，長在綠陰中。"]'),
('cda0cb3c-d5ce-4bf4-aad5-e0497a45a055','題鑒止堂','吳芾','宋','宋诗','song-poetry','','[]','道人本無俗，肯與世浮沉。',48,'全唐诗/poet.song.113000.json','["道人本無俗，肯與世浮沉。", "坐對一池水，浄觀千古心。", "月高天宇豁，風靜夜堂深。", "此意知誰會，泠然撫素琴。"]'),
('50ebe9f2-3824-413f-a582-40feed80c73f','題先春亭','吳芾','宋','宋诗','song-poetry','','[]','洪鈞轉一氣，萬彙俱爭妍。',48,'全唐诗/poet.song.113000.json','["洪鈞轉一氣，萬彙俱爭妍。", "我不與春競，春胡推我先。", "清寒徒自苦，幽獨有誰憐。", "且與江南客，共結詩酒緣。"]'),
('ee3f2e71-7841-4b42-b420-0b33745d794f','和錢倅秋晚登帢幘亭','吳芾','宋','宋诗','song-poetry','','[]','滿目悲凉意，憑誰斷送秋。',48,'全唐诗/poet.song.113000.json','["滿目悲凉意，憑誰斷送秋。", "尋僧求竹舍，俯檻得江流。", "天末高低雁，波間出沒鷗。", "時危身局促，却羨汝無愁。"]'),
('e2b0f054-0031-491e-8a19-be4f35ecad2b','聯句題吉祥寺','吳芾','宋','宋诗','song-poetry','','[]','繫舟枯柳岸，窮勝古城陰。',48,'全唐诗/poet.song.113000.json','["繫舟枯柳岸，窮勝古城陰。", "松徑雲生屧，竹窗風滿襟。", "不妨情話好，且放酒杯深。", "杖履尋歸路，西山日未沈。"]'),
('b76b92ac-b7f3-4d0d-bd47-b57c75734adc','聞鹿生子','吳芾','宋','宋诗','song-poetry','','[]','再上歸田疏，從違未可知。',48,'全唐诗/poet.song.113000.json','["再上歸田疏，從違未可知。", "方憂鶴怨我，忽喜鹿生兒。", "六月事已驗，千年壽可期。", "我歸須汝健，正要汝相隨。"]'),
('d6b02873-939b-45d2-b3e9-611f1a69ea38','生朝有感','吳芾','宋','宋诗','song-poetry','','[]','姑溪來幾日，兩度見生朝。',48,'全唐诗/poet.song.113000.json','["姑溪來幾日，兩度見生朝。", "親舊三年隔，鄉關千里遥。", "梅還開舊樹，柳更長新條。", "只有雙蓬鬢，天公不見饒。"]'),
('360b2249-314f-4c47-8a63-6b714570c6a9','得三七姪書說湖山佳趣因以書中語成四韵','吳芾','宋','宋诗','song-poetry','','[]','今日家書到，從頭說故丘。',48,'全唐诗/poet.song.113000.json','["今日家書到，從頭說故丘。", "園林增茂密，池館愈清幽。", "嫩竹已千箇，新蓮僅萬頭。", "欲歸歸未得，長是夢中遊。"]'),
('b050c493-115d-4ade-8006-8e5f85752a67','寄四二姪','吳芾','宋','宋诗','song-poetry','','[]','書來言舊隠，湖上足烟光。',48,'全唐诗/poet.song.113000.json','["書來言舊隠，湖上足烟光。", "樹密交青蔭，花繁溢暗香。", "紅塵飛不入，綠水去何長。", "回首千山隔，歸心欲發狂。"]'),
('62781b39-ecc7-4c13-972b-834e68daff8b','泛舟歸自郡中舟中偶成  其一','吳芾','宋','宋诗','song-poetry','','[]','寒流清更淺，短棹去仍來。',48,'全唐诗/poet.song.113000.json','["寒流清更淺，短棹去仍來。", "山色侵書帙，波光映酒杯。", "龜魚應舊識，鷗鷺莫相猜。", "全勝山陰路，空船載月回。"]'),
('da23e33d-81fc-460a-8b69-8d2e423bdc2f','泛舟歸自郡中舟中偶成  其二','吳芾','宋','宋诗','song-poetry','','[]','薄日烘雲影，輕風濺浪花。',48,'全唐诗/poet.song.113000.json','["薄日烘雲影，輕風濺浪花。", "數峯排絕岸，一雁落平沙。", "冉冉寒生袖，悠悠夢到家。", "前村誰有酒，試遣小童賒。"]'),
('3f2b30e4-cc6d-4f76-aee9-3407d949f7b2','暮春感懷  其一','吳芾','宋','宋诗','song-poetry','','[]','寰區殊未定，懷抱幾時寬。',48,'全唐诗/poet.song.113000.json','["寰區殊未定，懷抱幾時寬。", "倦馬驅馳苦，窮猿叫嘯酸。", "烟深春草碧，日薄暮雲寒。", "豈料滄波上，經年駐玉鑾。"]'),
('cc4917cf-6329-45b7-ab75-9c11ebf0489b','暮春感懷  其二','吳芾','宋','宋诗','song-poetry','','[]','是處兵戈滿，誰言宇宙寬。',48,'全唐诗/poet.song.113000.json','["是處兵戈滿，誰言宇宙寬。", "戰聲驚膽破，春色入心酸。", "北狩江天遠，東巡海氣寒。", "野人元任運，愁夢亦隨鑾。"]'),
('987b8588-ffb8-47ef-a894-c252d207c0c9','暮春感懷  其三','吳芾','宋','宋诗','song-poetry','','[]','途窮朝絕爨，世亂夜忘眠。',48,'全唐诗/poet.song.113000.json','["途窮朝絕爨，世亂夜忘眠。", "遁跡幾無地，全生頼有天。", "江山春滿眼，豺虎日駢肩。", "萬事愁歌裏，看花淚迸泉。"]'),
('5a9c69d7-f89e-4b55-b7c9-2a3c814dfe6f','暮春感懷  其四','吳芾','宋','宋诗','song-poetry','','[]','憶昔平居日，春來足醉眠。',48,'全唐诗/poet.song.113000.json','["憶昔平居日，春來足醉眠。", "黄鸝鳴綠樹，白鳥印青天。", "片片花經眼，垂垂柳拂肩。", "誰知遭喪亂，空負酒如泉。"]'),
('af40d732-649a-4c2a-897a-8f8c675e1970','憶昔','吳芾','宋','宋诗','song-poetry','','[]','憶昔從吾友，茲焉事筆耕。',48,'全唐诗/poet.song.113000.json','["憶昔從吾友，茲焉事筆耕。", "螢窗秋夜短，蓮社晚風清。", "亂後成陳迹，重來愴故情。", "惟餘雲水客，依舊戲長鯨。"]'),
('87bcb33e-bf15-434f-bae7-e559de8ab6ed','與江朝宗丁彥功飲酒梅花下二首  其一','吳芾','宋','宋诗','song-poetry','','[]','挈榼西園去，花光照月華。',48,'全唐诗/poet.song.113000.json','["挈榼西園去，花光照月華。", "共看花上月，肯負月中花。", "酒與花俱白，人如月不瑕。", "且陪月花醉，何用苦思家。"]'),
('0165c868-552a-4398-8f45-0d335a48be4e','與江朝宗丁彥功飲酒梅花下二首  其二','吳芾','宋','宋诗','song-poetry','','[]','一笑未易得，今朝豈偶然。',48,'全唐诗/poet.song.113000.json','["一笑未易得，今朝豈偶然。", "故園方自適，我輩更相便。", "好月好花夜，不寒不暖天。", "莫辭拚一醉，爲我棹觥船。"]'),
('ea96f5ac-73c8-4cfb-883d-de062b1c07bd','六鶴中偶一鶴折翅','吳芾','宋','宋诗','song-poetry','','[]','皓鶴相從久，衰顔每爲開。',48,'全唐诗/poet.song.113000.json','["皓鶴相從久，衰顔每爲開。", "忽聞渠翅折，頻使我心摧。", "本意俱仙去，那知偶禍來。", "縱令醫得活，無復見毰毸。"]'),
('152293ce-a2bd-40f6-af91-159d8fa2f706','挽范丞相五首  其一','吳芾','宋','宋诗','song-poetry','','[]','蚤歲登三事，皇朝第一人。',48,'全唐诗/poet.song.113000.json','["蚤歲登三事，皇朝第一人。", "聲名塞寰宇，功業在生民。", "千載風雲會，三朝柱石臣。", "堂堂無復見，空憶吐車茵。"]'),
('15f5a568-2e8d-4e9a-9438-fdc9d493922b','挽范丞相五首  其二','吳芾','宋','宋诗','song-poetry','','[]','伊昔宣和際，公來射策初。',48,'全唐诗/poet.song.113000.json','["伊昔宣和際，公來射策初。", "獨陳天下事，不負古人書。", "宣室方前席，蒼生欲奠居。", "黑頭成奄忽，天意果何如。"]'),
('ee0ab38d-eab3-4f65-b567-fafabb3b9075','挽范丞相五首  其三','吳芾','宋','宋诗','song-poetry','','[]','貴處人臣極，居忘相位尊。',48,'全唐诗/poet.song.113000.json','["貴處人臣極，居忘相位尊。", "朝廷名德重，前輩典刑存。", "方喜生同世，俄驚弔在門。", "百年知己恨，寂寞向誰論。"]'),
('e8ad190b-b6e5-440b-8a22-2b79e3cf7a5c','挽范丞相五首  其四','吳芾','宋','宋诗','song-poetry','','[]','七十方强半，天胡不憗遺。',48,'全唐诗/poet.song.113000.json','["七十方强半，天胡不憗遺。", "致身雖宰輔，遭世已艱危。", "計策安宗社，勳庸載鼎彝。", "國讎猶未滅，豈料哲人萎。"]'),
('4ab1da3a-91b6-4b3f-9ddd-0bce3af9823c','挽范丞相五首  其五','吳芾','宋','宋诗','song-poetry','','[]','長計公生日，年年獻壽詩。',48,'全唐诗/poet.song.113000.json','["長計公生日，年年獻壽詩。", "祇今良月近，遽作九泉悲。", "世事真難料，人生信有涯。", "西風吹畫翣，心折淚空垂。"]'),
('fe1654f2-da88-44a6-bc4f-f7830dfee921','挽湯丞相三首  其一','吳芾','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','平步青雲上，逢辰亦盛哉。',48,'全唐诗/poet.song.113000.json','["平步青雲上，逢辰亦盛哉。", "十年登兩地，四見入中台。", "獨擅調元手，咸推濟世才。", "如何天不憗，一夕泰山頹。"]'),
('269f6a32-6f48-43f9-92ac-4f758c64f631','挽湯丞相三首  其二','吳芾','宋','宋诗','song-poetry','','[]','游刃有餘地，孤忠不愧天。',48,'全唐诗/poet.song.113000.json','["游刃有餘地，孤忠不愧天。", "兩朝資弼亮，四海頼陶甄。", "身後浮言洶，生前素履全。", "他時公論定，史筆看流傳。"]'),
('405b6c41-f440-464a-ba2c-de01f8f749be','挽湯丞相三首  其三','吳芾','宋','宋诗','song-poetry','','[]','吳郡爲僚日，如公最妙齡。',48,'全唐诗/poet.song.113000.json','["吳郡爲僚日，如公最妙齡。", "衆尋歸鬼錄，獨出佐王庭。", "道喪思人物，公存尚典刑。", "傷哉今亦逝，唯我老零丁。"]'),
('c64f553b-f3eb-4794-87ec-c6ad6713670b','挽鹿國强二首  其一','吳芾','宋','宋诗','song-poetry','','[]','藉甚鳴場屋，居然好弟兄。',48,'全唐诗/poet.song.113000.json','["藉甚鳴場屋，居然好弟兄。", "桂林同擢秀，梓里頓增榮。", "泮水清規在，家山雅趣成。", "投簪方自適，何處掩佳城。"]'),
('7a085a71-3d92-45da-af57-76fbb592abc5','挽鹿國强二首  其二','吳芾','宋','宋诗','song-poetry','','[]','仕宦吾鄉少，咸尊魯一儒。',48,'全唐诗/poet.song.113000.json','["仕宦吾鄉少，咸尊魯一儒。", "名雖登上第，身不到亨衢。", "耆舊今垂盡，游從孰與俱。", "百年如夢幻，回首但驚呼。"]'),
('3fb3007c-71bb-46e9-8988-bc22bd1ef567','挽謝次安二首  其一','吳芾','宋','宋诗','song-poetry','','[]','耆舊今無幾，鄉閭素所依。',48,'全唐诗/poet.song.113000.json','["耆舊今無幾，鄉閭素所依。", "官登五馬貴，年及七旬稀。", "一旦成長往，九原誰與歸。", "寒風吹畫翣，回首淚空揮。"]'),
('a0f26446-b632-4fd5-9eaa-96ba75c1fbfd','挽謝次安二首  其二','吳芾','宋','宋诗','song-poetry','','[]','場屋聲名久，簪紳譽望優。',48,'全唐诗/poet.song.113000.json','["場屋聲名久，簪紳譽望優。", "心雖馳北闕，化止被南州。", "緬想生無憾，猶憐志未酬。", "庭階有蘭玉，身後復何憂。"]'),
('bdaf77a8-93c2-4759-98f3-0448e1dbe6c2','挽林紹伊二首  其一','吳芾','宋','宋诗','song-poetry','','[]','早負經綸志，居然欲起家。',48,'全唐诗/poet.song.113000.json','["早負經綸志，居然欲起家。", "持身惟孝友，告后盡忠嘉。", "位望隆青瑣，文章在白麻。", "忍聞埋玉樹，四海共驚嗟。"]'),
('4fd941f8-916e-4919-b7bb-62df80268f09','挽林紹伊二首  其二','吳芾','宋','宋诗','song-poetry','','[]','三朝褒舊德，一代仰名儒。',48,'全唐诗/poet.song.113000.json','["三朝褒舊德，一代仰名儒。", "晚歲持荷橐，頻年剖竹符。", "共期調鼎鼐，豈謂老江湖。", "身後知無憾，傳家有鳳雛。"]'),
('ddcd4c37-e585-49a8-a8b4-77ff631aef51','挽周希舜二首  其一','吳芾','宋','宋诗','song-poetry','','[]','末俗事浮競，夫君志不移。',48,'全唐诗/poet.song.113000.json','["末俗事浮競，夫君志不移。", "至誠閭里化，純孝冕旒知。", "恬養方安命，騫騰未濟時。", "一朝埋玉樹，空使萬人悲。"]'),
('9713984a-c2eb-4db6-87fb-485febd979f7','挽周希舜二首  其二','吳芾','宋','宋诗','song-poetry','','[]','傾蓋如前日，分携忽累年。',48,'全唐诗/poet.song.113000.json','["傾蓋如前日，分携忽累年。", "我方來舊治，公已闢新阡。", "宿草荒三徑，寒雲慘一川。", "善人無復見，回首已茫然。"]'),
('7965865c-a878-408e-9428-3522923246df','挽梁尚書二首  其一','吳芾','宋','宋诗','song-poetry','','[]','早歲膺宸眷，回翔老禁塗。',48,'全唐诗/poet.song.113000.json','["早歲膺宸眷，回翔老禁塗。", "三持周版籍，九佩漢銅符。", "度量包千頃，聲名滿八區。", "誰知成奄忽，陳迹付龜趺。"]'),
('988a07c2-04d7-42fb-bba2-0c3513257aaf','挽梁尚書二首  其二','吳芾','宋','宋诗','song-poetry','','[]','身在名卿數，人懷長者風。',48,'全唐诗/poet.song.113000.json','["身在名卿數，人懷長者風。", "愛民餘善政，富國著休功。", "敭歷周中外，哀榮極始終。", "芝蘭方競秀，流慶看無窮。"]'),
('dfcc5d40-3d04-47f5-a29b-7cbd34334bb5','挽吳尚書三首  其一','吳芾','宋','宋诗','song-poetry','','[]','奇才從古少，厚德獨公全。',48,'全唐诗/poet.song.113000.json','["奇才從古少，厚德獨公全。", "克己强爲善，虛心樂薦賢。", "立朝忠貫日，謀國力回天。", "閲世雖多故，胸中固湛然。"]'),
('9fd5ac59-739e-4bda-bade-d0c1cb6a89a7','挽吳尚書三首  其二','吳芾','宋','宋诗','song-poetry','','[]','晚歲登臺省，頻年侍殿墀。',48,'全唐诗/poet.song.113000.json','["晚歲登臺省，頻年侍殿墀。", "從容如素宦，卓犖冠明時。", "人冀終圖任，天胡不憗遺。", "流芳知未艾，家有寧馨兒。"]'),
('4983cb23-b792-4f25-abdd-e584e82bcc30','挽吳尚書三首  其三','吳芾','宋','宋诗','song-poetry','','[]','公守東陽郡，於今已十年。',48,'全唐诗/poet.song.113000.json','["公守東陽郡，於今已十年。", "人猶誦遺愛，政不愧前賢。", "清議當時重，休聲後代傳。", "我來叨郡佐，悵望隔重泉。"]'),
('068fcdf8-2d58-44eb-a0bf-209952148d17','挽樓樞密二首  其一','吳芾','宋','宋诗','song-poetry','','[]','耆舊凋零久，惟公作世程。',48,'全唐诗/poet.song.113000.json','["耆舊凋零久，惟公作世程。", "險夷全一節，終始保榮名。", "二府勳庸著，三州政績成。", "十連方倚重，何遽掩佳城。"]'),
('2833031e-6370-442d-ba2b-ab48ef17b6e7','挽樓樞密二首  其二','吳芾','宋','宋诗','song-poetry','','[]','憶昔登龍日，從容接勝遊。',48,'全唐诗/poet.song.113000.json','["憶昔登龍日，從容接勝遊。", "軒窗臨綠野，尊俎俯清流。", "尚欲榮花塢，那知負釣舟。", "新阡何處是，極目暮雲愁。"]'),
('d7da674f-b4db-4216-a34b-8c44e91dceac','挽周季卿','吳芾','宋','宋诗','song-poetry','','[]','一時推曠達，末俗少如公。',48,'全唐诗/poet.song.113000.json','["一時推曠達，末俗少如公。", "自得高人趣，居多長者風。", "生涯書卷裏，世事酒杯中。", "瞑目應無憾，傳家有阿戎。"]'),
('f4688f21-60ab-4141-b43a-4c4a08c057db','挽陳兖仲','吳芾','宋','宋诗','song-poetry','','[]','慷慨平羣盜，能爲衆所難。',48,'全唐诗/poet.song.113000.json','["慷慨平羣盜，能爲衆所難。", "身雖淹武弁，志不負儒冠。", "義概千鈞重，心田萬頃寬。", "故山方適意，清夢忽驚殘。"]'),
('65f0e8cb-54f8-4f1a-a1dd-283ec7e92461','挽朱樞言','吳芾','宋','宋诗','song-poetry','','[]','持心常近厚，遇事不辭難。',48,'全唐诗/poet.song.114000.json','["持心常近厚，遇事不辭難。", "早歲曾攀桂，中年更握蘭。", "盛名馳海內，素望聳朝端。", "尚有清芬在，流光永後觀。"]'),
('0aacd44b-9a7f-4e83-9b60-8a8342efca98','挽姚君二首  其一','吳芾','宋','宋诗','song-poetry','','[]','處世心無愧，持身德有常。',48,'全唐诗/poet.song.114000.json','["處世心無愧，持身德有常。", "施恩周里閈，植福遍僧坊。", "入戶書盈室，開樽客滿堂。", "清芬傳後葉，看取桂枝芳。"]'),
('8095361a-c1e4-4f54-8fe0-fac2036b9551','挽姚君二首  其二','吳芾','宋','宋诗','song-poetry','','[]','晚得田園趣，平居樂有餘。',48,'全唐诗/poet.song.114000.json','["晚得田園趣，平居樂有餘。", "好賢聞善道，奉佛契真如。", "往事歌謠在，浮生夢幻虛。", "我慚居堊室，無路挽靈車。"]'),
('a5e0a593-362c-4dd9-83d4-1ef298ab2c96','挽胡經仲二首  其一','吳芾','宋','宋诗','song-poetry','','[]','千載微言絕，夫君妙獨傳。',48,'全唐诗/poet.song.114000.json','["千載微言絕，夫君妙獨傳。", "鈎深探閫奧，養浩塞天淵。", "憂世心雖切，歸田志頗堅。", "斯文今已矣，空復誦遺編。"]'),
('b398a59d-e063-46ba-b76b-a83fccc42281','挽胡經仲二首  其二','吳芾','宋','宋诗','song-poetry','','[]','相距一百里，相從四十年。',48,'全唐诗/poet.song.114000.json','["相距一百里，相從四十年。", "話言窮理窟，酬唱足詩篇。", "我始歸三徑，公胡掩九泉。", "無由論舊事，尚擬誌新阡。"]'),
('d9e921a5-19a9-4d52-99dd-14542180ea16','初冬山居即事十首  其一','吳芾','宋','宋诗','song-poetry','','[]','我愛山居好，冬來愜野情。',48,'全唐诗/poet.song.114000.json','["我愛山居好，冬來愜野情。", "簷前朝日暖，谷口暮雲橫。", "柏子當軒墮，蕉花傍檻生。", "自堪安樸拙，何苦慕塵纓。"]'),
('065377f4-a8ee-4ead-8fe4-7d4225375a43','初冬山居即事十首  其二','吳芾','宋','宋诗','song-poetry','','[]','屋角營書室，新成八九椽。',48,'全唐诗/poet.song.114000.json','["屋角營書室，新成八九椽。", "開林延愛日，甃石截流泉。", "山近嵐光逼，窗疏月色穿。", "寒梅何日吐，我欲醉花前。"]'),
('1994cfd4-3f6a-45ad-bfb1-6e9ddd4cc924','初冬山居即事十首  其三','吳芾','宋','宋诗','song-poetry','','[]','歸來非計失，事少得心寬。',48,'全唐诗/poet.song.114000.json','["歸來非計失，事少得心寬。", "村落年方稔，庭闈病復安。", "詩當隨景賦，酒莫放杯乾。", "插架書還在，仍容子細看。"]'),
('b3ffa5b3-cca1-43d6-9a5b-37dad7f9420d','初冬山居即事十首  其四','吳芾','宋','宋诗','song-poetry','','[]','自笑謀生拙，空驚歲月除。',48,'全唐诗/poet.song.114000.json','["自笑謀生拙，空驚歲月除。", "年衰惟藉藥，髮少不禁梳。", "盡日扃蓬戶，無人過草廬。", "晚來閑策杖，緩步當柴車。"]'),
('d46505fb-e5f5-4457-b6c2-a47449c1697c','初冬山居即事十首  其五','吳芾','宋','宋诗','song-poetry','','[]','節物隨時變，斜陽一望中。',48,'全唐诗/poet.song.114000.json','["節物隨時變，斜陽一望中。", "暮雲重疊碧，遠樹淺深紅。", "菊色滋寒露，蘆花蕩晚風。", "一樽誰與共，獨立意無窮。"]'),
('f66a3e65-5c01-499f-8f82-8aadde4d3f8d','初冬山居即事十首  其六','吳芾','宋','宋诗','song-poetry','','[]','本是山中客，胡爲作遠遊。',48,'全唐诗/poet.song.114000.json','["本是山中客，胡爲作遠遊。", "風波驚脫險，巖谷喜尋幽。", "紙帳寒來煖，僧蔬飽即休。", "百年如一夢，此外復何求。"]'),
('05855133-30f7-4a1d-ae62-c8924e9477ca','初冬山居即事十首  其七','吳芾','宋','宋诗','song-poetry','','[]','久出畏人事，端來避世紛。',48,'全唐诗/poet.song.114000.json','["久出畏人事，端來避世紛。", "山光閑裏見，樵唱靜中聞。", "茗碗晴翻雪，香爐曉吐雲。", "已應空百念，勿復歎離羣。"]'),
('92989d7c-b9a4-45ce-b6d7-6c7216334bd2','初冬山居即事十首  其八','吳芾','宋','宋诗','song-poetry','','[]','年去驚人老，坐來忘夜深。',48,'全唐诗/poet.song.114000.json','["年去驚人老，坐來忘夜深。", "未能成一事，何敢廢分陰。", "燈盡添殘燭，山寒擁敗衾。", "幸無塵俗慮，聊遂讀書心。"]'),
('6dd0d387-cd6c-48c8-b022-ef34d9e5369a','初冬山居即事十首  其九','吳芾','宋','宋诗','song-poetry','','[]','搔首寒窗下，荒山草樹迷。',48,'全唐诗/poet.song.114000.json','["搔首寒窗下，荒山草樹迷。", "鳥聲喧晝寂，雁陣接天低。", "更欲開三徑，終當把一犁。", "此心非傲世，揣分合幽棲。"]'),
('0bcd2c3d-388b-42c5-bf7e-6cdbce08f7a2','初冬山居即事十首  其一○','吳芾','宋','宋诗','song-poetry','','[]','田宅雖無幾，琴書幸有餘。',48,'全唐诗/poet.song.114000.json','["田宅雖無幾，琴書幸有餘。", "不妨臨水賦，况是背山居。", "適意真爲樂，浮名總是虛。", "前賢猶若此，我輩欲何如。"]'),
('e71b6bff-650b-4d89-93e4-bbdafade3fd7','范丞相生日','吳芾','宋','宋诗','song-poetry','','[]','天啟中興運，時生間世人。',240,'全唐诗/poet.song.114000.json','["天啟中興運，時生間世人。", "峴山鍾氣象，漢水賦精神。", "文采傾場屋，聲猷聳縉紳。", "千言醫國策，一日致君身。", "平步登黄閣，孤忠結紫宸。", "聖心資啟沃，帝業頼經綸。", "嶷嶷文章伯，堂堂社稷臣。", "威名騰異域，德澤遍斯民。", "相越風流在，歸秦意氣伸。", "有才俱擢用，靡事不咨詢。", "十載空天路，三年澤國濱。", "宵衣方念遠，皂蓋且行春。", "令下人咸喜，風行俗自淳。", "一方新沐惠，四海舊依仁。", "佇見飛還詔，重煩秉國鈞。", "從容扶日轂，慷慨掃邊塵。", "爲相賢如此，當朝信絕倫。", "邦人逢誕日，和氣滿城闉。", "貴極纔三紀，冬來始浹辰。", "願隨靈壽杖，千歲閲莊椿。"]'),
('56465084-fa6e-4116-ba26-a37e98ae34b9','和許守喜雪','吳芾','宋','宋诗','song-poetry','','[]','一夜飄瓊屑，雕鎸竟孰施。',144,'全唐诗/poet.song.114000.json','["一夜飄瓊屑，雕鎸竟孰施。", "主張歸白帝，勾引自雲師。", "飛灑斜穿牖，連翩亂入池。", "漫空疑柳絮，着樹混梅枝。", "月射光偏瑩，風迴勢轉危。", "聯華憐鶴髮，耐冷羨冰肌。", "萬壑填將合，千林壓欲垂。", "拂簷輕似粉，繞砌白於脂。", "公已齊高潔，吾方守鈍遲。", "共欣占嗣歲，仍喜沒多歧。", "政已騰民頌，忠宜結主知。", "會看頒紫詔，早晚下丹墀。"]'),
('7fe49b34-0f11-490b-b4ea-35bec2239bce','二十八日出郊勸農陳澤民見示佳作因次來韵','吳芾','宋','宋诗','song-poetry','','[]','雨多晴少恐妨農，相勸欣逢日出東。',64,'全唐诗/poet.song.114000.json','["雨多晴少恐妨農，相勸欣逢日出東。", "烟藹已收霄漢外，江山如在畫圖中。", "相看且喜頭俱白，一醉休辭頰暫紅。", "萬事要從勤苦得，莫言豐歉在天公。"]'),
('9463c9d9-871f-41fc-806d-f73776fb9a20','同日和黄繁昌韵','吳芾','宋','宋诗','song-poetry','','[]','乘閑聊復出城遊，所喜相從盡勝流。',64,'全唐诗/poet.song.114000.json','["乘閑聊復出城遊，所喜相從盡勝流。", "已對江山銷客恨，更添花卉解人愁。", "須知世事渾如夢，還念人生盡若浮。", "君若更辭花下醉，問君能有幾春秋。"]'),
('734bb039-e177-4a9a-897f-ff6ebf14aa55','同日登青山偶作','吳芾','宋','宋诗','song-poetry','','[]','公餘不憚陟崔嵬，三到謝公池上來。',64,'全唐诗/poet.song.114000.json','["公餘不憚陟崔嵬，三到謝公池上來。", "下視衆山俱培塿，俯窺塵世盡氛埃。", "松生清籟醒人耳，花褪殘紅墮酒杯。", "喜與諸君同勝賞，莫辭一醉少徘徊。"]'),
('ce8ce080-d788-4e7a-a847-d5fa9e30b5c8','和李相之勸農','吳芾','宋','宋诗','song-poetry','','[]','憂民無語對東君，一雨霶𩃱慰望雲。',64,'全唐诗/poet.song.114000.json','["憂民無語對東君，一雨霶𩃱慰望雲。", "宣化但期施實惠，勸耕寧復事虛文。", "已看野老扶藜去，應有幽人植杖耘。", "千里農桑知帝力，自慚濫把竹符分。"]'),
('8d9225e1-963d-416f-a0bd-b7a219c4dbef','送任漕','吳芾','宋','宋诗','song-poetry','','[]','聖主方將大有爲，有如二老盍來歸。',64,'全唐诗/poet.song.114000.json','["聖主方將大有爲，有如二老盍來歸。", "不應飛輓留江表，且使澄清向日畿。", "四海英豪從古少，一時耆舊似君稀。", "相將穩入修門去，直上雲霄拱太微。"]'),
('b5a64050-211c-4d43-a425-fd6dc65ba5ef','送魯漕四首  其一','吳芾','宋','宋诗','song-poetry','','[]','高人本愛水雲鄉，攬轡登車未免忙。',64,'全唐诗/poet.song.114000.json','["高人本愛水雲鄉，攬轡登車未免忙。", "連歲已陪徐孺子，今年更訪賀知章。", "近家上冢情何限，尋壑經丘興更長。", "祇恐便歸清禁去，稽山未必得徜徉。"]'),
('bce869fc-f252-4621-89b5-493caabb2709','送魯漕四首  其二','吳芾','宋','宋诗','song-poetry','','[]','聚散無期自古來，偶然相值且徘徊。',64,'全唐诗/poet.song.114000.json','["聚散無期自古來，偶然相值且徘徊。", "百年能得幾回醉，三世肯辭平等杯。", "晚歲誰如君激烈，高情應念我衰頹。", "亦知分袂無多日，懷抱何妨更盡開。"]'),
('082190e7-e586-4d36-951d-c1261942bc6e','送魯漕四首  其三','吳芾','宋','宋诗','song-poetry','','[]','自別頻驚歲月遷，又來此地奉周旋。',64,'全唐诗/poet.song.114000.json','["自別頻驚歲月遷，又來此地奉周旋。", "雖欣同會成三老，却恨相從未一年。", "君已促裝行詣闕，我方投紱欲歸田。", "須知出處從今異，一醉休辭拍酒船。"]'),
('3310f759-7542-43d8-865e-4ce698d9df30','送魯漕四首  其四','吳芾','宋','宋诗','song-poetry','','[]','不貪燕寢日凝香，祇要歸休深處藏。',64,'全唐诗/poet.song.114000.json','["不貪燕寢日凝香，祇要歸休深處藏。", "大火已流秋尚暑，商飈微動夜初凉。", "身縻官事老不止，心著家山夢更長。", "頗羨浙東新使者，如今衣錦更還鄉。"]'),
('2d41c9f5-af36-4e4a-8e3a-bb9c97a60980','送黄仲秉舍人赴湖南漕','吳芾','宋','宋诗','song-poetry','','[]','巧僞由來苦亂真，獨持正論竦簪紳。',64,'全唐诗/poet.song.114000.json','["巧僞由來苦亂真，獨持正論竦簪紳。", "身心贏得爲君子，學術寧將殺世人。", "已向廷中伸此道，更來湖外濟斯民。", "願言恢作經綸業，會有功名遇合辰。"]'),
('8d750fab-86fd-4bbc-8299-729ed8501d25','魯漕按行諸郡以所得江山之秀形之篇章燦然成軸出以相示卒卒未能盡和且作數語以報來辱','吳芾','宋','宋诗','song-poetry','','[]','十分秋色滿江天，準擬遊觀快目前。',64,'全唐诗/poet.song.114000.json','["十分秋色滿江天，準擬遊觀快目前。", "愧我把麾成束縛，羨君攬轡得盤旋。", "平時已富瓊瑶什，行處還多錦繡篇。", "何計獲陪軺傳去，肯將吟筆寫山川。"]'),
('c9571261-3689-41b6-9567-6ef4c6e0a770','前日小詩併呈魯漕','吳芾','宋','宋诗','song-poetry','','[]','華髮蕭蕭我與君，未能免俗尚馳奔。',64,'全唐诗/poet.song.114000.json','["華髮蕭蕭我與君，未能免俗尚馳奔。", "相看已是成三老，得暇何妨共一樽。", "我欲丐閑歸故里，君行趣召入修門。", "亦知聚首無多日，且把交情更細論。"]'),
('b1e1b816-2ce9-4543-8943-8d521eda7c67','和魯漕節中見示','吳芾','宋','宋诗','song-poetry','','[]','天時又是一番新，顧我猶爲逆旅人。',64,'全唐诗/poet.song.114000.json','["天時又是一番新，顧我猶爲逆旅人。", "詩酒情懷聊自遣，山林志願幾時伸。", "羨君職事有餘暇，贈我篇章不厭頻。", "一讀灑然忘鄙吝，渾勝笑語得相親。"]'),
('f94aab49-35b3-4efd-aa93-7dae5709dd93','陳時中法臺得郡而歸喜而成詩','吳芾','宋','宋诗','song-poetry','','[]','去歲秋風話別離，今秋俄報有歸期。',64,'全唐诗/poet.song.114000.json','["去歲秋風話別離，今秋俄報有歸期。", "自應冠豸登三院，何遽憑熊把一麾。", "治行佇爲千里最，才猷已是九重知。", "莫辭小憩留仙隠，伴我花前倒玉巵。"]'),
('989d58e3-d89a-4e82-9451-830f447040b6','龔漕見示遊山唱和詩卷用其首章和二篇  其一','吳芾','宋','宋诗','song-poetry','','[]','說著登臨喜欲顛，正慚拘俗未能前。',64,'全唐诗/poet.song.114000.json','["說著登臨喜欲顛，正慚拘俗未能前。", "羨君領客同遊去，使我聞風亦豁然。", "已歎高懷能放曠，還欣佳句更清圓。", "如今便蠟尋山屐，夙駕何須吉日涓。"]'),
('faa8022d-61a4-4912-a849-7932b8d8b093','龔漕見示遊山唱和詩卷用其首章和二篇  其二','吳芾','宋','宋诗','song-poetry','','[]','塵埃終日滿華顛，忽見新詩墮我前。',64,'全唐诗/poet.song.114000.json','["塵埃終日滿華顛，忽見新詩墮我前。", "溢目衆篇雖傑出，驚人逸思獨飄然。", "秀如松檜枝枝老，好似珠璣顆顆圓。", "自此得聞清廟瑟，懶從灘上聽師涓。"]'),
('8058c594-907b-4305-b0aa-4bc6384b86f2','和任漕開宴值雨','吳芾','宋','宋诗','song-poetry','','[]','正是千花萬卉開，一時景物亦佳哉。',64,'全唐诗/poet.song.114000.json','["正是千花萬卉開，一時景物亦佳哉。", "良辰已幸陪龍節，盛宴仍容飫豹胎。", "雖喜風光環几席，其如烟雨暗池臺。", "明朝天宇應澄霽，尚擬尋芳一再來。"]'),
('55447442-31df-49da-a77b-50bc4fa66d77','加恩進秩有作','吳芾','宋','宋诗','song-poetry','','[]','慶典施恩及萬方，老臣遭遇亦非常。',64,'全唐诗/poet.song.114000.json','["慶典施恩及萬方，老臣遭遇亦非常。", "頓加多邑慚非稱，倍進崇階懼莫當。", "自念生來無此望，却憂福過有餘殃。", "病軀莫效循牆避，且上天庭控免章。"]'),
('bca413ad-6785-45fa-a5db-7cb1efb934af','寄魯漕','吳芾','宋','宋诗','song-poetry','','[]','四海耆英世共知，七旬强健似公稀。',64,'全唐诗/poet.song.114000.json','["四海耆英世共知，七旬强健似公稀。", "使星姑暫淹黄髮，卿月還須近紫微。", "門外塤箎方合奏，庭前蘭玉更相輝。", "人生樂事誰能及，莫惜通宵壽斚飛。"]'),
('9745d00e-3425-486d-b510-c7c235b95864','送魏簽','吳芾','宋','宋诗','song-poetry','','[]','平分冬氣恰經旬，天應新陽産異人。',64,'全唐诗/poet.song.114000.json','["平分冬氣恰經旬，天應新陽産異人。", "家世舊來推碩學，胸襟自許作良臣。", "不應蓮幕淹留久，會見楓宸拔擢新。", "但願朱顔長不老，穩看他日畫麒麟。"]'),
('fea7efe6-aa10-492f-86bb-f1cb8cb531cf','贈蕭守  其一','吳芾','宋','宋诗','song-poetry','','[]','一代簪紳仰老成，天生賢德佐昇平。',64,'全唐诗/poet.song.114000.json','["一代簪紳仰老成，天生賢德佐昇平。", "慶傳八葉源流遠，氣稟三秋表裏清。", "蚤戴豸冠居憲府，旋持荷橐直承明。", "祇今名德如公少，寧久淹留海上城。"]'),
('d5d1b170-b747-4037-89a8-a69a31cdfe69','贈蕭守  其二','吳芾','宋','宋诗','song-poetry','','[]','天界仁賢鎮一方，坐令歉歲作豐穰。',64,'全唐诗/poet.song.114000.json','["天界仁賢鎮一方，坐令歉歲作豐穰。", "盡鋤海上鯨鯢跡，頓肅庭中雁鶩行。", "萬室共知歌邵杜，千年重喜見龔黄。", "修齡已逐陰功長，不待邦人獻壽觴。"]'),
('73c6e8f4-866f-40a3-823d-003d25c9b33d','贈許守','吳芾','宋','宋诗','song-poetry','','[]','天賦奇才屬意深，一時人望冠儒林。',64,'全唐诗/poet.song.114000.json','["天賦奇才屬意深，一時人望冠儒林。", "文章世有中和氣，政術家傳清白箴。", "屏翰豈能淹大手，江山聊助發高吟。", "寒梅已有調羹意，壽斚何妨且滿斟。"]'),
('e5d1a889-9d61-4a92-8ef6-d5fc6a491e5f','送謝子肅之官','吳芾','宋','宋诗','song-poetry','','[]','吾鄉人物苦彫零，頼子傳家有典刑。',64,'全唐诗/poet.song.114000.json','["吾鄉人物苦彫零，頼子傳家有典刑。", "仕宦方期行古道，姓名早已達天庭。", "致君事業須先辦，涉世風霜要飽經。", "終不負丞寧久屈，會看感遇際千齡。"]'),
('63f78d24-8dfd-467b-aef6-a02336025533','送江朝宗之官','吳芾','宋','宋诗','song-poetry','','[]','芳草連天柳拂堤，憐君俯首去勾稽。',64,'全唐诗/poet.song.114000.json','["芳草連天柳拂堤，憐君俯首去勾稽。", "賦成梁苑方同樂，唱徹陽關遽解携。", "指日鵾鵬當直上，待時鸞鳳且卑棲。", "若逢訪戴人乘興，莫惜相隨泛剡溪。"]'),
('4878b20d-dca4-46d0-9ea3-ef54436bf4d8','送王若夫造朝','吳芾','宋','宋诗','song-poetry','','[]','要路如公今著鞭，况逢聖主正需賢。',64,'全唐诗/poet.song.114000.json','["要路如公今著鞭，况逢聖主正需賢。", "長貧豈謂連三世，不調那知又十年。", "道在未應終困躓，時來看取即騰騫。", "此行會有知音者，送上通津歲九遷。"]'),
('9705d5b8-6d2f-4d4b-abe6-8a8c8a6e2af2','送孟世功','吳芾','宋','宋诗','song-poetry','','[]','男兒三十未成名，肯但區區事筆耕。',64,'全唐诗/poet.song.114000.json','["男兒三十未成名，肯但區區事筆耕。", "王粲平時希負鼎，賈生今日請長纓。", "漫漫海內妖氛暗，策策腰間老劍鳴。", "會使蒼生重奠枕，北山休顧小猿驚。"]'),
('1cee3a19-ae82-498d-b0cc-8a7021de8441','潘公舍人義榮當世第一流人也僕頃得金華私竊自喜將獲從公之遊洎至而公已云亡至今以爲恨金元鼎出公往還詩帖因即公韵和數句於後姑以少見平生慕用之意云','吳芾','宋','宋诗','song-poetry','','[]','一代名流世許誰，獨公皎皎著明暉。',64,'全唐诗/poet.song.114000.json','["一代名流世許誰，獨公皎皎著明暉。", "少攄妙藴聊持橐，欲振孤風便拂衣。", "愧我仰高乖晤對，羨君請益探玄微。", "今朝刮眼看遺墨，更覺平生萬事非。"]'),
('eafbaa5f-bd29-4572-9037-303471a1573c','送張甥歸上饒','吳芾','宋','宋诗','song-poetry','','[]','悲惱情懷未易除，相逢猶未免嗟吁。',64,'全唐诗/poet.song.114000.json','["悲惱情懷未易除，相逢猶未免嗟吁。", "暫停絲竹雖云冷，只對江山亦足娛。", "我得退閑爲上策，汝能勤苦是亨衢。", "欲行千里非難事，須作人間汗血駒。"]'),
('d20a16d3-710e-444c-8952-c513eb1dfc2d','與鹿郎中','吳芾','宋','宋诗','song-poetry','','[]','思到高人見一堂，經年魂夢鎮飛揚。',64,'全唐诗/poet.song.114000.json','["思到高人見一堂，經年魂夢鎮飛揚。", "抱疴已恨身無力，拗俗還疑路有妨。", "聊寄一樽牽酒興，更憑五字惱詩腸。", "巡簷應索梅花笑，無計從君醉幾場。"]'),
('12c7179a-00fd-4904-aa91-e1c3b2b71bdc','王百洪遭旱經火之後赴官荆南作詩勉之','吳芾','宋','宋诗','song-poetry','','[]','莫將外物撓胸中，旱魃從他更祝融。',64,'全唐诗/poet.song.114000.json','["莫將外物撓胸中，旱魃從他更祝融。", "道業不應緣火盡，生涯會復值年豐。", "事經盤錯才方見，詩到羈窮句始工。", "休歎徒勞淹幕府，要君努力振家風。"]'),
('36757ab1-92d6-47d4-8ef1-865da23e6183','李倉子長按行偶成四韵奉呈  其一','吳芾','宋','宋诗','song-poetry','','[]','强把州麾楚水東，星軺臨按偶相逢。',64,'全唐诗/poet.song.114000.json','["强把州麾楚水東，星軺臨按偶相逢。", "平居已是同閭里，歲晚還來託部封。", "千里江山多契闊，一樽風月且從容。", "我將投紱林泉去，拭目公歸侍九重。"]'),
('1cc62530-dd27-4b2c-a92e-1959890584a3','李倉子長按行偶成四韵奉呈  其二','吳芾','宋','宋诗','song-poetry','','[]','長年蹤迹歎西東，此地那知得會逢。',64,'全唐诗/poet.song.114000.json','["長年蹤迹歎西東，此地那知得會逢。", "老去我將歸梓里，時來君合拜芝封。", "故交零落添新冢，晚景衰頹減舊容。", "今日尊前休惜醉，回頭千里暮山重。"]'),
('2e553b52-b121-4da7-9eb8-779c9fc6afd0','遠眺','吳芾','宋','宋诗','song-poetry','','[]','萬壑千巖百尺樓，地形高壓浙東州。',64,'全唐诗/poet.song.114000.json','["萬壑千巖百尺樓，地形高壓浙東州。", "旁窺照水烟波闊，四顧滄溟雪浪浮。", "遠望尚賒秦轍迹，懷人還想晉風流。", "憑欄已足消塵慮，何必三山汗漫遊。"]'),
('1ce6a07c-c8be-4a6c-9122-03c5488db6f4','和王龜齡待制貢院落成二首  其一','吳芾','宋','宋诗','song-poetry','','[]','扁舟猶記拂洲蘋，轉眼年華幾度新。',64,'全唐诗/poet.song.114000.json','["扁舟猶記拂洲蘋，轉眼年華幾度新。", "愧我今成雙白鬢，喜君來駕兩朱輪。", "一時令下從如水，千里威行敬若神。", "擬訪舊遊觀盛事，一官何苦絆吾身。"]'),
('c3695c24-ac43-4392-aca2-58f660e5a2cb','和王龜齡待制貢院落成二首  其二','吳芾','宋','宋诗','song-poetry','','[]','主盟湖學屬何人，頼有公來爲作新。',64,'全唐诗/poet.song.114000.json','["主盟湖學屬何人，頼有公來爲作新。", "士俗似聞衰也久，文場今見美哉輪。", "挈還舊觀人爭覩，賦就新詩筆有神。", "苕霅儒風從此振，文翁端恐是前身。"]'),
('0b4c32be-f701-4291-9294-3cc24a96e616','貢院落成郡庠諸生畢集因作詩以勉之','吳芾','宋','宋诗','song-poetry','','[]','多士如林古豫章，不應較藝寓僧房。',64,'全唐诗/poet.song.114000.json','["多士如林古豫章，不應較藝寓僧房。", "一朝盡闢荆榛地，萬礎俄新翰墨場。", "文筆要同孤塔聳，詞源宜與兩湖長。", "會看從此飛鳴去，九萬鵬程未易量。"]'),
('91c36594-9d2c-423d-90d3-aa0caf189c58','和池州陳教授韵二首  其一','吳芾','宋','宋诗','song-poetry','','[]','人物今誰似此郎，合居嚴近贊垂裳。',64,'全唐诗/poet.song.114000.json','["人物今誰似此郎，合居嚴近贊垂裳。", "未將事業先諸老，且把文章變一方。", "今日杏壇風似魯，向來鐵硯志如桑。", "會看奮迅爲時用，展盡胸中計策長。"]'),
('a401559b-e853-4608-b4b0-f2a7df9a162b','和池州陳教授韵二首  其二','吳芾','宋','宋诗','song-poetry','','[]','平時野性愛吟詩，一字長慚未得師。',64,'全唐诗/poet.song.114000.json','["平時野性愛吟詩，一字長慚未得師。", "妙句既容窺格律，良辰更喜覿光儀。", "絳帷暫且留三楚，丹陛行將命一夔。", "莫爲浮榮求速化，功名到底屬男兒。"]'),
('37bf0d9b-f111-463a-9d23-0321fe8cb4ab','和郭教授立春除夜之作二首  其一','吳芾','宋','宋诗','song-poetry','','[]','兒童爭喜歲時新，老去方知感此辰。',64,'全唐诗/poet.song.114000.json','["兒童爭喜歲時新，老去方知感此辰。", "始具杯盤來送臘，又簪幡勝去鞭春。", "滿斟蕉葉休辭醉，且對桃花痛飲醇。", "况有故人能過我，相看歲晚更情親。"]'),
('b9472418-9544-4df0-af4c-4b30e9ec54f0','和郭教授立春除夜之作二首  其二','吳芾','宋','宋诗','song-poetry','','[]','意廣才高困謗傷，又還客裏換年光。',64,'全唐诗/poet.song.114000.json','["意廣才高困謗傷，又還客裏換年光。", "驅馳道路風霜苦，放蕩江湖日月長。", "縱未致身登鳳閣，也應平步入鵷行。", "胡爲尚鬰騫騰志，無地棲遲寄寺廊。"]'),
('4692828e-e128-4400-ab1f-1decb56b3d01','和許守韵','吳芾','宋','宋诗','song-poetry','','[]','臺閣如公盍見收，尚淹外補爲民憂。',64,'全唐诗/poet.song.114000.json','["臺閣如公盍見收，尚淹外補爲民憂。", "身爲邦國三年計，心在江湖萬里秋。", "乘興舉杯還對月，得閒搜句或臨流。", "平生恨不逢名士，豈謂年來遂此謀。"]'),
('aa0e59cb-3b3f-4ae0-aca1-326094284d0f','和詹守二首  其一','吳芾','宋','宋诗','song-poetry','','[]','一日相逢喜有餘，對談勝讀十年書。',64,'全唐诗/poet.song.114000.json','["一日相逢喜有餘，對談勝讀十年書。", "歡聲已溢枌榆社，和氣還蒸蓬蓽居。", "敢道高標攀靖節，或疑勝致到華胥。", "願言莫惜留連醉，看我東皋带雨鋤。"]'),
('52b359ff-4fc8-42af-9d5c-d3073c303664','和詹守二首  其二','吳芾','宋','宋诗','song-poetry','','[]','特迂千騎訪柴門，多謝清朝皂蓋臣。',64,'全唐诗/poet.song.114000.json','["特迂千騎訪柴門，多謝清朝皂蓋臣。", "肯爲衰翁留竟日，頓令寒谷暖生春。", "論心便覺塵襟豁，刮目仍觀妙句新。", "轉盼又還成遠別，相思後夜定傷神。"]'),
('b54b25aa-3259-444d-bd5d-b3ce21a7c9e6','和許守野亭登眺','吳芾','宋','宋诗','song-poetry','','[]','夫君自合代王言，暫寓空齋八九椽。',64,'全唐诗/poet.song.114000.json','["夫君自合代王言，暫寓空齋八九椽。", "盡日清談揮麈尾，閉門危坐爇龍涎。", "詩囊遣興隨時賦，茗碗袪魔對客煎。", "看即除書催入覲，得閒登眺且欣然。"]'),
('652473fe-d1be-4105-8cc5-822d480c2f4b','送許守  其一','吳芾','宋','宋诗','song-poetry','','[]','慣分符竹理疲民，來往賢星又兩春。',64,'全唐诗/poet.song.114000.json','["慣分符竹理疲民，來往賢星又兩春。", "語到江山端有助，化行風俗自還淳。", "我知既去思何武，人歎無從借寇恂。", "別酒徑須拚一醉，他時良會恐無因。"]'),
('2568f00e-401b-49f7-bcd5-9b907ac0310f','送許守  其二','吳芾','宋','宋诗','song-poetry','','[]','千里歡謠處處同，使君遺愛信無窮。',64,'全唐诗/poet.song.114000.json','["千里歡謠處處同，使君遺愛信無窮。", "不容昏墊爲民患，解轉凶荒作歲豐。", "治行好書循吏傳，清聲無愧古人風。", "九重想已知名久，看即黄麻出禁中。"]'),
('5e0baa2a-96bb-4f09-9c8e-fa819cd87e02','和梁次張得酒之作','吳芾','宋','宋诗','song-poetry','','[]','在處人爭饋五漿，風標端是紫微郎。',64,'全唐诗/poet.song.114000.json','["在處人爭饋五漿，風標端是紫微郎。", "已能遣興追工部，更欲消憂對杜康。", "闡教暫煩臨水泮，趨朝行見裛天香。", "老夫素乏驚人句，徒歎辭鋒未易當。"]'),
('55ca2837-5183-480e-8b13-d7b062f91b3c','十五夜與朝宗對月把酒朝宗屢懷歸因賦二首  其一','吳芾','宋','宋诗','song-poetry','','[]','人間無處避炎光，頼有湖山六月凉。',64,'全唐诗/poet.song.114000.json','["人間無處避炎光，頼有湖山六月凉。", "清夜已欣天似水，長空還愛月如霜。", "我將乘興拚沉醉，君苦懷歸有底忙。", "試問今宵能飲否，更來月下對胡床。"]'),
('26a55000-9aa5-49bc-9700-17b61ffb66c8','十五夜與朝宗對月把酒朝宗屢懷歸因賦二首  其二','吳芾','宋','宋诗','song-poetry','','[]','霧捲雲收月迸光，一時煩濁變清凉。',64,'全唐诗/poet.song.114000.json','["霧捲雲收月迸光，一時煩濁變清凉。", "怪來坐上深無暑，疑是山間已有霜。", "老去豈期身尚健，閒中且以酒爲忙。", "故人若也堅辭醉，忍負良宵月滿床。"]'),
('e1f65608-b889-47d8-b3f1-463ded7c5032','登南樓二首  其一','吳芾','宋','宋诗','song-poetry','','[]','人生安用惹閒愁，得暇何妨且少休。',64,'全唐诗/poet.song.114000.json','["人生安用惹閒愁，得暇何妨且少休。", "睡起徑須烹北苑，興來聊復上南樓。", "公庭漸覺日無事，田里仍逢歲有秋。", "滿目江山還可樂，歸心已動不容留。"]'),
('d98170c7-98c9-48e0-9b41-4121b35c49b1','登南樓二首  其二','吳芾','宋','宋诗','song-poetry','','[]','新敞南樓百尺雄，一溪遥跨兩長虹。',64,'全唐诗/poet.song.114000.json','["新敞南樓百尺雄，一溪遥跨兩長虹。", "青山疊疊登臨外，碧瓦鱗鱗指顧中。", "倦客自憐如倦翼，歸心長是逐歸鴻。", "憑高幸與賓僚共，酒盞何妨爲我空。"]'),
('0e3a9c2c-dd1f-41fe-9951-bd30cbd4d015','凌歊臺六首  其一','吳芾','宋','宋诗','song-poetry','','[]','莫辭千騎小徘徊，共上凌歊百尺臺。',64,'全唐诗/poet.song.114000.json','["莫辭千騎小徘徊，共上凌歊百尺臺。", "過雨江山新似洗，連天草樹翠成堆。", "搜羅好景歸詩句，斷送閒愁付酒杯。", "對此願公拚一醉，相逢能得幾回來。"]'),
('b66c98ab-b8b1-47e9-9e84-666e6cfa6de8','凌歊臺六首  其二','吳芾','宋','宋诗','song-poetry','','[]','萬里清光絕點塵，別來經歲鎮如新。',64,'全唐诗/poet.song.114000.json','["萬里清光絕點塵，別來經歲鎮如新。", "恨居平地去天遠，喜上高臺與月親。", "正好賞心拚酩酊，不堪懷古倍酸辛。", "向來登此知何限，傳到如今有幾人。"]'),
('f8447951-9a34-40d5-aa8f-3625c8e0af1c','凌歊臺六首  其三','吳芾','宋','宋诗','song-poetry','','[]','簿書終日困拘攣，每到凌歊意豁然。',64,'全唐诗/poet.song.114000.json','["簿書終日困拘攣，每到凌歊意豁然。", "千里日光斜照水，一川草色遠連天。", "青山頂上玄暉宅，采石江頭太白船。", "俱在目中渾可樂，何妨時復一揚鞭。"]'),
('7d265036-14c6-471d-aaa9-bc8c032c9552','凌歊臺六首  其四','吳芾','宋','宋诗','song-poetry','','[]','黄山高處敞層臺，伊昔規模想壯哉。',64,'全唐诗/poet.song.114000.json','["黄山高處敞層臺，伊昔規模想壯哉。", "江上依然雙闕在，日邊不見六龍來。", "落花啼鳥空遺恨，翠竹青松且漫栽。", "先是老懷多感慨，每來弔古一興哀。"]'),
('8f78b557-6ba6-45d9-92b2-8ec2a33241ea','凌歊臺六首  其五','吳芾','宋','宋诗','song-poetry','','[]','百尺臺前萬頃寬，風烟縹緲隔塵寰。',64,'全唐诗/poet.song.114000.json','["百尺臺前萬頃寬，風烟縹緲隔塵寰。", "天浮江水兼湖水，雲抹淮山與楚山。", "景物宛如圖畫裏，星河祇在戶庭間。", "登臨莫作悲秋意，且對黄花一解顔。"]'),
('5326eb4f-a270-406a-93f4-bcd78d07cf18','凌歊臺六首  其六','吳芾','宋','宋诗','song-poetry','','[]','宋武當年迹已陳，荒臺寂寞幾經春。',64,'全唐诗/poet.song.114000.json','["宋武當年迹已陳，荒臺寂寞幾經春。", "一番棟宇從頭葺，四面軒窗入眼新。", "陡覺江山增氣象，更添風月愈精神。", "老夫無處逃炎暑，領客時來一岸巾。"]'),
('23c354de-8c47-4b73-8c3b-2c43c55eea71','江月臺','吳芾','宋','宋诗','song-poetry','','[]','秋來江月十分明，臺上凉生氣倍清。',64,'全唐诗/poet.song.114000.json','["秋來江月十分明，臺上凉生氣倍清。", "正好醉吟時自適，若爲衰病日相縈。", "苦無佳况人空老，數盡殘更夢不成。", "料想賓僚應笑我，鬢絲如此尚含情。"]'),
('e6142bc0-63eb-431e-ab39-f032edb67025','陪梁大諫察院同登蔣山','吳芾','宋','宋诗','song-poetry','','[]','山如屏障阜如鐘，中有巍巍古梵宮。',64,'全唐诗/poet.song.114000.json','["山如屏障阜如鐘，中有巍巍古梵宮。", "六代興王俱掃跡，一僧遺塔尚摩空。", "萬松雪類長波掛，八水源從異域通。", "家在天台最深處，見山還憶故山中。"]'),
('3c2ae843-87e3-43a7-acc7-b1edbef8b75d','過吳江題臞庵','吳芾','宋','宋诗','song-poetry','','[]','壯歲經行今白頭，未容歸老復來遊。',64,'全唐诗/poet.song.114000.json','["壯歲經行今白頭，未容歸老復來遊。", "人如化鶴雲間去，橋似垂虹天際浮。", "風月一川無限興，烟波萬頃不勝愁。", "三賢高躅何難繼，猶抗塵容祇自羞。"]'),
('ce9465e0-898e-4034-af27-c15f1e1e32e6','遊臞庵','吳芾','宋','宋诗','song-poetry','','[]','松江橋畔闞名園，一別重遊二十年。',64,'全唐诗/poet.song.114000.json','["松江橋畔闞名園，一別重遊二十年。", "種德堂前松菊茂，浮天閣下水雲連。", "同來朋舊今誰在，獨去情懷祇自憐。", "若許拂衣從此逝，不妨長泛釣魚船。"]'),
('19555532-c70b-42c4-906d-89b1e0aeed4d','過吳門登簡孚堂有感','吳芾','宋','宋诗','song-poetry','','[]','三十年前此宦遊，經從偶得駐扁舟。',64,'全唐诗/poet.song.114000.json','["三十年前此宦遊，經從偶得駐扁舟。", "回頭歲月如駒隙，到眼風烟獨虎丘。", "無復故人論舊事，却因陳迹惹新愁。", "此生未必能重到，且爲斯堂更少留。"]'),
('22324439-64ae-4ed3-bf6a-994c0c3a6df9','遊朱氏園','吳芾','宋','宋诗','song-poetry','','[]','萋萋芳草遍池塘，歎惜韶華一半强。',64,'全唐诗/poet.song.114000.json','["萋萋芳草遍池塘，歎惜韶華一半强。", "聞道名園千畝勝，來看浪蕊萬枝芳。", "渾疑席上紅裙擁，未讓階前綺帳張。", "坐客徑須拚痛飲，要將一醉答春光。"]'),
('ec7c37a2-0f72-4631-b342-be2afcfded4c','自湖上歸遊朱園和李相之韵二首  其一','吳芾','宋','宋诗','song-poetry','','[]','萬頃湖光一鏡開，幾人湖上散輪蹄。',64,'全唐诗/poet.song.114000.json','["萬頃湖光一鏡開，幾人湖上散輪蹄。", "水明盡倒千巖影，沙軟新成百里堤。", "草際已橫烟雨艇，眼前無復稻粱畦。", "馬侯遺迹依然在，顧我無功敢與齊。"]'),
('32aa37c0-50be-4244-bbee-21dc51eb6a78','自湖上歸遊朱園和李相之韵二首  其二','吳芾','宋','宋诗','song-poetry','','[]','聞道城東有故家，海棠初試萬枝花。',64,'全唐诗/poet.song.114000.json','["聞道城東有故家，海棠初試萬枝花。", "偶來花下燒銀燭，還似空中散綺霞。", "園裏高人全曠達，坐中騷客富文華。", "新詩已就驚人句，醉墨縱橫似亂鴉。"]'),
('3f48ab41-113f-40b1-a5dd-9fe52d990078','遊鹿田三洞','吳芾','宋','宋诗','song-poetry','','[]','野性平生酷愛山，好山不厭絕躋攀。',64,'全唐诗/poet.song.114000.json','["野性平生酷愛山，好山不厭絕躋攀。", "感時又見三春暮，乘興聊同一日閑。", "雲出岫時迷古洞，鹿耕田處認禪關。", "自憐擾擾塵埃裏，眼底欣逢水石環。"]'),
('9458ae32-650a-4817-be9c-a42602e0d623','次韵沈漕寄和題碧雲亭之作','吳芾','宋','宋诗','song-poetry','','[]','昔日危亭迹已陳，我來聊試運風斤。',64,'全唐诗/poet.song.114000.json','["昔日危亭迹已陳，我來聊試運風斤。", "斷垣無復生青草，舊觀依然聳碧雲。", "千里江山簷下見，一天星斗坐中分。", "他時有客來登覽，應記當年老使君。"]'),
('bec4c0f7-9f18-4045-b302-866f9eb8b754','和王致君見寄望海亭詩','吳芾','宋','宋诗','song-poetry','','[]','領客閑登木杪亭，坐來四面對崢嶸。',64,'全唐诗/poet.song.114000.json','["領客閑登木杪亭，坐來四面對崢嶸。", "野田散漫高低綠，湖水瀰茫遠近清。", "覽勝喜窮千里目，放懷笑引百壺傾。", "酒闌未用忙歸去，更看亭前海月明。"]'),
('d2c7ce81-f444-4ae0-bcd3-092bdd2d8f5b','題陳彥山草堂','吳芾','宋','宋诗','song-poetry','','[]','矯首江天正奉懷，一緘遥寄百篇來。',64,'全唐诗/poet.song.114000.json','["矯首江天正奉懷，一緘遥寄百篇來。", "頗聞新築草堂就，仍對舊穿花徑開。", "坐上好山長作伴，窗前修竹鎮相陪。", "嘉君深得閑中趣，千里何時共一杯。"]'),
('64b0e5c5-1bce-4bfa-981e-88cec07c5fc0','題養浩軒','吳芾','宋','宋诗','song-poetry','','[]','丈夫窮餓亦陶陶，肯使胸襟掛一毫。',64,'全唐诗/poet.song.114000.json','["丈夫窮餓亦陶陶，肯使胸襟掛一毫。", "千古功名輸慷慨，百年榮辱付酕醄。", "斗間古劍光芒直，雪後青松意氣高。", "安得泊船沽美酒，月明相對讀離騷。"]'),
('6bcd53e4-0970-4f46-af6c-a68e8b81a3d2','姑溪樓','吳芾','宋','宋诗','song-poetry','','[]','四面樓成已壯觀，茲樓仍更出雲間。',64,'全唐诗/poet.song.114000.json','["四面樓成已壯觀，茲樓仍更出雲間。", "一條溪引五湖水，千里江分兩岸山。", "是處風烟俱秀發，舊家氣象頓追還。", "公餘幸此同登覽，一醉休辭酒量慳。"]'),
('9041967b-d63a-49ae-afa8-05b5f7a1260b','和天予孺子亭三首  其一','吳芾','宋','宋诗','song-poetry','','[]','南州高士務躬行，不事王侯祇力耕。',64,'全唐诗/poet.song.114000.json','["南州高士務躬行，不事王侯祇力耕。", "西嶺已如剛節峻，東湖還似古心清。", "正慚老拙非良牧，安有仁恩及庶氓。", "若也當年能逐迹，他時容或可齊名。"]'),
('9d3d7679-d8c6-46fb-b505-8317f215db12','和天予孺子亭三首  其二','吳芾','宋','宋诗','song-poetry','','[]','東漢諸公孰最賢，南州高士獨推先。',64,'全唐诗/poet.song.114000.json','["東漢諸公孰最賢，南州高士獨推先。", "蒲輪徒枉當年聘，塵榻從教盡日懸。", "吾道固應天未喪，此時爭奈木將顛。", "栖栖爾輩成何事，那似清風萬古傳。"]'),
('1cb77f70-2b75-40a7-be45-5967cd797c33','和天予孺子亭三首  其三','吳芾','宋','宋诗','song-poetry','','[]','我來湖上訪前賢，正值清秋欲暮天。',64,'全唐诗/poet.song.114000.json','["我來湖上訪前賢，正值清秋欲暮天。", "十頃敗荷欹淺水，千章古木鎖寒煙。", "遍尋陳迹俱亡矣，獨立幽亭祇黯然。", "清德照人增我愧，暮年獨未返林泉。"]'),
('64d4a9cd-5add-4b24-ab11-ec6b2e7bf8c5','黄超然參議和拙者去郡十五絕又以詩見寄屬痰眩未能一一次韵且和二篇以謝  其一','吳芾','宋','宋诗','song-poetry','','[]','三復詩翁白雪篇，渴塵俄得醉心泉。',64,'全唐诗/poet.song.114000.json','["三復詩翁白雪篇，渴塵俄得醉心泉。", "高人固已追摩詰，好句還應壓玉川。", "快似凉風來木末，清如皓月出雲邊。", "呼兒好爲藏巾笥，莫許閑人取次傳。"]'),
('2ef99a40-077b-45ae-a8b4-c62e2201fe14','黄超然參議和拙者去郡十五絕又以詩見寄屬痰眩未能一一次韵且和二篇以謝  其二','吳芾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','向來從宦鄭公鄉，每遇清遊坐有光。',64,'全唐诗/poet.song.114000.json','["向來從宦鄭公鄉，每遇清遊坐有光。", "江上憑欄天一色，湖邊艤棹木千章。", "眼前景物俱堪賦，心著家山獨未忘。", "歸到小西湖更好，觀魚何必遠如棠。"]'),
('fff6e03a-ec6a-4b25-af32-caf19f60c9d5','陪任漕胡倉登滕王閣秋屏列岫','吳芾','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','滕閣秋屏已快哉，更登列岫少徘徊。',64,'全唐诗/poet.song.114000.json','["滕閣秋屏已快哉，更登列岫少徘徊。", "溶溶一水簷前去，隠隠千帆坐上來。", "每恨長年成契闊，頗欣今日得追陪。", "能并四樂由來少，且對江山舉一杯。"]'),
('dd9e3ef8-7bf1-47d7-84bf-733d7ec46e27','登列岫','吳芾','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','此邦已是富烟光，那更斯亭冠此邦。',64,'全唐诗/poet.song.114000.json','["此邦已是富烟光，那更斯亭冠此邦。", "正向座中窺列岫，恰從簷下瞰長江。", "閑穿松徑雲生屧，宴坐蒲團月滿窗。", "想得山人應笑我，老來强擁碧油幢。"]'),
('0b8a286e-91e6-4872-93f7-f24be0b67e5e','滕王閣三首  其一','吳芾','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','昔日驕王鎮此州，特營高閣瞰清流。',64,'全唐诗/poet.song.114000.json','["昔日驕王鎮此州，特營高閣瞰清流。", "一時傑出稱雄觀，千古爭傳作勝遊。", "遍覽遺蹤容可想，回思往事却堪羞。", "時人漫說珠簾雨，空惹騷人拄笏愁。"]'),
('e43e9295-eefa-4593-89cb-3d7edce18c1d','滕王閣三首  其二','吳芾','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','高閣秋登第一回，頓令心目豁然開。',64,'全唐诗/poet.song.114000.json','["高閣秋登第一回，頓令心目豁然開。", "山騰翠靄浮空去，水引清風入座來。", "九夏炎光今已矣，一時佳興更悠哉。", "和君妙句如冰雪，想見胸中絕點埃。"]'),
('39858f30-55ba-4a3f-9548-9b30eb619059','滕王閣三首  其三','吳芾','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','向來高閣久成空，今日雕欄勢尚雄。',64,'全唐诗/poet.song.114000.json','["向來高閣久成空，今日雕欄勢尚雄。", "觸影自憐人已老，題詩還愧我非工。", "江山滿目長悲古，樽俎開懷幸對公。", "莫惜躊躇連日醉，此回別後幾時同。"]'),
('ab5c5204-572e-42ad-8099-00bd6f940f9e','賀梁氏書樓初成','吳芾','宋','宋诗','song-poetry','','[]','于門高處許誰同，傑閣新成氣象雄。',64,'全唐诗/poet.song.114000.json','["于門高處許誰同，傑閣新成氣象雄。", "輝映萬家增壯觀，崢嶸百尺聳層空。", "一天風月登臨後，千里溪山指顧中。", "此地舊多仙窟宅，對君疑是老仙翁。"]'),
('68a1ba5a-b1c3-4f05-b590-e3c0a9d611d7','城上初作新亭猶未名也邦人閧然稱爲三槐殊不知所從來揣其意必以亭下有槐一根三幹挺然秀出故有是號然非所宜言也余恐不知者謂出自我作數語以解之','吳芾','宋','宋诗','song-poetry','','[]','我心祇是憶天台，欲去無從首重回。',64,'全唐诗/poet.song.114000.json','["我心祇是憶天台，欲去無從首重回。", "若得此時追五柳，絕勝他日面三槐。", "年年白髮催人老，夜夜青山入夢來。", "縱有萬鍾非我事，何如且覆掌中杯。"]'),
('d4001fb5-7a82-444d-9961-0e378d86d8a2','再題周處士山居  其一','吳芾','宋','宋诗','song-poetry','','[]','山鎖烟蘿自古青，更臨絕頂敞簷楹。',64,'全唐诗/poet.song.114000.json','["山鎖烟蘿自古青，更臨絕頂敞簷楹。", "前瞻江氣連雲起，回顧湖光照日明。", "坐久已驚毛骨爽，歸來猶覺夢魂清。", "從今便擬休官去，夢伴幽人度此生。"]'),
('ad88bbb3-9739-4c9e-b062-e0b204967479','再題周處士山居  其二','吳芾','宋','宋诗','song-poetry','','[]','閑驅小隊出城闉，春色三分已二分。',64,'全唐诗/poet.song.114000.json','["閑驅小隊出城闉，春色三分已二分。", "到處有花渾灼灼，望中無木不欣欣。", "故池尚想玄暉宅，荒草空悲太白墳。", "滿目青山誰是主，獨輸高士卧烟雲。"]'),
('1a688559-a044-4858-848f-75587a2efcf7','和李子儀到山居','吳芾','宋','宋诗','song-poetry','','[]','接得新詩喜有餘，詩中字字說山居。',64,'全唐诗/poet.song.114000.json','["接得新詩喜有餘，詩中字字說山居。", "固知還舍方爲樂，亦悟浮名總是虛。", "無計林間閑放鶴，何時湖上靜觀魚。", "我心萬事都無累，祇欠歸來得自如。"]'),
('52ddbd41-d2d3-4556-8819-25b1f12f99f0','和董伯玉讀當塗小集','吳芾','宋','宋诗','song-poetry','','[]','昔時乘障楚江邊，信筆題詩度歲年。',64,'全唐诗/poet.song.114000.json','["昔時乘障楚江邊，信筆題詩度歲年。", "豈敢嘲風仍詠月，祇思問舍與求田。", "歸心雖似陶元亮，句法寧窺孟浩然。", "多謝君詩過褒拂，愈令慚汗出如泉。"]'),
('1656c0cc-2c55-459b-a13f-692a0485cff6','和方叔載讀小集','吳芾','宋','宋诗','song-poetry','','[]','江城留滯兩經年，强把詩篇擬昔賢。',64,'全唐诗/poet.song.114000.json','["江城留滯兩經年，强把詩篇擬昔賢。", "豈有高歌翻白雪，祇憑短句問青天。", "優人獻伎徒供笑，醜婦添裝豈解妍。", "君欲學詩須學古，不應讀此向窗前。"]'),
('d2e4c069-abbc-4e3a-b251-71f1e8f301d7','前日小集梅花猶在乘興移其下杯行樂甚是夕風微月朗花飛入坐者紛紛如雪待制曾丈有四并之歎謂不可無作屢屬唱之因成拙句','吳芾','宋','宋诗','song-poetry','','[]','老去逢春倍感時，興來聊復對芳菲。',64,'全唐诗/poet.song.114000.json','["老去逢春倍感時，興來聊復對芳菲。", "月明更覺花枝好，風動還驚雪片飛。", "一笑休辭今夕醉，四并須信古來稀。", "乘閑莫惜頻相過，要共携壺上翠微。"]'),
('1f95e2cd-c243-400a-b74a-ccf8d1541ebb','五月五日領客泛舟','吳芾','宋','宋诗','song-poetry','','[]','要同佳客濯清泉，却下危樓上畫船。',64,'全唐诗/poet.song.114000.json','["要同佳客濯清泉，却下危樓上畫船。", "拭目已看雲際月，洗心還愛水中天。", "更無暑氣侵尊俎，但有薰風入管弦。", "我欲就閑行作別，且拚一醉共陶然。"]'),
('2b169c7e-45e7-4891-8335-0bec29e03837','待史志道不至','吳芾','宋','宋诗','song-poetry','','[]','欲覿英標慰此懷，既推印綬尚裴回。',64,'全唐诗/poet.song.114000.json','["欲覿英標慰此懷，既推印綬尚裴回。", "心馳巖壑吾將老，目斷雲霄君不來。", "清夜漫勞蝴蝶夢，重陽已負菊花杯。", "儻能諒此拳拳意，勝似心顔相對開。"]'),
('4c543d0b-d363-41d6-9f52-89a0150efccc','王瞻叔參政寄惠雲笈經因成四韵奉酬','吳芾','宋','宋诗','song-poetry','','[]','老來猶未返林泉，終日區區亦可憐。',64,'全唐诗/poet.song.114000.json','["老來猶未返林泉，終日區區亦可憐。", "擬扣玄關求至道，喜披雲笈探真筌。", "他時使我離塵境，今日由君結妙緣。", "莫謂骨凡難變化，丹成鷄犬尚升仙。"]'),
('16ccdc80-31d4-4d09-894a-a306664962f0','懷梁丈陳丈','吳芾','宋','宋诗','song-poetry','','[]','不見高標動浹旬，寸心如渴欲生塵。',64,'全唐诗/poet.song.114000.json','["不見高標動浹旬，寸心如渴欲生塵。", "春深漸覺梅花老，風暖還驚柳色新。", "對景想題詩句滿，開懷應把酒杯頻。", "扁舟前後空相望，安得從容笑語親。"]'),
('866fe725-a26f-4921-97cf-311eac75c613','會使帥郭侯燕於采石','吳芾','宋','宋诗','song-poetry','','[]','高牙大纛拂層雲，樽酒相逢楚水濱。',64,'全唐诗/poet.song.114000.json','["高牙大纛拂層雲，樽酒相逢楚水濱。", "千里江山俱入眼，一天風月解留人。", "橫吹玉笛漁船晚，醉擁金釵綺席春。", "此地謫仙歸去後，誰知今日興尤新。"]'),
('26782aad-fbae-4007-9dae-8d60e94f3538','再用前韵堅使帥凌歊之約','吳芾','宋','宋诗','song-poetry','','[]','喜對東風玩朵雲，按行知已遍淮濱。',64,'全唐诗/poet.song.114000.json','["喜對東風玩朵雲，按行知已遍淮濱。", "論心我正懷良晤，乘興公應繼昔人。", "采石江頭天欲霽，凌歊臺上物長春。", "從容儻許留牙纛，看取姑溪歲事新。"]'),
('7dacfe80-ae2e-4ddc-9b8f-f09188aeb6c6','送黄作霖','吳芾','宋','宋诗','song-poetry','','[]','有志男兒走四方，憐君羈旅歲時長。',64,'全唐诗/poet.song.114000.json','["有志男兒走四方，憐君羈旅歲時長。", "數千里外干微祿，三十年餘返故鄉。", "老著青衫唯可恨，光生白屋亦非常。", "時來會有摶風便，莫道窮途便感傷。"]'),
('0fddf829-3e11-45f8-86f1-75021621f85e','耿曼老自去秋起歸興以被旨捄荒方有行色來告別傷成數語送之','吳芾','宋','宋诗','song-poetry','','[]','去秋已作送君詩，豈意淹留復許時。',64,'全唐诗/poet.song.114000.json','["去秋已作送君詩，豈意淹留復許時。", "端爲九重憂歲歉，故令六轡緩歸期。", "萬人全活俱安業，二麥收成足療饑。", "此事一歸君妙畫，陰功當自有天知。"]'),
('0f624e4f-9cb2-4534-9d68-a575f6cf148a','送陳澤民赴銅陵簿','吳芾','宋','宋诗','song-poetry','','[]','鄉閭人物久凋零，輩行如君却老成。',64,'全唐诗/poet.song.114000.json','["鄉閭人物久凋零，輩行如君却老成。", "自合懷鉛居冊府，若爲棲棘向江城。", "簿書且作三年計，事業當爲萬里程。", "林下賢人如未泯，尚期拭目看飛鳴。"]'),
('e3b72e48-50a9-4858-918f-f962d4b1c91b','送江簿歸括蒼','吳芾','宋','宋诗','song-poetry','','[]','羈懷索寞苦難禁，頼有良朋與盍簪。',64,'全唐诗/poet.song.114000.json','["羈懷索寞苦難禁，頼有良朋與盍簪。", "同志自憐今日少，知心誰復似君深。", "哦詩喜得江天句，把酒愁分歲暮襟。", "莫戀故山乖素約，春來準擬共登臨。"]'),
('722d7f33-45eb-4dfe-bc99-a8d7f07daa07','和高簿  其一','吳芾','宋','宋诗','song-poetry','','[]','不憚驅馳半驛間，勸耕聊復到禪關。',64,'全唐诗/poet.song.114000.json','["不憚驅馳半驛間，勸耕聊復到禪關。", "耳根暗瀉潺潺水，眼界橫陳疊疊山。", "已喜新來春事好，還嗟老去世塗艱。", "洪崖幸爾心相契，此後何妨數往還。"]'),
('872d7b22-38bd-4356-bc36-af2dd0b1f16a','和高簿  其二','吳芾','宋','宋诗','song-poetry','','[]','家家門外與牆頭，疊足排肩看我遊。',64,'全唐诗/poet.song.114000.json','["家家門外與牆頭，疊足排肩看我遊。", "出郭不應祇獨樂，勞農端欲與同憂。", "偶逢佳處寧空過，縱迫歸時亦暫留。", "慚愧高軒遠相過，聊持杯酒當茶甌。"]'),
('0063b311-198d-4693-a0b4-2ea1bf406224','送汪樞帥福唐','吳芾','宋','宋诗','song-poetry','','[]','試數中興社稷臣，獨公名德冠簪紳。',64,'全唐诗/poet.song.114000.json','["試數中興社稷臣，獨公名德冠簪紳。", "合依衮繡歸雙闕，却擁旌幢帥七閩。", "帝欲十連均雨露，人思四海靜風塵。", "會須展盡經綸手，總把安危佩一身。"]'),
('5fd3a407-b8fa-4e09-8497-86e85b6e1a07','送王舍人彥正奉祠東歸','吳芾','宋','宋诗','song-poetry','','[]','去年趨召偶同時，每喜蒹葭玉樹依。',64,'全唐诗/poet.song.114000.json','["去年趨召偶同時，每喜蒹葭玉樹依。", "偉論崢嶸從古少，高懷恬退似君稀。", "身遊紫禁方持橐，心著青山便拂衣。", "顧我滯留徒有愧，扁舟何日送東歸。"]'),
('2a465aaa-6012-4ce9-8a51-9c384750bb8c','送方務德侍郎得請東歸','吳芾','宋','宋诗','song-poetry','','[]','三抗封章未得歸，故山歸夢每飛馳。',64,'全唐诗/poet.song.114000.json','["三抗封章未得歸，故山歸夢每飛馳。", "羨君却向林泉去，愧我猶爲印紱縻。", "忙裏光陰能自惜，靜中氣味許誰知。", "祇疑天靳清閑福，丹詔還催上赤墀。"]'),
('8021cb00-9fd4-4f66-b50f-ddad8117f1a1','送人出使  其一','吳芾','宋','宋诗','song-poetry','','[]','天心軫念國西陲，妙選廷臣下赤墀。',64,'全唐诗/poet.song.114000.json','["天心軫念國西陲，妙選廷臣下赤墀。", "要布寬仁慰彫瘵，用資根本濟艱危。", "九重眷遇風雲會，萬里威名草木知。", "此去願羅天下士，歸來共立太平基。"]'),
('088cb5dd-ff74-440c-94f3-45547fc3246c','送人出使  其二','吳芾','宋','宋诗','song-poetry','','[]','驛騎駸駸犯露霜，定知遐俗喜生光。',64,'全唐诗/poet.song.114000.json','["驛騎駸駸犯露霜，定知遐俗喜生光。", "千官弩矢迎郊外，百姓壺漿夾道旁。", "要使遠謀安井邑，盡令諸將守封疆。", "更將餘力籌邊策，歸日收功坐廟堂。"]'),
('c610cdcf-3e05-4c3b-ab05-9407fce50d8c','和閭丘莘叟','吳芾','宋','宋诗','song-poetry','','[]','此時狂敵合灰飛，致我天王下紫微。',64,'全唐诗/poet.song.114000.json','["此時狂敵合灰飛，致我天王下紫微。", "士馬生風增銳氣，旌旗蔽日耀皇威。", "愧無一策裨黄屋，濫逐千官扈赭衣。", "智畧如君宜有用，周行指日看來歸。"]'),
('39a17b81-e335-46e9-bad7-54a91a570a40','送王仲矜赴興元倅','吳芾','宋','宋诗','song-poetry','','[]','有志男兒自不同，出門慷慨氣如虹。',64,'全唐诗/poet.song.114000.json','["有志男兒自不同，出門慷慨氣如虹。", "遠謀尚欲安天下，小試何妨佐漢中。", "此地從來爲重鎮，乃翁還更有遺風。", "一行莫起徒勞歎，看即人歌別駕功。"]'),
('608442f5-8bb3-46f9-a862-daa9c58d48e6','和嚴倅覓碧香','吳芾','宋','宋诗','song-poetry','','[]','不勞齋戒絕羶葷，聞已潛通妙衆門。',64,'全唐诗/poet.song.114000.json','["不勞齋戒絕羶葷，聞已潛通妙衆門。", "此道能明從古少，今朝正要與君論。", "十年未免憂茅塞，一詣終期破棗昏。", "縱有香醪堪寄遠，何如相對倒清樽。"]'),
('edf1b731-5bcb-4b70-92df-2093f5eba271','和鮑倅  其一','吳芾','宋','宋诗','song-poetry','','[]','彯纓誰不是王臣，抗志如今有幾人。',64,'全唐诗/poet.song.114000.json','["彯纓誰不是王臣，抗志如今有幾人。", "墜典固嘗深探討，頹綱猶未許彌綸。", "擬歸舊隠消殘臘，旋買新田作好春。", "聖主搜揚方側席，不應無術濟生民。"]'),
('f400a33c-d306-479f-9133-e4ae2f6fefa8','和鮑倅  其二','吳芾','宋','宋诗','song-poetry','','[]','參軍已去作飛仙，俊逸聲名久不傳。',64,'全唐诗/poet.song.114000.json','["參軍已去作飛仙，俊逸聲名久不傳。", "千古家風期爾振，一時句法許誰先。", "心惟酷好佳山水，手不停披舊簡編。", "想得錦囊應是富，年來知有幾千篇。"]'),
('9a4ccf11-00ab-4ba6-927d-7824db5bb03e','和鮑倅  其三','吳芾','宋','宋诗','song-poetry','','[]','人生出處苦難全，老矣安能了世緣。',64,'全唐诗/poet.song.114000.json','["人生出處苦難全，老矣安能了世緣。", "聊向此時看捉月，敢希他日上凌烟。", "行吟雖愧無新語，坐食猶欣有故廛。", "若得放歸多種秫，不憂長欠酒家錢。"]'),
('aabad4a6-5fd7-4db1-9436-848773372346','勸農題岩寺','吳芾','宋','宋诗','song-poetry','','[]','西山千仞鬰崔嵬，寺在山椒勝處開。',64,'全唐诗/poet.song.114000.json','["西山千仞鬰崔嵬，寺在山椒勝處開。", "暇日久思乘興去，中春始爲勸耕來。", "屋頭水色青如染，簷外嵐光翠作堆。", "幽賞未窮天已暮，驅車欲去更徘徊。"]'),
('8247b349-74c8-413e-a8ee-947d629aa810','開河畢功喜而有作','吳芾','宋','宋诗','song-poetry','','[]','汙河積水困薰蒸，開鑿那知不日成。',64,'全唐诗/poet.song.114000.json','["汙河積水困薰蒸，開鑿那知不日成。", "野水盡從簷下過，客舟還傍市中行。", "江山自昔天然秀，人物從今分外清。", "本爲此邦開眼目，老夫雙目亦增明。"]'),
('b04f78d8-a834-45f6-bd6a-5470a056e639','和十五姪見寄','吳芾','宋','宋诗','song-poetry','','[]','草廬高卧幾經春，被褐深藏席上珍。',64,'全唐诗/poet.song.114000.json','["草廬高卧幾經春，被褐深藏席上珍。", "已自閉門甘澹泊，不妨琢句自清新。", "我慚老去同流俗，日念歸來作野人。", "此後塤箎酬唱罷，因風見寄莫辭頻。"]'),
('1179648c-e5b4-49c3-917b-6aab23e953b4','和十五姪韵','吳芾','宋','宋诗','song-poetry','','[]','無補公家祇主臣，但思高卧故山雲。',64,'全唐诗/poet.song.114000.json','["無補公家祇主臣，但思高卧故山雲。", "宦遊恥蠹太倉粟，歸去貪羹碧澗芹。", "喜得醇醪堪飲客，還驚妙句更超羣。", "速來共爲梅花醉，趁取枝頭香正芬。"]'),
('b350247c-c3d9-4ee7-a929-86f1624e0d1d','和四二姪用林道叟見寄字韵','吳芾','宋','宋诗','song-poetry','','[]','華髮蕭蕭日夜疏，奔馳不止欲何如。',64,'全唐诗/poet.song.114000.json','["華髮蕭蕭日夜疏，奔馳不止欲何如。", "得拋印綬心方適，歸見湖山氣始舒。", "世事轉頭如蝶夢，人生到此似蘧廬。", "我今已作終焉計，却悔當年赴鶴書。"]'),
('4fa1fd8a-e52a-47cd-b89b-2c72659dbdf1','元夕有感','吳芾','宋','宋诗','song-poetry','','[]','當塗連歲看燒燈，又見洪都爛滿城。',64,'全唐诗/poet.song.114000.json','["當塗連歲看燒燈，又見洪都爛滿城。", "紫陌人疑春欲曉，清宵天放月爭明。", "老逢好景知能幾，暗數流年祇自驚。", "亦擬樽前成一笑，吾衰無復舊心情。"]'),
('4752cefa-a805-4797-a331-d68168ac2c5a','元夕用胡經仲所寄韵呈辛倅及諸僚友','吳芾','宋','宋诗','song-poetry','','[]','星斗潛移下九天，滿城如晝酒如泉。',64,'全唐诗/poet.song.114000.json','["星斗潛移下九天，滿城如晝酒如泉。", "當時行樂陪千騎，今日重來恰十年。", "燈燭光中春更好，綺羅叢裏月爭妍。", "諸君莫惜長鯨量，要向樽前中聖賢。"]'),
('9894ec2b-ce83-496b-9cff-ebf78520e973','和澤民送春  其一','吳芾','宋','宋诗','song-poetry','','[]','我家還分有園池，正願春遲春又歸。',64,'全唐诗/poet.song.114000.json','["我家還分有園池，正願春遲春又歸。", "風掃花枝猶隠約，日烘雲影漸熹微。", "客來但欲拚同醉，事往何須歎昨非。", "自念生平魚鳥性，又思川泳與雲飛。"]'),
('26e3ccee-24e1-4078-ac85-0774f925ce1e','和澤民送春  其二','吳芾','宋','宋诗','song-poetry','','[]','不堪歲歲送青春，消黯渾如失所親。',64,'全唐诗/poet.song.114000.json','["不堪歲歲送青春，消黯渾如失所親。", "短句吟成猶恨別，清樽買盡不辭貧。", "興來直欲遊三島，老去何由駐二輪。", "頼有君能知我意，肯來同作送春人。"]'),
('d3867b20-f877-4358-868d-ed7ba38f8a6d','又和金克家送春','吳芾','宋','宋诗','song-poetry','','[]','春來縱使日銜杯，老去逢春能幾回。',64,'全唐诗/poet.song.114000.json','["春來縱使日銜杯，老去逢春能幾回。", "幸有良朋同雅集，不妨爛醉罄餘罍。", "羞看落絮愁盈抱，强對殘花淚滿腮。", "惆悵又爲經歲別，莫辭花下少徘徊。"]'),
('8079aad7-7d17-4eb0-845a-a69c21256e93','和經仲春日即事  其一','吳芾','宋','宋诗','song-poetry','','[]','淡烟籠水一溪虛，別有風光在野廬。',64,'全唐诗/poet.song.114000.json','["淡烟籠水一溪虛，別有風光在野廬。", "幽哢喚人回遠夢，落紅鋪水失清渠。", "此生得酒休辭醉，今日何人是奠居。", "正向東山念蕭索，筠筒煩寄指南車。"]'),
('6d77cf51-1ef9-4c3b-82db-0b640552007f','和經仲春日即事  其二','吳芾','宋','宋诗','song-poetry','','[]','策杖郊原信步行，沙邊春水半涵清。',64,'全唐诗/poet.song.114000.json','["策杖郊原信步行，沙邊春水半涵清。", "花開舊樹香仍在，燕葺破巢功未成。", "世路十年塵土面，春風萬里鼓鼙聲。", "從今準擬開懷去，到手荷杯莫厭傾。"]'),
('71316b07-910c-43c6-9f6a-44d2dd94b7a4','喜雨','吳芾','宋','宋诗','song-poetry','','[]','聞道他邦盡禱祈，沛然膏澤尚遲遲。',64,'全唐诗/poet.song.114000.json','["聞道他邦盡禱祈，沛然膏澤尚遲遲。", "有年已是天私我，連日那堪雨及時。", "聲入萬家添喜氣，凉生千里解炎曦。", "也知造物恩難報，且採歡謠綴小詩。"]'),
('79fdfa13-e5b4-483e-b21e-5bfea617dc06','和許守喜雨韵  其一','吳芾','宋','宋诗','song-poetry','','[]','使君盛德格皇天，奔走羣龍雨霈然。',64,'全唐诗/poet.song.114000.json','["使君盛德格皇天，奔走羣龍雨霈然。", "坐使槁苗成茂實，潛將豐歲換凶年。", "荷鋤野老欣嘉應，抱甕田夫得晏眠。", "擬倩樂工弦盛事，山城那得有師涓。"]'),
('bc1d9b54-dfc0-4cee-9fc1-089e05aeb17f','和許守喜雨韵  其二','吳芾','宋','宋诗','song-poetry','','[]','千里焦枯頓鬰蒼，邦人寧復慮年荒。',64,'全唐诗/poet.song.114000.json','["千里焦枯頓鬰蒼，邦人寧復慮年荒。", "大田一雨渾霑足，鄰壤羣偷更伏藏。", "治郡羨君端有術，救民愧我獨無方。", "夜來復誦新詩句，歎賞徘徊月轉廊。"]'),
('86dccd13-ecca-4da8-abc6-81fc85ba04b2','和閭丘省幹喜雨韵  其一','吳芾','宋','宋诗','song-poetry','','[]','良田方苦莠驕驕，甘雨如何閟九霄。',64,'全唐诗/poet.song.114000.json','["良田方苦莠驕驕，甘雨如何閟九霄。", "賢守治聲喧道路，聖君德澤播黎苗。", "寧容赤地炎威熾，果見青天旱氣消。", "昨夜東皋已霑足，康衢滿耳沸歌謠。"]'),
('df4bef6b-827f-46ec-b408-48e7eda46a68','和閭丘省幹喜雨韵  其二','吳芾','宋','宋诗','song-poetry','','[]','鈴齋坐嘯不爲頗，愁歎翻然變詠歌。',64,'全唐诗/poet.song.114000.json','["鈴齋坐嘯不爲頗，愁歎翻然變詠歌。", "千里正憂無舊穀，一朝俄喜浹新禾。", "雲師蔽日如張幟，雨陣橫空似擁戈。", "我忝郡丞何所補，但將新句對松哦。"]'),
('65aa4263-9dae-49ed-b81d-25b0dd6bfa11','和趙觀使喜雨','吳芾','宋','宋诗','song-poetry','','[]','膏澤愆時愧已深，敢期誠意達天垠。',64,'全唐诗/poet.song.114000.json','["膏澤愆時愧已深，敢期誠意達天垠。", "片雲忽送千峯雨，一氣潛回萬壑春。", "頓覺老農生喜色，坐令凶歲變佳辰。", "憂民雖切功何有，坱圠無私荷大鈞。"]'),
('2de9f796-c887-419d-905c-6d210e0397e7','喜雨偶成','吳芾','宋','宋诗','song-poetry','','[]','麥熟蠶登處處同，萬家舉首謝天公。',64,'全唐诗/poet.song.114000.json','["麥熟蠶登處處同，萬家舉首謝天公。", "尚憂六月旱爲虐，却喜連宵雨已通。", "萬事自知成老懶，一心祇是願年豐。", "從今準擬添新釀，要使樽中酒不空。"]'),
('bdf2390f-3427-47e6-ba77-9fffae261b12','和澤民喜雨','吳芾','宋','宋诗','song-poetry','','[]','陰長陽消帝怒深，盡驅赫日掃羣陰。',64,'全唐诗/poet.song.114000.json','["陰長陽消帝怒深，盡驅赫日掃羣陰。", "却疑枉致一秋旱，聊復霈爲三日霖。", "隴畝共知成樂歲，里閭誰不起歡心。", "朝來幽鳥知予意，亦向簷前作好音。"]'),
('ef08273d-7481-4a23-98d7-91eea0b39f54','和葉性之喜雨','吳芾','宋','宋诗','song-poetry','','[]','去歲饑荒特異常，那知今日便豐穰。',64,'全唐诗/poet.song.114000.json','["去歲饑荒特異常，那知今日便豐穰。", "田疇雨足經時潤，院宇風生着處凉。", "老去我方辭五斗，秋來誰解積千倉。", "從今閭里無艱食，會見家家酒熟香。"]'),
('83eb08a5-dded-4482-9af7-e59d8f5781dc','癸巳夏秋旱七月十日得雨喜雨有作','吳芾','宋','宋诗','song-poetry','','[]','旱魃爲災害有秋，焦枯滿目使人憂。',64,'全唐诗/poet.song.114000.json','["旱魃爲災害有秋，焦枯滿目使人憂。", "片雲忽向天邊合，一雨俄驚地上流。", "盡道槁苗須半活，如云晚稻可全收。", "老農兩手齊加額，且免流離過外州。"]'),
('2a12f938-0941-4d3f-abee-6cb2d555131e','喜入冬初七八得雨','吳芾','宋','宋诗','song-poetry','','[]','夏旱連秋又及冬，大田高下總成空。',64,'全唐诗/poet.song.114000.json','["夏旱連秋又及冬，大田高下總成空。", "千倉已失三農望，一雨欣聞百里同。", "青入平疇看麥秀，綠回枯沼喜泉通。", "從今得免填溝壑，皆謝天公惠困窮。"]'),
('25ab121e-8dd4-4f2b-8a5a-5cf6ce81978e','和魯漕喜雨二首  其一','吳芾','宋','宋诗','song-poetry','','[]','冬暖曾無欲雪天，正憂饑饉在新年。',64,'全唐诗/poet.song.114000.json','["冬暖曾無欲雪天，正憂饑饉在新年。", "忽聞夜滴簷前雨，便覺春歸郭外田。", "千里已知俱樂只，一尊亦擬共陶然。", "其如使者拘臺制，不肯花間聽管弦。"]'),
('d437ea7f-e717-4f29-9e8b-55f25b52ec4b','和魯漕喜雨二首  其二','吳芾','宋','宋诗','song-poetry','','[]','秋來日日困驕陽，正欲齋心問彼蒼。',64,'全唐诗/poet.song.114000.json','["秋來日日困驕陽，正欲齋心問彼蒼。", "倏爾四郊雲氣合，霈然一夜雨聲長。", "三農已有倉箱慶，萬室還欣枕簟凉。", "幸值故人來過我，尊前莫惜醉淋浪。"]'),
('1491435b-fdc6-45da-981e-e672dab23790','和魯漕春雨有感三首  其一','吳芾','宋','宋诗','song-poetry','','[]','自憐齒豁與頭童，心事都非少壯同。',64,'全唐诗/poet.song.114000.json','["自憐齒豁與頭童，心事都非少壯同。", "那更閉門聽夜雨，不容步屧趁東風。", "勝遊尚喜朋簪盍，痛飲寧辭酒盞空。", "只恐酒醒歸興動，愈令倦客憶山中。"]'),
('94808063-51b0-487e-a896-f9995880442c','和魯漕春雨有感三首  其二','吳芾','宋','宋诗','song-poetry','','[]','自歎蒼顔不復童，幸然三老此時同。',64,'全唐诗/poet.song.114000.json','["自歎蒼顔不復童，幸然三老此時同。", "登高能賦多佳詠，把酒論文有古風。", "可恨雨師頻作惡，直疑春事遂成空。", "愁來不用殷勤勸，已判花前爲一中。"]'),
('439b3cd9-2fa5-42ab-953e-0c660d5a3ee0','和魯漕春雨有感三首  其三','吳芾','宋','宋诗','song-poetry','','[]','我心雖老尚如童，春到惟思笑語同。',64,'全唐诗/poet.song.114000.json','["我心雖老尚如童，春到惟思笑語同。", "正欲對花歌且舞，那知通夕雨兼風。", "千疇固喜俱霑足，百卉還愁一掃空。", "安得晴天開萬里，緩行花下豁胸中。"]'),
('16e7664b-42cf-4f78-9f49-b0c3851a726e','雨後','吳芾','宋','宋诗','song-poetry','','[]','朝來一雨灑炎光，陡覺園林處處凉。',64,'全唐诗/poet.song.114000.json','["朝來一雨灑炎光，陡覺園林處處凉。", "烟柳數行縈翠带，風荷十里擁紅妝。", "莫憂鏡裏朱顔改，且喜壺中白晝長。", "只恐吾衰無此福，不容終老水雲鄉。"]'),
('6fad3482-081c-4cbf-85ad-230f85213862','喜晴  其一','吳芾','宋','宋诗','song-poetry','','[]','積陰初散雨初收，一解霖霪十日憂。',64,'全唐诗/poet.song.114000.json','["積陰初散雨初收，一解霖霪十日憂。", "已見郡條平似水，不妨官舍冷如秋。", "年來觸緒無佳思，老去同僚得勝流。", "更喜豐年消息好，從今還遂稻粱謀。"]'),
('86a6bc20-7956-473b-962f-a2c6e5a68879','喜晴  其二','吳芾','宋','宋诗','song-poetry','','[]','久雨無聊喜乍晴，尚餘春色到簷楹。',64,'全唐诗/poet.song.114000.json','["久雨無聊喜乍晴，尚餘春色到簷楹。", "楊花飛去今無力，燕子歸來似有情。", "靜看遊鱼波面躍，閑隨野鶴竹間行。", "世緣到此消磨盡，只欲徜徉度此生。"]'),
('2e72ede3-d5c3-44d3-a97f-8f31e5d61eb2','未臘已見四白偶得數語呈子壽且述挽留之意','吳芾','宋','宋诗','song-poetry','','[]','人言三白兆豐年，四白欣逢向臘前。',64,'全唐诗/poet.song.114000.json','["人言三白兆豐年，四白欣逢向臘前。", "細糝蘆花初着地，亂飄柳絮忽漫天。", "雅宜領客登臺上，正欲開尊向酒邊。", "樂歲幸君同賦詠，若爲歸棹遽翩然。"]'),
('4d65911e-7ead-4667-b863-391f7bee3e39','和蔣無退詠雪','吳芾','宋','宋诗','song-poetry','','[]','臘中三白幾年無，今歲呈祥事可書。',64,'全唐诗/poet.song.114000.json','["臘中三白幾年無，今歲呈祥事可書。", "披得一蓑方入畫，翻成雙带又隨車。", "共驚飛絮迷清晝，更覺同雲滿太虛。", "憶昔讀書燈火少，喜穿窗牖映吾廬。"]'),
('2f33e4f3-83c6-4ee8-80a2-a53dc92dfccf','和魏簽雪詩上趙守  其一','吳芾','宋','宋诗','song-poetry','','[]','臘盡東君已報春，雪花猶未歛輕塵。',64,'全唐诗/poet.song.114000.json','["臘盡東君已報春，雪花猶未歛輕塵。", "二天默禱渾如響，一夜呈祥覺有神。", "千里妖氛應洗滌，萬家喜氣欲輪囷。", "試詢治行今誰最，屈指公爲第一人。"]'),
('49d1873d-d9ff-4fab-a5d6-fd5998b34d2a','和魏簽雪詩上趙守  其二','吳芾','宋','宋诗','song-poetry','','[]','透戶穿簾到眼邊，陡驚滕六逞威權。',64,'全唐诗/poet.song.114000.json','["透戶穿簾到眼邊，陡驚滕六逞威權。", "禦寒我獨憂無褐，得飽人皆喜有年。", "已見歡聲騰比屋，好將盛事被丹弦。", "此時且莫孤清賞，早晚除書下九天。"]'),
('042b6ed3-d320-43b9-b8e1-7b92919ae0cb','和朱文卿春雪韵','吳芾','宋','宋诗','song-poetry','','[]','春來何事尚凝嚴，一夜空庭霰雪兼。',64,'全唐诗/poet.song.114000.json','["春來何事尚凝嚴，一夜空庭霰雪兼。", "坐久羅衣驚頓薄，更闌杯酒覺頻添。", "旋消疏滴簷間雨，更看平堆地上鹽。", "誰道東風回暖律，韜霞掩日不容覘。"]'),
('376e4f48-e2cc-4521-a4de-b4e6466862b6','喜雪  其一','吳芾','宋','宋诗','song-poetry','','[]','糝遍山巔與水涯，天公着意做年華。',64,'全唐诗/poet.song.114000.json','["糝遍山巔與水涯，天公着意做年華。", "要令臘裏呈三白，時向空中散六花。", "勒住玉梅還可恨，妝成瓊樹却堪誇。", "須知造物憂民切，預把豐穰報萬家。"]'),
('22b1ddc4-4113-4b44-a99a-1e45ea93d6d6','喜雪  其二','吳芾','宋','宋诗','song-poetry','','[]','雪意初疑作不成，纔飛數片又還晴。',64,'全唐诗/poet.song.114000.json','["雪意初疑作不成，纔飛數片又還晴。", "正思潤澤霑千里，忽見繽紛滿一城。", "凋郡共欣消沴氣，老農相慶沸歡聲。", "我將盡把姑溪釀，要與邦人樂太平。"]'),
('24998039-fcfc-4c85-89f4-9ff1cbf2e5ff','喜雪  其三','吳芾','宋','宋诗','song-poetry','','[]','凍雲黯淡浩無涯，雪陣橫空勢欲斜。',64,'全唐诗/poet.song.114000.json','["凍雲黯淡浩無涯，雪陣橫空勢欲斜。", "入戶有人疑柳絮，繞園無處認梅花。", "舉頭頓覺青山老，撲面還驚綠鬢華。", "我醉未眠愁酒盡，挈瓶來問爾東家。"]'),
('977b9827-c62e-4777-b38e-a7a015ee8b00','和魯漕途中喜雪','吳芾','宋','宋诗','song-poetry','','[]','陡覺同雲翳四山，捲簾聊復望江干。',64,'全唐诗/poet.song.114000.json','["陡覺同雲翳四山，捲簾聊復望江干。", "舉頭喜見迎春雪，抱膝從教徹地寒。", "預卜豐穰知歲樂，潛消瘴癘想民安。", "一樽正欲同清賞，咫尺胡爲會合難。"]'),
('9ab3e693-e8c4-4bbb-a54b-fd75455b3fb3','和津喜雪二首  其一','吳芾','宋','宋诗','song-poetry','','[]','六花一夜降中天，飛繞吾廬頓滿前。',64,'全唐诗/poet.song.114000.json','["六花一夜降中天，飛繞吾廬頓滿前。", "幻出仙家新窟宅，疑非塵世舊山川。", "但驚巖上青松老，不見天邊白雁連。", "頼有甕頭新釀熟，何妨沉醉度殘年。"]'),
('a440896b-51a3-4b91-88f2-81a9a6c0e898','和津喜雪二首  其二','吳芾','宋','宋诗','song-poetry','','[]','我愛平湖繞碧山，山光倒碧到樽前。',64,'全唐诗/poet.song.114000.json','["我愛平湖繞碧山，山光倒碧到樽前。", "同雲何事迷千嶂，飛雪俄然蔽一川。", "縱使玉樓從地湧，便教銀闕與天連。", "到頭幻化非真實，爭似湖山耐歲年。"]'),
('4e484cc9-6584-4c38-bc4b-e41952ebdf51','和許守喜雪韵','吳芾','宋','宋诗','song-poetry','','[]','凍雲垂地木停號，六出飛花遍九皋。',64,'全唐诗/poet.song.114000.json','["凍雲垂地木停號，六出飛花遍九皋。", "已見隨車翻縞带，還疑縱獵散風毛。", "幽人乘興空回棹，公子無言獨擁袍。", "顧我年來詩思澀，强吟冰柱愧才高。"]'),
('8916b084-3d9d-4f0e-ae5c-a0de2daeaf25','元宵雪作因成短句','吳芾','宋','宋诗','song-poetry','','[]','天公着意做元宵，陡使新春樂事饒。',64,'全唐诗/poet.song.114000.json','["天公着意做元宵，陡使新春樂事饒。", "已放金蓮開陸地，更疑銀闕下雲霄。", "坐中星斗渾相照，庭下瓊瑰更亂飄。", "佳客莫辭通夕醉，要令來歲記今朝。"]'),
('9de67f63-c262-431d-8942-63885d9487fb','是日大雪際晚復晴月色輝映尤爲可喜偶成數句','吳芾','宋','宋诗','song-poetry','','[]','滿城着地折紅蓮，天使今宵樂事全。',64,'全唐诗/poet.song.114000.json','["滿城着地折紅蓮，天使今宵樂事全。", "已是雪中千里白，更兼月色十分圓。", "胡爲佳客猶辭醉，正恐明年未必然。", "我欲乞身歸去也，懸知此酒是離筵。"]'),
('c8f335db-2a7f-44ef-b787-b8b29c5479f0','和王夷仲雪中見貽','吳芾','宋','宋诗','song-poetry','','[]','歲晚端居寂寞濱，雪花零亂更愁人。',64,'全唐诗/poet.song.114000.json','["歲晚端居寂寞濱，雪花零亂更愁人。", "捲簾已覺青山老，入座仍添白髮新。", "寫景自憐佳句少，論交還喜宿心親。", "來詩况復清如雪，想見吟成泣鬼神。"]'),
('25861e05-fb5a-4964-9689-2e1589f98eed','待雪不至呈子儀','吳芾','宋','宋诗','song-poetry','','[]','冬暖方憂雪意慳，俄然飄灑到人間。',64,'全唐诗/poet.song.114000.json','["冬暖方憂雪意慳，俄然飄灑到人間。", "夜聞便謂迷三徑，曉看依然在半山。", "明日既容殘臘去，今朝已是迫春還。", "如何滕六渾無意，不上雲霄叩九關。"]'),
('145f8874-210a-4e1c-a7be-1712f73d4203','三月十一日風雹','吳芾','宋','宋诗','song-poetry','','[]','向晚欣逢霽色開，方思花下共銜杯。',64,'全唐诗/poet.song.114000.json','["向晚欣逢霽色開，方思花下共銜杯。", "一時雨雹排簷急，萬里風雲捲地來。", "掃蕩千花真可恨，摧殘二麥亦堪哀。", "賞心樂事俱休矣，惆悵青春去不回。"]'),
('1334e476-525c-4856-bdf1-64e40ff35f4a','初夏登城上有感','吳芾','宋','宋诗','song-poetry','','[]','來守孤城忽兩朞，可堪登眺又斜暉。',64,'全唐诗/poet.song.114000.json','["來守孤城忽兩朞，可堪登眺又斜暉。", "經春不見流鶑語，終日唯看乳燕飛。", "風舞新荷青裊裊，烟籠細柳綠依依。", "此邦縱美非吾土，莫怪山翁只念歸。"]'),
('964fc1ed-a022-45c8-ad59-257def9847e1','和朱世同夜坐待月','吳芾','宋','宋诗','song-poetry','','[]','新凉初入我庭中，滿座清風孰與同。',64,'全唐诗/poet.song.114000.json','["新凉初入我庭中，滿座清風孰與同。", "已喜故人來聚首，那堪明月更當空。", "滿傾濁酒休辭醉，剩作新詩莫諱窮。", "屈指如今詩酒社，有誰胸次得如公。"]'),
('3f1c9fa4-25cb-40c1-be55-5d7730cd7400','十六夜再登月臺','吳芾','宋','宋诗','song-poetry','','[]','虛度中秋頗動懷，今宵却再上高臺。',64,'全唐诗/poet.song.114000.json','["虛度中秋頗動懷，今宵却再上高臺。", "强延風月雖聊爾，一對江山亦快哉。", "小子仍携竹葉至，同僚還折桂枝來。", "老夫爲爾牽詩興，笑向花前覆一杯。"]'),
('12786cb5-d239-4b12-b108-e15c9c17f777','中秋後一夕烟雨樓玩月','吳芾','宋','宋诗','song-poetry','','[]','危樓百尺俯層城，烟歛雲收眼更明。',64,'全唐诗/poet.song.114000.json','["危樓百尺俯層城，烟歛雲收眼更明。", "四面月華千頃白，一天秋氣十分清。", "昨宵欲見渾無計，今夕相看似有情。", "又值病夫慵對酒，賞心樂事信難并。"]'),
('85fcb805-fd23-4768-9ef7-f9d9b2881e47','和陳澤民韵','吳芾','宋','宋诗','song-poetry','','[]','雨歇雲收天意回，放教明月下天來。',64,'全唐诗/poet.song.114000.json','["雨歇雲收天意回，放教明月下天來。", "爲憐病守懷三徑，故遣姮娥薦一杯。", "坐上賓僚方共集，城頭更漏莫相催。", "來年此夕知誰在，對月何妨笑口開。"]'),
('863126d4-a9a1-4fad-9f41-e8b737e4e236','寄題魯郎中遂隠堂','吳芾','宋','宋诗','song-poetry','','[]','老向江頭强剖符，夢魂長是繞吾廬。',64,'全唐诗/poet.song.114000.json','["老向江頭强剖符，夢魂長是繞吾廬。", "正慚我未成歸計，却羨君先遂隠居。", "湖上烟雲常縹緲，園中花木總扶疏。", "他時尚冀相從醉，剩把鴟夷載後車。"]'),
('a911ff87-9dec-47b3-b832-d99081c55ff2','送王龜齡得請還鄉  其一','吳芾','宋','宋诗','song-poetry','','[]','兩馳章奏叩天關，只願歸來老故山。',64,'全唐诗/poet.song.114000.json','["兩馳章奏叩天關，只願歸來老故山。", "愧我尚留牽吏役，羨君先去得身閑。", "冥鴻已逐高風舉，倦鳥終隨落照還。", "尚擬杖藜尋舊約，雁峯深處共躋攀。"]'),
('430ec9a2-2df5-4c67-92e8-6db1a9183f36','送王龜齡得請還鄉  其二','吳芾','宋','宋诗','song-poetry','','[]','和氣融融動白蘋，歡傳千里政方新。',64,'全唐诗/poet.song.114000.json','["和氣融融動白蘋，歡傳千里政方新。", "若爲擺落遊珍館，不顧悲啼擁畫輪。", "鯨海無津堪縱目，雁山如舊足怡神。", "願言分我閑中趣，已問君王乞此身。"]'),
('332a3535-833e-4230-a37b-957f705a005d','送江朝宗還鄉','吳芾','宋','宋诗','song-poetry','','[]','欲留車騎少徘徊，歸興那知苦見催。',64,'全唐诗/poet.song.114000.json','["欲留車騎少徘徊，歸興那知苦見催。", "只許霜前同把菊，不容雪裏共觀梅。", "今朝對酒休辭醉，明日有懷誰與開。", "別後願言無爽約，菊花開日又重來。"]'),
('037c5b9c-3d9a-4d5f-b755-19b7f37d9525','和章德文侍郎題晞浣堂韵寄張法師','吳芾','宋','宋诗','song-poetry','','[]','丹成人去幾經年，怪石峻嶒樹曲拳。',64,'全唐诗/poet.song.114000.json','["丹成人去幾經年，怪石峻嶒樹曲拳。", "超脫每思攀逸駕，沉迷無奈縛塵緣。", "勝遊徒有騷人詠，絕景難憑妙筆傳。", "投紱歸來應未晚，尚期一訪洞中仙。"]'),
('4374cb9c-106e-451e-9edc-85c402253c1f','余以前年五月八日到官今年又於此日去郡同僚作餞即席援筆言別','吳芾','宋','宋诗','song-poetry','','[]','來守江山恰二年，同僚何幸得諸賢。',64,'全唐诗/poet.song.114000.json','["來守江山恰二年，同僚何幸得諸賢。", "屢邀風月供吟筆，幾度江山棹酒船。", "自分衰頹今老矣，可堪離索更淒然。", "青雲有路平如砥，公等應須早着鞭。"]'),
('aa2042c0-6302-4c91-b6d6-47859c4d98a2','去郡日寄居諸公作餞即席奉呈','吳芾','宋','宋诗','song-poetry','','[]','三年江上守孤城，日日思歸去未能。',64,'全唐诗/poet.song.114000.json','["三年江上守孤城，日日思歸去未能。", "雖愧憩棠無惠政，却欣伐木有良朋。", "花開後圃春同醉，月滿高樓夜共燈。", "別後要須俱自愛，從今拭目看飛騰。"]'),
('e4bf5b66-e4a4-4543-9f7c-71ab9a4549fb','用天予貢院韵以餞行色','吳芾','宋','宋诗','song-poetry','','[]','直氣如君世莫雙，笑人老死利名場。',64,'全唐诗/poet.song.114000.json','["直氣如君世莫雙，笑人老死利名場。", "一言齟齬身雖去，萬口咨嗟道愈光。", "舌在何妨居澤國，時來會見佐巖廊。", "人間榮辱渾休問，日飲醇醪計亦長。"]'),
('708315fd-857d-4520-b35e-08e79a142e40','和曾吉甫九日','吳芾','宋','宋诗','song-poetry','','[]','龍山陳迹已成灰，尚憶當年戲馬臺。',64,'全唐诗/poet.song.114000.json','["龍山陳迹已成灰，尚憶當年戲馬臺。", "我幸偶陪黄菊醉，君應亦向白衣來。", "風高日朗三秋霽，野曠天清萬象開。", "好對良辰成樂事，若爲不飲竟空回。"]'),
('55eba943-aab9-4b24-b3bf-05571c9ecb24','再辱九日和章連日公冗失於奉賡今日大閲偶於馬上得之兼簡是日座客','吳芾','宋','宋诗','song-poetry','','[]','老子年來百念灰，尚懷月觀與風臺。',64,'全唐诗/poet.song.114000.json','["老子年來百念灰，尚懷月觀與風臺。", "良辰祇恐轉頭過，好景還欣入眼來。", "几席坐窮千里勝，軒窗高揖四山開。", "公餘不厭頻登眺，要伴諸君醉百回。"]'),
('2f3fc7ad-dc49-4f2d-8026-b7c918b5bfe1','重陽有作呈朝宗','吳芾','宋','宋诗','song-poetry','','[]','殘年脚力已摧頹，不謂登高尚可來。',64,'全唐诗/poet.song.114000.json','["殘年脚力已摧頹，不謂登高尚可來。", "每恨故人多爽約，那知今日共銜杯。", "挪挲黄菊香仍在，悵恨朱顔挽不回。", "君若此時猶惜醉，酒懷更待幾時開。"]'),
('f3c242be-0cf0-4126-ac26-a520eba8ccb5','用前韵示三七姪','吳芾','宋','宋诗','song-poetry','','[]','吾家小阮亦賢哉，又得携壺爲我來。',64,'全唐诗/poet.song.114000.json','["吾家小阮亦賢哉，又得携壺爲我來。", "應念難逢重九節，要陪痛飲十分杯。", "頭添白髮那能久，眼看黄花有幾回。", "頗恨病衰鯨量減，只將笑口爲君開。"]'),
('e71e264f-809b-4237-8a8c-f48456aa5b9d','重陽用昔年所作韵','吳芾','宋','宋诗','song-poetry','','[]','行盡天涯鬢欲霜，又來姑孰過重陽。',64,'全唐诗/poet.song.114000.json','["行盡天涯鬢欲霜，又來姑孰過重陽。", "試登翠巘邀珠履，更喚紅裙侑玉觴。", "野菊有花供客眼，公庭無事惱人腸。", "諸君莫惜長鯨量，且伴衰翁入醉鄉。"]'),
('111f88e2-488b-421d-9343-162c98fce23e','和許守重陽出城韵','吳芾','宋','宋诗','song-poetry','','[]','曉從千騎越重闉，軋軋籃輿渡古津。',64,'全唐诗/poet.song.114000.json','["曉從千騎越重闉，軋軋籃輿渡古津。", "萬疊青山烟漠漠，一溪寒水石粼粼。", "笑携紅袖尋蓮社，醉折黄花上葛巾。", "此會從今成故事，他年應記座中人。"]'),
('e6185016-c160-4b26-9281-97e9818a5853','江朝宗許重陽見過候終日竟不聞車音使人悵然因成拙句以誚之','吳芾','宋','宋诗','song-poetry','','[]','故人平日號推誠，然諾應當作世程。',64,'全唐诗/poet.song.114000.json','["故人平日號推誠，然諾應當作世程。", "已是賞花頻爽約，若爲把菊又渝盟。", "詩成本擬君相和，酒熟當憐我獨傾。", "惆悵死生猶未隔，如今先已見交情。"]'),
('c829623c-263e-424c-a82d-986d3acacedc','拙者有重陽詩以陽字韵歲和一篇復繼前作','吳芾','宋','宋诗','song-poetry','','[]','登臨端欲賞秋光，病眼昏花怯太陽。',64,'全唐诗/poet.song.114000.json','["登臨端欲賞秋光，病眼昏花怯太陽。", "老去不堪逢節物，愁來聊復近壺觴。", "沉迷有靦塵埃面，感慨空存鐵石腸。", "已是思歸無可奈，更來高處望家鄉。"]'),
('8af2a919-c290-4546-b7fc-7fe4d45489b2','重陽有感呈諸丈','吳芾','宋','宋诗','song-poetry','','[]','九日長年客異鄉，今年又復到南昌。',64,'全唐诗/poet.song.114000.json','["九日長年客異鄉，今年又復到南昌。", "眼看黄菊依然好，心着青山祇自傷。", "已是歲華成晼晚，可堪秋色更淒涼。", "諸公不用羞吹帽，且試登高共一觴。"]'),
('928d71fa-8c05-4628-b593-90867fc58b14','春閲偶成三首  其一','吳芾','宋','宋诗','song-poetry','','[]','曉驅千騎出郊坰，極目江天萬里晴。',64,'全唐诗/poet.song.114000.json','["曉驅千騎出郊坰，極目江天萬里晴。", "風入鼓鼙聲益壯，日烘旗幟色增明。", "安邊雖是難忘戰，和衆由來在戢兵。", "但願從今烽燧息，早歸林下看昇平。"]'),
('615bfc7d-22fa-4647-96c3-4f806b58a85c','春閲偶成三首  其二','吳芾','宋','宋诗','song-poetry','','[]','大閲歸來日未西，柳絲摇曳草萋迷。',64,'全唐诗/poet.song.114000.json','["大閲歸來日未西，柳絲摇曳草萋迷。", "桑開蟬翼枝方綠，麥露蝦鬚穗半齊。", "池面新荷爭出水，道傍飛燕競銜泥。", "風光撩我歸心動，猶喜初無杜宇啼。"]'),
('7324aa8b-f4ef-41bb-bcb7-599c48997a57','春閲偶成三首  其三','吳芾','宋','宋诗','song-poetry','','[]','肩摩袂屬擁如山，夾道爭看大閲還。',64,'全唐诗/poet.song.114000.json','["肩摩袂屬擁如山，夾道爭看大閲還。", "無限兒童齊拍手，幾多父老盡酡顔。", "八方共樂青春好，我亦常欣白晝閑。", "無奈老來歸念重，夢魂夜夜繞鄉關。"]'),
('1a29aa9b-0055-4aeb-abd3-367d33b88f2b','大閲即事書懷  其一','吳芾','宋','宋诗','song-poetry','','[]','東郊雨後好風烟，大閲歸來意豁然。',64,'全唐诗/poet.song.114000.json','["東郊雨後好風烟，大閲歸來意豁然。", "十里旌旗明照日，九衢鼓吹閙喧天。", "酴醿開也渾如雪，楊柳飛來總是綿。", "景物眼前雖不惡，老來無奈憶林泉。"]'),
('60817c53-508c-4234-aac8-b89ce72dcbfa','大閲即事書懷  其二','吳芾','宋','宋诗','song-poetry','','[]','懶散無堪合杜門，十連帥閫若爲分。',64,'全唐诗/poet.song.114000.json','["懶散無堪合杜門，十連帥閫若爲分。", "仁風尚可揚千里，勇氣安能作六軍。", "戈甲紛紛徒曜日，旌旗獵獵漫連雲。", "歸來夾道人爭看，應笑蒼顔老使君。"]'),
('1c3ae5fc-8212-498d-a08d-5d545744d4ef','和陳澤民詠巖桂','吳芾','宋','宋诗','song-poetry','','[]','我家千樹正芬芳，不見羈懷已倍傷。',64,'全唐诗/poet.song.114000.json','["我家千樹正芬芳，不見羈懷已倍傷。", "豈謂幽姿憐索寞，亦來孤館伴淒涼。", "追尋尚想年時侶，披拂還同故里香。", "花下光陰能有幾，若爲飄泊向江鄉。"]'),
('8c133f70-c8c0-463d-bbce-bef3967e732f','巖桂盛開感而有作','吳芾','宋','宋诗','song-poetry','','[]','抱痾三月未能瘳，樂事都無祇有愁。',64,'全唐诗/poet.song.114000.json','["抱痾三月未能瘳，樂事都無祇有愁。", "忽覺天香參鼻觀，頓令病客展眉頭。", "擬招賓佐同歡賞，奈怯壺觴且罷休。", "却憶向來無事日，年年花下醉千秋。"]'),
('479f2c93-801f-4cb2-be93-ec5e45f5b19f','和天予即席詠巖桂','吳芾','宋','宋诗','song-poetry','','[]','衰病無悰日日加，喜君來自帝王家。',64,'全唐诗/poet.song.114000.json','["衰病無悰日日加，喜君來自帝王家。", "素娥正駕一輪玉，老桂方開雙樹花。", "置酒雖欣陪重客，侑樽還愧乏名娃。", "莫辭今夕如泥醉，須念明朝各一涯。"]'),
('34430101-12fd-4b01-a514-5920ccfedd23','和子儀同賞荷花','吳芾','宋','宋诗','song-poetry','','[]','晚凉領客泛漣漪，境勝形容頗費詩。',64,'全唐诗/poet.song.114000.json','["晚凉領客泛漣漪，境勝形容頗費詩。", "人自紅蓮叢裏過，舟從綠柳岸邊移。", "興來滯思俄然豁，坐久煩襟頓覺披。", "佳客要須拚一醉，莫辜風細月明時。"]'),
('ec2fcb4b-619b-47ec-b4d9-59e4b9ee7700','得三七舍姪書云二月二十五日同族人至湖山賞海棠花枝繁麗宛如神仙窟宅感而有作','吳芾','宋','宋诗','song-poetry','','[]','報言宗族競尋芳，共到吾廬賞海棠。',64,'全唐诗/poet.song.114000.json','["報言宗族競尋芳，共到吾廬賞海棠。", "亭下定知春爛熳，花間想見醉淋浪。", "長年心著神仙窟，此日身縻雲水鄉。", "苦恨欲歸無羽翼，夜深魂夢只悠颺。"]'),
('7e5099b0-5a6c-445a-a0ea-a3d2876f144a','見市上有賣海棠者悵然有感','吳芾','宋','宋诗','song-poetry','','[]','連年蹤跡滯江鄉，長憶吾廬萬海棠。',64,'全唐诗/poet.song.114000.json','["連年蹤跡滯江鄉，長憶吾廬萬海棠。", "想得春來增豔麗，無因歸去賞芬芳。", "偶然擔上逢人賣，猶記樽前爲爾狂。", "何日故園修舊約，剩燒銀燭照紅妝。"]'),
('a91fe443-ed16-4a42-bf13-b3e7b455c161','和昝通彥早梅韵','吳芾','宋','宋诗','song-poetry','','[]','歲歲梅花破臘開，賞花嘗記坐蒼苔。',64,'全唐诗/poet.song.114000.json','["歲歲梅花破臘開，賞花嘗記坐蒼苔。", "今年似覺寒猶未，昨夜不知春已回。", "喜有暗香供雅客，可無佳句助深杯。", "須知不比閑桃李，莫把金刀取次裁。"]'),
('a86ceab5-67c9-4824-8e2e-b51322bd7709','觀梅偶成二首  其一','吳芾','宋','宋诗','song-poetry','','[]','化工一夜報春回，雪裏南枝已漸開。',64,'全唐诗/poet.song.114000.json','["化工一夜報春回，雪裏南枝已漸開。", "不與凡條鬭紅紫，獨將孤豔照池臺。", "勝遊濫綴蓬山侶，高唱寧追郢客才。", "多病自憐心尚在，不辭歲歲爲君來。"]'),
('36cdbd0e-146c-44e8-8163-8d110c9d6c37','觀梅偶成二首  其二','吳芾','宋','宋诗','song-poetry','','[]','經年不見夢魂飛，依舊仙裝淡薄衣。',64,'全唐诗/poet.song.114000.json','["經年不見夢魂飛，依舊仙裝淡薄衣。", "玉骨已無塵俗氣，冰姿還耐雪霜威。", "携壺正欲酬清賞，策杖何妨歷翠微。", "莫惜對花拚劇飲，看看風雨捲春歸。"]'),
('4e1555c0-c19b-415c-9086-c8d14b2ab5a3','遠老惠雪中觀梅詩次韵以謝','吳芾','宋','宋诗','song-poetry','','[]','山頭飛雪已漫漫，雲散須臾復見山。',64,'全唐诗/poet.song.114000.json','["山頭飛雪已漫漫，雲散須臾復見山。", "踏雪不辭來野外，愛梅須遍走林間。", "爲憐孤艷思經目，擬索疏枝笑解顔。", "師肯相過宜及早，預愁花點綠苔斑。"]'),
('4eb5f204-dec3-408f-81a6-6e5d2062a925','遠老自和前詩再寄復次韵','吳芾','宋','宋诗','song-poetry','','[]','雪到梅開恰欲漫，扶藜得得繞湖山。',64,'全唐诗/poet.song.114000.json','["雪到梅開恰欲漫，扶藜得得繞湖山。", "折將冷蕊疏枝去，浸在明窗浄几間。", "一見已堪資琢句，細看還足助怡顔。", "只愁冰艷相侵逼，映得衰翁鬢愈斑。"]'),
('fc04730a-df45-46e7-890c-12d3fd038361','和紫巖老雪中觀梅','吳芾','宋','宋诗','song-poetry','','[]','清寒池館靜沉沉，慘淡江梅弄晚陰。',64,'全唐诗/poet.song.114000.json','["清寒池館靜沉沉，慘淡江梅弄晚陰。", "雪裏有誰能載酒，花前無語自傷心。", "低枝似欲迎人笑，清賞何妨倚樹吟。", "况有爭妍佳句在，愈撩詩思不能禁。"]'),
('59f084be-4d31-44a3-a8e3-7e7809d410f8','賞梅偶成','吳芾','宋','宋诗','song-poetry','','[]','一冬準擬賞江梅，直至如今始見開。',64,'全唐诗/poet.song.114000.json','["一冬準擬賞江梅，直至如今始見開。", "已怪輕寒勒春住，更憂橫雨把花摧。", "相携且看枝頭雪，共坐聊傾樹下杯。", "况是公庭無箇事，何妨一醉習池回。"]'),
('5e066a6f-d18d-434a-8334-20529090eb8a','愛梅','吳芾','宋','宋诗','song-poetry','','[]','經年不得見江梅，繞樹行行日幾回。',64,'全唐诗/poet.song.114000.json','["經年不得見江梅，繞樹行行日幾回。", "已擬開時拚徑醉，其如病後怯銜杯。", "傷心不覺成三歎，忍淚猶能强一來。", "顧我已衰無酒分，從今花更不須開。"]'),
('8c9785d0-850f-4f60-a578-5be11e8827f1','和隠老詠梅韵','吳芾','宋','宋诗','song-poetry','','[]','不憚行行雪滿巔，要看與雪鬭清妍。',64,'全唐诗/poet.song.114000.json','["不憚行行雪滿巔，要看與雪鬭清妍。", "開花雖在三冬杪，結子還居萬木先。", "水淺橫斜聊自見，夜寒幽獨有誰憐。", "君詩况與梅相亞，傳寫慚無十樣牋。"]'),
('d6393b35-affa-48bd-9467-6c3a11b2140f','自京口至建康一路不見梅花慨然有作','吳芾','宋','宋诗','song-poetry','','[]','盡日經行不見梅，竹籬茅屋漫徘徊。',64,'全唐诗/poet.song.114000.json','["盡日經行不見梅，竹籬茅屋漫徘徊。", "無時得遣愁懷去，有底能教詩思來。", "遥想故園應好在，不知今歲爲誰開。", "何時花下還如舊，一笑相看把酒杯。"]'),
('e755b59c-a064-43fa-b248-ec7bc38ebb9a','自建康路中見梅次前韵','吳芾','宋','宋诗','song-poetry','','[]','行盡山岡喜見梅，停驂深欲少徘徊。',64,'全唐诗/poet.song.114000.json','["行盡山岡喜見梅，停驂深欲少徘徊。", "那知急雨連天暗，更有狂風捲地來。", "無計畧臨花下坐，却嗟空向眼前開。", "行人頼有尊中綠，遥想孤芳寄一杯。"]'),
('dfac3c12-d4ae-4261-bc2d-a636803857bc','北山席上見梅偶成','吳芾','宋','宋诗','song-poetry','','[]','聞道前村梅已開，有心踏月共徘徊。',64,'全唐诗/poet.song.114000.json','["聞道前村梅已開，有心踏月共徘徊。", "誰知白日匆匆過，竟阻青鞋得得來。", "席上相逢如有舊，尊前佇立恨無媒。", "樓頭且莫橫孤管，我欲今宵醉百杯。"]'),
('7911e7ba-749b-4696-b29a-390c23b19e03','再和二首  其一','吳芾','宋','宋诗','song-poetry','','[]','一枝昨夜雪中開，報道江南春信回。',64,'全唐诗/poet.song.114000.json','["一枝昨夜雪中開，報道江南春信回。", "自與東君私有約，不須驛使寄將來。", "風姿端是飛瓊侶，標格宜爲弄玉媒。", "莫惜移尊來月下，要看疏影落金杯。"]'),
('6bd9e0e7-43a4-4925-8441-4695d222b683','再和二首  其二','吳芾','宋','宋诗','song-poetry','','[]','平生相見即眉開，幾遣車停馬首回。',64,'全唐诗/poet.song.114000.json','["平生相見即眉開，幾遣車停馬首回。", "窗外每憐隨月到，竹邊還喜過牆來。", "寒香入坐如相覓，幽艷迎人欲自媒。", "不負此花惟有醉，殷勤且覆掌中杯。"]'),
('d0eab643-a3de-4828-83a4-38a95f500a67','用金克家韵賦梅花','吳芾','宋','宋诗','song-poetry','','[]','我賦梅花逼古人，人疑和靖是前身。',64,'全唐诗/poet.song.114000.json','["我賦梅花逼古人，人疑和靖是前身。", "祇思長向花前醉，不厭閑來樹下頻。", "俗眼但知誇潔白，老懷端是愛清真。", "大家管領須宜早，莫待飄零作地茵。"]'),
('8b11191e-76a6-4f3a-87a9-7500e2b73fb8','詩勉及門赴海棠之約','吳芾','宋','宋诗','song-poetry','','[]','君與吾遊積有年，未曾同醉海棠前。',64,'全唐诗/poet.song.114000.json','["君與吾遊積有年，未曾同醉海棠前。", "如今君乃先春到，似赴花朝豈偶然。", "已是詩中參造化，何妨花裏見神仙。", "暫歸莫負重來約，未及春風便着鞭。"]'),
('c3b5c6e6-37af-4100-b643-88f3456d591a','四月六日同江朝宗花下飲','吳芾','宋','宋诗','song-poetry','','[]','十分擬共醉花枝，底事君來苦後期。',64,'全唐诗/poet.song.114000.json','["十分擬共醉花枝，底事君來苦後期。", "芍藥階前猶爛熳，酴醿架上已離披。", "春歸又是辜杯酒，老去還應惜歲時。", "今日要須拚酩酊，從教人笑賞花遲。"]'),
('8079d713-19fd-4471-bb3c-13c3ef8d8ebf','和管大老瑞麥','吳芾','宋','宋诗','song-poetry','','[]','別來長恨見無時，不謂相逢總泣岐。',64,'全唐诗/poet.song.114000.json','["別來長恨見無時，不謂相逢總泣岐。", "愧我滯留身已老，憐君偃蹇宦猶卑。", "思歸正續孤松賦，溢美空傳瑞麥詩。", "萬事從今休更問，祇知痛飲是吾師。"]'),
('f6b89766-50b9-4e17-ab5e-44fbc42fff13','憶鹿鶴','吳芾','宋','宋诗','song-poetry','','[]','山中鹿鶴久相疏，恨不歸來與汝俱。',64,'全唐诗/poet.song.114000.json','["山中鹿鶴久相疏，恨不歸來與汝俱。", "飛舞尚如前日否，奔騰還上後山無。", "不聞警露來庭下，猶想銜花近座隅。", "歎我素鍾山野性，從來與汝本無殊。"]'),
('6a9fe094-5fb4-4bc8-8721-fc5859927944','偶得數琉璃瓶置窗几間因取小魚漾其中乃見其浮遊自適感而有作','吳芾','宋','宋诗','song-poetry','','[]','方安林下樂樵漁，底事牽來剖竹符。',64,'全唐诗/poet.song.114000.json','["方安林下樂樵漁，底事牽來剖竹符。", "道院固知人少訟，豐年何幸俗多娛。", "閑隨野鶴穿花徑，靜看遊鱼戲玉壺。", "却愧此身猶束縛，未能歸去老江湖。"]'),
('2b848112-861a-4d9f-8e06-f7dd4d7c9bfd','和陳義卿','吳芾','宋','宋诗','song-poetry','','[]','自顧迂疏不入時，朅來此地亦何爲。',64,'全唐诗/poet.song.114000.json','["自顧迂疏不入時，朅來此地亦何爲。", "遊從斷絕憑誰語，蹤跡飄零祇自知。", "方喜朋簪今復合，却慚酒盞但空持。", "何時得遂歸休去，把手臨流共賦詩。"]'),
('4201af4e-91ec-4d00-806a-1100c02203ae','和蔣宣卿韵  其一','吳芾','宋','宋诗','song-poetry','','[]','丐閑章上早知還，卓犖高風豈易攀。',64,'全唐诗/poet.song.114000.json','["丐閑章上早知還，卓犖高風豈易攀。", "闊步未歸龍尾道，勝遊先到虎丘山。", "千尋古木軒窗外，一縷沉烟几席間。", "况是登臨有佳客，何妨終夕對孱顔。"]'),
('8ff6db65-e573-4bc6-9856-db72ce5d9382','和蔣宣卿韵  其二','吳芾','宋','宋诗','song-poetry','','[]','不將有限逐無涯，聊爲尋幽駐使華。',64,'全唐诗/poet.song.114000.json','["不將有限逐無涯，聊爲尋幽駐使華。", "千古山川埋劍氣，半空臺閣雨天花。", "終期香火參同社，且賦新詩寄作家。", "歸晚不須添列炬，預愁驚散暮林鴉。"]'),
('3b898b6e-eaba-41eb-acbb-e667aa052b7e','和沈子壽見寄','吳芾','宋','宋诗','song-poetry','','[]','心地荒蕪曠幾春，朅來邂逅共耕耘。',64,'全唐诗/poet.song.114000.json','["心地荒蕪曠幾春，朅來邂逅共耕耘。", "交情正喜清如水，歸興那知去似雲。", "百首漫勞頻寄遠，一樽終擬再論文。", "胡爲竟爾乖前約，寂寞車音杳不聞。"]'),
('8118d77a-0faa-49e3-b56e-45e65dca8132','和梁次張韵','吳芾','宋','宋诗','song-poetry','','[]','妙齡才藻擢文犀，聲價何須待品題。',64,'全唐诗/poet.song.114000.json','["妙齡才藻擢文犀，聲價何須待品題。", "獨狍孤衷長拱北，擬攄妙畫欲平西。", "五年不見心如渴，一笑相逢醉似泥。", "我老已爲林下計，看君平步上雲梯。"]'),
('8565387a-d9e2-437f-be60-434f1cc3bb07','和王夷仲韵','吳芾','宋','宋诗','song-poetry','','[]','灑落胸襟有古風，日臨清泚面巃嵸。',64,'全唐诗/poet.song.114000.json','["灑落胸襟有古風，日臨清泚面巃嵸。", "不堪世路千重險，直與溪流萬折東。", "刮眼相看言有味，傾懷一笑興無窮。", "何時同訪連檣老，快意觥船一棹空。"]'),
('7ff04f5b-691e-4dd8-8261-758f067c6238','和韓子雲見寄四首  其一','吳芾','宋','宋诗','song-poetry','','[]','鬰鬰愁懷不自傾，時時倒指勘歸程。',64,'全唐诗/poet.song.114000.json','["鬰鬰愁懷不自傾，時時倒指勘歸程。", "情知歲月來無幾，心着湖山去未成。", "惡語豈能賡絕唱，故人聊欲話平生。", "頗思共索梅花笑，點檢枝頭半吐英。"]'),
('07155013-5677-45b9-87ba-d902bf072bcf','和韓子雲見寄四首  其二','吳芾','宋','宋诗','song-poetry','','[]','日在桑榆勢欲傾，此時那可更貪程。',64,'全唐诗/poet.song.114000.json','["日在桑榆勢欲傾，此時那可更貪程。", "屢憑熊軾慚無補，新葺燕巢欣有成。", "便好棄官還故里，不妨把酒樂餘生。", "經綸事業須公等，看即持荷侍邇英。"]'),
('bddbf1ae-315b-415a-b678-3a4da2ac1918','和韓子雲見寄四首  其三','吳芾','宋','宋诗','song-poetry','','[]','有花須折酒須傾，少日追歡不計程。',64,'全唐诗/poet.song.114000.json','["有花須折酒須傾，少日追歡不計程。", "老去自憐心易懶，時過還恐道難成。", "城頭又是暮雲合，江上何時春水生。", "早理扁舟歸去好，故園猶有萬紅英。"]'),
('af6e3954-d0a6-4cb7-8c9d-625cd0e094b2','和韓子雲見寄四首  其四','吳芾','宋','宋诗','song-poetry','','[]','當時邂逅已心傾，別後逢人問去程。',64,'全唐诗/poet.song.114000.json','["當時邂逅已心傾，別後逢人問去程。", "顧我拙疏非世用，喜君明悟自天成。", "十年不見懷芝宇，一笑相逢付麯生。", "暫爾就閑宜自愛，上方着意擢豪英。"]'),
('be5cd0fc-9653-4b7a-8870-cb2c082da4d9','僕平日聞有此生待足何時足未老得閑方是閑之句每歎服之恨不知作者姓名一日與魯漕話次方聞此詩乃福唐余倅所作魯繼錄全詩及余君所夢始末見示讀之使人益起懷歸之興因成小詩以記其事','吳芾','宋','宋诗','song-poetry','','[]','寒士叨塵分已踰，不爲歸計待何如。',64,'全唐诗/poet.song.114000.json','["寒士叨塵分已踰，不爲歸計待何如。", "暮年光景那能久，浮世榮華總是虛。", "此去直須甘澹泊，箇中元自有乘除。", "因公拈起余君話，愈使衰翁憶故廬。"]'),
('4e17c9fe-8c31-4459-b754-1920c866990a','挈累來當塗聞已入境感懷有作二首  其一','吳芾','宋','宋诗','song-poetry','','[]','鷗鷺相疏雁鶩親，簿書叢裏度光陰。',64,'全唐诗/poet.song.114000.json','["鷗鷺相疏雁鶩親，簿書叢裏度光陰。", "塵埃已覺胸中滿，霜雪還從鬢上侵。", "盡室修途方在念，連宵苦雨若爲心。", "明朝儻得成團聚，有酒從教取次斟。"]'),
('9b3efa25-9c68-4367-84d0-e1bfd797f45e','挈累來當塗聞已入境感懷有作二首  其二','吳芾','宋','宋诗','song-poetry','','[]','方與晴窗愛日親，若爲天又作重陰。',64,'全唐诗/poet.song.114000.json','["方與晴窗愛日親，若爲天又作重陰。", "年來已是憂思過，老去那堪疾病侵。", "默數七旬寧幾日，更添一歲愈驚心。", "喜聞已辦周身具，對酒何妨且滿斟。"]'),
('d7856353-7774-43e9-8407-a87a8eaa6ea3','和志道送行韵','吳芾','宋','宋诗','song-poetry','','[]','聖君圖治事如何，但見風雲氣象和。',64,'全唐诗/poet.song.114000.json','["聖君圖治事如何，但見風雲氣象和。", "公似一夔奚翅足，我如乘雁豈加多。", "西郊索索飄黄葉，南浦鱗鱗起綠波。", "今日郵亭休恨別，行看麻制草鑾坡。"]'),
('e9997140-a74d-47c0-b685-6a40f71e2149','壽元伯母太夫人八秩','吳芾','宋','宋诗','song-poetry','','[]','七十康强自古稀，年登八秩有誰宜。',64,'全唐诗/poet.song.114000.json','["七十康强自古稀，年登八秩有誰宜。", "壽鍾賢母人難及，慶襲佳兒世共知。", "榮養已爲人子範，清規還作女流師。", "綵衣更戲蘭階下，遥想慈顔笑解頤。"]'),
('5445f457-ad9b-433e-a99a-d1164c8bb04e','送朱彥聰和韵','吳芾','宋','宋诗','song-poetry','','[]','傷時已老壯夫顔，可使分携一日間。',64,'全唐诗/poet.song.114000.json','["傷時已老壯夫顔，可使分携一日間。", "細細梅花薰別酒，依依寒日淡前山。", "由來世上知音少，况是人生會面難。", "他日詩成能念我，寄來莫放驛筒閑。"]'),
('c17deffb-451e-4710-9a94-d1347648786c','送丘尉赴試南宮','吳芾','宋','宋诗','song-poetry','','[]','儒冠鼎盛縉紳多，海內如今數永嘉。',64,'全唐诗/poet.song.114000.json','["儒冠鼎盛縉紳多，海內如今數永嘉。", "士習藝文爭擢第，君明經術合傳家。", "莫言黄綬官猶小，須信青雲路不賒。", "好上漢廷晁董對，要令吾道益光華。"]'),
('5448a309-d2d3-4906-935b-ccad303c5310','送諸鄉人赴試南宮','吳芾','宋','宋诗','song-poetry','','[]','聞道諸君上玉京，一杯聊復話離情。',64,'全唐诗/poet.song.114000.json','["聞道諸君上玉京，一杯聊復話離情。", "青錢既中三年選，黄鵠須看萬里程。", "欲向他時成遠器，要從今日立修名。", "吾君銳意圖興復，好把嘉言對集英。"]'),
('968608d2-72e7-445d-83de-4ea9df698a3f','送二十七弟五三姪赴試南宮','吳芾','宋','宋诗','song-poetry','','[]','家世登科能幾人，兩人今歲奄沉淪。',64,'全唐诗/poet.song.114000.json','["家世登科能幾人，兩人今歲奄沉淪。", "不應天遽衰吾族，會見時當發汝身。", "聯轡莫辭金鐙冷，奪標爭鬭錦袍新。", "還須益勵青雲志，門戶何憂不再振。"]'),
('67ae00d1-7a3c-41f6-a00a-2b6785236d1f','送姪赴廷試  其一','吳芾','宋','宋诗','song-poetry','','[]','經術傳家幾縉紳，孫吳决策舊無人。',64,'全唐诗/poet.song.114000.json','["經術傳家幾縉紳，孫吳决策舊無人。", "上將用武方留意，汝始程能遂發身。", "佇展六韜登上第，更資三釜及偏親。", "兩科自此增雙美，何患衰宗不再振。"]'),
('ddeb3237-57e3-4b16-a04d-21b24583832d','送姪赴廷試  其二','吳芾','宋','宋诗','song-poetry','','[]','昔年三榜偶聯榮，人道吾家好弟兄。',64,'全唐诗/poet.song.114000.json','["昔年三榜偶聯榮，人道吾家好弟兄。", "更喜鴒原俱有子，還來雁塔再題名。", "衰宗正恐儒風墜，晚景那知好事并。", "老子已爲歸去計，從今看汝奮鵬程。"]'),
('10f7e31f-e614-4e2c-a064-72ee003b67e0','和曾吉甫四明見寄二首  其一','吳芾','宋','宋诗','song-poetry','','[]','老矣何堪剖竹符，頻年强出應時須。',64,'全唐诗/poet.song.114000.json','["老矣何堪剖竹符，頻年强出應時須。", "腰間謾佩買臣印，月下同遊賀老湖。", "白雪已知人寡和，清風還憶醉相扶。", "十洲三島登臨處，能記稽山病守無。"]'),
('1ef9d195-0ce2-4f9b-af19-6b8d1e9d81fe','和曾吉甫四明見寄二首  其二','吳芾','宋','宋诗','song-poetry','','[]','風烟浩蕩甬東州，方羨公爲爛漫遊。',64,'全唐诗/poet.song.114000.json','["風烟浩蕩甬東州，方羨公爲爛漫遊。", "豈料連宵垂雨脚，未容杲日出雲頭。", "扶藜登眺心應在，隠几吟哦趣更幽。", "遥想乍晴須痛賞，詩成還肯寄來不。"]'),
('8165a3d3-f046-4763-95db-cc3d5e473068','和梁大諫望亭述懷','吳芾','宋','宋诗','song-poetry','','[]','屢試乘軺與把麾，笑談自可解重圍。',64,'全唐诗/poet.song.114000.json','["屢試乘軺與把麾，笑談自可解重圍。", "暮年强健人爭羨，平日剛方世所稀。", "國步尚艱端有頼，君恩方渥未須歸。", "時清益展經綸手，直上巖廊秉政機。"]'),
('1a1ab946-e642-4e4f-a6ed-3e2f05b1a714','又和陳天予','吳芾','宋','宋诗','song-poetry','','[]','邊敵臨江强指麾，狂圖欲效白登圍。',64,'全唐诗/poet.song.114000.json','["邊敵臨江强指麾，狂圖欲效白登圍。", "一朝殄滅妖氛浄，萬里歡傳盛事稀。", "故國山河看克復，中原父老徯來歸。", "六飛便好乘時進，順取天心莫失機。"]'),
('d90cd931-6e0a-434f-8e2d-d401efebe8cd','月下獨酌有懷梁丈因和前韵以寄且約爲明夜之集','吳芾','宋','宋诗','song-poetry','','[]','晚來清蹕駐旌麾，月色分明徹四圍。',64,'全唐诗/poet.song.114000.json','["晚來清蹕駐旌麾，月色分明徹四圍。", "對景已欣羣動息，仰天還覺衆星稀。", "如今路入中原去，看即春從上苑歸。", "况是昇平時節近，一尊相屬且忘機。"]'),
('ff21c0bf-e5e3-4df3-9a63-81f0a7044b04','和朱文卿見贈','吳芾','宋','宋诗','song-poetry','','[]','簿書終日歎徒勞，俄喜相看有故交。',64,'全唐诗/poet.song.114000.json','["簿書終日歎徒勞，俄喜相看有故交。", "抱道尚稽懷印綬，安貧還不厭衡茅。", "草廬誰識真龍卧，阿閣行看彩鳳巢。", "歸去不妨深閉戶，靜聽修竹晚風敲。"]'),
('19184160-5256-411f-b6b1-cade37d0a746','和林徽之見寄','吳芾','宋','宋诗','song-poetry','','[]','涉世無堪足亂離，蕭蕭風雨一聲雞。',64,'全唐诗/poet.song.114000.json','["涉世無堪足亂離，蕭蕭風雨一聲雞。", "故人別後乾坤窄，三徑歸來草木迷。", "黄鳥翩翻思出谷，老龍頭角尚蟠泥。", "一尊濁酒無人共，又是悲吟到日西。"]'),
('b7bc45bd-2b51-4f8e-8f83-5296a69bd9f6','和韓子雲韵留沈子壽','吳芾','宋','宋诗','song-poetry','','[]','一雨連宵繼日傾，豈容吾子語歸程。',64,'全唐诗/poet.song.114000.json','["一雨連宵繼日傾，豈容吾子語歸程。", "我爲千里政方暇，子寓三年學已成。", "要把老懷傾倒盡，忍令別恨等閑生。", "江城先自傷牢落，况失一時人物英。"]'),
('a260a353-1bd8-4bcb-b9a0-0e5927820b12','和陳澤民見寄三首  其一','吳芾','宋','宋诗','song-poetry','','[]','平生懶病苦難醫，長爲家山詠式微。',64,'全唐诗/poet.song.114000.json','["平生懶病苦難醫，長爲家山詠式微。", "投老但思拋世網，非才安敢近天威。", "不堪人事來如織，况復年華去若飛。", "胸次萬端誰與語，何時玉麈對君揮。"]'),
('141e77d4-72e4-4496-bda6-0f7a9f077f59','和陳澤民見寄三首  其二','吳芾','宋','宋诗','song-poetry','','[]','青衫晚得自蟾宮，簿領雖卑道自隆。',64,'全唐诗/poet.song.114000.json','["青衫晚得自蟾宮，簿領雖卑道自隆。", "不爲小官忘大計，要從舊學著新功。", "忽來書劄情何厚，細讀詩篇句更雄。", "還憶去年相聚日，風前月下酒頻中。"]'),
('58bfb203-327b-4431-844f-bf898a29c014','和陳澤民見寄三首  其三','吳芾','宋','宋诗','song-poetry','','[]','不學羣兒事詭隨，世途雖險此心夷。',64,'全唐诗/poet.song.114000.json','["不學羣兒事詭隨，世途雖險此心夷。", "人生富貴誰無分，男子功名自有時。", "好稱良辰聊適意，莫因末路輒興悲。", "山寒已有梅花放，想見尋梅日有詩。"]'),
('e62d7f4a-cc05-439f-8889-5c3b7634e263','和王夷仲至日有感','吳芾','宋','宋诗','song-poetry','','[]','葭灰管裏氣初浮，陽長陰消不自謀。',64,'全唐诗/poet.song.114000.json','["葭灰管裏氣初浮，陽長陰消不自謀。", "吾道窮耶當復泰，此身老矣不禁愁。", "得閑正好尋詩社，乘興何妨上釣舟。", "擬待梅開同勝賞，且寬歸興少遲留。"]'),
('b85de7e0-c971-4b7e-8801-18516fc5c99a','和曾吉甫寄韵呈李相之二首  其一','吳芾','宋','宋诗','song-poetry','','[]','千齡景運適相符，况復才華世所須。',64,'全唐诗/poet.song.114000.json','["千齡景運適相符，况復才華世所須。", "騰蹋自應登館殿，滯留誰謂尚江湖。", "從來太瘦緣詩苦，想見閑行信杖扶。", "聞道朝來病良愈，高軒還解出門無。"]'),
('a7bdef9c-c85f-4c95-9b77-352723bede7f','和曾吉甫寄韵呈李相之二首  其二','吳芾','宋','宋诗','song-poetry','','[]','早已相從海上州，朅來鑑水又同遊。',64,'全唐诗/poet.song.114000.json','["早已相從海上州，朅來鑑水又同遊。", "驅馳官路俱華髮，繾綣交情異白頭。", "公即橫翔層漢去，我將歸卧故山幽。", "連宵月色如明晝，乘興還能過我不。"]'),
('f99bfadd-4e6c-4059-8001-3bb5c8537f6f','和楊元明雪中見贈','吳芾','宋','宋诗','song-poetry','','[]','爲別多年不記旬，雪中聞到喜難陳。',64,'全唐诗/poet.song.114000.json','["爲別多年不記旬，雪中聞到喜難陳。", "尚稽良會心如渴，頻展新詩手欲皴。", "和寡莫追歌郢客，興來還愧泛溪人。", "要須早了官中事，趁取元宵作好春。"]'),
('37e15368-9f07-4339-bb7b-4698177ca74c','再和','吳芾','宋','宋诗','song-poetry','','[]','老去光陰有幾旬，到官俄見歲華新。',64,'全唐诗/poet.song.114000.json','["老去光陰有幾旬，到官俄見歲華新。", "陡驚懶慢隨年長，更覺衰殘畏客頻。", "愧我方爲牽俗士，羨君欲作獨醒人。", "相逢未用辭歸去，且向雙溪醉早春。"]'),
('ffbd4198-b3e9-4f6d-b0ec-e62798619810','和陳天予冠字韵','吳芾','宋','宋诗','song-poetry','','[]','已是頭童懶整冠，尊前猶欲强追歡。',64,'全唐诗/poet.song.114000.json','["已是頭童懶整冠，尊前猶欲强追歡。", "浮生得滿七旬少，樂事能并四者難。", "閑去稍知心地適，興來殊覺醉鄉寬。", "入朝更誦公詩句，兩腋風生盛暑寒。"]'),
('8e20890b-7cf8-4c4b-bf46-0fcf77faf3e9','和孟世功秋日吳江見寄','吳芾','宋','宋诗','song-poetry','','[]','扁舟西去氣凌雲，坐看魚龍躍浪紋。',64,'全唐诗/poet.song.114000.json','["扁舟西去氣凌雲，坐看魚龍躍浪紋。", "風起白蘋初日晚，霜彫紅葉欲秋分。", "忘機鷗鷺情相狎，入筆江山句不羣。", "正恐功名來追逐，烟波深處未留君。"]'),
('137b776c-b748-4b5c-bb0f-61643b8e8d23','和魯憲見寄','吳芾','宋','宋诗','song-poetry','','[]','一笑同登卷雨樓，相歡曾記昔年不。',64,'全唐诗/poet.song.114000.json','["一笑同登卷雨樓，相歡曾記昔年不。", "幾憑詩句論心曲，屢折花枝作酒籌。", "醉裏忘形俱可樂，別來握手兩無由。", "何時傾倒還如舊，月下花前恣獻酬。"]'),
('dadd692b-eb99-4c8f-aac7-ecc4b333095c','和方叔載留別','吳芾','宋','宋诗','song-poetry','','[]','臨別殷勤贈我詩，一披何喜得如之。',64,'全唐诗/poet.song.114000.json','["臨別殷勤贈我詩，一披何喜得如之。", "怪來筆下能高妙，元是胸中自崛奇。", "長恨頃時纔一面，方欣今歲展雙眉。", "明年莫負論文約，要向新元副所期。"]'),
('686cd68e-2b11-4e27-92e4-26963567b72b','和朱世同詠梅','吳芾','宋','宋诗','song-poetry','','[]','竹籬茅舍舊同居，不見冰姿恰歲餘。',64,'全唐诗/poet.song.114000.json','["竹籬茅舍舊同居，不見冰姿恰歲餘。", "別後有誰親几席，朝來忽喜映階除。", "雪中有酒宜相就，月下無人肯自疏。", "端與歲寒長有約，不須青帝更吹噓。"]'),
('f5893425-8e87-4977-be82-9b016beacf02','和朱世同夜聞竹聲','吳芾','宋','宋诗','song-poetry','','[]','醉卧空齋靜絕人，夜闌霜月白紛紛。',64,'全唐诗/poet.song.114000.json','["醉卧空齋靜絕人，夜闌霜月白紛紛。", "寒生枕上渾無夢，聲到窗前疑是君。", "玉軫誰家調古曲，鐵衣何處角孤軍。", "羨君寫入新詩裏，清壯還應過所聞。"]'),
('066fa7ac-677b-4a6e-86b9-ea848a8a1976','和劉與幾悟昔','吳芾','宋','宋诗','song-poetry','','[]','先生豈是傲當時，知向名場早識機。',64,'全唐诗/poet.song.114000.json','["先生豈是傲當時，知向名場早識機。", "擾擾半生蝴蝶夢，休休今日綠蓑衣。", "筆端信有江山助，醉裏從教日月飛。", "應笑蘧生回首晚，纔知四十九年非。"]'),
('6a376fd9-ae5b-401c-8ae2-0bcc963dc1b9','感舊','吳芾','宋','宋诗','song-poetry','','[]','達宦吾鄉舊罕聞，躋榮兩禁止三人。',64,'全唐诗/poet.song.114000.json','["達宦吾鄉舊罕聞，躋榮兩禁止三人。", "二公嗟已歸長夜，一老知能得幾春。", "軒冕但堪遮俗眼，湖山正好樂天真。", "不妨日日花前醉，已是行年及七旬。"]'),
('147fc9a2-d856-4c28-b83c-bf13b9c0060d','范丞相生日','吳芾','宋','宋诗','song-poetry','','[]','鬰鬰葱葱瑞氣新，中興周室復生申。',64,'全唐诗/poet.song.114000.json','["鬰鬰葱葱瑞氣新，中興周室復生申。", "半千休運逢良月，十二祥蓂表慶辰。", "自有元勳書史冊，漫留遺愛及邦人。", "願同四海躋仁壽，剩賞蟠桃幾萬春。"]'),
('0eb72ddc-21a2-4e60-aaa7-624300ba2e15','老妻生朝爲壽','吳芾','宋','宋诗','song-poetry','','[]','人生七十古來稀，我幸君今及見之。',64,'全唐诗/poet.song.114000.json','["人生七十古來稀，我幸君今及見之。", "教得子能傳素業，養成孫亦守清規。", "稟生坎坷今當泰，積善初終志不移。", "白首喜爲林下伴，願從今日到期頤。"]'),
('2efadd96-9633-460f-abd1-c93a1961ed7d','余年七十輒和樂天詩以自廣','吳芾','宋','宋诗','song-poetry','','[]','已是年齡及七旬，田園稍給未全貧。',64,'全唐诗/poet.song.114000.json','["已是年齡及七旬，田園稍給未全貧。", "兒孫初識傳儒業，世俗還稱作貴人。", "門外湖山渾可樂，沙頭鷗鷺更相親。", "莫將塵事干吾慮，已向君王乞此身。"]'),
('15304396-9cdb-44cc-afa5-ab86ae695429','曾元伯以余七十用韵見慶復和之','吳芾','宋','宋诗','song-poetry','','[]','迂疏如我世間稀，自笑於時百不宜。',64,'全唐诗/poet.song.114000.json','["迂疏如我世間稀，自笑於時百不宜。", "但欲平生無鬼責，豈期長命有天知。", "七旬雖慰白司馬，三黜空慚柳士師。", "多謝君詩遠相慶，一披頓解老人頤。"]'),
('d5138a22-b139-431a-99db-80c8b2379d03','余既和樂天詩而喜於年及之心猶不能自已又復再和八首  其一','吳芾','宋','宋诗','song-poetry','','[]','坐閲流年已七旬，從前憂道不憂貧。',64,'全唐诗/poet.song.114000.json','["坐閲流年已七旬，從前憂道不憂貧。", "肯教世指爲癡漢，只願鄉稱作善人。", "老去固應忘物我，歸來豈是負君親。", "嘗聞知進須知退，庶得終全不辱身。"]'),
('6199b0e7-9f61-4cb2-b5de-28a582232e19','余既和樂天詩而喜於年及之心猶不能自已又復再和八首  其二','吳芾','宋','宋诗','song-poetry','','[]','乞得行年到七旬，歸田不問富和貧。',64,'全唐诗/poet.song.114000.json','["乞得行年到七旬，歸田不問富和貧。", "初非潔己爲高士，但欲頤心如古人。", "每對青山常意適，纔逢白叟便情親。", "靜中百念俱灰滅，識破浮生夢幻身。"]'),
('0e3ed594-bee6-41bf-8743-cca7ecf6099b','余既和樂天詩而喜於年及之心猶不能自已又復再和八首  其三','吳芾','宋','宋诗','song-poetry','','[]','封章上達已經旬，所乞原非爲賤貧。',64,'全唐诗/poet.song.114000.json','["封章上達已經旬，所乞原非爲賤貧。", "七秩自知非久客，一心只欲作閑人。", "雖慚綠鬢朱顔改，却喜清泉白石親。", "榮辱是非都不問，尊前且樂自由身。"]'),
('d56fdf7e-168a-4556-96fb-e43a6a6ec654','余既和樂天詩而喜於年及之心猶不能自已又復再和八首  其四','吳芾','宋','宋诗','song-poetry','','[]','先子春秋僅八旬，一生多難只安貧。',64,'全唐诗/poet.song.114000.json','["先子春秋僅八旬，一生多難只安貧。", "豈期有子登清禁，亦復如今作老人。", "共羨浮榮光故里，自慚實德忝吾親。", "從前萬事皆踰分，只合歸休保此身。"]'),
('a3d8d495-2f51-430c-b782-ab92e16d4eeb','余既和樂天詩而喜於年及之心猶不能自已又復再和八首  其五','吳芾','宋','宋诗','song-poetry','','[]','新歲妻孥慶七旬，遍賙鄰里及孤貧。',64,'全唐诗/poet.song.114000.json','["新歲妻孥慶七旬，遍賙鄰里及孤貧。", "高年滿座有醉客，丐者塞涂無餒人。", "平日要同人喜樂，此時寧間物疏親。", "餘生自度渾能幾，詎可徒勞負此身。"]'),
('44f7132c-9081-40ad-863c-ea130c91c05d','余既和樂天詩而喜於年及之心猶不能自已又復再和八首  其六','吳芾','宋','宋诗','song-poetry','','[]','故園春到已三旬，滿目繁華未覺貧。',64,'全唐诗/poet.song.114000.json','["故園春到已三旬，滿目繁華未覺貧。", "年老得逢無事日，心閑不類有官人。", "戴花休管頭無那，酌酒何妨手自親。", "七十人生從古少，安知來歲有吾身。"]'),
('13425bd7-f6b6-4e9c-9589-972d194bbf4c','余既和樂天詩而喜於年及之心猶不能自已又復再和八首  其七','吳芾','宋','宋诗','song-poetry','','[]','憶在霜臺未六旬，嘗陳仕宦縱家貧。',64,'全唐诗/poet.song.114000.json','["憶在霜臺未六旬，嘗陳仕宦縱家貧。", "豈容七十不納祿，却爲斗升猶牧人。", "年齒幸吾今已及，官曹從此不應親。", "願天許遂終焉志，養此疏慵老大身。"]'),
('4ddf54e8-c45a-4ae0-b79d-71c4c8477f23','余既和樂天詩而喜於年及之心猶不能自已又復再和八首  其八','吳芾','宋','宋诗','song-poetry','','[]','一年三百有餘旬，舉世栖栖苦迫貧。',64,'全唐诗/poet.song.114000.json','["一年三百有餘旬，舉世栖栖苦迫貧。", "得享安寧七十歲，已勝衰謝萬千人。", "好官縱使登三事，榮養何由及二親。", "爭似山間林下坐，無憂無毀足全身。"]'),
('5988407c-56f4-4456-b21f-61bb26f36899','乞身不獲再和','吳芾','宋','宋诗','song-poetry','','[]','老合休官况七旬，我非辭富欲居貧。',64,'全唐诗/poet.song.114000.json','["老合休官况七旬，我非辭富欲居貧。", "也知光景無多日，更覺筋骸不逮人。", "豈謂九重恩未替，復頒一札意猶親。", "囊封再上終期允，已對蒼穹誓此身。"]'),
('753e45d0-86bf-4d54-a850-cc499921518d','懷歸有作','吳芾','宋','宋诗','song-poetry','','[]','一病兼旬百不禁，愈牽歸夢繞家林。',64,'全唐诗/poet.song.114000.json','["一病兼旬百不禁，愈牽歸夢繞家林。", "向來豈有功名念，此去斷無人我心。", "但願天憐將就木，許從人欲便投簪。", "若蒙不靳清閑福，尚惜餘年盡寸陰。"]'),
('a140563b-b873-4aa8-961e-2067543af83d','和四哥錢塘思歸韵','吳芾','宋','宋诗','song-poetry','','[]','鬰鬰羈懷久欲東，故園何日割蒿蓬。',64,'全唐诗/poet.song.114000.json','["鬰鬰羈懷久欲東，故園何日割蒿蓬。", "可堪世路塵纓縛，却使雲山蕙帳空。", "待價深藏非左計，汗顔爲斲豈良工。", "須知呂望嚴陵輩，亦是滄浪一釣翁。"]'),
('d64612d3-1c8e-4ddd-863d-a4c6b5916196','讀丐辭不允詔書感而有作  其一','吳芾','宋','宋诗','song-poetry','','[]','朅來江上再經年，衰病無時强自憐。',64,'全唐诗/poet.song.114000.json','["朅來江上再經年，衰病無時强自憐。", "屢控危衷甘屏縮，豈期優詔更留連。", "政平訟理曾何補，職稱民安亦偶然。", "雖感上恩容卧治，何如便許老林泉。"]'),
('2902abaa-2bf4-46a0-bfc4-31078dc4a0da','讀丐辭不允詔書感而有作  其二','吳芾','宋','宋诗','song-poetry','','[]','齒豁頭童已暮年，未容歸去亦堪憐。',64,'全唐诗/poet.song.114000.json','["齒豁頭童已暮年，未容歸去亦堪憐。", "只思舊隠如元亮，寧有新詩似惠連。", "萬事此生渾已矣，一尊今日且陶然。", "宦情况復清如水，何必移封向酒泉。"]'),
('e6c6cdfd-b00d-464d-a99f-78ba594c4ee9','復和憐字韵二首  其一','吳芾','宋','宋诗','song-poetry','','[]','擬歸林下度餘年，底事天公不見憐。',64,'全唐诗/poet.song.114000.json','["擬歸林下度餘年，底事天公不見憐。", "新歲已驚青鬢換，故園還想綠陰連。", "敢萌癡意貪非據，但欲冥心任自然。", "今日有誰聞此語，祇應白石與清泉。"]'),
('ba2b6e3f-e63b-4958-b720-641041816c37','復和憐字韵二首  其二','吳芾','宋','宋诗','song-poetry','','[]','春色撩人勝去年，鶑啼燕語若相憐。',64,'全唐诗/poet.song.114000.json','["春色撩人勝去年，鶑啼燕語若相憐。", "一川烟水清還淺，萬疊雲山斷復連。", "好景會心宜樂矣，故園回首却悽然。", "同僚頼有清新句，似聽松風潄玉泉。"]'),
('4ea3a099-59ce-424c-885e-5265b24e0152','二兒納婦有感','吳芾','宋','宋诗','song-poetry','','[]','老乘一障楚江濱，無奈星星鬢影新。',64,'全唐诗/poet.song.114000.json','["老乘一障楚江濱，無奈星星鬢影新。", "客裏情懷那似舊，忙中日月不知春。", "若爲經歲拋泉石，猶把非才玷縉紳。", "還盡此生兒女債，盍歸林下作閑人。"]'),
('444b3ed2-0035-4e88-af3b-c63270795878','重陽用去年韵  其一','吳芾','宋','宋诗','song-poetry','','[]','不堪秋色已悲凉，那更重陽對夕陽。',64,'全唐诗/poet.song.114000.json','["不堪秋色已悲凉，那更重陽對夕陽。", "白髮蒼顔羞覽鏡，紫萸黄菊喜浮觴。", "且來高處開心目，莫引愁端撓肺腸。", "未信天教長作客，會須有日放還鄉。"]'),
('db6adca2-e6e8-43b1-8bfa-822db9c6f1d7','重陽用去年韵  其二','吳芾','宋','宋诗','song-poetry','','[]','此生幾度換炎凉，過了重陽又一陽。',64,'全唐诗/poet.song.114000.json','["此生幾度換炎凉，過了重陽又一陽。", "無奈流年如轉轂，得逢佳節且飛觴。", "風前落帽從吹鬢，江上登臺任斷腸。", "老去已忘榮與辱，只思歸卧水雲鄉。"]'),
('0ad37cdb-6e69-4a01-81f1-4500e66fd29a','池上近作假山引水穿石撒珠其上亦有可觀因成拙句','吳芾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','終日塵勞困簿書，無因歸泛小西湖。',64,'全唐诗/poet.song.114000.json','["終日塵勞困簿書，無因歸泛小西湖。", "且來池上看堆翠，更向峯前認撒珠。", "觸石有雲時點綴，隨風無雨自霑濡。", "老夫行矣休官去，留與邦人作畫圖。"]'),
('e214a9e8-1dcc-4f13-9728-f47829c21a2a','假山','吳芾','宋','宋诗','song-poetry','','[]','我愛青山欲細看，如何不在戶庭間。',64,'全唐诗/poet.song.114000.json','["我愛青山欲細看，如何不在戶庭間。", "聊移野外玲瓏石，來作窗前重疊山。", "拄笏已堪供嘯詠，杖藜還更得躋攀。", "莫言道院過從少，亦有修眉相伴閑。"]'),
('a4883c45-11a0-4325-b4db-86f8a523d68d','生日','吳芾','宋','宋诗','song-poetry','','[]','藜杖綸巾度幾春，紫袍頳带一番新。',64,'全唐诗/poet.song.114000.json','["藜杖綸巾度幾春，紫袍頳带一番新。", "恩榮可但將延世，渥澤還欣再及親。", "已見里中誇盛事，何妨林下作閑人。", "年踰七十仍希有，壽酒須拚飲百巡。"]'),
('56d8d9e2-383d-4878-8795-bcbbca12b573','謝錢參惠馿','吳芾','宋','宋诗','song-poetry','','[]','白髮衰翁七十餘，尚勞軫記特馳書。',64,'全唐诗/poet.song.114000.json','["白髮衰翁七十餘，尚勞軫記特馳書。", "知無仙骨能騎鶴，喜有殘骸可跨馿。", "廐下分來齊駿駟，林間乘去勝巾車。", "更煩拈出荆申事，遐想風流愧莫如。"]'),
('dec532d2-7360-4fe8-998f-03d1995ae022','聞故舊二三公或不幸於官或以疾病而去或以口語而罷悵然有感','吳芾','宋','宋诗','song-poetry','','[]','平日衰遲衆所憐，偶逢亨運亦騰騫。',64,'全唐诗/poet.song.114000.json','["平日衰遲衆所憐，偶逢亨運亦騰騫。", "七旬已過宜休矣，一出不歸終溘然。", "幸免煩言全晚節，且無多病惱殘年。", "直須更作投簪計，莫待將身到九泉。"]'),
('52870756-070b-43e9-81fb-ae6ccea02da3','寄周表卿','吳芾','宋','宋诗','song-poetry','','[]','別來星紀兩周天，夢想風標每慨然。',64,'全唐诗/poet.song.114000.json','["別來星紀兩周天，夢想風標每慨然。", "靖退喜公今就第，奔馳愧我未歸田。", "得閑正好哦詩句，乘興何妨棹酒船。", "頗恨路長還病暑，無由一見話當年。"]'),
('f1bb3248-6ed9-456f-a47f-b7dcda9588c0','再和','吳芾','宋','宋诗','song-poetry','','[]','舉世爭披樂廣天，得聯契好豈徒然。',64,'全唐诗/poet.song.114000.json','["舉世爭披樂廣天，得聯契好豈徒然。", "少留接武遊麟閣，晚更先期到鹿田。", "此日莫登揚子宅，何時能泛剡溪船。", "儻容一夜陪清話，勝把陳編讀十年。"]'),
('06e3c645-22e8-43a5-b6be-73ec3b974564','和劉正夫見寄  其一','吳芾','宋','宋诗','song-poetry','','[]','攬轡澄清慕古人，觀風問俗按行頻。',64,'全唐诗/poet.song.114000.json','["攬轡澄清慕古人，觀風問俗按行頻。", "振荒已視饑由己，畜水猶思利及民。", "美意共推君體國，高懷還喜我抽身。", "名章下逮情何厚，和氣薰然暖似春。"]'),
('d7806da5-cc23-4742-86b8-c01c0cb4632f','和劉正夫見寄  其二','吳芾','宋','宋诗','song-poetry','','[]','已是龍鍾七十人，故應告老上章頻。',64,'全唐诗/poet.song.114000.json','["已是龍鍾七十人，故應告老上章頻。", "九重垂念如慈父，一旦容歸作幸民。", "今我可憐非故我，此身纔喜是吾身。", "花前幸有尊中醁，且醉湖山幾度春。"]'),
('0e081355-02fb-4a97-99f5-27df6fbc992c','和澤民二首  其一','吳芾','宋','宋诗','song-poetry','','[]','歸心已動不容留，多謝君恩許退休。',64,'全唐诗/poet.song.114000.json','["歸心已動不容留，多謝君恩許退休。", "雖喜溪山歸似舊，却驚歲月去如流。", "門前已是開三徑，湖上何妨具一舟。", "莫道此時無伴侶，得公足可共遨遊。"]'),
('88648827-767a-4d57-b06b-d1b952cea516','和澤民二首  其二','吳芾','宋','宋诗','song-poetry','','[]','欲紹家聲每自鞭，肯同流俗飲貪泉。',64,'全唐诗/poet.song.114000.json','["欲紹家聲每自鞭，肯同流俗飲貪泉。", "已將止足安心地，更把吟哦樂性天。", "笑日桃花將獻媚，先春梅蕊欲爭妍。", "人生會合真難遇，幸有杯觴且共傳。"]'),
('fee5f277-fbf3-4fd2-a712-39a506c4bb1d','和蔣無退懷湖山','吳芾','宋','宋诗','song-poetry','','[]','多謝君恩許引年，容親白石與清泉。',64,'全唐诗/poet.song.114000.json','["多謝君恩許引年，容親白石與清泉。", "不來山下尋詩社，即向湖中棹酒船。", "意適更穿花塢去，興闌還傍竹林眠。", "那聞高士飄然句，陡覺身輕似得仙。"]'),
('594efaf4-8a3c-4793-b618-4d3035019bb4','志道相見和前韵','吳芾','宋','宋诗','song-poetry','','[]','每憶湖山動老懷，今朝始作故鄉回。',64,'全唐诗/poet.song.114000.json','["每憶湖山動老懷，今朝始作故鄉回。", "正慚行李匆匆去，忽報軺車得得來。", "幸對清談揮玉麈，肯辭痛飲倒金杯。", "我歸已遂終焉計，何日重逢笑口開。"]'),
('47c349a0-71db-42c8-8679-88bfdc1bac31','李子儀喜津改秩作詩相慶因次韵  其一','吳芾','宋','宋诗','song-poetry','','[]','懶復從人問里評，縱今得譽亦虛聲。',64,'全唐诗/poet.song.114000.json','["懶復從人問里評，縱今得譽亦虛聲。", "有兒第使傳儒業，改秩何期冒寵榮。", "敢望芝蘭如謝氏，但親松菊學淵明。", "煩君慰藉來佳句，讀罷欣然酒一傾。"]'),
('55ae6b47-38d0-4361-9fa3-3d18daaf3543','李子儀喜津改秩作詩相慶因次韵  其二','吳芾','宋','宋诗','song-poetry','','[]','有屋依山復面湖，幽棲試問有誰如。',64,'全唐诗/poet.song.114000.json','["有屋依山復面湖，幽棲試問有誰如。", "門前更種千竿竹，堂上還堆萬卷書。", "每恨暮年方卜築，豈知今日得安居。", "鯉庭况有新桃李，莫惜時來長者車。"]'),
('29a883ea-ec52-4e84-aedf-ca9f4876e1c0','歸來到紅梅下有感','吳芾','宋','宋诗','song-poetry','','[]','惜花端擬醉花時，不謂花開失素期。',64,'全唐诗/poet.song.114000.json','["惜花端擬醉花時，不謂花開失素期。", "去日橫枝纔蓓蕾，歸來滿樹已離披。", "雖知勝賞輸同舍，尚愛餘芳繞曲池。", "花亦念予情不淺，更留殘萼索題詩。"]'),
('8213e8b0-afe2-4c6b-bdac-51c03aa679d4','二月望日三七姪移庖於休休堂約四老人爲送春之集拙者預一老之數因成八句','吳芾','宋','宋诗','song-poetry','','[]','光陰過眼似奔輪，誰保生前夢幻身。',64,'全唐诗/poet.song.114000.json','["光陰過眼似奔輪，誰保生前夢幻身。", "四老共成三百歲，一時已勝萬千人。", "得閒對酒須拚醉，乘健看花莫厭頻。", "勿謂病多衰已甚，尚堪開口送殘春。"]'),
('f32e1f36-e690-4667-8561-2080c8949ce5','偶苦耳聾','吳芾','宋','宋诗','song-poetry','','[]','衰年已是病雙瞳，那更新添兩耳聾。',64,'全唐诗/poet.song.114000.json','["衰年已是病雙瞳，那更新添兩耳聾。", "山外鐘聲元不到，窗前雞唱亦難通。", "便遭謗駡安能累，縱有笙歌也是空。", "每恨肚皮從舊窄，而今却做得家翁。"]'),
('16cc7c05-10e3-453c-b972-69abba746217','巢內燕園中鹿俱生子喜而有作','吳芾','宋','宋诗','song-poetry','','[]','倦似淵明懶似嵇，歸來聊向此中棲。',64,'全唐诗/poet.song.114000.json','["倦似淵明懶似嵇，歸來聊向此中棲。", "湖山圍繞吾廬靜，草樹高低野望迷。", "燕葺新巢方乳子，鹿遊故苑又生麛。", "眼前景物俱堪賦，落日何妨一杖藜。"]'),
('d4f1ddd5-ef9f-44a0-b573-4891b113b8f2','有感','吳芾','宋','宋诗','song-poetry','','[]','自度吾生不久長，老懷猶自愛風光。',64,'全唐诗/poet.song.114000.json','["自度吾生不久長，老懷猶自愛風光。", "春來扶杖觀花急，夏到穿林看筍忙。", "無限故人成鬼錄，幾多逐客寓他鄉。", "我今幸得身無事，剩向湖邊醉幾場。"]'),
('fa478e09-df08-4334-8b85-29bc2f6ecc75','和江朝宗韵奉寄','吳芾','宋','宋诗','song-poetry','','[]','休言簿領尚沉迷，器業如公豈久稽。',64,'全唐诗/poet.song.114000.json','["休言簿領尚沉迷，器業如公豈久稽。", "不見自憐心若失，相從還記手同携。", "飛黄正欲馳長坂，倦翼方欣返故棲。", "出處不同空悵望，何時來過武陵溪。"]'),
('f344ae68-43a8-4419-81e1-61fe2565b9ce','陳天予喜拙者得謝作詩相慶次韵以報來辱','吳芾','宋','宋诗','song-poetry','','[]','一自同簪獬豸冠，幾經離合幾悲歡。',64,'全唐诗/poet.song.114000.json','["一自同簪獬豸冠，幾經離合幾悲歡。", "荷君終始於人厚，知我疏慵涉世難。", "聞道休官能自適，惠然貽問更相寬。", "交遊耐久如君少，松柏方能保歲寒。"]'),
('dd3dc861-fd62-4f1e-8eb2-bc035940fac1','再用前韵奉寄','吳芾','宋','宋诗','song-poetry','','[]','向來雖著侍臣冠，憂國曾無一日歡。',64,'全唐诗/poet.song.114000.json','["向來雖著侍臣冠，憂國曾無一日歡。", "正色立朝從古少，犯顔論事似君難。", "思賢會見重相得，樂聖何妨且自寬。", "回首高風誰復繼，凜然名節照人寒。"]'),
('d8026f0d-3ae6-400e-9696-afb0f1c1d6e1','趙默卿用拙者所和樂天七旬詩賦二篇見寄因狀山中之景復成一首以報之','吳芾','宋','宋诗','song-poetry','','[]','買山將近一由旬，若比淵明未是貧。',64,'全唐诗/poet.song.114000.json','["買山將近一由旬，若比淵明未是貧。", "萬疊峰巒俱入眼，四時景物總宜人。", "花開自足供心賞，酒熟何妨與客親。", "何日杖藜能過我，竹林深處共藏身。"]'),
('e24122b1-c49d-471c-ab28-418d37fa1ef5','龔帥以久別寄詩遠惠因次其韵  其一','吳芾','宋','宋诗','song-poetry','','[]','性便野服厭朝裾，一意歸休學二疏。',64,'全唐诗/poet.song.114000.json','["性便野服厭朝裾，一意歸休學二疏。", "門外渾無俗士駕，案頭惟有道家書。", "勝遊但欲尋蓬島，舊事那能記石渠。", "亦擬冥搜酬絕唱，慚將瓦礫報瓊琚。"]'),
('baa13c59-4f75-42e4-a7c8-878a9047b11a','龔帥以久別寄詩遠惠因次其韵  其二','吳芾','宋','宋诗','song-poetry','','[]','天與疏慵一味閒，許辭畫戟老柴關。',64,'全唐诗/poet.song.114000.json','["天與疏慵一味閒，許辭畫戟老柴關。", "幾年欲作冥鴻舉，今日方隨倦鳥還。", "有水不妨時載月，無人誰與共登山。", "相望千里空相憶，尊酒何時一破顔。"]'),
('d3cc5cce-7dde-47d2-aefa-1f152db07956','再和龔帥所寄  其一','吳芾','宋','宋诗','song-poetry','','[]','契濶經年阻曳裾，滿簪華髮愈蕭疏。',64,'全唐诗/poet.song.114000.json','["契濶經年阻曳裾，滿簪華髮愈蕭疏。", "五禽聊作林間戲，雙鯉忽傳江上書。", "詩句方慚成間斷，交情豈謂益勤渠。", "開緘更誦驚人語，恍若相從聽珮琚。"]'),
('7709f397-497f-4ed6-8a32-6d89c25c21f1','再和龔帥所寄  其二','吳芾','宋','宋诗','song-poetry','','[]','聞道公庭白晝閒，更無夜犬吠江關。',64,'全唐诗/poet.song.114000.json','["聞道公庭白晝閒，更無夜犬吠江關。", "一時戾氣俱銷盡，千載淳風頓使還。", "但恐賜環來北闕，不容拄笏看西山。", "祇今汲直如公少，正頼忠言一犯顔。"]'),
('877799d2-5479-41ad-8fc7-e7aae7e63dbe','和朱文卿落解後書懷','吳芾','宋','宋诗','song-poetry','','[]','先生英氣欲橫秋，唾手功名豈待求。',64,'全唐诗/poet.song.114000.json','["先生英氣欲橫秋，唾手功名豈待求。", "共指層霄看展翼，誰知平地亦沉舟。", "簀中宰相寧嫌辱，胯下將軍未足羞。", "有志會須騰踏去，莫將富貴羨王侯。"]'),
('d15ce11b-e1ba-4f00-bb5b-995b14f719b4','清明登白紵山','吳芾','宋','宋诗','song-poetry','','[]','偷得鈴齋半日閒，喜逢佳節漫追攀。',64,'全唐诗/poet.song.114000.json','["偷得鈴齋半日閒，喜逢佳節漫追攀。", "扶衰强策青藜杖，尋勝聊登白紵山。", "遠岫千重雲出沒，清溪一带水回環。", "我來恨未窮游覽，回首孤城落照間。"]'),
('9970afe5-8c98-4665-a84a-d8f9d2b52294','謝子肅任崑山丞和余留題舊游詩復次韵謝之','吳芾','宋','宋诗','song-poetry','','[]','故鄉春好阻同游，誰與花前倒玉舟。',64,'全唐诗/poet.song.114000.json','["故鄉春好阻同游，誰與花前倒玉舟。", "陳迹未能忘茂苑，新詩俄喜寄丹丘。", "開緘已慰三年別，展誦還消萬斛愁。", "文行如君今日少，藍田寧許久淹留。"]'),
('85d8e269-b375-4239-8d47-b66d67958eef','臨湖閣爲向巨源郎中題','吳芾','宋','宋诗','song-poetry','','[]','胸襟灑落一塵無，晚歲歸來足自娛。',64,'全唐诗/poet.song.114000.json','["胸襟灑落一塵無，晚歲歸來足自娛。", "去國何須懷北地，卜居且喜面東湖。", "夕陽影裏山相映，古木陰中鳥自呼。", "正好凴欄吟復醉，胡爲止酒太拘拘。"]'),
('1899b3a1-ded3-4ca6-bcb9-badef0c02367','拙者得歸子儀喜而作詩見寄因次韵','吳芾','宋','宋诗','song-poetry','','[]','奉祠命下大明宮，盡室歡呼笑語同。',64,'全唐诗/poet.song.114000.json','["奉祠命下大明宮，盡室歡呼笑語同。", "但欲從容全晚節，敢言高尚激貪風。", "醉鄉有約誰陪我，詩社無人頼有公。", "從此故山添勝事，未饒弘景相山中。"]'),
('b7b870c7-44f9-4102-a185-0ae5acb079cd','和道叟韵','吳芾','宋','宋诗','song-poetry','','[]','自憐涉世太迂疏，豈料今朝得自如。',64,'全唐诗/poet.song.114000.json','["自憐涉世太迂疏，豈料今朝得自如。", "老去不知官况好，歸來頓覺道心舒。", "湖山深處非凡景，松竹陰中有舊廬。", "靜坐忽聞烏鵲喜，開門還得故人書。"]'),
('03fc9477-bc1b-4f93-aeee-03315624318e','澤民因誦樂天欲留年少待富貴富貴不來年少去之句慨然有感遂廣此意作詩相示余以謂人之會遇各自有時年少固不可留而時亦何可待樂天自不應出此語而澤民亦不應爲此詩因反其意以和之  其一','吳芾','宋','宋诗','song-poetry','','[]','老去疏慵厭仕途，歸來林下學真如。',64,'全唐诗/poet.song.114000.json','["老去疏慵厭仕途，歸來林下學真如。", "不思身外千般事，只占人間一味愚。", "但得清尊長對客，縱添白髮亦從渠。", "世間達宦多憂畏，胸次還能似我無。"]'),
('8c696e17-63cb-4d9d-a789-f75ce3317211','澤民因誦樂天欲留年少待富貴富貴不來年少去之句慨然有感遂廣此意作詩相示余以謂人之會遇各自有時年少固不可留而時亦何可待樂天自不應出此語而澤民亦不應爲此詩因反其意以和之  其二','吳芾','宋','宋诗','song-poetry','','[]','勸君且醉甕頭春，休把升沉累此身。',64,'全唐诗/poet.song.114000.json','["勸君且醉甕頭春，休把升沉累此身。", "自古功名須遇主，到頭富貴不由人。", "蟠胸器業元高世，落筆詞章更出塵。", "道在何憂年少去，九重前席會相親。"]'),
('baec7415-6e3b-4b78-b7c3-339e2087e428','和李光祖  其一','吳芾','宋','宋诗','song-poetry','','[]','英才端合在星躔，不謂淹回閲歲年。',64,'全唐诗/poet.song.114000.json','["英才端合在星躔，不謂淹回閲歲年。", "却向山中親白石，更來澗下濯清泉。", "高情雖似秋雲淡，麗句還如蜀錦鮮。", "怪得了無塵俗氣，家風元是謫來仙。"]'),
('fc93405e-00d2-4ead-997d-f52c48e295f9','和李光祖  其二','吳芾','宋','宋诗','song-poetry','','[]','老去深悲寵辱驚，歸來胸次渺寰瀛。',64,'全唐诗/poet.song.114000.json','["老去深悲寵辱驚，歸來胸次渺寰瀛。", "登山臨水隨宜坐，問柳尋花信意行。", "境勝已勾詩興動，身閒還引道心生。", "親知滿眼如君少，何不時來共一觥。"]'),
('784a4e54-df0b-4e9d-be65-da9c9f304986','和李光祖  其三','吳芾','宋','宋诗','song-poetry','','[]','男子升沉自有時，莫輕感慨歎稽遲。',64,'全唐诗/poet.song.114000.json','["男子升沉自有時，莫輕感慨歎稽遲。", "古來常患才難得，道在寧憂世不知。", "會際亨嘉膺晝接，且將粗糲療朝饑。", "他年富貴君何慮，造物於人豈有私。"]'),
('80501495-2e08-4a99-86d6-7a38211eb2ca','和田伯清見寄  其一','吳芾','宋','宋诗','song-poetry','','[]','可歎人生有限身，終朝長是困囂塵。',64,'全唐诗/poet.song.114000.json','["可歎人生有限身，終朝長是困囂塵。", "向來每愧爲人役，今日方能保我真。", "幸有一丘堪避俗，何妨百歲作閒人。", "更煩妙句相褒借，頓覺柴門暖似春。"]'),
('b7829be2-3d50-4bb1-878d-a0534466f71f','和田伯清見寄  其二','吳芾','宋','宋诗','song-poetry','','[]','落筆摛辭爛有章，故應往歲擅文場。',64,'全唐诗/poet.song.114000.json','["落筆摛辭爛有章，故應往歲擅文場。", "身登霄漢聲猷著，興寄湖山氣味長。", "無計盍簪同把酒，尚懷掃地對焚香。", "依然日暮碧雲合，相望回頭各一方。"]'),
('f8c1ec3a-f352-42c3-8b0a-6387e80cb1fd','和楊季恪景疏希白二首  其一','吳芾','宋','宋诗','song-poetry','','[]','二疏高躅聳簪紳，寂寞無人繼後塵。',64,'全唐诗/poet.song.114000.json','["二疏高躅聳簪紳，寂寞無人繼後塵。", "一代風流雖已遠，千年名德鎮如新。", "幸拋印綬歸空谷，得與湖山作好春。", "若較前賢那可並，却慚溫詔下嚴宸。"]'),
('b8fe678a-aa4f-487d-a179-d3dd2e675025','和楊季恪景疏希白二首  其二','吳芾','宋','宋诗','song-poetry','','[]','人譏居士老來迂，與世依違總不符。',64,'全唐诗/poet.song.114000.json','["人譏居士老來迂，與世依違總不符。", "雖似子牟懷魏闕，却同居易學浮屠。", "鋤荒只欲開三徑，適意寧論泛五湖。", "胸次更無塵一點，且同高士話虛無。"]'),
('86e0240a-6649-441b-a7c5-ddd9f7f3b84a','和胡宗澤見寄  其一','吳芾','宋','宋诗','song-poetry','','[]','湖邊策杖步新晴，陡覺胸襟萬慮平。',64,'全唐诗/poet.song.114000.json','["湖邊策杖步新晴，陡覺胸襟萬慮平。", "老去不須防意馬，靜中已是息心兵。", "閒來綠樹陰中坐，懶去紅塵閙裏行。", "頼與故人供一醉，不辜今夜月華明。"]'),
('be6e7c96-8860-4bdc-94a4-8998bd8ac597','和胡宗澤見寄  其二','吳芾','宋','宋诗','song-poetry','','[]','故人皮裏貯陽秋，愛我身如不繫舟。',64,'全唐诗/poet.song.114000.json','["故人皮裏貯陽秋，愛我身如不繫舟。", "羞向人間爲諂首，喜來林下作遨頭。", "雖無仙骨能騎鶴，尚有閒心可狎鷗。", "乘興惠然時過我，一樽相對笑言稠。"]'),
('3ac7757a-c233-4eb7-aaa3-45c9f4848bb2','和李光祖二首  其一','吳芾','宋','宋诗','song-poetry','','[]','漏殘休更問銅壺，自視平生分已踰。',64,'全唐诗/poet.song.114000.json','["漏殘休更問銅壺，自視平生分已踰。", "每歎奔馳非得計，只知靜退是良圖。", "耽詩况味今雖在，愛酒情懷近已無。", "詔比二疏吾豈敢，或言出處亦相符。"]'),
('25c965b8-8d3b-4f36-9c26-0d6ad50911c2','和李光祖二首  其二','吳芾','宋','宋诗','song-poetry','','[]','天資灑落更瑰奇，何患諸公不己知。',64,'全唐诗/poet.song.114000.json','["天資灑落更瑰奇，何患諸公不己知。", "運蹇尚須資汲引，時來寧復藉維持。", "家聲况是鈞公裔，文采還高幼婦碑。", "大器成時須在晚，如君方壯未爲遲。"]'),
('fdde8249-e880-44a4-84eb-dc31b4497b20','和孟世功二首  其一','吳芾','宋','宋诗','song-poetry','','[]','老大疏慵一腐儒，長年離索與誰俱。',64,'全唐诗/poet.song.114000.json','["老大疏慵一腐儒，長年離索與誰俱。", "杜門有意修黄老，開卷無心誦典謨。", "不是穿林尋鶴鹿，即來臨水伴龜魚。", "故人今日如君少，乘興還能過我無。"]'),
('13964a11-371d-4ed0-95e8-d5dfb0e31c6f','和孟世功二首  其二','吳芾','宋','宋诗','song-poetry','','[]','不見風標六歲餘，閒中應是樂琴書。',64,'全唐诗/poet.song.114000.json','["不見風標六歲餘，閒中應是樂琴書。", "逢辰自合膺殊選，遯世何妨且隠居。", "已愛新詩如沈謝，更聽高論似嚴徐。", "時來會有騰驤日，未許傍人笑問疏。"]'),
('cfc40f12-97ff-45ee-9df2-bbd2fe478505','和若夫韵二首  其一','吳芾','宋','宋诗','song-poetry','','[]','此身雖縛此心飛，脫得東還似解圍。',64,'全唐诗/poet.song.114000.json','["此身雖縛此心飛，脫得東還似解圍。", "鹿鶴向人如贊善，林泉見我欲生輝。", "食珍他日終難飽，飲水從今亦可肥。", "况與親朋時一醉，益知真樂是來歸。"]'),
('45f9579a-bbd7-48e6-824f-6613772d1802','和若夫韵二首  其二','吳芾','宋','宋诗','song-poetry','','[]','老夫吟詠本非長，僻性年來忽異常。',64,'全唐诗/poet.song.114000.json','["老夫吟詠本非長，僻性年來忽異常。", "唯是平生愛風月，致令清夜夢池塘。", "正慚遣與非工部，却喜言詩有卜商。", "佳句偶從閒裏得，片心如到白雲鄉。"]'),
('9128ca93-a1d6-4fed-b50f-ed0ba2477e76','和魯憲見寄二首  其一','吳芾','宋','宋诗','song-poetry','','[]','厭直承明老從臣，不將人事撓天真。',64,'全唐诗/poet.song.114000.json','["厭直承明老從臣，不將人事撓天真。", "幾年欲作山中相，今日得爲林下人。", "竹裏醉吟聊遣興，水邊宴坐足怡神。", "回思當日遊從地，過眼渾如陌上塵。"]'),
('5ea76635-b08c-4b56-8caf-027372dd0ad9','和魯憲見寄二首  其二','吳芾','宋','宋诗','song-poetry','','[]','向來三老楚江濱，一笑相歡氣味真。',64,'全唐诗/poet.song.114000.json','["向來三老楚江濱，一笑相歡氣味真。", "君向越溪持使節，我歸台嶺作閒人。", "頗思花下酒無算，尚記詩成筆有神。", "何日軺車能過我，開懷一洗渴心塵。"]'),
('b38ac938-1823-4404-bcca-a697ec6f000c','和葉先生韵  其一','吳芾','宋','宋诗','song-poetry','','[]','三分春色一分强，風雨憂愁莫見妨。',64,'全唐诗/poet.song.114000.json','["三分春色一分强，風雨憂愁莫見妨。", "何幸山城官事少，且看溪路野花香。", "絲絲嫩綠垂流水，片片飛紅逐去檣。", "一日要須拚一醉，百年能醉幾千場。"]'),
('e142d35e-d60c-4201-a5f8-df8861ef9ee0','和葉先生韵  其二','吳芾','宋','宋诗','song-poetry','','[]','杯酒忘懷不計巡，少年行樂肯輸人。',64,'全唐诗/poet.song.114000.json','["杯酒忘懷不計巡，少年行樂肯輸人。", "年來性復便疏懶，老去誰能浪苦辛。", "春暖園林花放早，月長庭院燕來頻。", "物華正爾撩詩思，况得詩翁好句新。"]'),
('ae44e0b3-dd52-4a11-b0ca-3611bc6f52c5','和董伯玉韵','吳芾','宋','宋诗','song-poetry','','[]','野性躭閒晝掩扉，坐看斜日上書帷。',64,'全唐诗/poet.song.114000.json','["野性躭閒晝掩扉，坐看斜日上書帷。", "不妨挾冊從吾好，亦學吹竽笑昨癡。", "鬢髮星星行且老，胸襟碌碌苦亡奇。", "與君正欲論心事，又恐分携各一涯。"]'),
('f727304d-3e27-4639-a7f0-59ffe7c82c29','和人見寄','吳芾','宋','宋诗','song-poetry','','[]','高義如君舉世無，賢關十載會琴書。',64,'全唐诗/poet.song.114000.json','["高義如君舉世無，賢關十載會琴書。", "匆匆邊馬來時別，鬰鬰亂山深處居。", "天外風塵仍斷絕，人間豪傑正蕭疏。", "何時樽酒論文去，千里相思寄望舒。"]'),
('ba375f14-0b05-4a7a-ae6b-958f84168109','和金克孝韵','吳芾','宋','宋诗','song-poetry','','[]','天公放我作閒人，寵辱無緣到我身。',64,'全唐诗/poet.song.114000.json','["天公放我作閒人，寵辱無緣到我身。", "濁酒興來寧惜醉，小園日涉不嫌頻。", "祇知丘壑追元亮，敢望京師說子真。", "漸近青春尤可樂，有花如錦草如茵。"]'),
('3700d4b2-e7ab-487a-a789-93469c79defe','和韓子雲見寄二首  其一','吳芾','宋','宋诗','song-poetry','','[]','投紱歸來意適然，從今免詠式微篇。',64,'全唐诗/poet.song.114000.json','["投紱歸來意適然，從今免詠式微篇。", "但令晚歲胸中適，安用虛名身後傳。", "顧我只宜乘載月，如君端合上凌烟。", "功成或欲尋真去，莫惜馭風來揖仙。"]'),
('3713a6a9-cdae-4a13-ace4-85e770a3f1c7','和韓子雲見寄二首  其二','吳芾','宋','宋诗','song-poetry','','[]','世態無常似暮霞，人生難久類春花。',64,'全唐诗/poet.song.114000.json','["世態無常似暮霞，人生難久類春花。", "已堪入谷携樵斧，還好臨湖把釣車。", "對酒未能忘酒伴，哦詩尤更憶詩家。", "何由會面論心曲，兩地相望天一涯。"]'),
('86d504cf-d7de-4c2a-9fd2-f7a300dd9728','和陳澤民見寄  其一','吳芾','宋','宋诗','song-poetry','','[]','長年擾擾走紅塵，今日方還自在身。',64,'全唐诗/poet.song.114000.json','["長年擾擾走紅塵，今日方還自在身。", "行處湖光侵杖屨，坐來山色照衣巾。", "敢希寄傲陶元亮，且學躬耕鄭子真。", "猶恐風烟勞顧揖，未能終日作閒人。"]'),
('7fa23ef0-6c50-4a59-b4d8-edef909d92e0','和陳澤民見寄  其二','吳芾','宋','宋诗','song-poetry','','[]','應喜衰翁得掛冠，裁成妙語鼎來頒。',64,'全唐诗/poet.song.114000.json','["應喜衰翁得掛冠，裁成妙語鼎來頒。", "清如水上看修竹，秀似雲中見遠山。", "已播政聲來闕下，更傳詩句滿人間。", "祇疑自此飛騰去，未許歸來伴我閑。"]'),
('21609238-d929-4830-aaa0-bc48de46cace','和朱世同韵  其一','吳芾','宋','宋诗','song-poetry','','[]','聊向空山避世喧，數椽茅屋鎖苔錢。',64,'全唐诗/poet.song.114000.json','["聊向空山避世喧，數椽茅屋鎖苔錢。", "怕逢俗客慵開戶，欣慕前賢願執鞭。", "已見二毛真老矣，幸存三徑盍終焉。", "細思萬計惟閒好，敢爲浮名誤百年。"]'),
('297670ee-2fc3-4b85-bba4-4b04cd032e58','和朱世同韵  其二','吳芾','宋','宋诗','song-poetry','','[]','幽棲終日斷經過，坐閲殘編眼欲花。',64,'全唐诗/poet.song.114000.json','["幽棲終日斷經過，坐閲殘編眼欲花。", "道在固應甘淡薄，心閒尤覺厭紛華。", "正慚我老無佳思，頗羨君詩似作家。", "拙惡豈能賡妙句，臨風吟詠祇咨嗟。"]'),
('83bc6039-9818-433f-b10f-3278881ea855','和朱世同韵  其三','吳芾','宋','宋诗','song-poetry','','[]','道義誰人似乃翁，有兒如子豈憂窮。',64,'全唐诗/poet.song.114000.json','["道義誰人似乃翁，有兒如子豈憂窮。", "自應便享千鍾養，不謂今猶四壁空。", "好遣江山歸筆下，莫將荆棘置胸中。", "詩書儻不辭勤苦，衣繡何難繼祖風。"]'),
('cc6ca547-90a1-497e-9559-6548bfe075df','和葉先生見寄','吳芾','宋','宋诗','song-poetry','','[]','春到山城花木深，興來誰與共登臨。',64,'全唐诗/poet.song.114000.json','["春到山城花木深，興來誰與共登臨。", "空驚節物催人老，强對芳菲索酒斟。", "已喜筠筒先見寄，更聞藜杖欲相尋。", "勸君未用忙歸去，要向樽前話寸心。"]'),
('f0b3543b-7086-4d4a-a17a-4cfcbf785cd0','和范希孟韵','吳芾','宋','宋诗','song-poetry','','[]','急隠歸來趣轉深，靜中不放一塵侵。',64,'全唐诗/poet.song.114000.json','["急隠歸來趣轉深，靜中不放一塵侵。", "日長宴坐風敲竹，夜久澄心月滿林。", "詩句每從佳境得，酒杯長爲故人斟。", "時危莫用計然策，身在五湖空鑄金。"]'),
('2049733f-d651-4558-a472-05394e3aa17f','和范遷善見寄','吳芾','宋','宋诗','song-poetry','','[]','溪山深處養清高，名位雖窮節行饒。',64,'全唐诗/poet.song.114000.json','["溪山深處養清高，名位雖窮節行饒。", "舉世何人堪寂寞，杜門終日自逍遥。", "交情已作千金重，別恨空驚一葉飄。", "莫向五湖成獨往，他年相與到雲霄。"]'),
('519711b2-245e-48e5-bcea-44695dfc264d','和金克孝韵','吳芾','宋','宋诗','song-poetry','','[]','長嗟軒冕累吾身，幸得歸來見此君。',64,'全唐诗/poet.song.114000.json','["長嗟軒冕累吾身，幸得歸來見此君。", "晚出漁樵呼作伴，行隨鹿鶴與同羣。", "浮光喜踏山前月，弄影貪看水底雲。", "還有江梅通信息，一枝暗裏遞清芬。"]'),
('fb854393-60f1-443e-afe7-f0ac2646604b','和世同見懷','吳芾','宋','宋诗','song-poetry','','[]','君去經春未得還，老夫幽恨滿春山。',64,'全唐诗/poet.song.114000.json','["君去經春未得還，老夫幽恨滿春山。", "海棠花過乖同賞，楊柳陰成阻共攀。", "對月有誰陪笑傲，臨流惟影伴清閒。", "何時策杖來過我，把酒論文一解顔。"]'),
('8bcd4ecc-4674-406d-b1bc-575a268c97fb','立春','吳芾','宋','宋诗','song-poetry','','[]','老夫近日苦多屯，且喜來朝已立春。',64,'全唐诗/poet.song.114000.json','["老夫近日苦多屯，且喜來朝已立春。", "但得餘殃隨臘去，敢圖好事逐年新。", "湖山入眼風光好，親舊論心氣味真。", "更若此身無疾疚，快哉天地一閒人。"]'),
('3d2d949f-8548-4ab2-ae12-b95fde4a41e6','和王瞻叔泉字韵','吳芾','宋','宋诗','song-poetry','','[]','暮年亦復侍甘泉，每對青銅只自憐。',64,'全唐诗/poet.song.114000.json','["暮年亦復侍甘泉，每對青銅只自憐。", "寧忍憂疑探虎穴，且將得失付魚筌。", "歸來但欲無身累，老去那能徇世緣。", "若得優游全晚節，從人喚作地行仙。"]'),
('2c277f61-d032-4f9f-99ab-f0cf1a7f157c','和陳天予見寄真字韵','吳芾','宋','宋诗','song-poetry','','[]','前賢惟有太丘真，豈謂於今見後身。',64,'全唐诗/poet.song.114000.json','["前賢惟有太丘真，豈謂於今見後身。", "雖是一時爲逐客，不妨千古作全人。", "自從別後心如渴，却喜詩來句絕塵。", "無計復陪花下醉，對花只覺倍傷春。"]'),
('bd298a08-bcaf-4588-95fb-46bff4900d81','和鮑昌朝湖上二首  其一','吳芾','宋','宋诗','song-poetry','','[]','青山疊疊起汀沙，幽鳥驚人噪古槎。',64,'全唐诗/poet.song.114000.json','["青山疊疊起汀沙，幽鳥驚人噪古槎。", "竹葉受風樅甲刃，松膏流地蟄龜蛇。", "愛閒正喜逢僧話，乘興何妨到酒家。", "飲罷相携磨石壁，淋灕醉墨半欹斜。"]'),
('946c20e4-f17e-4028-a80d-0bfcc0f9268f','和鮑昌朝湖上二首  其二','吳芾','宋','宋诗','song-poetry','','[]','一片湖光浄見沙，晚來閒上釣鯿槎。',64,'全唐诗/poet.song.114000.json','["一片湖光浄見沙，晚來閒上釣鯿槎。", "山橫平野堆寒玉，水繞孤城綰卧蛇。", "遥認茶烟知禁苑，忽聞機杼得人家。", "夕陽歸路西風急，笑倩旁人整帽斜。"]'),
('654f1ef6-e8b3-45d0-9fcc-2f69687683ac','湖上遣興','吳芾','宋','宋诗','song-poetry','','[]','閒來湖上覓清凉，竹杖芒鞋野興長。',64,'全唐诗/poet.song.114000.json','["閒來湖上覓清凉，竹杖芒鞋野興長。", "青嶂回環如洞府，綠波澄澈似滄浪。", "枝頭落絮隨風急，水面浮魚逐餌忙。", "自笑衰翁無箇事，悠然身世兩相忘。"]'),
('e864872e-5071-4e0e-8b41-d802a21e583e','大雨後湖上有感','吳芾','宋','宋诗','song-poetry','','[]','擬爲紅蕖棹綠波，那知一夜作霶𩃱。',64,'全唐诗/poet.song.114000.json','["擬爲紅蕖棹綠波，那知一夜作霶𩃱。", "風狂俄失雲中樹，雨漲全無水面荷。", "尋壑勝遊先自減，泛湖樂事又多磨。", "老懷自度無閒處，且向尊前强笑歌。"]'),
('ee454320-50e5-435e-af91-fe335fbc4d8a','九日和向巨源送行韵','吳芾','宋','宋诗','song-poetry','','[]','世事無窮生有涯，羞將白髮對黄花。',64,'全唐诗/poet.song.114000.json','["世事無窮生有涯，羞將白髮對黄花。", "一江秋水涵初雁，萬里暮天飛落霞。", "昔日自憐長作客，今朝方喜得還家。", "尊前話別寧辭醉，後夜相思月滿沙。"]'),
('0a8a04e4-23ed-4db6-9f4f-6e5b100fea58','和逐年九日陽字韵','吳芾','宋','宋诗','song-poetry','','[]','天上恩來解郡章，人間那復是重陽。',64,'全唐诗/poet.song.114000.json','["天上恩來解郡章，人間那復是重陽。", "老身已許歸三徑，佳節何妨醉百觴。", "但有笑容生面目，更無閒事撓心腸。", "旁人不信吾歸去，今日真成返故鄉。"]'),
('3c3d27d9-757c-46f1-8cff-4f14bb03ec33','余有重陽詩歲和一篇今日偶和成二首  其一','吳芾','宋','宋诗','song-poetry','','[]','此會從來有故常，湖山歲歲做重陽。',64,'全唐诗/poet.song.114000.json','["此會從來有故常，湖山歲歲做重陽。", "黄花已是鋪三徑，綠酒何妨舉百觴。", "小圃晚來堪散步，薄田秋入足充腸。", "登臨莫起淒涼歎，且喜成歸老故鄉。"]'),
('9dd90a76-eab4-4d24-9abd-9af22826a05c','余有重陽詩歲和一篇今日偶和成二首  其二','吳芾','宋','宋诗','song-poetry','','[]','去歲重陽解郡章，歸來又復見重陽。',64,'全唐诗/poet.song.114000.json','["去歲重陽解郡章，歸來又復見重陽。", "此身已作林泉客，今日更持萸菊觴。", "正要登高窮遠目，不妨拚醉浣愁腸。", "佳辰若得長無事，何必乘雲至帝鄉。"]'),
('61c21bcc-cb97-4afa-8228-98ec5316b293','重陽即席呈諸兄叔','吳芾','宋','宋诗','song-poetry','','[]','淅淅西風作晚凉，驚人節物又重陽。',64,'全唐诗/poet.song.114000.json','["淅淅西風作晚凉，驚人節物又重陽。", "頻年此會成千里，環坐如今共一觴。", "且把黄花開笑口，莫因白髮攪愁腸。", "人生聚散渾無定，來歲那知在故鄉。"]'),
('57e8412f-771a-4d37-a29b-36b2ab54974c','重陽再和乙丑歲韵','吳芾','宋','宋诗','song-poetry','','[]','老去逢秋倍感傷，此生能見幾重陽。',64,'全唐诗/poet.song.114000.json','["老去逢秋倍感傷，此生能見幾重陽。", "喜君綠蟻初浮甕，容我黄花滿泛觴。", "幸返丘園如素志，况陪新舊話中腸。", "已拚今日如泥醉，苦恨頻年客異鄉。"]'),
('6a8e4a46-e297-4c04-825d-50a352fa091d','和吳致政韵','吳芾','宋','宋诗','song-poetry','','[]','晚學知誰繼後塵，鄉閭舊仰老成人。',64,'全唐诗/poet.song.114000.json','["晚學知誰繼後塵，鄉閭舊仰老成人。", "門無車馬何妨靜，室有詩書不厭貧。", "閙裏抽身甘寂寞，閒中覓句鬭清新。", "杖藜莫惜頻過我，共醉床頭滿榼春。"]'),
('b75907af-ee21-48b2-bf01-a2ba6cd65fbf','和沈先覺韵','吳芾','宋','宋诗','song-poetry','','[]','枉度浮生八十春，休談天數與人倫。',64,'全唐诗/poet.song.114000.json','["枉度浮生八十春，休談天數與人倫。", "長貧已是難餬口，久病那堪更累身。", "獨把新詩娛晚景，誰將靈劑起痿人。", "若教得酒時時醉，醉裏高吟尚絕塵。"]'),
('4c18efa6-0a2c-4066-9315-14acc07e3e31','和朱世同韵二首  其一','吳芾','宋','宋诗','song-poetry','','[]','立朝初不愧廷臣，晚節胡爲苦乞身。',64,'全唐诗/poet.song.114000.json','["立朝初不愧廷臣，晚節胡爲苦乞身。", "自度濟時無遠畧，不如辭祿作閒人。", "林間幸已安禪榻，湖上何妨擲釣綸。", "若也故人能過我，尚堪共醉甕頭春。"]'),
('9636a040-f678-4363-97ce-c350493e1287','和朱世同韵二首  其二','吳芾','宋','宋诗','song-poetry','','[]','已歸林下得從容，還喜時和與歲豐。',64,'全唐诗/poet.song.114000.json','["已歸林下得從容，還喜時和與歲豐。", "好景盡歸詩句裏，閒愁俱付酒杯中。", "臘殘惟願呈三白，春去從教落萬紅。", "親舊自今休問位，只須喚我作吳公。"]'),
('3ca1cdf6-cec9-4d22-a07b-b35a608c3d54','和朱世同見寄','吳芾','宋','宋诗','song-poetry','','[]','門外青山玉作堆，山前一水更縈回。',64,'全唐诗/poet.song.114000.json','["門外青山玉作堆，山前一水更縈回。", "歸來雖喜風烟好，老去還驚歲月催。", "不見故人增寂寞，尚懷往日共徘徊。", "何時軒蓋重相過，伴我花前醉百杯。"]'),
('0ffd7afb-9f40-4640-bd90-1859fcaeed99','到雙勝匆匆不及款舟中成小詩寄良器兼簡楊宰','吳芾','宋','宋诗','song-poetry','','[]','海濱何處足春風，盡在王孫小圃中。',64,'全唐诗/poet.song.114000.json','["海濱何處足春風，盡在王孫小圃中。", "雨洗山光供几席，日移花影上簾櫳。", "扁舟回首烟波隔，尊酒何時笑語同。", "若對揚雄賞幽勝，杯行應亦話衰翁。"]'),
('abce2310-4921-4e67-bbe5-8b58599dfbe0','寄江朝宗','吳芾','宋','宋诗','song-poetry','','[]','君來已是後花期，不見春風爛熳時。',64,'全唐诗/poet.song.114000.json','["君來已是後花期，不見春風爛熳時。", "檻外止餘新芍藥，簷前祇有舊酴醿。", "尚堪共泛忘憂酒，亦可同吟遣興詩。", "倒指春歸能幾日，速來相就賞殘枝。"]'),
('cb9920f0-7292-44a5-bd65-7b23c73103ba','寄周子及','吳芾','宋','宋诗','song-poetry','','[]','回頭一別兩經秋，喜奉安輿返故丘。',64,'全唐诗/poet.song.114000.json','["回頭一別兩經秋，喜奉安輿返故丘。", "自謂此時須見過，誰知官事不容留。", "君遊幕府聲猷著，我住湖山景趣幽。", "出處雖殊心不異，迂程能爲一來不。"]'),
('761ba694-8d0a-4b26-b94f-fc887b40a87e','寄江朝宗','吳芾','宋','宋诗','song-poetry','','[]','碧雲暮合首重回，正擬前村共探梅。',64,'全唐诗/poet.song.114000.json','["碧雲暮合首重回，正擬前村共探梅。", "耐久直須看歲晚，追歡何必待春來。", "山中縱有詩千首，花下誰同酒一杯。", "顧我與君非面友，願言命駕莫徘徊。"]'),
('591e8aee-839f-43f2-9099-cf63f5d868f1','寄陳能之','吳芾','宋','宋诗','song-poetry','','[]','烏府延登謇諤臣，共知吾道一時伸。',64,'全唐诗/poet.song.114000.json','["烏府延登謇諤臣，共知吾道一時伸。", "方陳讜論來裨國，還守清規去潔身。", "峩豸豈能忘去佞，憑熊聊復試臨民。", "頗思一見論心曲，同醉梅花爛漫春。"]'),
('a99b9856-64d6-4315-93d7-084ee5c24a42','寄陳叔進','吳芾','宋','宋诗','song-poetry','','[]','鄉里衣冠久不振，後來猶喜有斯人。',64,'全唐诗/poet.song.114000.json','["鄉里衣冠久不振，後來猶喜有斯人。", "曾爲蓬島神仙主，端是儲闈羽翼臣。", "大節已觀能直己，小淹何惜且臨民。", "君家幸有佳山水，莫向他鄉別卜隣。"]'),
('cff9ec96-8d3b-4853-9dda-d39422f407ea','寄楊次雲岸長老','吳芾','宋','宋诗','song-poetry','','[]','高僧良士總貪閒，雖我同庚不往還。',64,'全唐诗/poet.song.114000.json','["高僧良士總貪閒，雖我同庚不往還。", "詩罷誰知勤治圃，齋餘無事只潛山。", "亦聞相約來傾蓋，久待如何未叩關。", "湖上藕花今正發，不妨共戲水雲間。"]'),
('52592b49-c2cb-451a-b6b4-0c455cc1a68f','寄趙德莊','吳芾','宋','宋诗','song-poetry','','[]','故人分袂幾何年，不謂乘軺到海邊。',64,'全唐诗/poet.song.114000.json','["故人分袂幾何年，不謂乘軺到海邊。", "我守丘園甘已矣，君馳原隰尚依然。", "有懷風月空相憶，無計杯觴可共傳。", "出處不齊徒悵望，夕陽衰草自連天。"]'),
('73f6575e-a1db-482c-9c3d-cf5d855b03c2','又陳伯明知郡遠寄詩篇因次韵二首  其一','吳芾','宋','宋诗','song-poetry','','[]','信筆題詩不記篇，聊憑賦詠寫林泉。',64,'全唐诗/poet.song.114000.json','["信筆題詩不記篇，聊憑賦詠寫林泉。", "閒來倚杖雲千嶂，睡起憑欄月一川。", "野性已安三徑裏，吟魂猶繞兩湖邊。", "何時更許陪清話，復把深杯手自傳。"]'),
('dd3340fa-db03-4112-b053-58d064f13425','又陳伯明知郡遠寄詩篇因次韵二首  其二','吳芾','宋','宋诗','song-poetry','','[]','喜到舊家山水鄉，依然山色與湖光。',64,'全唐诗/poet.song.114000.json','["喜到舊家山水鄉，依然山色與湖光。", "此身宛在真仙窟，回首空懷太守章。", "豈意新詩猶見及，尚言故郡不相忘。", "自憐粃政無遺愛，安得人思蔽芾棠。"]'),
('f690a9d1-2588-4c3b-8a4b-3952b4eddd0c','寄陳彥邦二首  其一','吳芾','宋','宋诗','song-poetry','','[]','自古中興用實才，正資賢哲共圖回。',64,'全唐诗/poet.song.114000.json','["自古中興用實才，正資賢哲共圖回。", "若爲清禁挽不住，亦效衰翁歸去來。", "幸有江水供笑傲，更邀風月與徘徊。", "得閒莫惜頻相過，伴我樽前笑口開。"]'),
('339bab69-93ab-4973-9252-ab1b8d0986a3','寄陳彥邦二首  其二','吳芾','宋','宋诗','song-poetry','','[]','不須細細說行藏，四十年來夢一場。',64,'全唐诗/poet.song.114000.json','["不須細細說行藏，四十年來夢一場。", "我得放歸心已足，君能勇退道尤光。", "閒中倍覺林泉好，閙裏誰知日月長。", "我已與君成二老，更將一節起吾鄉。"]');
